// Application lifecycle and entry point.
package vogui

import "encoding/json"

// App defines the application structure.
//
// Required fields:
//   - Init: returns the initial state value; called once at startup.
//   - View: renders the UI from the current state. Required when Routes is empty.
//
// Optional fields:
//   - Routes: if non-empty, route-based rendering is used instead of View.
//     When both Routes and View are set, Routes takes priority.
//   - OnError: called on handler errors; defaults to println if nil.
type App struct {
	Init    func() any
	View    func(state any) Node
	Routes  []Route
	OnError func(err error)
}

// Internal state
var currentState any
var currentApp App

// Run initializes the application and starts the event loop.
// The main fiber blocks on waitForEvent() and processes events inline —
// no separate fiber is spawned per event.
func Run(app App) {
	currentApp = app
	currentState = app.Init()
	render()

	for {
		handlerID, payload := waitForEvent()
		processEvent(Event{HandlerID: handlerID, Payload: payload})
	}
}

// updatePath is called by Navigate to trigger a re-render.
func updatePath(path string) {
	render()
}

// timerPayload is the JSON structure for timer events.
type timerPayload struct {
	Id int
}

// keyPayload is the JSON structure for global key events.
type keyPayload struct {
	Key string
}

// animFramePayload is the JSON structure for animation frame events.
type animFramePayload struct {
	Id int
}

// gameLoopPayload is the JSON structure for game loop events.
type gameLoopPayload struct {
	Dt float64
}

func processEvent(event Event) {
	switch event.HandlerID {
	case eventIDTimer:
		var p timerPayload
		if err := json.Unmarshal([]byte(event.Payload), &p); err != nil {
			reportError(err)
			return
		}
		invokeTimerHandler(p.Id, currentState)
	case eventIDGlobalKey:
		var p keyPayload
		if err := json.Unmarshal([]byte(event.Payload), &p); err != nil {
			reportError(err)
			return
		}
		err := invokeGlobalKeyHandler(currentState, p.Key)
		if err != nil {
			reportError(err)
		}
	case eventIDNavigation:
		// popstate: just re-render
	case eventIDAnimFrame:
		var p animFramePayload
		if err := json.Unmarshal([]byte(event.Payload), &p); err != nil {
			reportError(err)
			return
		}
		invokeAnimFrameHandler(p.Id, currentState)
	case eventIDGameLoop:
		var p gameLoopPayload
		if err := json.Unmarshal([]byte(event.Payload), &p); err != nil {
			reportError(err)
			return
		}
		invokeGameLoopHandler(currentState, p.Dt)
	case eventIDMeasure:
		if err := invokeMeasureCallback(currentState, event.Payload); err != nil {
			reportError(err)
		}
	default:
		err := invokeHandler(currentState, event.HandlerID, event.Payload)
		if err != nil {
			reportError(err)
		}
	}
	render()
}

func render() {
	resetHandlers()

	var tree Node
	if len(currentApp.Routes) > 0 {
		path := GetCurrentPath()
		matched := false
		for _, route := range currentApp.Routes {
			params, ok := matchRoute(route.Path, path)
			if ok {
				tree = route.View(currentState, params)
				matched = true
				break
			}
		}
		if !matched {
			tree = Text("404 Not Found: " + path)
		}
	} else {
		tree = currentApp.View(currentState)
	}

	// Clean up components that are no longer in the tree
	cleanupDestroyedComponents()

	styles := flushPendingStyles()
	canvasCmds := flushPendingCanvasCommands()
	themeVars := themeToCSSVars()
	refActions := flushPendingRefActions()
	data := encodeRender(renderGen, tree, styles, canvasCmds, themeVars, refActions)
	emitRenderBinary(data)
}

func reportError(err error) {
	if currentApp.OnError != nil {
		currentApp.OnError(err)
	} else {
		println("VoGUI: error:", err)
	}
}

// ============ Extern Declarations ============

// waitForEvent blocks the current fiber until the host sends an event.
// Returns (handlerID, payload) when woken.
func waitForEvent() (int, string)

func emitRenderBinary(data []byte)
func HasHostCapability(name string) bool

// Audio playback: load clips, play SFX/music, volume control, 3D spatial audio.
//
// This is the single audio API for the Vo ecosystem. Both vogui apps and
// voplay games use it. voplay adds path-based loading on top via file_io.
package vogui

// ============ Extern Declarations ============

func audioLoadBytes(data []byte) (int, error)
func audioFree(clipID int)
func audioPlaySound(clipID int, volume, pitch float64)
func audioSetListener(px, py, pz, fx, fy, fz, ux, uy, uz float64)
func audioPlaySound3D(clipID int, px, py, pz, volume, refDistance, maxDistance float64)
func audioCreateSource3D(clipID int, px, py, pz, volume, refDistance, maxDistance float64) (int, error)
func audioUpdateSpatial()
func audioSetSource3DPos(sourceID int, px, py, pz float64)
func audioSetSource3DParams(sourceID int, volume, pitch float64)
func audioRemoveSource3D(sourceID int)
func audioPlayMusic(clipID int, volume float64)
func audioStopMusic()
func audioPauseMusic()
func audioResumeMusic()
func audioSetSFXVolume(vol float64)
func audioSetMusicVolume(vol float64)

// ============ Public Types ============

// AudioClipID is a handle to a loaded audio resource (WAV, OGG, MP3).
type AudioClipID int

// AudioSourceID is a handle to a persistent 3D audio source.
type AudioSourceID int

// ============ Basic Audio ============

// LoadAudioBytes loads an audio clip from encoded bytes (WAV, OGG, MP3).
func LoadAudioBytes(data []byte) (AudioClipID, error) {
	id := audioLoadBytes(data)?
	return AudioClipID(id), nil
}

// Free releases a loaded audio clip.
func (c AudioClipID) Free() {
	audioFree(int(c))
}

// Play plays this clip as a one-shot sound effect at default volume and pitch.
func (c AudioClipID) Play() {
	audioPlaySound(int(c), 1.0, 1.0)
}

// PlayEx plays this clip as a sound effect with explicit parameters.
// volume: amplitude scale (1.0 = normal).
// pitch: playback speed (1.0 = normal, 2.0 = double speed/octave up).
func (c AudioClipID) PlayEx(volume, pitch float64) {
	audioPlaySound(int(c), volume, pitch)
}

// ============ Music ============

// PlayMusic starts this clip as looping background music.
// Stops any currently playing music. volume: 0.0–1.0.
func (c AudioClipID) PlayMusic(volume float64) {
	audioPlayMusic(int(c), volume)
}

// StopMusic stops the currently playing background music.
func StopMusic() {
	audioStopMusic()
}

// PauseMusic pauses the currently playing background music.
func PauseMusic() {
	audioPauseMusic()
}

// ResumeMusic resumes paused background music.
func ResumeMusic() {
	audioResumeMusic()
}

// ============ Volume Control ============

// SetSFXVolume sets the global volume multiplier for sound effects (0.0–1.0).
func SetSFXVolume(vol float64) {
	audioSetSFXVolume(vol)
}

// SetMusicVolume sets the global volume multiplier for music (0.0–1.0).
func SetMusicVolume(vol float64) {
	audioSetMusicVolume(vol)
}

// ============ 3D Spatial Audio ============

// Vec3 is a minimal 3D vector for audio positioning.
// If the consumer already has its own Vec3 type (e.g. voplay), it can
// convert or call the lower-level extern functions directly.
type AudioVec3 struct {
	X, Y, Z float64
}

// SetAudioListener sets the listener position and orientation for 3D audio.
func SetAudioListener(position, forward, up AudioVec3) {
	audioSetListener(
		position.X, position.Y, position.Z,
		forward.X, forward.Y, forward.Z,
		up.X, up.Y, up.Z,
	)
}

// PlaySound3D plays a one-shot 3D positional sound.
func (c AudioClipID) PlaySound3D(pos AudioVec3, volume, refDistance, maxDistance float64) {
	audioPlaySound3D(int(c), pos.X, pos.Y, pos.Z, volume, refDistance, maxDistance)
}

// CreateAudioSource3D creates a persistent looping 3D audio source.
func CreateAudioSource3D(clip AudioClipID, pos AudioVec3, volume, refDistance, maxDistance float64) (AudioSourceID, error) {
	id := audioCreateSource3D(int(clip), pos.X, pos.Y, pos.Z, volume, refDistance, maxDistance)?
	return AudioSourceID(id), nil
}

// UpdateSpatialAudio updates all persistent 3D sources with current listener.
func UpdateSpatialAudio() {
	audioUpdateSpatial()
}

// SetPosition updates the world position of a persistent 3D source.
func (s AudioSourceID) SetPosition(pos AudioVec3) {
	audioSetSource3DPos(int(s), pos.X, pos.Y, pos.Z)
}

func (s AudioSourceID) SetParams(volume, pitch float64) {
	audioSetSource3DParams(int(s), volume, pitch)
}

// Remove stops and removes a persistent 3D source.
func (s AudioSourceID) Remove() {
	audioRemoveSource3D(int(s))
}

// Canvas component for GPU/2D rendering with 2D drawing API.
package vogui

// CanvasProps configures the canvas element.
type CanvasProps struct {
	Width      int
	Height     int
	Fullscreen bool
	OnPointer  Handler // receives PointerEvent on mouse/touch interactions
	OnResize   Handler // receives ResizeEvent when canvas size changes
}

// Canvas renders a canvas element for GPU or 2D rendering.
func Canvas(opts CanvasProps) Node {
	props := map[string]any{}
	if opts.Width > 0 {
		props["width"] = opts.Width
	}
	if opts.Height > 0 {
		props["height"] = opts.Height
	}
	if opts.Fullscreen {
		props["fullscreen"] = true
	}
	if opts.OnPointer.IsSet() {
		props["onPointer"] = opts.OnPointer.ID
	}
	if opts.OnResize.IsSet() {
		props["onResize"] = opts.OnResize.ID
	}
	return Node{Type: "Canvas", Props: props}
}

// PointerEvent contains unified mouse/touch event data.
type PointerEvent struct {
	Kind    string  // "down", "up", "move", "enter", "leave"
	X       float64 // Canvas-relative X coordinate
	Y       float64 // Canvas-relative Y coordinate
	Button  int     // 0=left, 1=middle, 2=right (mouse only)
	Buttons int     // Bitmask of currently pressed buttons
}

// ResizeEvent contains canvas resize data.
type ResizeEvent struct {
	Width  int
	Height int
}

// OnPointer wraps an action that receives pointer events.
// Action signature: func(s *State, e PointerEvent)
func OnPointer(action any) Handler {
	return registerHandler(action, handlerPointer, 0)
}

// OnResize wraps an action that receives canvas resize events.
// Action signature: func(s *State, e ResizeEvent)
func OnResize(action any) Handler {
	return registerHandler(action, handlerResize, 0)
}

// ============ Canvas 2D Drawing API ============

// canvasCommand represents a single drawing operation.
type canvasCommand struct {
	Cmd  string    `json:"c"`
	Args []any     `json:"a,omitempty"`
}

// CanvasCtx is a drawing context for a named canvas element.
// Commands are buffered and sent to JS on Flush().
type CanvasCtx struct {
	ref      string
	commands []canvasCommand
}

// Pending canvas command batches to include in render output.
// Each entry maps ref name -> commands.
var pendingCanvasCommands []map[string]any

// GetCanvas returns a drawing context for a canvas identified by its Ref name.
func GetCanvas(refName string) *CanvasCtx {
	return &CanvasCtx{ref: refName}
}

// Flush sends all buffered commands to JS for execution on the canvas.
func (c *CanvasCtx) Flush() {
	if len(c.commands) == 0 {
		return
	}
	pendingCanvasCommands = append(pendingCanvasCommands, map[string]any{
		"ref":  c.ref,
		"cmds": c.commands,
	})
	c.commands = nil
}

func (c *CanvasCtx) cmd(name string, args ...any) {
	c.commands = append(c.commands, canvasCommand{Cmd: name, Args: args})
}

// flushPendingCanvasCommands returns and clears pending canvas command batches.
func flushPendingCanvasCommands() []map[string]any {
	if len(pendingCanvasCommands) == 0 {
		return nil
	}
	result := pendingCanvasCommands
	pendingCanvasCommands = nil
	return result
}

// ============ State Commands ============

// Clear clears the entire canvas.
func (c *CanvasCtx) Clear() { c.cmd("clear") }

// SetFill sets the fill color/style.
func (c *CanvasCtx) SetFill(color string) { c.cmd("fill", color) }

// SetStroke sets the stroke color/style.
func (c *CanvasCtx) SetStroke(color string) { c.cmd("stroke", color) }

// SetLineWidth sets the line width.
func (c *CanvasCtx) SetLineWidth(w float64) { c.cmd("lw", w) }

// SetFont sets the font for text drawing.
func (c *CanvasCtx) SetFont(font string) { c.cmd("font", font) }

// SetAlpha sets the global alpha (opacity).
func (c *CanvasCtx) SetAlpha(a float64) { c.cmd("alpha", a) }

// SetTextAlign sets the text alignment ("left", "center", "right", "start", "end").
func (c *CanvasCtx) SetTextAlign(align string) { c.cmd("ta", align) }

// SetTextBaseline sets the text baseline ("top", "middle", "bottom", "alphabetic").
func (c *CanvasCtx) SetTextBaseline(baseline string) { c.cmd("tb", baseline) }

// SetLineCap sets the line cap style ("butt", "round", "square").
func (c *CanvasCtx) SetLineCap(cap string) { c.cmd("lc", cap) }

// SetLineJoin sets the line join style ("miter", "round", "bevel").
func (c *CanvasCtx) SetLineJoin(join string) { c.cmd("lj", join) }

// SetShadow sets the shadow properties.
func (c *CanvasCtx) SetShadow(offsetX, offsetY, blur float64, color string) {
	c.cmd("shadow", offsetX, offsetY, blur, color)
}

// ============ Shape Commands ============

// FillRect fills a rectangle.
func (c *CanvasCtx) FillRect(x, y, w, h float64) { c.cmd("fr", x, y, w, h) }

// StrokeRect strokes a rectangle outline.
func (c *CanvasCtx) StrokeRect(x, y, w, h float64) { c.cmd("sr", x, y, w, h) }

// ClearRect clears a rectangular area.
func (c *CanvasCtx) ClearRect(x, y, w, h float64) { c.cmd("cr", x, y, w, h) }

// FillCircle fills a circle.
func (c *CanvasCtx) FillCircle(cx, cy, r float64) { c.cmd("fc", cx, cy, r) }

// StrokeCircle strokes a circle outline.
func (c *CanvasCtx) StrokeCircle(cx, cy, r float64) { c.cmd("sc", cx, cy, r) }

// FillRoundRect fills a rectangle with rounded corners.
func (c *CanvasCtx) FillRoundRect(x, y, w, h, r float64) { c.cmd("frr", x, y, w, h, r) }

// StrokeRoundRect strokes a rectangle outline with rounded corners.
func (c *CanvasCtx) StrokeRoundRect(x, y, w, h, r float64) { c.cmd("srr", x, y, w, h, r) }

// FillEllipse fills an ellipse.
func (c *CanvasCtx) FillEllipse(cx, cy, rx, ry float64) { c.cmd("fe", cx, cy, rx, ry) }

// StrokeEllipse strokes an ellipse outline.
func (c *CanvasCtx) StrokeEllipse(cx, cy, rx, ry float64) { c.cmd("se", cx, cy, rx, ry) }

// ============ Path Commands ============

// BeginPath starts a new path.
func (c *CanvasCtx) BeginPath() { c.cmd("bp") }

// MoveTo moves to a point without drawing.
func (c *CanvasCtx) MoveTo(x, y float64) { c.cmd("mt", x, y) }

// LineTo draws a line to a point.
func (c *CanvasCtx) LineTo(x, y float64) { c.cmd("lt", x, y) }

// ArcTo draws an arc between two tangent lines.
func (c *CanvasCtx) ArcTo(x1, y1, x2, y2, r float64) { c.cmd("at", x1, y1, x2, y2, r) }

// Arc draws an arc (portion of a circle).
func (c *CanvasCtx) Arc(cx, cy, r, startAngle, endAngle float64) {
	c.cmd("arc", cx, cy, r, startAngle, endAngle)
}

// QuadraticCurveTo draws a quadratic Bezier curve.
func (c *CanvasCtx) QuadraticCurveTo(cpx, cpy, x, y float64) { c.cmd("qct", cpx, cpy, x, y) }

// BezierCurveTo draws a cubic Bezier curve.
func (c *CanvasCtx) BezierCurveTo(cp1x, cp1y, cp2x, cp2y, x, y float64) {
	c.cmd("bct", cp1x, cp1y, cp2x, cp2y, x, y)
}

// ClosePath closes the current path.
func (c *CanvasCtx) ClosePath() { c.cmd("cp") }

// Fill fills the current path.
func (c *CanvasCtx) Fill() { c.cmd("f") }

// Stroke strokes the current path.
func (c *CanvasCtx) Stroke() { c.cmd("s") }

// Clip sets the current path as the clipping region.
func (c *CanvasCtx) Clip() { c.cmd("clip") }

// ============ Text Commands ============

// FillText draws filled text.
func (c *CanvasCtx) FillText(text string, x, y float64) { c.cmd("ft", text, x, y) }

// StrokeText draws stroked text.
func (c *CanvasCtx) StrokeText(text string, x, y float64) { c.cmd("st", text, x, y) }

// FillTextWrap draws text with automatic word wrapping using Pretext.
// The current font (set via SetFont) is used for measurement.
// maxWidth: maximum line width in pixels.
// lineHeight: vertical distance between line baselines in pixels.
func (c *CanvasCtx) FillTextWrap(text string, x, y, maxWidth, lineHeight float64) {
	c.cmd("ftw", text, x, y, maxWidth, lineHeight)
}

// ============ Image Commands ============

// DrawImage draws an image at position. The image is identified by URL.
// The image is loaded and cached by the JS runtime on first use.
func (c *CanvasCtx) DrawImage(url string, x, y float64) {
	c.cmd("di", url, x, y)
}

// DrawImageScaled draws an image scaled to a specific size.
func (c *CanvasCtx) DrawImageScaled(url string, x, y, w, h float64) {
	c.cmd("dis", url, x, y, w, h)
}

// DrawImageSub draws a sub-rectangle of an image to a destination rectangle.
func (c *CanvasCtx) DrawImageSub(url string, sx, sy, sw, sh, dx, dy, dw, dh float64) {
	c.cmd("disub", url, sx, sy, sw, sh, dx, dy, dw, dh)
}

// ============ Transform Commands ============

// Save saves the current canvas state.
func (c *CanvasCtx) Save() { c.cmd("save") }

// Restore restores the previously saved canvas state.
func (c *CanvasCtx) Restore() { c.cmd("rest") }

// Translate translates the canvas origin.
func (c *CanvasCtx) Translate(x, y float64) { c.cmd("tr", x, y) }

// Rotate rotates the canvas (angle in radians).
func (c *CanvasCtx) Rotate(angle float64) { c.cmd("rot", angle) }

// Scale scales the canvas.
func (c *CanvasCtx) Scale(sx, sy float64) { c.cmd("scl", sx, sy) }

// ResetTransform resets the transform to identity.
func (c *CanvasCtx) ResetTransform() { c.cmd("rt") }

// ============ Gradient & Pattern Commands ============

// SetLinearGradient sets the fill style to a linear gradient.
func (c *CanvasCtx) SetLinearGradient(x0, y0, x1, y1 float64, stops []GradientStop) {
	c.cmd("lg", x0, y0, x1, y1, stops)
}

// SetRadialGradient sets the fill style to a radial gradient.
func (c *CanvasCtx) SetRadialGradient(x0, y0, r0, x1, y1, r1 float64, stops []GradientStop) {
	c.cmd("rg", x0, y0, r0, x1, y1, r1, stops)
}

// GradientStop defines a color stop in a gradient.
type GradientStop struct {
	Offset float64 `json:"offset"`
	Color  string  `json:"color"`
}

// ============ requestAnimationFrame & Game Loop ============

// Animation frame handler type constants
const (
	eventIDAnimFrame = -4
	eventIDGameLoop  = -5
)

var animFrameHandlers = map[int]any{}
var nextAnimFrameID int = 1

// RequestAnimationFrame schedules a callback for the next animation frame.
// Returns a cancel ID.
// Handler signature: func(state any)
func RequestAnimationFrame(handler any) int {
	id := nextAnimFrameID
	nextAnimFrameID++
	animFrameHandlers[id] = handler
	startAnimFrame(id)
	return id
}

// CancelAnimationFrame cancels a pending animation frame request.
func CancelAnimationFrame(id int) {
	delete(animFrameHandlers, id)
	cancelAnimFrame(id)
}

// GameLoop state
var gameLoopHandler any
var gameLoopID int
var gameLoopActive bool

// RunGameLoop starts a continuous game loop that calls handler every frame.
// Handler signature: func(state any, dt float64)
// dt is milliseconds since last frame.
// Returns a loop ID for StopGameLoop.
func RunGameLoop(handler any) int {
	gameLoopHandler = handler
	gameLoopActive = true
	gameLoopID = nextAnimFrameID
	nextAnimFrameID++
	startGameLoop(gameLoopID)
	return gameLoopID
}

// StopGameLoop stops a running game loop.
func StopGameLoop(id int) {
	if id == gameLoopID {
		gameLoopActive = false
		gameLoopHandler = nil
		stopGameLoop(id)
	}
}

func invokeAnimFrameHandler(id int, state any) {
	handler, ok := animFrameHandlers[id]
	if !ok {
		return
	}
	delete(animFrameHandlers, id)
	err := handler~>(state)
	if err != nil {
		println("VoGUI: animFrame handler error:", err)
	}
}

func invokeGameLoopHandler(state any, dt float64) {
	if !gameLoopActive || gameLoopHandler == nil {
		return
	}
	err := gameLoopHandler~>(state, dt)
	if err != nil {
		println("VoGUI: gameLoop handler error:", err)
	}
}

// ============ Extern Declarations ============

func startAnimFrame(id int)
func cancelAnimFrame(id int)
func startGameLoop(id int)
func stopGameLoop(id int)

// Component model: local state, lifecycle, and memo.
//
// A Component is any struct with a View() Node method.
// Optional lifecycle methods: Init(), Destroy(), ShouldUpdate() bool.
//
// Lifecycle contract:
//   - View() Node          [REQUIRED]  Called every render cycle to produce the subtree.
//   - Init()               [OPTIONAL]  Called once on first Mount(). If absent, skipped silently.
//   - Destroy()            [OPTIONAL]  Called when the component is absent from the tree after a render.
//                                      If absent, skipped silently.
//   - ShouldUpdate() bool  [OPTIONAL]  Called before View() when a cached subtree exists.
//                                      Return true to re-render, false to reuse the cached DOM.
//                                      If absent or returns an error, the component always re-renders.
//
// All lifecycle methods are invoked via dynamic call (~>). If a method does not exist
// on the struct, the call returns an error which is silently ignored (the method is
// treated as absent). If a method exists but returns an error, the error is ignored
// and the default behavior applies (re-render for ShouldUpdate, no-op for Init/Destroy).
//
// Handlers inside View() close over the component pointer directly:
//
//   type Counter struct{ Count int }
//   func (c *Counter) View() vogui.Node {
//       return vogui.Row(
//           vogui.Text(fmt.Sprint(c.Count)),
//           vogui.Button("+", vogui.OnClick(func(c *Counter) { c.Count++ })),
//       )
//   }
//
//   // In parent View (component must live on the parent state struct):
//   return vogui.Mount(&s.Counter)
package vogui

// componentEntry tracks a mounted component's lifecycle state.
type componentEntry struct {
	ptr      any
	cached   Node
	hasCache bool
	inited   bool
	alive    bool
}

var componentRegistry = map[int]*componentEntry{}
var componentPtrToID  = map[any]int{}
var nextComponentID   = 1

// Mount renders a Component, managing Init/Destroy lifecycle and optional ShouldUpdate memo.
// component must be a pointer to a struct with a View() Node method.
func Mount(component any) Node {
	id, entry := getOrCreateEntry(component)
	entry.alive = true

	if !entry.inited {
		entry.inited = true
		component~>Init()
	}

	if entry.hasCache {
		skip, err := component~>ShouldUpdate()
		if err == nil && !skip.(bool) {
			// Return cached marker: JS reuses stored DOM subtree without re-diffing.
			return Node{Type: "__cached__", Props: map[string]any{"_cid": id}}
		}
	}

	// Set component context so handlers registered during View() are scoped to this component.
	prevCtx := currentComponentCtx
	currentComponentCtx = component
	result, _ := component~>View()
	currentComponentCtx = prevCtx

	tree := result.(Node)
	// Wrap with component marker so JS can track the subtree root for cache reuse.
	wrapped := Node{Type: "__comp__", Props: map[string]any{"_cid": id}, Children: []Node{tree}}
	entry.cached = wrapped
	entry.hasCache = true
	return wrapped
}

func getOrCreateEntry(component any) (int, *componentEntry) {
	if id, ok := componentPtrToID[component]; ok {
		return id, componentRegistry[id]
	}
	id := nextComponentID
	nextComponentID++
	entry := &componentEntry{ptr: component}
	componentPtrToID[component] = id
	componentRegistry[id] = entry
	return id, entry
}

// cleanupDestroyedComponents calls Destroy() on components absent from the last render.
func cleanupDestroyedComponents() {
	for id, entry := range componentRegistry {
		if !entry.alive {
			entry.ptr~>Destroy()
			delete(componentRegistry, id)
			delete(componentPtrToID, entry.ptr)
		}
	}
	for _, entry := range componentRegistry {
		entry.alive = false
	}
}

