// Binary render protocol encoder.
//
// Wire format (little-endian):
//   [u32: gen][u8: flags][NODE][u16: handlerCount][HANDLER...][styles?][canvas?]
//
// Node tags: 0=null 1=element 2=text 3=fragment
// Value tags: 0=null 1=bool 2=int 3=float64 4=string 5=map 6=array 7=node
package vogui

// Private extern: returns the IEEE-754 bit representation of f as int64.
func float64bits(f float64) int64

const (
	binNodeNull      = 0
	binNodeElement   = 1
	binNodeText      = 2
	binNodeFrag      = 3
	binNodeComponent = 4 // u32: componentID, then the subtree node
	binNodeCached    = 5 // u32: componentID; JS reuses stored DOM subtree

	binValNull    = 0
	binValBool    = 1
	binValInt     = 2
	binValFloat64 = 3
	binValString  = 4
	binValMap     = 5
	binValArray   = 6
	binValNode    = 7
)

// BinWriter is a growable byte buffer for binary encoding.
type BinWriter struct {
	buf []byte
}

func (w *BinWriter) u8(v int) {
	w.buf = append(w.buf, byte(v))
}

func (w *BinWriter) u16(v int) {
	w.buf = append(w.buf, byte(v), byte(v>>8))
}

func (w *BinWriter) u32(v int) {
	w.buf = append(w.buf, byte(v), byte(v>>8), byte(v>>16), byte(v>>24))
}

func (w *BinWriter) i32(v int) {
	w.u32(v)
}

func (w *BinWriter) f64(v float64) {
	var bits int64 = float64bits(v)
	w.buf = append(w.buf,
		byte(bits), byte(bits>>8), byte(bits>>16), byte(bits>>24),
		byte(bits>>32), byte(bits>>40), byte(bits>>48), byte(bits>>56))
}

func (w *BinWriter) str(s string) {
	b := []byte(s)
	w.u16(len(b))
	w.buf = append(w.buf, b...)
}

func (w *BinWriter) writeValue(v any) {
	if v == nil {
		w.u8(binValNull)
		return
	}
	switch val := v.(type) {
	case bool:
		w.u8(binValBool)
		if val {
			w.u8(1)
		} else {
			w.u8(0)
		}
	case int:
		w.u8(binValInt)
		w.i32(val)
	case float64:
		w.u8(binValFloat64)
		w.f64(val)
	case string:
		w.u8(binValString)
		w.str(val)
	case map[string]any:
		w.u8(binValMap)
		w.u16(len(val))
		for k, mv := range val {
			w.str(k)
			w.writeValue(mv)
		}
	case []any:
		w.u8(binValArray)
		w.u32(len(val))
		for _, av := range val {
			w.writeValue(av)
		}
	case Handler:
		// Serialize Handler as a map so JS can reconstruct VoHandler with modifiers/keyFilter
		w.u8(binValMap)
		count := 2 // iD, gen always present
		if len(val.Modifiers) > 0 {
			count++
		}
		if val.KeyFilter != "" {
			count++
		}
		w.u16(count)
		w.str("iD")
		w.writeValue(val.ID)
		w.str("gen")
		w.writeValue(val.Gen)
		if len(val.Modifiers) > 0 {
			w.str("modifiers")
			modsAny := make([]any, len(val.Modifiers))
			for i, m := range val.Modifiers {
				modsAny[i] = m
			}
			w.writeValue(modsAny)
		}
		if val.KeyFilter != "" {
			w.str("keyFilter")
			w.writeValue(val.KeyFilter)
		}
	case Node:
		w.u8(binValNode)
		w.writeNode(val)
	default:
		w.u8(binValNull)
	}
}

func (w *BinWriter) writeNode(n Node) {
	if n.Type == "" {
		w.u8(binNodeNull)
		return
	}
	if n.Type == "__cached__" {
		w.u8(binNodeCached)
		w.u32(n.Props["_cid"].(int))
		propCount := 0
		for k := range n.Props {
			if k != "_cid" {
				propCount++
			}
		}
		w.u16(propCount)
		for k, v := range n.Props {
			if k == "_cid" {
				continue
			}
			w.str(k)
			w.writeValue(v)
		}
		return
	}
	if n.Type == "__comp__" {
		w.u8(binNodeComponent)
		w.u32(n.Props["_cid"].(int))
		propCount := 0
		for k := range n.Props {
			if k != "_cid" {
				propCount++
			}
		}
		w.u16(propCount)
		for k, v := range n.Props {
			if k == "_cid" {
				continue
			}
			w.str(k)
			w.writeValue(v)
		}
		if len(n.Children) > 0 {
			w.writeNode(n.Children[0])
		} else {
			w.u8(binNodeNull)
		}
		return
	}
	if n.Type == "Fragment" {
		w.u8(binNodeFrag)
		w.u16(len(n.Children))
		for _, child := range n.Children {
			w.writeNode(child)
		}
		return
	}
	w.u8(binNodeElement)
	w.str(n.Type)
	w.u16(len(n.Props))
	for k, v := range n.Props {
		w.str(k)
		w.writeValue(v)
	}
	w.u32(len(n.Children))
	for _, child := range n.Children {
		w.writeNode(child)
	}
}

func (w *BinWriter) writeHandlerMeta(h Handler) {
	w.u16(h.ID)
	w.u16(h.Gen)
	w.u8(h.Type)
	w.i32(h.IntVal)
	w.u8(len(h.Modifiers))
	for _, mod := range h.Modifiers {
		w.str(mod)
	}
	w.str(h.KeyFilter)
}

// encodeRender encodes the full render message to a binary byte slice.
func encodeRender(gen int, tree Node, styles []string, canvasCmds []map[string]any, themeVars map[string]string, refActions []refAction) []byte {
	w := &BinWriter{}

	w.u32(gen)

	flags := 0
	if len(styles) > 0 {
		flags |= 1
	}
	if len(canvasCmds) > 0 {
		flags |= 2
	}
	if len(themeVars) > 0 {
		flags |= 4
	}
	if len(refActions) > 0 {
		flags |= 8
	}
	w.u8(flags)

	w.writeNode(tree)

	w.u16(len(handlerMetas))
	for _, h := range handlerMetas {
		w.writeHandlerMeta(h)
	}

	if len(styles) > 0 {
		w.u16(len(styles))
		for _, s := range styles {
			w.str(s)
		}
	}

	if len(canvasCmds) > 0 {
		w.u16(len(canvasCmds))
		for _, batch := range canvasCmds {
			ref := batch["ref"].(string)
			w.str(ref)
			cmds := batch["cmds"].([]canvasCommand)
			w.u32(len(cmds))
			for _, cmd := range cmds {
				w.str(cmd.Cmd)
				w.u8(len(cmd.Args))
				for _, arg := range cmd.Args {
					w.writeValue(arg)
				}
			}
		}
	}

	if len(themeVars) > 0 {
		w.u16(len(themeVars))
		for k, v := range themeVars {
			w.str(k)
			w.str(v)
		}
	}

	if len(refActions) > 0 {
		w.u16(len(refActions))
		for _, action := range refActions {
			w.str(action.Ref)
			w.str(action.Cmd)
			if action.HasTop {
				w.u8(1)
				w.i32(action.Top)
			} else {
				w.u8(0)
			}
			if action.HasMeasureID {
				w.u8(1)
				w.i32(action.MeasureID)
			} else {
				w.u8(0)
			}
		}
	}

	return w.buf
}

// Event handling: handler constructors, modifiers, and invocation.
//
// Handler constructors create event bindings. Each takes an action function
// whose first parameter is your concrete state pointer (e.g., *MyState).
// The framework dispatches via dynamic call (~>), so no interface is needed.
//
// Pre-bound handlers (OnInt, OnIntValue, OnIntChecked) capture an integer at
// registration time — useful in lists to bind an item ID without closures.
//
// Handler optionality convention:
//   - Positional parameter (e.g., Button(label, handler)): always required.
//     The caller must provide a valid handler from OnClick/OnValue/etc.
//   - Struct field (e.g., DialogProps.OnClose): optional.
//     Components guard these with handler.IsSet() before writing to props.
package vogui

import (
	"encoding/json"
	"errors"
)

// System event IDs (negative to distinguish from user handlers)
const (
	eventIDTimer      = -1
	eventIDGlobalKey  = -2
	eventIDNavigation = -3
)

// Handler type constants
const (
	handlerClick      = 1
	handlerValue      = 2
	handlerChecked    = 3
	handlerInt        = 4
	handlerIntValue   = 5
	handlerIntChecked = 6
	handlerKey        = 7
	handlerSubmit     = 8
	handlerSelect     = 9
	handlerIndex      = 10
	handlerFiles      = 11
	handlerPointer    = 12
	handlerResize     = 13
	handlerWidget     = 14
	handlerGeneric    = 15
	handlerScroll     = 16
	handlerIntersect  = 17
)

// Handler represents an event handler binding.
type Handler struct {
	ID           int
	Gen          int
	Type         int
	IntVal       int
	Modifiers    []string
	KeyFilter    string
	ComponentCtx any // non-nil when registered inside Mount()
}

// Event represents an event from JS.
type Event struct {
	Gen       int
	HandlerID int
	Payload   string
}

// ScrollEvent is the browser-reported scroll state of a scroll container.
// All fields are real DOM values — no predictions, no Vo-side estimation.
type ScrollEvent struct {
	ScrollTop    float64
	ClientHeight float64
	ScrollHeight float64
	AtBottom     bool    // true when BottomGap <= 1px
	BottomGap    float64 // pixels from current scrollTop to the true DOM bottom
}

// IntersectEvent is reported by an IntersectionObserver when a sentinel
// element enters or leaves the viewport.
type IntersectEvent struct {
	IsIntersecting    bool
	IntersectionRatio float64
}

// FileInfo holds file upload data.
type FileInfo struct {
	Name string
	Size int
	Type string
	Data string // base64 encoded
}

// Internal handler storage
var handlers []any
var handlerMetas []Handler
var renderGen int

// currentComponentCtx is set during Mount()'s View() call for handler scoping.
var currentComponentCtx any
var globalKeyHandler any

func resetHandlers() {
	handlers = []any{}
	handlerMetas = []Handler{}
	renderGen++
	currentComponentCtx = nil
}

// ============ Handler Constructors ============

func registerHandler(action any, typ int, intVal int) Handler {
	id := len(handlers)
	handlers = append(handlers, action)
	h := Handler{ID: id, Gen: renderGen, Type: typ, IntVal: intVal, ComponentCtx: currentComponentCtx}
	handlerMetas = append(handlerMetas, h)
	return h
}

// OnClick creates a click handler. This is the most common handler type.
//   Action: func(s *YourState)
func OnClick(action any) Handler { return registerHandler(action, handlerClick, 0) }

// OnValue creates a handler for text input changes.
//   Action: func(s *YourState, value string)
func OnValue(action any) Handler { return registerHandler(action, handlerValue, 0) }

// OnChecked creates a handler for checkbox/switch toggles.
//   Action: func(s *YourState, checked bool)
func OnChecked(action any) Handler { return registerHandler(action, handlerChecked, 0) }

// OnInt creates a click handler with a pre-bound integer.
// Use in lists to bind an item ID without closures.
//   Action: func(s *YourState, id int)
//   Usage:  Button("x", OnInt(removeItem, item.ID))
func OnInt(action any, val int) Handler { return registerHandler(action, handlerInt, val) }

// OnIntValue creates a handler with pre-bound int and text input value.
//   Action: func(s *YourState, id int, value string)
func OnIntValue(action any, val int) Handler { return registerHandler(action, handlerIntValue, val) }

// OnIntChecked creates a handler with pre-bound int and checked state.
//   Action: func(s *YourState, id int, checked bool)
//   Usage:  Checkbox(done, OnIntChecked(toggleItem, item.ID))
func OnIntChecked(action any, val int) Handler { return registerHandler(action, handlerIntChecked, val) }

// OnKey creates a handler for keyboard events.
//   Action: func(s *YourState, key string)
func OnKey(action any) Handler { return registerHandler(action, handlerKey, 0) }

// OnSubmit creates a handler for form submission.
//   Action: func(s *YourState)
func OnSubmit(action any) Handler { return registerHandler(action, handlerSubmit, 0) }

// OnSelect creates a handler for select dropdown changes.
//   Action: func(s *YourState, value string)
func OnSelect(action any) Handler { return registerHandler(action, handlerSelect, 0) }

// OnIndex creates a handler that receives an integer value from a component.
// Use for Tabs, Accordion, Pagination, Slider, and similar indexed selections.
//   Action: func(s *YourState, index int)
func OnIndex(action any) Handler { return registerHandler(action, handlerIndex, 0) }

// OnFiles creates a handler for file input changes.
//   Action: func(s *YourState, files []FileInfo)
func OnFiles(action any) Handler { return registerHandler(action, handlerFiles, 0) }

// OnScrollState creates a handler that receives real browser scroll state.
// Backed by a DOM scroll listener; the JS side computes AtBottom and BottomGap
// from true scrollHeight/clientHeight so Vo never needs to predict heights.
//   Action: func(s *YourState, e ScrollEvent)
func OnScrollState(action any) Handler { return registerHandler(action, handlerScroll, 0) }

// OnIntersect creates a handler backed by IntersectionObserver.
// Fires when the node enters or leaves the viewport.
//   Action: func(s *YourState, e IntersectEvent)
func OnIntersect(action any) Handler { return registerHandler(action, handlerIntersect, 0) }

// OnEvent creates a generic handler for arbitrary DOM events.
// Bind with node.On(eventName, handler) for events not covered above.
//   Action: func(s *YourState, payload string)
//
// The payload is a JSON string with fields present based on the event type:
//   Type     string  — always present, DOM event type (e.g. "scroll", "focus")
//   Value    string  — target.value, present for form elements
//   Checked  bool    — target.checked, present for checkboxes/radios
//   Key      string  — key name, present for keyboard events
//   ClientX  float64 — viewport X, present for mouse/pointer events
//   ClientY  float64 — viewport Y, present for mouse/pointer events
//   Detail   int     — click count or custom detail, when available
func OnEvent(action any) Handler { return registerHandler(action, handlerGeneric, 0) }

// ============ Handler Modifiers ============

// IsSet reports whether this handler was actually registered (not a zero value).
// Use this to guard optional handler fields in component props (e.g., Dialog.OnClose).
func (h Handler) IsSet() bool { return h.Gen > 0 }

// addModifier copies the modifiers slice before appending to avoid shared backing array aliasing.
func (h Handler) addModifier(mod string) Handler {
	mods := make([]string, len(h.Modifiers)+1)
	copy(mods, h.Modifiers)
	mods[len(h.Modifiers)] = mod
	h.Modifiers = mods
	return h
}

// Prevent adds preventDefault modifier.
func (h Handler) Prevent() Handler { return h.addModifier("prevent") }

// Stop adds stopPropagation modifier.
func (h Handler) Stop() Handler { return h.addModifier("stop") }

// Once adds fire-once modifier.
func (h Handler) Once() Handler { return h.addModifier("once") }

// Debounce adds debounce modifier with milliseconds.
func (h Handler) Debounce(ms int) Handler { return h.addModifier("debounce:" + toString(ms)) }

// Throttle adds throttle modifier with milliseconds.
func (h Handler) Throttle(ms int) Handler { return h.addModifier("throttle:" + toString(ms)) }

// Filter adds a key filter (for OnKey handlers).
func (h Handler) Filter(key string) Handler {
	h.KeyFilter = key
	return h
}

// ============ Global Key Handler ============

// SetGlobalKeyHandler registers a handler for global key events.
// Call this before Run(). The handler receives all keydown events.
//   Action: func(s *YourState, key string)
func SetGlobalKeyHandler(action any) {
	globalKeyHandler = action
}

// ============ Handler Invocation ============

func invokeHandler(state any, idx int, payload string) error {
	if idx < 0 || idx >= len(handlers) {
		return nil
	}
	handler := handlers[idx]
	meta := handlerMetas[idx]

	// Route to component context when handler was registered inside Mount()
	target := state
	if meta.ComponentCtx != nil {
		target = meta.ComponentCtx
	}

	switch meta.Type {
	case handlerClick, handlerSubmit:
		return handler~>(target)
	case handlerValue, handlerSelect:
		var p struct{ Value string }
		if err := json.Unmarshal([]byte(payload), &p); err != nil {
			return errors.Wrap(err, "vogui: unmarshal Value payload")
		}
		return handler~>(target, p.Value)
	case handlerChecked:
		var p struct{ Checked bool }
		if err := json.Unmarshal([]byte(payload), &p); err != nil {
			return errors.Wrap(err, "vogui: unmarshal Checked payload")
		}
		return handler~>(target, p.Checked)
	case handlerInt:
		return handler~>(target, meta.IntVal)
	case handlerIntValue:
		var p struct{ Value string }
		if err := json.Unmarshal([]byte(payload), &p); err != nil {
			return errors.Wrap(err, "vogui: unmarshal IntValue payload")
		}
		return handler~>(target, meta.IntVal, p.Value)
	case handlerIntChecked:
		var p struct{ Checked bool }
		if err := json.Unmarshal([]byte(payload), &p); err != nil {
			return errors.Wrap(err, "vogui: unmarshal IntChecked payload")
		}
		return handler~>(target, meta.IntVal, p.Checked)
	case handlerKey:
		var p struct{ Key string }
		if err := json.Unmarshal([]byte(payload), &p); err != nil {
			return errors.Wrap(err, "vogui: unmarshal Key payload")
		}
		return handler~>(target, p.Key)
	case handlerIndex:
		var p struct{ Value int }
		if err := json.Unmarshal([]byte(payload), &p); err != nil {
			return errors.Wrap(err, "vogui: unmarshal Index payload")
		}
		return handler~>(target, p.Value)
	case handlerFiles:
		var p struct{ Files []FileInfo }
		if err := json.Unmarshal([]byte(payload), &p); err != nil {
			return errors.Wrap(err, "vogui: unmarshal Files payload")
		}
		return handler~>(target, p.Files)
	case handlerPointer:
		var p PointerEvent
		if err := json.Unmarshal([]byte(payload), &p); err != nil {
			return errors.Wrap(err, "vogui: unmarshal PointerEvent payload")
		}
		return handler~>(target, p)
	case handlerResize:
		var p ResizeEvent
		if err := json.Unmarshal([]byte(payload), &p); err != nil {
			return errors.Wrap(err, "vogui: unmarshal ResizeEvent payload")
		}
		return handler~>(target, p)
	case handlerWidget:
		return handler~>(target, payload)
	case handlerGeneric:
		return handler~>(target, payload)
	case handlerScroll:
		var p ScrollEvent
		if err := json.Unmarshal([]byte(payload), &p); err != nil {
			return errors.Wrap(err, "vogui: unmarshal ScrollEvent payload")
		}
		return handler~>(target, p)
	case handlerIntersect:
		var p IntersectEvent
		if err := json.Unmarshal([]byte(payload), &p); err != nil {
			return errors.Wrap(err, "vogui: unmarshal IntersectEvent payload")
		}
		return handler~>(target, p)
	case handlerVirtualRange:
		var p RangeEvent
		if err := json.Unmarshal([]byte(payload), &p); err != nil {
			return errors.Wrap(err, "vogui: unmarshal RangeEvent payload")
		}
		return handler~>(target, p)
	}
	return handler~>(target)
}

func invokeGlobalKeyHandler(state any, key string) error {
	if globalKeyHandler == nil {
		return nil
	}
	return globalKeyHandler~>(state, key)
}

// FileExplorer provides a VS Code-style file explorer sidebar widget.
// The widget implementation lives in TypeScript (HostWidget "file-explorer"),
// so the host application must register the factory via registerWidget().
// This file provides the clean Vo API wrapper.
package vogui

import "encoding/json"

// ── Event types ───────────────────────────────────────────────────────────────

// FileExplorerEventType enumerates the events emitted by the file explorer widget.
const (
	FileExplorerOpen   = "open"   // user opens a file; Path+Content set
	FileExplorerCreate = "create" // user creates a new file; Path+Content set
	FileExplorerRename = "rename" // user renames; Path=new, OldPath=old
	FileExplorerDelete = "delete" // user deletes; Path set
)

// FileExplorerEvent is the parsed payload from an OnWidget handler attached to FileExplorer.
//
// Type is one of the FileExplorer* constants.
// Use ParseFileExplorerEvent to obtain a typed value from the raw payload string.
type FileExplorerEvent struct {
	Type    string `json:"type"`
	Path    string `json:"path"`    // new path (or current for open/delete)
	OldPath string `json:"oldPath"` // previous path (rename only)
	Content string `json:"content"` // file content (open/create only)
}

// ParseFileExplorerEvent parses a raw OnWidget payload into a FileExplorerEvent.
// Use this inside your OnWidget handler for type-safe event handling:
//
//	func onExplorer(state any, payload string) {
//	    evt, err := vogui.ParseFileExplorerEvent(payload)
//	    if err != nil { return }
//	    switch evt.Type {
//	    case vogui.FileExplorerOpen:
//	        ...
//	    }
//	}
func ParseFileExplorerEvent(payload string) (FileExplorerEvent, error) {
	var e FileExplorerEvent
	err := json.Unmarshal([]byte(payload), &e)
	return e, err
}

// ── Options ───────────────────────────────────────────────────────────────────

// FileExplorerProps configures the file explorer widget.
type FileExplorerProps struct {
	// ActivePath is the currently open file path, used for active-row highlighting.
	ActivePath string
	// ReadOnly disables rename, delete, and create operations when true.
	ReadOnly bool
	// ShowHidden shows files and directories starting with "." when true.
	ShowHidden bool
	// Filter restricts visible files to those matching a glob pattern (e.g. "*.vo").
	// Directories are always shown regardless of filter. Empty string = show all.
	Filter string
}

// ── Constructors ──────────────────────────────────────────────────────────────

// FileExplorer renders a file explorer sidebar with default options.
// activePath highlights the currently open file.
// handler receives FileExplorerEvent payloads; use ParseFileExplorerEvent to decode.
//
// Usage:
//
//	vogui.FileExplorer(s.ActiveFilePath, vogui.OnWidget(onExplorerEvent))
func FileExplorer(activePath string, handler Handler) Node {
	return FileExplorerWith(FileExplorerProps{ActivePath: activePath}, handler)
}

// FileExplorerWith renders a file explorer sidebar with full configuration.
//
// Usage:
//
//	vogui.FileExplorerWith(vogui.FileExplorerProps{
//	    ActivePath: s.ActiveFilePath,
//	    ReadOnly:   true,
//	    Filter:     "*.vo",
//	}, vogui.OnWidget(onExplorerEvent))
func FileExplorerWith(opts FileExplorerProps, handler Handler) Node {
	return HostWidget(
		"file-explorer",
		map[string]any{
			"activePath": opts.ActivePath,
			"readOnly":   opts.ReadOnly,
			"showHidden": opts.ShowHidden,
			"filter":     opts.Filter,
		},
	).ObserveWidget(handler)
}

// Form components.
package vogui

// Form renders a form element with submit handler.
func Form(handler Handler, children ...Node) Node {
	return Node{Type: "form", Props: map[string]any{
		"onSubmit": handler.ID,
	}, Children: children}
}

