// Layout container components.
package vogui

// Div is a generic block container element.
func Div(children ...Node) Node {
	return Node{Type: "div", Children: children}
}

// Span is a generic inline container element.
func Span(children ...Node) Node {
	return Node{Type: "span", Children: children}
}

// Row arranges children horizontally.
func Row(children ...Node) Node {
	return Node{Type: "vo-row", Children: children}
}

// Column arranges children vertically.
func Column(children ...Node) Node {
	return Node{Type: "vo-column", Children: children}
}

// Center centers its children both horizontally and vertically.
func Center(children ...Node) Node {
	return Node{Type: "vo-center", Children: children}
}

// Stack layers children on top of each other (position relative).
func Stack(children ...Node) Node {
	return Node{Type: "vo-stack", Children: children}
}

// Grid creates a CSS grid container.
func Grid(cols int, children ...Node) Node {
	props := map[string]any{"cols": cols}
	return Node{Type: "vo-grid", Props: props, Children: children}
}

// Spacer fills available space in a flex container.
func Spacer() Node {
	return Node{Type: "vo-spacer"}
}

// Divider renders a horizontal divider line.
func Divider() Node {
	return Node{Type: "vo-divider"}
}

// Scroll creates a scrollable container.
func Scroll(children ...Node) Node {
	return Node{Type: "vo-scroll", Children: children}
}

// Wrap wraps children onto multiple lines.
func Wrap(children ...Node) Node {
	return Node{Type: "vo-wrap", Children: children}
}

// Fragment groups children without creating a DOM element.
func Fragment(children ...Node) Node {
	return Node{Type: "Fragment", Children: children}
}

// Empty returns an empty (null) node.
func Empty() Node {
	return Node{}
}

// AspectRatio constrains children to a fixed aspect ratio (width/height).
func AspectRatio(ratio float64, children ...Node) Node {
	return Node{Type: "vo-aspect-ratio", Props: map[string]any{
		"ratio": ratio,
	}, Children: children}
}

// VerticalDivider renders a vertical separator line.
func VerticalDivider() Node {
	return Node{Type: "vo-vertical-divider"}
}

// List and table components.
package vogui

// List renders an unordered list.
func List(children ...Node) Node {
	return Node{Type: "ul", Children: children}
}

// ListItem renders a list item.
func ListItem(children ...Node) Node {
	return Node{Type: "li", Children: children}
}

// OrderedList renders an ordered list.
func OrderedList(children ...Node) Node {
	return Node{Type: "ol", Children: children}
}

// Table renders a table element.
func Table(children ...Node) Node {
	return Node{Type: "table", Children: children}
}

// TableHead renders a table header section.
func TableHead(children ...Node) Node {
	return Node{Type: "thead", Children: children}
}

// TableBody renders a table body section.
func TableBody(children ...Node) Node {
	return Node{Type: "tbody", Children: children}
}

// TableRow renders a table row.
func TableRow(children ...Node) Node {
	return Node{Type: "tr", Children: children}
}

// TableCell renders a table data cell.
func TableCell(children ...Node) Node {
	return Node{Type: "td", Children: children}
}

// TableHeaderCell renders a table header cell.
func TableHeaderCell(children ...Node) Node {
	return Node{Type: "th", Children: children}
}

// Post-layout measurement bridge.
//
// RequestMeasure queues a one-shot getBoundingClientRect on a named ref
// element. After the next render, JS measures the real DOM element and
// delivers the result back as a Rect via the callback.
//
// This is the mechanism for Vo to read browser layout truth without
// predicting or estimating anything — popover positioning, tooltip
// alignment, FLIP animations, and scroll-anchoring all use this.
//
// Example:
//
//   func onOpenTooltip(s *State) {
//       RequestMeasure("anchor-btn", func(s *State, r Rect) {
//           s.tooltipX = r.X + r.Width/2
//           s.tooltipY = r.Bottom + 8
//       })
//   }
