import "encoding/json"

const eventIDMeasure = -6

// Rect is the browser-reported bounding rectangle of a DOM element.
// All coordinates are relative to the viewport (same as getBoundingClientRect).
type Rect struct {
	X      float64
	Y      float64
	Width  float64
	Height float64
	Top    float64
	Right  float64
	Bottom float64
	Left   float64
}

// measurePayload wraps the callback ID + rect for the event round-trip.
type measurePayload struct {
	ID   int
	Rect Rect
}

// Persistent measure callback registry — NOT reset between renders.
var measureCallbacks = map[int]any{}
var nextMeasureID = 1

// RequestMeasure queues a one-shot measurement of the named ref element.
// After the next render commit, JS calls getBoundingClientRect() and
// delivers the result to the callback. The callback is automatically
// removed after one invocation.
//
//   Action: func(s *YourState, r Rect)
func RequestMeasure(refName string, action any) {
	id := nextMeasureID
	nextMeasureID++
