		Ref:          refName,
		Cmd:          "measure",
		MeasureID:    id,
		HasMeasureID: true,
	})
}

// invokeMeasureCallback is called by processEvent when JS reports a
// measurement result (event ID = eventIDMeasure).
func invokeMeasureCallback(state any, payload string) error {
	var p measurePayload
	if err := json.Unmarshal([]byte(payload), &p); err != nil {
		return err
	}
