// Navigation components: Tabs, Accordion, Breadcrumb, Pagination, Steps, Nav.
package vogui

// ============ Tabs (Managed: keyboard nav + ARIA) ============

// TabItem represents a single tab.
type TabItem struct {
	Label   string
	Content Node
}

// TabsProps configures a Tabs component.
type TabsProps struct {
	Active   int
	OnChange Handler
}

// Tabs renders a tabbed interface.
// JS manages: arrow key navigation, Home/End, ARIA roles.
//
// Always controlled: Vo owns the active tab via Active (0-indexed).
// OnChange fires with the new index when the user clicks a tab; update your state
// to set Active in the handler. Without OnChange, tabs display but clicks have no effect.
func Tabs(props TabsProps, items []TabItem) Node {
	itemsAny := make([]any, len(items))
	for i, item := range items {
		itemsAny[i] = map[string]any{"label": item.Label, "content": item.Content}
	}
	p := map[string]any{
		"activeIndex": props.Active,
		"items":       itemsAny,
	}
	if props.OnChange.IsSet() {
		p["onChange"] = props.OnChange.ID
	}
	return Node{Type: "vo-tabs", Props: p}
}

// ============ Accordion (Managed: keyboard nav + transitions) ============

// AccordionItem represents a single accordion panel.
type AccordionItem struct {
	Title   string
	Content Node
}

// AccordionProps configures an Accordion component.
type AccordionProps struct {
	Open     int // currently expanded panel index (-1 for none)
	OnChange Handler
}

// Accordion renders a collapsible accordion.
//
// Always controlled: Vo owns the expanded panel via Open (0-indexed, -1 for none).
// OnChange fires with the clicked panel index; update your state to set Open in
// the handler. Without OnChange, panels display but clicks have no effect.
func Accordion(props AccordionProps, items []AccordionItem) Node {
	itemsAny := make([]any, len(items))
	for i, item := range items {
		itemsAny[i] = map[string]any{"title": item.Title, "content": item.Content}
	}
	p := map[string]any{
		"items":     itemsAny,
		"openIndex": props.Open,
	}
	if props.OnChange.IsSet() {
		p["onChange"] = props.OnChange.ID
	}
	return Node{Type: "vo-accordion", Props: p}
}

// ============ Breadcrumb ============

// BreadcrumbItem represents a breadcrumb link.
type BreadcrumbItem struct {
