// Node is the fundamental building block of the UI tree.
// Every UI element is a Node with a type, properties, and children.
//
// Nodes are value types with copy-on-write maps. All methods return a new Node,
// so chaining is safe: Text("hi").Bold().Fg("red") creates independent copies.
package vogui

// Node represents a UI element in the virtual tree.
type Node struct {
	Type     string
	Props    map[string]any
	Children []Node
}

// ============ Style Methods ============
// Style methods set CSS properties in Props["style"]. Values accept:
//   - int:    interpreted as pixels (e.g., W(200) → "200px")
//   - string: used as-is (e.g., W("50%"), Bg("var(--vo-primary)"))
// String-only methods (Bg, Fg, Border, etc.) take CSS values directly.

func (n Node) setStyle(key string, value any) Node {
	// Copy Props map (copy-on-write: Node is a value type but Props is a reference).
	props := make(map[string]any, len(n.Props)+1)
	for k, v := range n.Props {
		props[k] = v
	}
	// Copy style sub-map.
	var style map[string]any
	if s, ok := props["style"]; ok {
		old := s.(map[string]any)
		style = make(map[string]any, len(old)+1)
		for k, v := range old {
			style[k] = v
		}
	} else {
		style = make(map[string]any, 4)
	}
	style[key] = value
	props["style"] = style
	n.Props = props
	return n
}

// W sets width.
func (n Node) W(v any) Node { return n.setStyle("width", v) }

