func (n Node) JustifySelf(v string) Node { return n.setStyle("justifySelf", v) }

// MaxLines clamps text to a maximum number of visible lines (CSS -webkit-line-clamp).
// Automatically sets overflow:hidden and display:-webkit-box.
func (n Node) MaxLines(v int) Node {
	n = n.setStyle("maxLines", v)
	n = n.setStyle("overflow", "hidden")
	n = n.setStyle("display", "-webkit-box")
	return n.setStyle("-webkit-box-orient", "vertical")
}

// Style sets an arbitrary CSS property by camelCase name.
//   node.Style("textDecoration", "underline")
func (n Node) Style(key string, value any) Node { return n.setStyle(key, value) }

// Styles merges multiple CSS properties from a map in one operation.
func (n Node) Styles(styles map[string]any) Node {
	props := make(map[string]any, len(n.Props)+1)
	for k, v := range n.Props {
		props[k] = v
	}
	var sm map[string]any
	if s, ok := props["style"]; ok {
		old := s.(map[string]any)
		sm = make(map[string]any, len(old)+len(styles))
		for k, v := range old {
			sm[k] = v
		}
	} else {
		sm = make(map[string]any, len(styles))
	}
	for k, v := range styles {
		sm[k] = v
	}
	props["style"] = sm
	n.Props = props
	return n
}

// ============ Node Property Methods ============
// Property methods set values directly in Props (not in the style sub-map).

func (n Node) setProp(key string, value any) Node {
	// Copy Props map (copy-on-write).
	props := make(map[string]any, len(n.Props)+1)
	for k, v := range n.Props {
		props[k] = v
	}
	props[key] = value
	n.Props = props
	return n
}

// Class appends CSS class names to the node.
func (n Node) Class(cls string) Node {
	if existing, ok := n.Props["class"]; ok {
		return n.setProp("class", existing.(string)+" "+cls)
	}
	return n.setProp("class", cls)
}

// Variant sets the component variant (e.g., "primary", "outline", "danger").
func (n Node) Variant(v string) Node { return n.setProp("variant", v) }

// Size sets the component size (e.g., "sm", "md", "lg").
func (n Node) Size(s string) Node { return n.setProp("size", s) }

// Key sets the diffing key for stable DOM identity in lists.
func (n Node) Key(k string) Node { return n.setProp("key", k) }

// Ref names the DOM element for imperative access.
func (n Node) Ref(name string) Node { return n.setProp("ref", name) }

// Attr sets an arbitrary HTML attribute.
//   node.Attr("role", "navigation").Attr("aria-label", "Main menu")
func (n Node) Attr(key string, val any) Node {
	// Copy Props (copy-on-write).
	props := make(map[string]any, len(n.Props)+1)
	for k, v := range n.Props {
		props[k] = v
	}
	// Copy attrs sub-map.
	var attrs map[string]any
	if a, ok := props["attrs"]; ok {
		old := a.(map[string]any)
		attrs = make(map[string]any, len(old)+1)
		for k, v := range old {
			attrs[k] = v
		}
	} else {
		attrs = make(map[string]any, 2)
	}
	attrs[key] = val
	props["attrs"] = attrs
	n.Props = props
	return n
}

// Side sets the preferred side for overlay positioning (e.g., "top", "bottom", "left", "right").
// Used by Tooltip, Popover, and similar overlay components.
func (n Node) Side(s string) Node { return n.setProp("side", s) }

// AnimateWith sets the transition name for enter/leave animations.
func (n Node) AnimateWith(name string) Node { return n.setProp("transition", name) }

// On binds a named DOM event to a handler on this node.
//   Div(children...).On("scroll", OnEvent(onScroll))
// For common events, prefer the typed handler constructor directly:
//   Button("Save", OnClick(save))  // click is implicit via Button
func (n Node) On(event string, h Handler) Node {
	// Copy Props (copy-on-write).
	props := make(map[string]any, len(n.Props)+1)
	for k, v := range n.Props {
		props[k] = v
	}
	// Copy events sub-map.
	var events map[string]any
	if e, ok := props["events"]; ok {
		old := e.(map[string]any)
		events = make(map[string]any, len(old)+1)
		for k, v := range old {
			events[k] = v
		}
	} else {
		events = make(map[string]any, 2)
	}
	events[event] = h
	props["events"] = events
	n.Props = props
	return n
}

// ObserveResize attaches a ResizeObserver-backed handler to this node.
func (n Node) ObserveResize(h Handler) Node {
	return n.setProp("onResize", h.ID)
}

// ObserveScroll attaches a scroll-state handler to a scroll container.
// The handler receives a ScrollEvent with real DOM values (scrollTop,
// scrollHeight, clientHeight, AtBottom, BottomGap) — no Vo-side height
// prediction. Use with OnScrollState to drive followTail patterns.
func (n Node) ObserveScroll(h Handler) Node {
	return n.setProp("onScrollState", h.ID)
}

// ObserveIntersect attaches an IntersectionObserver-backed handler to this
// node. Fires with IntersectEvent when the node enters or leaves the viewport.
// Useful for infinite-scroll sentinels, lazy loading, and sticky headers.
func (n Node) ObserveIntersect(h Handler) Node {
	return n.setProp("onIntersect", h.ID)
}

