// ============ Collapsible (Managed) ============

// CollapsibleProps configures Collapsible behavior.
type CollapsibleProps struct {
	Open     bool
	OnChange Handler
}

// Collapsible wraps a trigger and collapsible content.
// First child = trigger, remaining = content.
//
// Controlled mode (OnChange set): Vo owns the open state.
// Uncontrolled mode (OnChange not set): JS manages toggle; Open sets default.
func Collapsible(props CollapsibleProps, children ...Node) Node {
	p := map[string]any{}
	if props.OnChange.IsSet() {
		// Controlled: Vo drives open state
		p["open"] = props.Open
		p["onChange"] = props.OnChange.ID
	} else if props.Open {
		// Uncontrolled but start expanded
		p["defaultOpen"] = true
	}
	return Node{Type: "vo-collapsible", Props: p, Children: children}
}

