// Portal system for rendering content into fixed DOM locations.
// Used for toasts, notifications, popovers that need to escape overflow:hidden.
package vogui

// Portal renders children into a named container outside the normal component tree.
// The JS runtime creates a container element for each unique portal name.
// CSS positions these containers appropriately (e.g., toast at top-right).
func Portal(name string, children ...Node) Node {
	return Node{Type: "vo-portal", Props: map[string]any{
		"portalName": name,
	}, Children: children}
}

// Toast displays a temporary notification message.
// Rendered via portal. Auto-dismisses after durationMs.
// typ: "info", "success", "warning", or "danger".
func Toast(message string, typ string, durationMs int) {
	toastEmit(message, typ, durationMs)
}

func toastEmit(message string, typ string, durationMs int) // extern

// DOM refs and imperative actions.
// Refs allow Vo code to trigger imperative DOM operations
// (focus, scroll, select) on named elements.
package vogui

type refAction struct {
	Ref          string
	Cmd          string
	Top          int
	HasTop       bool
	MeasureID    int
	HasMeasureID bool
}

var pendingRefActions []refAction

// Focus sets focus on the element with the given ref name.
// Must be called in an action function (after render).
func Focus(refName string) {
	pendingRefActions = append(pendingRefActions, refAction{Ref: refName, Cmd: "focus"})
}

// Blur removes focus from the element with the given ref name.
func Blur(refName string) {
	pendingRefActions = append(pendingRefActions, refAction{Ref: refName, Cmd: "blur"})
}

// ScrollTo scrolls the element to the given position (instant).
func ScrollTo(refName string, top float64) {
	rounded := int(top + 0.5)
	pendingRefActions = append(pendingRefActions, refAction{Ref: refName, Cmd: "scrollTo", Top: rounded, HasTop: true})
}

// ScrollToSmooth scrolls the element to the given position with smooth animation.
func ScrollToSmooth(refName string, top float64) {
	rounded := int(top + 0.5)
	pendingRefActions = append(pendingRefActions, refAction{Ref: refName, Cmd: "scrollToSmooth", Top: rounded, HasTop: true})
