// ScrollToBottomRef scrolls the element to the true DOM bottom (instant).
func ScrollToBottomRef(refName string) {
	pendingRefActions = append(pendingRefActions, refAction{Ref: refName, Cmd: "scrollToBottom"})
}

// ScrollToBottomSmooth scrolls the element to the true DOM bottom with smooth animation.
func ScrollToBottomSmooth(refName string) {
	pendingRefActions = append(pendingRefActions, refAction{Ref: refName, Cmd: "scrollToBottomSmooth"})
}

// ScrollIntoView scrolls the element into the visible area.
func ScrollIntoView(refName string) {
	pendingRefActions = append(pendingRefActions, refAction{Ref: refName, Cmd: "scrollIntoView"})
}

// ScrollIntoViewSmooth scrolls the element into the visible area with smooth animation.
func ScrollIntoViewSmooth(refName string) {
	pendingRefActions = append(pendingRefActions, refAction{Ref: refName, Cmd: "scrollIntoViewSmooth"})
}

// SelectText selects all text in the input element.
func SelectText(refName string) {
	pendingRefActions = append(pendingRefActions, refAction{Ref: refName, Cmd: "selectText"})
}

func flushPendingRefActions() []refAction {
	if len(pendingRefActions) == 0 {
		return nil
	}
	result := pendingRefActions
	pendingRefActions = nil
	return result
}

// Client-side routing for single-page applications.
package vogui

import "strings"

// Route defines a URL pattern and its view function.
type Route struct {
	Path string
	View func(state any, params map[string]string) Node
}

// Navigate programmatically navigates to a path.
func Navigate(path string) {
	navigate(path)
	updatePath(path)
}

// GetCurrentPath returns the current URL path.
func GetCurrentPath() string {
	return getCurrentPath()
}

// ============ Route Matching ============

func splitPath(path string) []string {
	parts := strings.Split(path, "/")
	result := []string{}
	for _, p := range parts {
		if p != "" {
			result = append(result, p)
		}
	}
	return result
}

func matchRoute(pattern string, path string) (map[string]string, bool) {
	patternParts := splitPath(pattern)
	pathParts := splitPath(path)

	if len(patternParts) != len(pathParts) {
		return nil, false
	}

	params := map[string]string{}
	for i, pp := range patternParts {
		if strings.HasPrefix(pp, ":") {
			params[pp[1:]] = pathParts[i]
		} else if pp != pathParts[i] {
			return nil, false
		}
	}
	return params, true
}

// ============ Extern Declarations ============

func navigate(path string)
func getCurrentPath() string

// Style combinator system for reusable and composable CSS styles.
//
// Styles are compiled into unique CSS class names and injected once.
// Supports pseudo-classes (:hover, :focus, :active) and media queries.
//
// Usage:
//
//   var cardStyle = vogui.NewStyle().P(16).Bg("var(--vo-surface)").Rounded(8).
//       Hover(vogui.NewStyle().Shadow("0 2px 8px rgba(0,0,0,0.1)"))
//
//   func view(s *State) vogui.Node {
//       return vogui.Div(children...).ApplyStyle(cardStyle)
//   }
package vogui

import (
	"fmt"
	"strings"
	"unicode"
)

// Style is a reusable, composable style definition.
// It compiles to a CSS class injected into the document at render time.
type Style struct {
	id     int
	props  map[string]any
	hover  map[string]any
	focus  map[string]any
	active map[string]any
	media  map[string]map[string]any
}

// Internal style registry: id -> CSS text (already injected)
var styleRegistry = map[int]bool{}

// Pending styles to send with the next render
var pendingStyles []string

// Global style ID counter
var nextStyleID int

// NewStyle creates a new empty Style.
func NewStyle() Style {
	nextStyleID++
	return Style{
		id:    nextStyleID,
		props: map[string]any{},
	}
}

// Extend creates a new Style that inherits all properties from this one.
func (s Style) Extend() Style {
	nextStyleID++
	ns := Style{
		id:    nextStyleID,
		props: copyMap(s.props),
	}
	if s.hover != nil {
		ns.hover = copyMap(s.hover)
	}
	if s.focus != nil {
		ns.focus = copyMap(s.focus)
	}
	if s.active != nil {
		ns.active = copyMap(s.active)
	}
	if s.media != nil {
		ns.media = map[string]map[string]any{}
		for q, m := range s.media {
			ns.media[q] = copyMap(m)
		}
	}
	return ns
}

func copyMap(m map[string]any) map[string]any {
	out := map[string]any{}
	for k, v := range m {
		out[k] = v
	}
	return out
}

// ============ Style Property Methods ============
// These mirror Node's style methods but operate on Style.

func (s Style) W(v any) Style      { s.props["width"] = v; return s }
func (s Style) H(v any) Style      { s.props["height"] = v; return s }
func (s Style) MinW(v any) Style   { s.props["minWidth"] = v; return s }
func (s Style) MaxW(v any) Style   { s.props["maxWidth"] = v; return s }
func (s Style) MinH(v any) Style   { s.props["minHeight"] = v; return s }
func (s Style) MaxH(v any) Style   { s.props["maxHeight"] = v; return s }
func (s Style) P(v any) Style      { s.props["padding"] = v; return s }
func (s Style) M(v any) Style      { s.props["margin"] = v; return s }
func (s Style) Gap(v any) Style    { s.props["gap"] = v; return s }
func (s Style) Bg(v string) Style  { s.props["background"] = v; return s } // CSS shorthand: color, gradient, or image
func (s Style) Fg(v string) Style  { s.props["color"] = v; return s }
func (s Style) Cursor(v string) Style   { s.props["cursor"] = v; return s }
func (s Style) Opacity(v any) Style     { s.props["opacity"] = v; return s }
func (s Style) Overflow(v string) Style { s.props["overflow"] = v; return s }
func (s Style) Flex(v any) Style        { s.props["flex"] = v; return s }
func (s Style) Font(v int) Style        { s.props["fontSize"] = v; return s }
func (s Style) FontSize(v any) Style    { s.props["fontSize"] = v; return s }
func (s Style) FontWeight(v any) Style  { s.props["fontWeight"] = v; return s }
func (s Style) Rounded(v any) Style     { s.props["borderRadius"] = v; return s }
func (s Style) Border(v string) Style   { s.props["border"] = v; return s }
