func (s Style) Pt(v any) Style { s.props["paddingTop"] = v; return s }
func (s Style) Pb(v any) Style { s.props["paddingBottom"] = v; return s }
func (s Style) Pl(v any) Style { s.props["paddingLeft"] = v; return s }
