func (s Style) Mt(v any) Style { s.props["marginTop"] = v; return s }
func (s Style) Mb(v any) Style { s.props["marginBottom"] = v; return s }
func (s Style) Ml(v any) Style { s.props["marginLeft"] = v; return s }
