	s.props["maxLines"] = v
	s.props["overflow"] = "hidden"
	s.props["display"] = "-webkit-box"
	s.props["-webkit-box-orient"] = "vertical"
	return s
}

func (s Style) Top(v any) Style          { s.props["top"] = v; return s }
func (s Style) Right(v any) Style        { s.props["right"] = v; return s }
