// float64frombits converts raw int64 bits to float64 (inverse of float64bits).
func float64frombits(bits int64) float64

// measureText returns (height, lineCount) for text wrapped to maxWidth.
// whiteSpace: 0=normal, 1=pre-wrap.
func measureText(text string, font string, maxWidth float64, lineHeight float64, whiteSpace int) (float64, int)

// measureTextLinesRaw returns binary line-level metrics.
// whiteSpace: 0=normal, 1=pre-wrap.
func measureTextLinesRaw(text string, font string, maxWidth float64, lineHeight float64, whiteSpace int) []byte

// Timer functions: setTimeout, setInterval, and their cleanup.
package vogui

// TimerHandler is a function that receives state for timer callbacks.
// Signature: func(state any)
type TimerHandler = any

var timerHandlers = map[int]TimerHandler{}
var timerRepeats = map[int]bool{}
var nextTimerID int = 1

func registerTimerHandler(handler TimerHandler) int {
	id := nextTimerID
	nextTimerID++
	timerHandlers[id] = handler
	return id
}

func invokeTimerHandler(id int, state any) {
	handler, ok := timerHandlers[id]
	if !ok {
		return
	}
	if !timerRepeats[id] {
		delete(timerHandlers, id)
		delete(timerRepeats, id)
	}
	err := handler~>(state)
	if err != nil {
		println("VoGUI: timer handler error:", err)
	}
}

// SetTimeout schedules a one-shot timer.
// Returns a timer ID that can be used with ClearTimeout.
func SetTimeout(handler TimerHandler, delayMs int) int {
	id := registerTimerHandler(handler)
	timerRepeats[id] = false
	startTimeout(id, delayMs)
	return id
}

// ClearTimeout cancels a scheduled timeout.
func ClearTimeout(id int) {
	delete(timerHandlers, id)
	delete(timerRepeats, id)
	clearTimeout(id)
}

// SetInterval schedules a repeating timer.
// Returns a timer ID that can be used with ClearInterval.
func SetInterval(handler TimerHandler, intervalMs int) int {
	id := registerTimerHandler(handler)
	timerRepeats[id] = true
	startInterval(id, intervalMs)
	return id
}

// ClearInterval cancels a repeating timer.
func ClearInterval(id int) {
	delete(timerHandlers, id)
	delete(timerRepeats, id)
	clearInterval(id)
}

// ============ Extern Declarations ============

func startTimeout(id int, delayMs int)
func clearTimeout(id int)
func startInterval(id int, intervalMs int)
func clearInterval(id int)

// Transition and TransitionGroup for enter/leave animations.
package vogui

// Transition wraps a conditional node with CSS-based enter/leave animation.
// name refers to a built-in or custom transition (e.g., "fade", "slide-up", "scale").
// The child should be a conditional node (from If or Show).
//
// Built-in transitions:
//   - "fade"        opacity 0→1 / 1→0
//   - "slide-down"  translateY(-10px)→0 / reverse
//   - "slide-up"    translateY(10px)→0 / reverse
//   - "slide-left"  translateX(10px)→0 / reverse
//   - "slide-right" translateX(-10px)→0 / reverse
//   - "scale"       scale(0.95)+opacity→1 / reverse
//
// Custom transitions are defined via CSS classes:
//   .vo-enter-from-{name} { ... }
//   .vo-enter-active-{name} { transition: ... }
//   .vo-leave-active-{name} { transition: ... }
//   .vo-leave-to-{name} { ... }
func Transition(name string, child Node) Node {
	return Node{Type: "vo-transition", Props: map[string]any{
		"transition": name,
	}, Children: []Node{child}}
}

// TransitionGroup wraps a list of keyed nodes with animations for
// entering, leaving, and reordering items.
// Uses FLIP animation for smooth reordering.
func TransitionGroup(name string, list Node) Node {
	return Node{Type: "vo-transition-group", Props: map[string]any{
		"transition": name,
	}, Children: []Node{list}}
}

