// VirtualList — a JS-native virtualized list component.
//
// Unlike VirtualScroll (which predicts heights in Vo), VirtualList delegates
// all scroll physics and viewport management to the browser/JS side. Vo only
// provides the visible window of items as children.
//
// Flow:
//   1. JS computes which items are visible based on scroll position
//   2. JS emits a RangeEvent with Start/End indices
//   3. Vo re-renders with only the visible items
//   4. JS positions them at the correct offset inside a spacer
//
// Usage:
//
//   type State struct {
//       items      []string
//       rangeStart int
//       rangeEnd   int
//   }
//
//   func (s *State) view() vogui.Node {
//       visible := make([]vogui.Node, 0, s.rangeEnd-s.rangeStart)
//       for i := s.rangeStart; i < s.rangeEnd && i < len(s.items); i++ {
//           visible = append(visible, vogui.Text(s.items[i]).Key(fmt.Sprint(i)))
//       }
//       return vogui.VirtualList(vogui.VirtualListConfig{
//           TotalCount:   len(s.items),
//           ItemHeight:   40,
//           VisibleStart: s.rangeStart,
//       }, visible...).
//           Flex(1).
//           OnRange(vogui.OnVirtualRange(func(st *State, e vogui.RangeEvent) {
//               st.rangeStart = e.Start
//               st.rangeEnd = e.End
//           }))
//   }
package vogui

import "encoding/json"

const (
	handlerVirtualRange = 18
)

// VirtualListConfig configures the JS-native virtual list component.
type VirtualListConfig struct {
	TotalCount   int     // total number of items in the data set
	ItemHeight   float64 // estimated or fixed height per item (px)
	VisibleStart int     // index of the first visible item (matches children[0])
	Overscan     int     // extra items above/below viewport (default 3 in JS)
}

// RangeEvent is emitted by the JS virtual list when the visible range changes.
type RangeEvent struct {
	Start     int     // first visible item index (inclusive)
	End       int     // last visible item index (exclusive)
	ScrollTop float64 // current scroll position
}

// VirtualList creates a JS-native virtualized list node.
// children should contain only the items for [config.VisibleStart, config.VisibleStart+len).
// Chain .OnRange(handler) to receive RangeEvent when the visible window changes.
func VirtualList(config VirtualListConfig, children ...Node) Node {
	p := map[string]any{
		"totalCount":   config.TotalCount,
		"itemHeight":   config.ItemHeight,
		"visibleStart": config.VisibleStart,
	}
	if config.Overscan > 0 {
		p["overscan"] = config.Overscan
	}
	return Node{Type: "vo-virtual-list", Props: p, Children: children}
}

// OnRange sets the visible range change handler on a VirtualList node.
func (n Node) OnRange(h Handler) Node {
	return n.setProp("onRange", h.ID)
}

// OnVirtualRange creates a handler that receives RangeEvent from a VirtualList.
//   Action: func(s *YourState, e RangeEvent)
func OnVirtualRange(action any) Handler {
	return registerHandler(action, handlerVirtualRange, 0)
}

// Host Widgets — JS-native components that Vo configures and observes.
//
// Use HostWidget for components that need direct DOM access: rich text
// editors, charts, maps, code editors, virtual lists, etc. Vo owns the
// configuration; JS owns the rendering and DOM lifecycle.
//
// Flow:
//   1. Vo calls HostWidget("chart", config, children...)  →  config + children serialized
//   2. JS widget factory receives container + props + onEvent callback
//   3. Factory creates DOM, observes config changes, emits events
//   4. Vo receives events via ObserveWidget handler
//
// Children passed to HostWidget are rendered as Preact-managed nodes
// inside the widget container. The JS factory can coexist with them
// or reposition/wrap them as needed.
package vogui

// HostWidget creates a JS-native widget node with optional child slot content.
// widgetType identifies the registered JS widget factory.
// config is a map of configuration values passed to the factory as props.
// children are rendered inside the widget container alongside factory DOM.
//
// Chain .ObserveWidget(handler) to receive structured events from the widget.
//
//   HostWidget("markdown", map[string]any{"content": text})
//   HostWidget("virtual-list", listConfig, renderedItems...).ObserveWidget(h)
func HostWidget(widgetType string, config map[string]any, children ...Node) Node {
	p := make(map[string]any, len(config)+1)
	for k, v := range config {
		p[k] = v
	}
	p["widgetType"] = widgetType
	return Node{Type: "vo-host-widget", Props: p, Children: children}
}

// ObserveWidget attaches an event handler to a HostWidget node.
// The handler receives structured events emitted by the JS widget factory.
//   Action: func(s *YourState, payload string)
func (n Node) ObserveWidget(h Handler) Node {
	return n.setProp("onWidget", h.ID)
}

// OnWidget wraps an action that receives widget events.
// Action signature: func(s *State, payload string)
func OnWidget(action any) Handler {
	return registerHandler(action, handlerWidget, 0)
}

// Compression support for vopack.
//
// Implements LZ4 block compression (compatible with the standard LZ4 block format).
//
// LZ4 block format summary:
//   A compressed block is a sequence of "sequences". Each sequence:
//     1. Token byte: high nibble = literal length, low nibble = match length - 4
//     2. Optional extra literal length bytes (if high nibble == 15, read uint8s until < 255)
//     3. Literal bytes
//     4. Offset: 2 bytes little-endian (distance back to match source)
//     5. Optional extra match length bytes (if low nibble == 15, read uint8s until < 255)
//   The last sequence has no match part (literals only, offset omitted).
//
// The decompressor needs to know the uncompressed size (stored in the Entry).
package vopack

import "errors"

// Compress compresses src using LZ4 block format.
// Returns compressed data, or nil if compression does not reduce size.
func Compress(src []byte) []byte {
	if len(src) == 0 {
		return []byte{}
	}

	dst := make([]byte, 0, len(src))
	srcLen := len(src)
	const minMatch = 4
	const lastLiterals = 5
	const matchFindLimit = 12

	if srcLen < matchFindLimit+1 {
		// Too short to find matches; emit as single literal sequence.
		dst = lz4EmitLiterals(dst, src)
	} else {
		hashTable := make([]uint32, 65536)
		matchLimit := srcLen - lastLiterals
		searchLimit := srcLen - matchFindLimit

		anchor := 0 // start of pending literals
		pos := 0

		for pos <= searchLimit {
			h := lz4Hash(src[pos:])
			idx := int(h)
			candidatePlusOne := hashTable[idx]
			hashTable[idx] = uint32(pos + 1)
			found := candidatePlusOne != 0
			candidate := int(candidatePlusOne - 1)

			// Check for match: must be within 65535 offset and actually match 4 bytes
			if !found || pos-candidate > 65535 || !lz4Match4(src, candidate, pos) {
				pos++
				continue
			}

			// Found a match. Extend it forward.
			matchLen := minMatch
			for pos+matchLen < matchLimit && candidate+matchLen < srcLen && src[candidate+matchLen] == src[pos+matchLen] {
				matchLen++
			}

			// Emit sequence: literals + match
			offset := pos - candidate
			dst = lz4EmitSequence(dst, src[anchor:pos], matchLen, offset)

			pos += matchLen
			anchor = pos
		}

		// Emit remaining bytes as the final literal-only sequence (no match part).
		if anchor < srcLen {
			dst = lz4EmitLiterals(dst, src[anchor:srcLen])
		}
	}

	// If compressed is not smaller, return nil to signal "don't compress".
	if len(dst) >= srcLen {
		return nil
	}
	return dst
}

// Decompress decompresses LZ4 block data into a buffer of the given raw size.
func Decompress(src []byte, rawSize int) ([]byte, error) {
	if rawSize < 0 {
		return nil, errors.New("vopack: negative raw size")
	}
	if rawSize == 0 {
		if len(src) != 0 {
			return nil, errors.New("vopack: unexpected compressed data for empty output")
		}
		return []byte{}, nil
	}
	dst := make([]byte, rawSize)
	sPos := 0
	dPos := 0

	for sPos < len(src) {
		// Read token
		token := src[sPos]
		sPos++

		// Literal length
		litLen := int(token >> 4)
		if litLen == 15 {
			for {
				if sPos >= len(src) {
					return nil, errors.New("vopack: lz4 truncated literal length")
				}
				extra := src[sPos]
				sPos++
				litLen += int(extra)
				if extra != 255 {
					break
				}
			}
		}

		// Copy literals
		if sPos+litLen > len(src) {
			return nil, errors.New("vopack: lz4 literal overflow")
		}
		if dPos+litLen > rawSize {
			return nil, errors.New("vopack: lz4 output overflow on literals")
		}
		copy(dst[dPos:], src[sPos:sPos+litLen])
		sPos += litLen
		dPos += litLen

		// If we've consumed all input, this was the last (literal-only) sequence.
		if sPos >= len(src) {
			break
		}

		// Read match offset (2 bytes LE)
		if sPos+2 > len(src) {
			return nil, errors.New("vopack: lz4 truncated offset")
		}
		offset := int(src[sPos]) | int(src[sPos+1])<<8
		sPos += 2
		if offset == 0 {
			return nil, errors.New("vopack: lz4 zero offset")
		}

		// Match length
		matchLen := int(token&0x0F) + 4
		if matchLen == 19 { // 15 + 4
			for {
				if sPos >= len(src) {
					return nil, errors.New("vopack: lz4 truncated match length")
				}
				extra := src[sPos]
				sPos++
				matchLen += int(extra)
				if extra != 255 {
					break
				}
			}
		}

		// Copy match (byte-by-byte to handle overlapping copies)
		matchStart := dPos - offset
		if matchStart < 0 {
			return nil, errors.New("vopack: lz4 match before start")
		}
		if dPos+matchLen > rawSize {
			return nil, errors.New("vopack: lz4 output overflow on match")
		}
		for i := 0; i < matchLen; i++ {
			dst[dPos] = dst[matchStart+i]
			dPos++
		}
	}

	if dPos != rawSize {
		return nil, errors.New("vopack: lz4 output size mismatch")
	}
	return dst, nil
}

// --- LZ4 internal helpers ---

// lz4Hash computes a 32-bit hash from 4 bytes for the hash table.
func lz4Hash(data []byte) uint32 {
	v := uint32(data[0]) | uint32(data[1])<<8 | uint32(data[2])<<16 | uint32(data[3])<<24
	return (v * 2654435761) >> 16
}

// lz4Match4 checks if 4 bytes at positions a and b in src are equal.
func lz4Match4(src []byte, a int, b int) bool {
	return src[a] == src[b] && src[a+1] == src[b+1] && src[a+2] == src[b+2] && src[a+3] == src[b+3]
}

// lz4EmitSequence appends a full LZ4 sequence (literals + match) to dst.
func lz4EmitSequence(dst []byte, literals []byte, matchLen int, offset int) []byte {
	// Encode token
	litCode := len(literals)
	matchCode := matchLen - 4
	tokenLit := litCode
	tokenMatch := matchCode
	if tokenLit > 15 {
		tokenLit = 15
	}
	if tokenMatch > 15 {
		tokenMatch = 15
	}
	dst = append(dst, byte(tokenLit<<4|tokenMatch))

	// Extra literal length bytes
	if litCode >= 15 {
		remaining := litCode - 15
		for remaining >= 255 {
			dst = append(dst, 255)
			remaining -= 255
		}
		dst = append(dst, byte(remaining))
	}

	// Literal bytes
	dst = append(dst, literals...)

	// Match offset (2 bytes LE)
	dst = append(dst, byte(offset&0xFF), byte((offset>>8)&0xFF))

	// Extra match length bytes
	if matchCode >= 15 {
		remaining := matchCode - 15
		for remaining >= 255 {
			dst = append(dst, 255)
			remaining -= 255
		}
		dst = append(dst, byte(remaining))
	}

	return dst
}

// lz4EmitLiterals appends a literal-only terminal sequence to dst.
// This is the last sequence in an LZ4 block — no match/offset follows.
func lz4EmitLiterals(dst []byte, literals []byte) []byte {
	litLen := len(literals)
	if litLen == 0 {
		return dst
	}

	// Token: literal length in high nibble, match = 0 in low nibble
	tokenLit := litLen
	if tokenLit > 15 {
		tokenLit = 15
	}
	dst = append(dst, byte(tokenLit<<4))

	// Extra literal length bytes
	if litLen >= 15 {
		remaining := litLen - 15
		for remaining >= 255 {
			dst = append(dst, 255)
			remaining -= 255
		}
		dst = append(dst, byte(remaining))
	}

	// Literal bytes
	dst = append(dst, literals...)
	return dst
}

// Binary format definitions for vopack archive files (.vpak).
//
// File layout:
//   ┌─────────────────────────────────┐
//   │  File Header       (64 bytes)   │
//   ├─────────────────────────────────┤
//   │  Data Region                    │
//   │    entry 0 data (aligned)       │
//   │    entry 1 data (aligned)       │
//   │    ...                          │
//   ├─────────────────────────────────┤
//   │  Path String Pool               │
//   │    "sprites/hero.pngtex..."     │  (offset+length, no separators)
//   ├─────────────────────────────────┤
//   │  Entry Table (48 bytes each)    │
//   │    [entry0][entry1]...          │
//   ├─────────────────────────────────┤
//   │  Footer              (32 bytes) │
//   └─────────────────────────────────┘
//
// Reading sequence:
//   1. Seek to EOF - footerSize, read footer
//   2. Validate footer checksum
//   3. Read path pool and entry table using footer offsets
//   4. Build in-memory path -> entry index
//
// All integers are little-endian.
package vopack

import (
	"encoding/binary"
	"errors"
)

const (
	magic   = "VPAK"
	version = 1

	headerSize = 64
	entrySize  = 48
	footerSize = 32

	defaultAlignment = 16

	// Header field offsets
	offHdrMagic    = 0
	offHdrVersion  = 4
	offHdrFlags    = 5
	offHdrDataOff  = 8
	offHdrDataSize = 16

	// Entry field offsets
	offEntPathOff     = 0
	offEntPathLen     = 4
	offEntCompression = 6
	offEntFlags       = 7
	offEntDataOff     = 8
	offEntRawSize     = 16
	offEntStoredSize  = 24
	offEntChecksum    = 32
	offEntReserved    = 36

	// Footer field offsets
	offFtrPathPoolOff  = 0
	offFtrPathPoolSize = 8
	offFtrEntryTableOff = 16
	offFtrEntryCount   = 24
	offFtrChecksum     = 28

	// CompressNone stores entry bytes exactly as provided.
	CompressNone = 0
	// CompressLZ4 stores entry bytes using LZ4 block compression.
	CompressLZ4  = 1
)

// fileHeader is the in-memory representation of the 64-byte file header.
type fileHeader struct {
	flags    uint8
	dataOff  uint64
	dataSize uint64
}

// entry is the in-memory representation of one archived resource.
type entry struct {
	pathOffset  uint32
	pathLen     uint16
	compression uint8
	flags       uint8
	dataOffset  uint64
	rawSize     uint64
	storedSize  uint64
	checksum    uint32
}

// footer is the in-memory representation of the 32-byte footer.
type footer struct {
	pathPoolOff  uint64
	pathPoolSize uint64
	entryTableOff uint64
	entryCount   uint32
}

// marshalHeader encodes a fileHeader into a 64-byte buffer.
func marshalHeader(h fileHeader) []byte {
	buf := make([]byte, headerSize)
	copy(buf[offHdrMagic:], []byte(magic))
	buf[offHdrVersion] = version
	buf[offHdrFlags] = h.flags
	binary.LittleEndian.PutUint64(buf[offHdrDataOff:], h.dataOff)
	binary.LittleEndian.PutUint64(buf[offHdrDataSize:], h.dataSize)
	return buf
}

// unmarshalHeader decodes a 64-byte buffer into a fileHeader.
func unmarshalHeader(buf []byte) (fileHeader, error) {
	if len(buf) < headerSize {
		return fileHeader{}, errors.New("vopack: header too short")
	}
	if string(buf[offHdrMagic:offHdrMagic+4]) != magic {
		return fileHeader{}, errors.New("vopack: invalid magic")
	}
	if buf[offHdrVersion] != version {
		return fileHeader{}, errors.New("vopack: unsupported version")
	}
	return fileHeader{
		flags:    buf[offHdrFlags],
		dataOff:  binary.LittleEndian.Uint64(buf[offHdrDataOff:]),
		dataSize: binary.LittleEndian.Uint64(buf[offHdrDataSize:]),
	}, nil
}

// marshalEntry encodes an entry into a 48-byte buffer.
func marshalEntry(e entry) []byte {
	buf := make([]byte, entrySize)
	binary.LittleEndian.PutUint32(buf[offEntPathOff:], e.pathOffset)
	binary.LittleEndian.PutUint16(buf[offEntPathLen:], e.pathLen)
	buf[offEntCompression] = e.compression
	buf[offEntFlags] = e.flags
	binary.LittleEndian.PutUint64(buf[offEntDataOff:], e.dataOffset)
	binary.LittleEndian.PutUint64(buf[offEntRawSize:], e.rawSize)
	binary.LittleEndian.PutUint64(buf[offEntStoredSize:], e.storedSize)
	binary.LittleEndian.PutUint32(buf[offEntChecksum:], e.checksum)
	return buf
}

// unmarshalEntry decodes a 48-byte buffer into an entry.
func unmarshalEntry(buf []byte) (entry, error) {
	if len(buf) < entrySize {
		return entry{}, errors.New("vopack: entry too short")
	}
	for i := offEntReserved; i < entrySize; i++ {
		if buf[i] != 0 {
			return entry{}, errors.New("vopack: non-zero reserved entry bytes")
		}
	}
	return entry{
		pathOffset:  binary.LittleEndian.Uint32(buf[offEntPathOff:]),
		pathLen:     binary.LittleEndian.Uint16(buf[offEntPathLen:]),
		compression: buf[offEntCompression],
		flags:       buf[offEntFlags],
		dataOffset:  binary.LittleEndian.Uint64(buf[offEntDataOff:]),
		rawSize:     binary.LittleEndian.Uint64(buf[offEntRawSize:]),
		storedSize:  binary.LittleEndian.Uint64(buf[offEntStoredSize:]),
		checksum:    binary.LittleEndian.Uint32(buf[offEntChecksum:]),
	}, nil
}

// marshalFooter encodes a footer into a 32-byte buffer with checksum.
func marshalFooter(f footer) []byte {
	buf := make([]byte, footerSize)
	binary.LittleEndian.PutUint64(buf[offFtrPathPoolOff:], f.pathPoolOff)
	binary.LittleEndian.PutUint64(buf[offFtrPathPoolSize:], f.pathPoolSize)
	binary.LittleEndian.PutUint64(buf[offFtrEntryTableOff:], f.entryTableOff)
	binary.LittleEndian.PutUint32(buf[offFtrEntryCount:], f.entryCount)
	binary.LittleEndian.PutUint32(buf[offFtrChecksum:], crc32(buf[:offFtrChecksum]))
	return buf
}

// unmarshalFooter decodes a 32-byte buffer into a footer.
func unmarshalFooter(buf []byte) (footer, error) {
	if len(buf) < footerSize {
		return footer{}, errors.New("vopack: footer too short")
	}
	stored := binary.LittleEndian.Uint32(buf[offFtrChecksum:])
	computed := crc32(buf[:offFtrChecksum])
	if stored != computed {
		return footer{}, errors.New("vopack: footer checksum mismatch")
	}
	return footer{
		pathPoolOff:  binary.LittleEndian.Uint64(buf[offFtrPathPoolOff:]),
		pathPoolSize: binary.LittleEndian.Uint64(buf[offFtrPathPoolSize:]),
		entryTableOff: binary.LittleEndian.Uint64(buf[offFtrEntryTableOff:]),
		entryCount:   binary.LittleEndian.Uint32(buf[offFtrEntryCount:]),
	}, nil
}

var crc32Table = makeCRC32Table()

func makeCRC32Table() []uint32 {
	table := make([]uint32, 256)
	for i := 0; i < 256; i++ {
		crc := uint32(i)
		for bit := 0; bit < 8; bit++ {
			if crc&1 != 0 {
				crc = (crc >> 1) ^ 0xEDB88320
			} else {
				crc >>= 1
			}
		}
		table[i] = crc
	}
	return table
}

// crc32 computes CRC-32 (IEEE) over data.
func crc32(data []byte) uint32 {
	crc := uint32(0xFFFFFFFF)
	table := crc32Table
	for _, b := range data {
		index := int((crc ^ uint32(b)) & 0xFF)
		crc = table[index] ^ (crc >> 8)
	}
	return crc ^ 0xFFFFFFFF
}

// alignUp rounds offset up to the given alignment boundary.
func alignUp(offset uint64, alignment uint32) uint64 {
	a := uint64(alignment)
	return (offset + a - 1) & ^(a - 1)
}

// Package vopack provides a compact archive format for bundling application or game assets into a single .vpak file.
//
// A vopack archive is optimized for simple asset packaging and fast indexed lookup rather than general-purpose filesystem
// emulation. Entry bytes are written sequentially into a data region, while the path string pool and fixed-size entry table
// are appended near the end of the file and described by a footer. This layout keeps writes simple and lets Open build an
// in-memory path index with a single metadata pass.
//
// The package provides the following guarantees:
//   - resource paths are unique within one archive
//   - footer metadata is validated when an archive is opened
//   - stored entry bytes are checksum-verified when a resource is read
//   - LZ4 compression is optional and transparent to callers of Read
//   - listing preserves insertion order within a single archive
//
// The main workflows are:
//   - Create, Add, AddFile, and Close for writing archives
//   - Open, Read, Has, Size, and List for indexed read-only access
//   - MountSet for priority-based overlay across multiple archives, where higher-priority archives shadow lower-priority ones
//
// This makes vopack suitable for shipped assets, patch or hot-update bundles, DLC layers, and mod loading where deterministic
// path lookup matters more than full directory semantics.
package vopack

package vopack

import (
	"encoding/json"
	"errors"
	"strconv"
)

const ManifestPath = ".vopack/manifest.json"

type Manifest struct {
	FormatVersion int             `json:"formatVersion"`
	PackName      string          `json:"packName,omitempty"`
	PackVersion   string          `json:"packVersion,omitempty"`
	Assets        []ManifestAsset `json:"assets"`
}

type ManifestAsset struct {
	Path         string   `json:"path"`
	Type         string   `json:"type,omitempty"`
	ContentHash  string   `json:"contentHash"`
	SourcePath   string   `json:"sourcePath,omitempty"`
	Dependencies []string `json:"dependencies,omitempty"`
}

func NewManifest(packName, packVersion string) Manifest {
	return Manifest{
		FormatVersion: 1,
		PackName:      packName,
		PackVersion:   packVersion,
		Assets:        []ManifestAsset{},
	}
}

func (m *Manifest) Find(path string) *ManifestAsset {
	if m == nil {
		return nil
	}
	for i := range m.Assets {
		if m.Assets[i].Path == path {
			return &m.Assets[i]
		}
	}
	return nil
}

func marshalManifest(m Manifest) ([]byte, error) {
	if m.FormatVersion == 0 {
		m.FormatVersion = 1
	}
	if m.Assets == nil {
		m.Assets = []ManifestAsset{}
	}
	return json.MarshalIndent(m, "", "  ")
}

func unmarshalManifest(data []byte) (*Manifest, error) {
	var manifest Manifest
	json.Unmarshal(data, &manifest)?
	if manifest.FormatVersion != 1 {
		fail errors.New("vopack: unsupported manifest version: " + strconv.Itoa(manifest.FormatVersion))
	}
	if manifest.Assets == nil {
		manifest.Assets = []ManifestAsset{}
	}
	return &manifest, nil
}

func verifyManifestDependencies(manifest *Manifest, exists func(string) bool, requester string) error {
	if manifest == nil {
		fail errors.New("vopack: manifest is nil")
	}
	if exists == nil {
		fail errors.New("vopack: manifest verifier missing exists function")
	}
	declared := map[string]*ManifestAsset{}
	for i := range manifest.Assets {
		asset := &manifest.Assets[i]
		if asset.Path == "" {
			fail errors.New("vopack: manifest asset path must not be empty")
		}
		if declared[asset.Path] != nil {
			fail errors.New("vopack: duplicate manifest asset: " + asset.Path)
		}
		declared[asset.Path] = asset
		if !exists(asset.Path) {
			fail errors.New("vopack: manifest asset missing payload: " + asset.Path)
		}
	}
	if requester != "" {
		asset := declared[requester]
		if asset == nil {
			fail errors.New("vopack: manifest requester not found: " + requester)
		}
		return verifyManifestAssetDependencies(declared, exists, requester, asset)
	}
	for _, asset := range manifest.Assets {
		if err := verifyManifestAssetDependencies(declared, exists, asset.Path, &asset); err != nil {
			return err
		}
	}
	return nil
}

func verifyManifestAssetDependencies(declared map[string]*ManifestAsset, exists func(string) bool, requester string, asset *ManifestAsset) error {
	for _, dep := range asset.Dependencies {
		if dep == "" {
			fail errors.New("vopack: empty dependency for requester: " + requester)
		}
		if declared[dep] == nil || !exists(dep) {
			fail errors.New("vopack: missing dependency for requester " + requester + ": " + dep)
		}
	}
	return nil
}

func manifestHash(data []byte) string {
	return "crc32:" + padHex8(strconv.FormatUint(uint(crc32(data)), 16))
}

func padHex8(s string) string {
	for len(s) < 8 {
		s = "0" + s
	}
	return s
}

func inferAssetType(path string) string {
	ext := pathExtLower(path)
	if ext == ".png" || ext == ".jpg" || ext == ".jpeg" || ext == ".webp" {
		return "texture"
	}
	if ext == ".glb" || ext == ".gltf" || ext == ".obj" {
		return "model"
	}
	if ext == ".wav" || ext == ".ogg" || ext == ".mp3" {
		return "audio"
	}
	if ext == ".json" {
		return "json"
	}
	return "bytes"
}

func pathExtLower(path string) string {
	start := -1
	for i := len(path) - 1; i >= 0; i-- {
		c := path[i]
		if c == '/' || c == '\\' {
			break
		}
		if c == '.' {
			start = i
			break
		}
	}
	if start < 0 {
		return ""
	}
	ext := []byte(path[start:])
	for i := 0; i < len(ext); i++ {
		if ext[i] >= 'A' && ext[i] <= 'Z' {
			ext[i] += 'a' - 'A'
		}
	}
	return string(ext)
}

// MountSet manages multiple vopack archives with priority-based overlay.
//
// Higher priority archives shadow lower priority ones for the same path.
// For equal priority, earlier mounts keep precedence.
// This enables DLC, hot-update, and mod workflows:
//   m := vopack.NewMountSet()
//   m.Mount("base.vpak", 0)       // base game assets
//   m.Mount("dlc1.vpak", 10)      // DLC overrides some base assets
//   m.Mount("mod.vpak", 100)      // mod overrides everything
//   data, err := m.Read("sprites/hero.png")  // returns from highest priority
package vopack

import "errors"

// mountEntry pairs a reader with its priority.
type mountEntry struct {
	path     string
	priority int
	reader   *PackReader
}

// MountSet overlays multiple .vpak archives by priority.
type MountSet struct {
	mounts []mountEntry // sorted by descending priority
}

// NewMountSet creates an empty mount set.
func NewMountSet() *MountSet {
	return &MountSet{
		mounts: make([]mountEntry, 0),
	}
}

// Mount opens and registers an archive at the given priority.
// Higher priority archives are searched first, and equal priorities preserve
// mount order.
func (m *MountSet) Mount(path string, priority int) error {
	r := Open(path)?
	m.mounts = append(m.mounts, mountEntry{
		path:     path,
		priority: priority,
		reader:   r,
	})
	// Insertion sort by descending priority (mount count is small)
	for i := len(m.mounts) - 1; i > 0; i-- {
		if m.mounts[i].priority > m.mounts[i-1].priority {
			m.mounts[i], m.mounts[i-1] = m.mounts[i-1], m.mounts[i]
		} else {
			break
		}
	}
	return nil
}

// Unmount removes and closes the archive at the given path.
func (m *MountSet) Unmount(path string) error {
	for i, me := range m.mounts {
		if me.path == path {
			err := me.reader.Close()
			m.mounts = append(m.mounts[:i], m.mounts[i+1:]...)
			return err
		}
	}
	fail errors.New("vopack: archive not mounted: " + path)
}

// Read returns the resource from the highest-priority archive that contains it.
func (m *MountSet) Read(name string) ([]byte, error) {
	for _, me := range m.mounts {
		if me.reader.Has(name) {
			return me.reader.Read(name)
		}
	}
	return nil, errors.New("vopack: resource not found in any mount: " + name)
}

func (m *MountSet) ManifestFor(name string) (*Manifest, error) {
	for _, me := range m.mounts {
		if me.reader.Has(name) {
			return me.reader.Manifest()
		}
	}
	return nil, errors.New("vopack: resource not found in any mount: " + name)
}

func (m *MountSet) VerifyManifestDependencies(requester string) error {
	if requester == "" {
		for _, me := range m.mounts {
			if err := me.reader.VerifyManifestDependencies(""); err != nil {
				return err
			}
		}
		return nil
	}
	for _, me := range m.mounts {
		if me.reader.Has(requester) {
			return me.reader.VerifyManifestDependencies(requester)
		}
	}
	return errors.New("vopack: requester not found in any mount: " + requester)
}

// Has returns true if any mounted archive contains the resource.
func (m *MountSet) Has(name string) bool {
	for _, me := range m.mounts {
		if me.reader.Has(name) {
			return true
		}
	}
	return false
}

// Size returns the uncompressed size from the highest-priority archive.
func (m *MountSet) Size(name string) (uint64, error) {
	for _, me := range m.mounts {
		if me.reader.Has(name) {
			return me.reader.Size(name)
		}
	}
	return 0, errors.New("vopack: resource not found in any mount: " + name)
}

// List returns all resource paths matching prefix, merged and deduplicated
// across all mounted archives. Higher-priority entries take precedence.
func (m *MountSet) List(prefix string) []string {
	seen := make(map[string]bool)
	result := make([]string, 0)
	// Iterate in priority order (highest first)
	for _, me := range m.mounts {
		for _, p := range me.reader.List(prefix) {
			if !seen[p] {
				seen[p] = true
				result = append(result, p)
			}
		}
	}
	return result
}

// Close closes all mounted archives.
func (m *MountSet) Close() error {
	var firstErr error
	for _, me := range m.mounts {
		if err := me.reader.Close(); err != nil && firstErr == nil {
			firstErr = err
		}
	}
	m.mounts = m.mounts[:0]
	return firstErr
}

// PackReader provides read-only access to a vopack archive.
//
// On Open, it reads the footer, path pool, and entry table into memory,
// then builds a hash map for O(1) path lookup. Data is read on demand.
package vopack

import (
	"errors"
	"os"
)

// tableEntry is the in-memory index entry for a single resource.
type tableEntry struct {
	dataOffset  uint64
	rawSize     uint64
	storedSize  uint64
	compression uint8
	checksum    uint32
	internal    bool
}

// PackReader reads resources from a .vpak archive.
type PackReader struct {
	file    *os.File
	index   map[string]tableEntry
	paths   []string // all paths in insertion order
}

// Open opens an existing .vpak archive for reading.
//
// It validates the header, footer, path pool, and entry table before building
// the in-memory index, so malformed archives fail during Open instead of later
// during path lookup.
func Open(path string) (*PackReader, error) {
	file := os.Open(path)?
	errdefer file.Close()

	// Read footer from the last 32 bytes
	info := file.Stat()?
	fileSize := info.Size()
	if fileSize < int64(headerSize+footerSize) {
		fail errors.New("vopack: file too small")
	}

	ftrBuf := make([]byte, footerSize)
	file.ReadAt(ftrBuf, fileSize-int64(footerSize))?
	ftr := unmarshalFooter(ftrBuf)?

	// Validate header
	hdrBuf := make([]byte, headerSize)
	file.ReadAt(hdrBuf, 0)?
	hdr := unmarshalHeader(hdrBuf)?

	fileSizeU := uint64(fileSize)
	footerOff := fileSizeU - footerSize
	if ftr.pathPoolOff > footerOff {
		fail errors.New("vopack: invalid path pool offset")
	}
	if ftr.pathPoolSize > footerOff-ftr.pathPoolOff {
		fail errors.New("vopack: invalid path pool size")
	}
	pathPoolEnd := ftr.pathPoolOff + ftr.pathPoolSize
	if hdr.dataOff != headerSize {
		fail errors.New("vopack: invalid data offset")
	}
	dataEnd := hdr.dataOff + hdr.dataSize
	if dataEnd < hdr.dataOff || dataEnd != ftr.pathPoolOff {
		fail errors.New("vopack: invalid data size")
	}
	entryTableSize := uint64(ftr.entryCount) * uint64(entrySize)
	if ftr.entryTableOff < pathPoolEnd || ftr.entryTableOff > footerOff {
		fail errors.New("vopack: invalid entry table offset")
	}
	if entryTableSize > footerOff-ftr.entryTableOff {
		fail errors.New("vopack: invalid entry table size")
	}

	// Read path pool
	var pathPool []byte
	if ftr.pathPoolSize > 0 {
		pathPool = make([]byte, ftr.pathPoolSize)
		file.ReadAt(pathPool, int64(ftr.pathPoolOff))?
	}

	// Read entry table
	var entryBuf []byte
	if ftr.entryCount > 0 {
		entryTableSize := int(ftr.entryCount) * entrySize
		entryBuf = make([]byte, entryTableSize)
		file.ReadAt(entryBuf, int64(ftr.entryTableOff))?
	}

	// Build index
	index := make(map[string]tableEntry)
	paths := make([]string, 0, int(ftr.entryCount))

	for i := 0; i < int(ftr.entryCount); i++ {
		e := unmarshalEntry(entryBuf[i*entrySize : (i+1)*entrySize])?
		pathEnd := uint64(e.pathOffset) + uint64(e.pathLen)
		if pathEnd > uint64(len(pathPool)) {
			fail errors.New("vopack: entry path out of bounds")
		}
		if e.flags != 0 {
			fail errors.New("vopack: unsupported entry flags")
		}
		if e.compression != CompressNone && e.compression != CompressLZ4 {
			fail errors.New("vopack: unsupported compression method")
		}
		if e.dataOffset < hdr.dataOff || e.dataOffset > dataEnd {
			fail errors.New("vopack: entry data offset out of bounds")
		}
		if e.storedSize > dataEnd-e.dataOffset {
			fail errors.New("vopack: entry data size out of bounds")
		}
		if e.compression == CompressNone && e.rawSize != e.storedSize {
			fail errors.New("vopack: uncompressed entry size mismatch")
		}
		name := string(pathPool[e.pathOffset : e.pathOffset+uint32(e.pathLen)])
		if _, ok := index[name]; ok {
			fail errors.New("vopack: duplicate resource path: " + name)
		}
		index[name] = tableEntry{
			dataOffset:  e.dataOffset,
			rawSize:     e.rawSize,
			storedSize:  e.storedSize,
			compression: e.compression,
			checksum:    e.checksum,
			internal:    name == ManifestPath,
		}
		if name != ManifestPath {
			paths = append(paths, name)
		}
	}

	return &PackReader{
		file:  file,
		index: index,
		paths: paths,
	}, nil
}

// Read returns the decompressed content of a resource by its path.
//
// Stored bytes are checksum-verified before optional decompression.
func (r *PackReader) Read(name string) ([]byte, error) {
	if name == ManifestPath {
		fail errors.New("vopack: manifest is metadata, use Manifest")
	}
	return r.readEntry(name)
}

func (r *PackReader) readEntry(name string) ([]byte, error) {
	te, ok := r.index[name]
	if !ok {
		fail errors.New("vopack: resource not found: " + name)
	}

	// Read stored (possibly compressed) data from disk
	stored := make([]byte, te.storedSize)
	r.file.ReadAt(stored, int64(te.dataOffset))?

	// Verify checksum
	if crc32(stored) != te.checksum {
		fail errors.New("vopack: checksum mismatch: " + name)
	}

	// Decompress if needed
	if te.compression == CompressLZ4 {
		return Decompress(stored, int(te.rawSize))
	}
	return stored, nil
}

// Has returns true if the archive contains a resource with the given path.
func (r *PackReader) Has(name string) bool {
	te, ok := r.index[name]
	return ok && !te.internal
}

// Size returns the uncompressed size of a resource.
func (r *PackReader) Size(name string) (uint64, error) {
	te, ok := r.index[name]
	if !ok {
		fail errors.New("vopack: resource not found: " + name)
	}
	if te.internal {
		fail errors.New("vopack: manifest is metadata, use Manifest")
	}
	return te.rawSize, nil
}

// Len returns the total number of resources in the archive.
func (r *PackReader) Len() int {
	return len(r.paths)
}

// List returns all resource paths that start with the given prefix.
// If prefix is empty, all paths are returned.
func (r *PackReader) List(prefix string) []string {
	if prefix == "" {
		result := make([]string, len(r.paths))
		copy(result, r.paths)
		return result
	}
	result := make([]string, 0)
	for _, p := range r.paths {
		if len(p) >= len(prefix) && p[:len(prefix)] == prefix {
			result = append(result, p)
		}
	}
	return result
}

func (r *PackReader) Manifest() (*Manifest, error) {
	data, err := r.readEntry(ManifestPath)
	if err != nil {
		return nil, err
	}
	return unmarshalManifest(data)
}

func (r *PackReader) VerifyManifestDependencies(requester string) error {
	manifest, err := r.Manifest()
	if err != nil {
		return err
	}
	return verifyManifestDependencies(manifest, func(path string) bool {
		te, ok := r.index[path]
		return ok && !te.internal
	}, requester)
}

// Close closes the underlying file.
func (r *PackReader) Close() error {
	return r.file.Close()
}

// PackWriter builds a vopack archive file.
//
// Usage:
//   w, err := vopack.Create("assets.vpak")
//   w.Add("sprites/hero.png", data, vopack.EntryOpts{})
//   w.AddFile("sounds/bgm.ogg", "/path/to/bgm.ogg", vopack.EntryOpts{Compression: vopack.CompressLZ4})
//   w.Close()
//
// Data is written sequentially: header first, then each entry's data as it is added.
// On Close, the path pool, entry table, and footer are appended.
package vopack

import (
	"errors"
	"os"
)

// EntryOpts controls per-entry options when adding resources.
type EntryOpts struct {
	Compression  uint8    // CompressNone or CompressLZ4
	Alignment    uint32   // 0 = default (16 bytes); otherwise must be a power of two
	Type         string   // optional manifest asset type; inferred from path when empty
	Dependencies []string // optional manifest dependency paths
}

// writerEntry stores metadata collected during writing.
type writerEntry struct {
	path        string
	compression uint8
	dataOffset  uint64
	rawSize     uint64
	storedSize  uint64
	checksum    uint32
	manifest    ManifestAsset
}

// PackWriter writes resources into a .vpak archive.
type PackWriter struct {
	file        *os.File
	offset      uint64       // current write position in the file
	entries     []writerEntry
	names       map[string]bool
	packName    string
	packVersion string
	closing     bool
}

// Create opens a new .vpak file for writing.
//
// Resource paths must be unique within a single archive.
func Create(path string) (*PackWriter, error) {
	file := os.Create(path)?
	errdefer file.Close()

	// Write placeholder header (will be updated on Close)
	file.Write(marshalHeader(fileHeader{dataOff: headerSize}))?

	return &PackWriter{
		file:    file,
		offset:  headerSize,
		entries: make([]writerEntry, 0),
		names:   make(map[string]bool),
	}, nil
}

func (w *PackWriter) SetManifestInfo(packName, packVersion string) {
	w.packName = packName
	w.packVersion = packVersion
}

// Add writes a resource from a byte slice into the archive.
//
// The archive preserves insertion order for listing, but duplicate paths are
// rejected so lookup and listing remain consistent.
func (w *PackWriter) Add(name string, data []byte, opts EntryOpts) error {
	if w.names[name] {
		fail errors.New("vopack: duplicate resource path: " + name)
	}
	if name == ManifestPath && !w.closing {
		fail errors.New("vopack: manifest path is reserved: " + name)
	}
	if len(name) > 0xFFFF {
		fail errors.New("vopack: resource path too long: " + name)
	}

	alignment := opts.Alignment
	if alignment == 0 {
		alignment = defaultAlignment
	} else if alignment&(alignment-1) != 0 {
		fail errors.New("vopack: alignment must be a power of two")
	}

	// Align the write position
	aligned := alignUp(w.offset, alignment)
	if aligned > w.offset {
		pad := make([]byte, aligned-w.offset)
		w.file.Write(pad)?
		w.offset = aligned
	}

	rawSize := uint64(len(data))
	storedData := data
	compression := opts.Compression
	if compression != CompressNone && compression != CompressLZ4 {
		fail errors.New("vopack: unsupported compression method")
	}

	if compression == CompressLZ4 {
		if len(data) > 0 {
			if compressed := Compress(data); compressed != nil {
				storedData = compressed
			} else {
				// Compression didn't help, store uncompressed
				compression = CompressNone
			}
		} else {
			compression = CompressNone
		}
	}

	storedSize := uint64(len(storedData))
	checksum := crc32(storedData)

	w.file.Write(storedData)?

	w.entries = append(w.entries, writerEntry{
		path:        name,
		compression: compression,
		dataOffset:  w.offset,
		rawSize:     rawSize,
		storedSize:  storedSize,
		checksum:    checksum,
		manifest: ManifestAsset{
			Path:         name,
			Type:         normalizeManifestAssetType(opts.Type, name),
			ContentHash:  manifestHash(data),
			Dependencies: cloneStringSlice(opts.Dependencies),
		},
	})
	w.names[name] = true

	w.offset += storedSize
	return nil
}

// AddFile reads a file from disk and adds it to the archive.
func (w *PackWriter) AddFile(name string, srcPath string, opts EntryOpts) error {
	data := os.ReadFile(srcPath)?
	err := w.Add(name, data, opts)
	if err != nil {
		return err
	}
	w.entries[len(w.entries)-1].manifest.SourcePath = srcPath
	return nil
}

// Close finalizes the archive by writing the path pool, entry table, and footer.
func (w *PackWriter) Close() error {
	w.closing = true
	if !w.names[ManifestPath] {
		manifest := NewManifest(w.packName, w.packVersion)
		for _, e := range w.entries {
			if e.path != ManifestPath {
				manifest.Assets = append(manifest.Assets, e.manifest)
			}
		}
		data, err := marshalManifest(manifest)
		if err != nil {
			return err
		}
		if err := w.Add(ManifestPath, data, EntryOpts{Type: "manifest"}); err != nil {
			return err
		}
	}

	// Build path string pool
	pathPool := make([]byte, 0)
	pathOffsets := make([]uint32, len(w.entries))
	pathLens := make([]uint16, len(w.entries))

	for i, e := range w.entries {
		if uint64(len(pathPool))+uint64(len(e.path)) > 0xFFFFFFFF {
			fail errors.New("vopack: path pool exceeds uint32 limit")
		}
		pathOffsets[i] = uint32(len(pathPool))
		pathLens[i] = uint16(len(e.path))
		pathPool = append(pathPool, []byte(e.path)...)
	}

	errdefer w.file.Close()

	// Write path pool
	pathPoolOff := w.offset
	w.file.Write(pathPool)?
	w.offset += uint64(len(pathPool))

	// Write entry table (batched into single write)
	entryTableOff := w.offset
	entryBuf := make([]byte, len(w.entries)*entrySize)
	for i, e := range w.entries {
		copy(entryBuf[i*entrySize:], marshalEntry(entry{
			pathOffset:  pathOffsets[i],
			pathLen:     pathLens[i],
			compression: e.compression,
			dataOffset:  e.dataOffset,
			rawSize:     e.rawSize,
			storedSize:  e.storedSize,
			checksum:    e.checksum,
		}))
	}
	w.file.Write(entryBuf)?
	w.offset += uint64(len(entryBuf))

	// Write footer
	w.file.Write(marshalFooter(footer{
		pathPoolOff:   pathPoolOff,
		pathPoolSize:  uint64(len(pathPool)),
		entryTableOff: entryTableOff,
		entryCount:    uint32(len(w.entries)),
	}))?
	w.offset += footerSize

	// Update file header with final data region size
	w.file.WriteAt(marshalHeader(fileHeader{
		dataOff:  headerSize,
		dataSize: pathPoolOff - headerSize,
	}), 0)?

	return w.file.Close()
}

func normalizeManifestAssetType(kind, path string) string {
	if kind != "" {
		return kind
	}
	return inferAssetType(path)
}

func cloneStringSlice(values []string) []string {
	if values == nil {
		return nil
	}
	out := make([]string, len(values))
	copy(out, values)
	return out
}

