package voplay

import "os"
import "strconv"
import "github.com/vo-lang/vopack"
import "github.com/vo-lang/vogui"

const (
	assetSourceFile  = 1
	assetSourceBytes = 2
)

// AssetLoader defines platform-specific load/free functions for one asset type.
type AssetLoader struct {
	LoadFile  func(path string) (int, error)
	LoadBytes func(data []byte) (int, error)
	Free      func(id int)
}

type CubemapLoader struct {
	LoadFiles func(paths [6]string) (int, error)
	LoadBytes func(faces [6][]byte) (int, error)
	Free      func(id int)
}

// AssetLoaders groups loaders for all supported asset types.
type AssetLoaders struct {
	Texture AssetLoader
	Font    AssetLoader
	Model   AssetLoader
	Audio   AssetLoader
	Cubemap CubemapLoader
}

// managedAsset tracks a loaded asset handle with group-based ownership.
type managedAsset struct {
	id     int
	source int
	owners map[string]bool
}

// assetStore manages assets of one type (textures, fonts, models, or audio).
// All four asset types share this single implementation.
type assetStore struct {
	label   string
	loader  AssetLoader
	entries map[string]*managedAsset
	groups  map[string]map[string]bool
}

type cubemapStore struct {
	loader  CubemapLoader
	entries map[string]*managedAsset
	groups  map[string]map[string]bool
}

// Assets manages game resource loading with vopack integration and group-based lifecycle.
//
// Assets can optionally be backed by one or more .vpak archives via Mount.
// When loading by path, mounted archives are searched first (highest priority wins),
// then the filesystem is used as fallback. Path is the key for deduplication.
//
// Group-based ownership tracks which assets belong to which loading phase.
// Multiple groups can share the same asset; the asset is freed only when its
// last owning group is released.
type Assets struct {
	mounts     *vopack.MountSet
	groupStack []string
	groupNames map[string]bool
	textures   *assetStore
	cubemaps   *cubemapStore
	fonts      *assetStore
	models     *assetStore
	audio      *assetStore
}

// BytesAssetKey builds a deterministic content-addressed key for generated assets.
// Use it with *Bytes loaders when the same logical generated asset can change
// contents during development or procedural rebuilds.
func BytesAssetKey(prefix string, data []byte, ext string) string {
	hash := bytesAssetHash(data)
	return prefix + "_" + strconv.Itoa(len(data)) + "_" + strconv.Itoa(hash) + ext
}

func bytesAssetHash(data []byte) int {
	hash := 2166136261
	for _, b := range data {
		hash = hash ^ int(b)
		hash = (hash * 16777619) % 2147483647
	}
	if hash < 0 {
		hash = -hash
	}
	return hash
}

func newAssetStore(label string, loader AssetLoader) *assetStore {
	return &assetStore{
		label:   label,
		loader:  loader,
		entries: map[string]*managedAsset{},
		groups:  map[string]map[string]bool{},
	}
}

func newCubemapStore(loader CubemapLoader) *cubemapStore {
	return &cubemapStore{
		loader:  loader,
		entries: map[string]*managedAsset{},
		groups:  map[string]map[string]bool{},
	}
}

func NewAssets() *Assets {
	return NewAssetsWithLoaders(defaultAssetLoaders())
}

func NewAssetsWithLoaders(loaders AssetLoaders) *Assets {
	validateAssetLoaders(loaders)
	return &Assets{
		groupNames: map[string]bool{},
		textures:   newAssetStore("Texture", loaders.Texture),
		cubemaps:   newCubemapStore(loaders.Cubemap),
		fonts:      newAssetStore("Font", loaders.Font),
		models:     newAssetStore("Model", loaders.Model),
		audio:      newAssetStore("Audio", loaders.Audio),
	}
}

func defaultAssetLoaders() AssetLoaders {
	return AssetLoaders{
		Texture: AssetLoader{
			LoadFile:  func(path string) (int, error) { return loadTexture(path) },
			LoadBytes: func(data []byte) (int, error) { return loadTextureBytes(data) },
			Free:      func(id int) { freeTexture(id) },
		},
		Font: AssetLoader{
			LoadFile:  func(path string) (int, error) { return loadFont(path) },
			LoadBytes: func(data []byte) (int, error) { return loadFontBytes(data) },
			Free:      func(id int) { freeFont(id) },
		},
		Model: AssetLoader{
			LoadFile:  func(path string) (int, error) { return loadModel(path) },
			LoadBytes: func(data []byte) (int, error) { return loadModelBytes(data) },
			Free:      func(id int) { freeModel(id) },
		},
		Audio: AssetLoader{
			LoadFile: func(path string) (int, error) { return audioLoadFile(path) },
			LoadBytes: func(data []byte) (int, error) {
				clip := vogui.LoadAudioBytes(data)?
				return int(clip), nil
			},
			Free: func(id int) { vogui.AudioClipID(id).Free() },
		},
		Cubemap: CubemapLoader{
			LoadFiles: func(paths [6]string) (int, error) {
				return loadCubemap(paths[0], paths[1], paths[2], paths[3], paths[4], paths[5])
			},
			LoadBytes: func(faces [6][]byte) (int, error) {
				return loadCubemapBytes(faces[0], faces[1], faces[2], faces[3], faces[4], faces[5])
			},
			Free: func(id int) {
				freeCubemap(id)
			},
		},
	}
}

func validateAssetLoader(l AssetLoader, label string) {
	if l.LoadFile == nil || l.LoadBytes == nil || l.Free == nil {
		panic("NewAssetsWithLoaders: " + label + " loader must be complete")
	}
}

func validateCubemapLoader(l CubemapLoader) {
	if l.LoadFiles == nil || l.LoadBytes == nil || l.Free == nil {
		panic("NewAssetsWithLoaders: Cubemap loader must be complete")
	}
}

func validateAssetLoaders(loaders AssetLoaders) {
	validateAssetLoader(loaders.Texture, "Texture")
	validateAssetLoader(loaders.Font, "Font")
	validateAssetLoader(loaders.Model, "Model")
	validateAssetLoader(loaders.Audio, "Audio")
	validateCubemapLoader(loaders.Cubemap)
}

// Mount opens a .vpak archive and registers it at the given priority.
// Higher priority archives are searched first when loading assets by path.
func (a *Assets) Mount(path string, priority int) error {
	if a.mounts == nil {
		a.mounts = vopack.NewMountSet()
	}
	return a.mounts.Mount(path, priority)
}

// Unmount removes and closes the archive at the given path.
func (a *Assets) Unmount(path string) error {
	return a.mounts.Unmount(path)
}

func (a *Assets) BeginGroup(name string) {
	if name == "" {
		panic("Assets.BeginGroup: name must not be empty")
	}
	a.groupNames[name] = true
	a.groupStack = append(a.groupStack, name)
}

func (a *Assets) EndGroup() {
	if len(a.groupStack) == 0 {
		panic("Assets.EndGroup: no active group")
	}
	a.groupStack = a.groupStack[:len(a.groupStack)-1]
}

func (a *Assets) CurrentGroup() string {
	if len(a.groupStack) == 0 {
		return ""
	}
	return a.groupStack[len(a.groupStack)-1]
}

func (a *Assets) ReleaseGroup(name string) {
	if name == "" {
		panic("Assets.ReleaseGroup: name must not be empty")
	}
	for _, active := range a.groupStack {
		if active == name {
			panic("Assets.ReleaseGroup: group is currently active: " + name)
		}
	}
	if !a.groupNames[name] {
		panic("Assets.ReleaseGroup: unknown group: " + name)
	}
	a.textures.releaseGroup(name)
	a.cubemaps.releaseGroup(name)
	a.fonts.releaseGroup(name)
	a.models.releaseGroup(name)
	a.audio.releaseGroup(name)
	delete(a.groupNames, name)
}

func (a *Assets) ReleaseAll() {
	names := make([]string, 0, len(a.groupNames))
	for name := range a.groupNames {
		names = append(names, name)
	}
	for _, name := range names {
		a.ReleaseGroup(name)
	}
}

// Close releases all assets and closes any mounted archives.
func (a *Assets) Close() error {
	a.ReleaseAll()
	if a.mounts == nil {
		return nil
	}
	err := a.mounts.Close()
	a.mounts = nil
	return err
}

// Texture loads a texture by path. Mounted archives are searched first,
// then the filesystem. The path is the deduplication key.
func (a *Assets) Texture(path string) (TextureID, error) {
	id := a.textures.get(a.mounts, a.requireCurrentGroup(), path)?
	return TextureID(id), nil
}

// TextureBytes loads a texture from raw bytes under the given key.
func (a *Assets) TextureBytes(key string, data []byte) (TextureID, error) {
	id := a.textures.getBytes(a.requireCurrentGroup(), key, data)?
	return TextureID(id), nil
}

func (a *Assets) Cubemap(right, left, top, bottom, front, back string) (CubemapID, error) {
	id := a.cubemaps.get(
		a.mounts,
		a.requireCurrentGroup(),
		[6]string{right, left, top, bottom, front, back},
	)?
	return CubemapID(id), nil
}

func (a *Assets) CubemapBytes(key string, right, left, top, bottom, front, back []byte) (CubemapID, error) {
	id := a.cubemaps.getBytes(
		a.requireCurrentGroup(),
		key,
		[6][]byte{right, left, top, bottom, front, back},
	)?
	return CubemapID(id), nil
}

// Font loads a font by path. Mounted archives are searched first,
// then the filesystem. The path is the deduplication key.
func (a *Assets) Font(path string) (FontID, error) {
	id := a.fonts.get(a.mounts, a.requireCurrentGroup(), path)?
	return FontID(id), nil
}

// FontBytes loads a font from raw bytes under the given key.
func (a *Assets) FontBytes(key string, data []byte) (FontID, error) {
	id := a.fonts.getBytes(a.requireCurrentGroup(), key, data)?
	return FontID(id), nil
}

// Model loads a model by path. Mounted archives are searched first,
// then the filesystem. The path is the deduplication key.
func (a *Assets) Model(path string) (ModelID, error) {
	id := a.models.get(a.mounts, a.requireCurrentGroup(), path)?
	return ModelID(id), nil
}

// ModelBytes loads a model from raw bytes under the given key.
func (a *Assets) ModelBytes(key string, data []byte) (ModelID, error) {
	id := a.models.getBytes(a.requireCurrentGroup(), key, data)?
	return ModelID(id), nil
}

// Bytes reads a raw asset by path. Mounted archives are searched first,
// then the filesystem. Raw bytes are not group-managed.
func (a *Assets) Bytes(path string) ([]byte, error) {
	return readAssetBytes(a.mounts, path)
}

func (a *Assets) VerifyPackDependencies(path string) error {
	if a.mounts == nil {
		return nil
	}
	return a.mounts.VerifyManifestDependencies(path)
}

func (a *Assets) PackManifestFor(path string) (*vopack.Manifest, error) {
	if a.mounts == nil {
		return nil, os.ErrNotExist
	}
	return a.mounts.ManifestFor(path)
}

// Audio loads an audio clip by path. Mounted archives are searched first,
// then the filesystem. The path is the deduplication key.
func (a *Assets) Audio(path string) (AudioClipID, error) {
	id := a.audio.get(a.mounts, a.requireCurrentGroup(), path)?
	return AudioClipID(id), nil
}

// AudioBytes loads an audio clip from raw bytes under the given key.
func (a *Assets) AudioBytes(key string, data []byte) (AudioClipID, error) {
	id := a.audio.getBytes(a.requireCurrentGroup(), key, data)?
	return AudioClipID(id), nil
}

// --- assetStore methods ---

// get loads an asset by path, using vopack mounts first, then filesystem.
func (s *assetStore) get(mounts *vopack.MountSet, group, key string) (int, error) {
	requireAssetKey(key)
	if entry := s.entries[key]; entry != nil {
		if entry.source != assetSourceFile {
			panic("Assets." + s.label + ": key loaded via bytes, not path: " + key)
		}
		s.attachOwner(group, key, entry)
		return entry.id, nil
	}
	var id int
	if mounts != nil && mounts.Has(key) {
		data := mounts.Read(key)?
		id = s.loader.LoadBytes(data)?
	} else {
		id = s.loader.LoadFile(key)?
	}
	entry := &managedAsset{id: id, source: assetSourceFile, owners: map[string]bool{}}
	s.entries[key] = entry
	s.attachOwner(group, key, entry)
	return id, nil
}

// getBytes loads an asset from raw bytes under the given key.
func (s *assetStore) getBytes(group, key string, data []byte) (int, error) {
	requireAssetKey(key)
	if len(data) == 0 {
		panic("Assets." + s.label + "Bytes: data must not be empty")
	}
	if entry := s.entries[key]; entry != nil {
		if entry.source != assetSourceBytes {
			panic("Assets." + s.label + ": key loaded via path, not bytes: " + key)
		}
		s.attachOwner(group, key, entry)
		return entry.id, nil
	}
	id := s.loader.LoadBytes(data)?
	entry := &managedAsset{id: id, source: assetSourceBytes, owners: map[string]bool{}}
	s.entries[key] = entry
	s.attachOwner(group, key, entry)
	return id, nil
}

func (s *assetStore) attachOwner(group, key string, entry *managedAsset) {
	if entry.owners[group] {
		return
	}
	entry.owners[group] = true
	if s.groups[group] == nil {
		s.groups[group] = map[string]bool{}
	}
	s.groups[group][key] = true
}

func (s *assetStore) releaseGroup(name string) {
	keys := s.groups[name]
	if keys == nil {
		return
	}
	for key := range keys {
		entry := s.entries[key]
		delete(entry.owners, name)
		if len(entry.owners) == 0 {
			s.loader.Free(entry.id)
			delete(s.entries, key)
		}
	}
	delete(s.groups, name)
}

func (s *cubemapStore) get(mounts *vopack.MountSet, group string, paths [6]string) (int, error) {
	key := cubemapKey(paths)
	requireAssetKey(key)
	if entry := s.entries[key]; entry != nil {
		if entry.source != assetSourceFile {
			panic("Assets.Cubemap: key loaded via bytes, not path: " + key)
		}
		s.attachOwner(group, key, entry)
		return entry.id, nil
	}
	if mounts == nil {
		id := s.loader.LoadFiles(paths)?
		entry := &managedAsset{id: id, source: assetSourceFile, owners: map[string]bool{}}
		s.entries[key] = entry
		s.attachOwner(group, key, entry)
		return id, nil
	}
	faces := [6][]byte{}
	for i := 0; i < 6; i++ {
		data, err := readAssetBytes(mounts, paths[i])
		if err != nil {
			return 0, err
		}
		faces[i] = data
	}
	id := s.loader.LoadBytes(faces)?
	entry := &managedAsset{id: id, source: assetSourceFile, owners: map[string]bool{}}
	s.entries[key] = entry
	s.attachOwner(group, key, entry)
	return id, nil
}

func (s *cubemapStore) getBytes(group, key string, faces [6][]byte) (int, error) {
	requireAssetKey(key)
	for i := 0; i < 6; i++ {
		if len(faces[i]) == 0 {
			panic("Assets.CubemapBytes: face data must not be empty")
		}
	}
	if entry := s.entries[key]; entry != nil {
		if entry.source != assetSourceBytes {
			panic("Assets.Cubemap: key loaded via path, not bytes: " + key)
		}
		s.attachOwner(group, key, entry)
		return entry.id, nil
	}
	id := s.loader.LoadBytes(faces)?
	entry := &managedAsset{id: id, source: assetSourceBytes, owners: map[string]bool{}}
	s.entries[key] = entry
	s.attachOwner(group, key, entry)
	return id, nil
}

func (s *cubemapStore) attachOwner(group, key string, entry *managedAsset) {
	if entry.owners[group] {
		return
	}
	entry.owners[group] = true
	if s.groups[group] == nil {
		s.groups[group] = map[string]bool{}
	}
	s.groups[group][key] = true
}

func (s *cubemapStore) releaseGroup(name string) {
	keys := s.groups[name]
	if keys == nil {
		return
	}
	for key := range keys {
		entry := s.entries[key]
		delete(entry.owners, name)
		if len(entry.owners) == 0 {
			s.loader.Free(entry.id)
			delete(s.entries, key)
		}
	}
	delete(s.groups, name)
}

func (a *Assets) requireCurrentGroup() string {
	group := a.CurrentGroup()
	if group == "" {
		panic("Assets: no active group")
	}
	return group
}

func requireAssetKey(key string) {
	if key == "" {
		panic("Assets: key must not be empty")
	}
}

func cubemapKey(paths [6]string) string {
	for i := 0; i < 6; i++ {
		requireAssetKey(paths[i])
	}
	return paths[0] + "|" + paths[1] + "|" + paths[2] + "|" + paths[3] + "|" + paths[4] + "|" + paths[5]
}

func readAssetBytes(mounts *vopack.MountSet, path string) ([]byte, error) {
	requireAssetKey(path)
	if mounts != nil && mounts.Has(path) {
		return mounts.Read(path)
	}
	return os.ReadFile(path)
}

// Audio playback for voplay games.
//
// Delegates all audio operations to vogui's audio engine. voplay adds:
//   - Path-based loading (via readFileBytes extern / file_io layer)
//   - AudioBackend interface for test injection
//   - Vec3-based convenience wrappers
package voplay

import "github.com/vo-lang/vogui"

// ============ Extern: path-based file reading (Rust file_io layer) ============

func audioLoadFile(path string) (int, error)

// ============ Public Types ============

// AudioClipID is a handle to a loaded audio resource (WAV, OGG, MP3).
// Same underlying type as vogui.AudioClipID (int).
type AudioClipID int

// AudioSourceID is a handle to a persistent 3D audio source.
type AudioSourceID int

// AudioBackend abstracts spatial audio operations so they can be
// replaced in tests without per-function hook boilerplate.
type AudioBackend interface {
	SetListener(position, forward, up Vec3)
	PlaySound3D(clip AudioClipID, pos Vec3, volume, refDistance, maxDistance float64)
	CreateSource3D(clip AudioClipID, pos Vec3, volume, refDistance, maxDistance float64) (AudioSourceID, error)
	UpdateSpatial()
	SetSource3DPos(id AudioSourceID, pos Vec3)
	SetSource3DParams(id AudioSourceID, volume, pitch float64)
	RemoveSource3D(id AudioSourceID)
}

// ============ Helpers: convert between voplay Vec3 and vogui AudioVec3 ============

func toAudioVec3(v Vec3) vogui.AudioVec3 {
	return vogui.AudioVec3{X: v.X, Y: v.Y, Z: v.Z}
}

func toVoguiClip(c AudioClipID) vogui.AudioClipID {
	return vogui.AudioClipID(int(c))
}

// ============ AudioBackend (test-injectable) ============

type defaultAudioBackend struct{}

func (defaultAudioBackend) SetListener(position, forward, up Vec3) {
	vogui.SetAudioListener(toAudioVec3(position), toAudioVec3(forward), toAudioVec3(up))
}

func (defaultAudioBackend) PlaySound3D(clip AudioClipID, pos Vec3, volume, refDistance, maxDistance float64) {
	toVoguiClip(clip).PlaySound3D(toAudioVec3(pos), volume, refDistance, maxDistance)
}

func (defaultAudioBackend) CreateSource3D(clip AudioClipID, pos Vec3, volume, refDistance, maxDistance float64) (AudioSourceID, error) {
	src := vogui.CreateAudioSource3D(toVoguiClip(clip), toAudioVec3(pos), volume, refDistance, maxDistance)?
	return AudioSourceID(int(src)), nil
}

func (defaultAudioBackend) UpdateSpatial() {
	vogui.UpdateSpatialAudio()
}

func (defaultAudioBackend) SetSource3DPos(id AudioSourceID, pos Vec3) {
	vogui.AudioSourceID(int(id)).SetPosition(toAudioVec3(pos))
}

func (defaultAudioBackend) SetSource3DParams(id AudioSourceID, volume, pitch float64) {
	vogui.AudioSourceID(int(id)).SetParams(volume, pitch)
}

func (defaultAudioBackend) RemoveSource3D(id AudioSourceID) {
	vogui.AudioSourceID(int(id)).Remove()
}

var audioBackend AudioBackend = defaultAudioBackend{}

// SetAudioBackend replaces the active audio backend and returns the previous one.
func SetAudioBackend(b AudioBackend) AudioBackend {
	prev := audioBackend
	audioBackend = b
	return prev
}

// ============ Loading ============

// LoadAudio loads an audio file from disk and returns an AudioClipID.
// Uses voplay's file_io layer (WASM-safe via VirtualFS).
func LoadAudio(path string) (AudioClipID, error) {
	id := audioLoadFile(path)?
	return AudioClipID(id), nil
}

// LoadAudioBytes loads an audio clip from encoded bytes (WAV, OGG, MP3).
func LoadAudioBytes(data []byte) (AudioClipID, error) {
	clip := vogui.LoadAudioBytes(data)?
	return AudioClipID(int(clip)), nil
}

// ============ Basic Playback ============

// Free releases a loaded audio clip.
func (c AudioClipID) Free() {
	toVoguiClip(c).Free()
}

// Play plays this clip as a one-shot sound effect.
func (c AudioClipID) Play() {
	toVoguiClip(c).Play()
}

// PlayEx plays this clip as a sound effect with explicit parameters.
func (c AudioClipID) PlayEx(volume, pitch float64) {
	toVoguiClip(c).PlayEx(volume, pitch)
}

// PlayMusic starts this clip as looping background music.
func (c AudioClipID) PlayMusic(volume float64) {
	toVoguiClip(c).PlayMusic(volume)
}

// StopMusic stops the currently playing background music.
func StopMusic() {
	vogui.StopMusic()
}

// PauseMusic pauses the currently playing background music.
func PauseMusic() {
	vogui.PauseMusic()
}

// ResumeMusic resumes paused background music.
func ResumeMusic() {
	vogui.ResumeMusic()
}

// SetSFXVolume sets the global volume multiplier for sound effects (0.0–1.0).
func SetSFXVolume(vol float64) {
	vogui.SetSFXVolume(vol)
}

// SetMusicVolume sets the global volume multiplier for music (0.0–1.0).
func SetMusicVolume(vol float64) {
	vogui.SetMusicVolume(vol)
}

// ============ 3D Spatial (delegated via AudioBackend for Vec3 convenience) ============

func SetAudioListenerTransform(position, forward, up Vec3) {
	audioBackend.SetListener(position, forward.Normalize(), up)
}

func SetAudioListener(position, target, up Vec3) {
	SetAudioListenerTransform(position, target.Sub(position), up)
}

func (c AudioClipID) PlaySound3D(pos Vec3, volume, refDistance, maxDistance float64) {
	audioBackend.PlaySound3D(c, pos, volume, refDistance, maxDistance)
}

func CreateAudioSource3D(clip AudioClipID, pos Vec3, volume, refDistance, maxDistance float64) (AudioSourceID, error) {
	return audioBackend.CreateSource3D(clip, pos, volume, refDistance, maxDistance)
}

func UpdateSpatialAudio() {
	audioBackend.UpdateSpatial()
}

func (s AudioSourceID) SetPosition(pos Vec3) {
	audioBackend.SetSource3DPos(s, pos)
}

func (s AudioSourceID) SetParams(volume, pitch float64) {
	audioBackend.SetSource3DParams(s, volume, pitch)
}

func (s AudioSourceID) Remove() {
	audioBackend.RemoveSource3D(s)
}

// ByteWriter and ByteReader for binary encoding/decoding.
// Used by DrawCtx, physics command buffers, and state deserialization.
//
// This package exists to keep serialization primitives out of the public
// voplay API surface. Game code should not import this package directly.
package codec

import "math"

// ByteWriter appends binary data to a byte slice.
type ByteWriter struct {
	buf []byte
}

func NewByteWriter(cap int) ByteWriter {
	return ByteWriter{buf: make([]byte, 0, cap)}
}

func (w *ByteWriter) Bytes() []byte { return w.buf }
func (w *ByteWriter) Len() int      { return len(w.buf) }
func (w *ByteWriter) Reset()        { w.buf = w.buf[:0] }

func (w *ByteWriter) WriteByte(v byte) {
	w.buf = append(w.buf, v)
}

func (w *ByteWriter) WriteU16(v int) {
	w.buf = append(w.buf, byte(v), byte(v>>8))
}

func (w *ByteWriter) WriteU32(v int) {
	w.buf = append(w.buf, byte(v), byte(v>>8), byte(v>>16), byte(v>>24))
}

func (w *ByteWriter) WriteF64(v float64) {
	b := math.Float64bits(v)
	w.buf = append(w.buf,
		byte(b), byte(b>>8), byte(b>>16), byte(b>>24),
		byte(b>>32), byte(b>>40), byte(b>>48), byte(b>>56),
	)
}

func (w *ByteWriter) WriteF32(v float64) {
	b := math.Float32bits(float32(v))
	w.buf = append(w.buf, byte(b), byte(b>>8), byte(b>>16), byte(b>>24))
}

func (w *ByteWriter) WriteBool(v bool) {
	if v {
		w.buf = append(w.buf, 1)
	} else {
		w.buf = append(w.buf, 0)
	}
}

func (w *ByteWriter) WritePrimitive3DKey(objectID, shapeID int, px, py, pz, rx, ry, rz, rw, sx, sy, sz float64, materialID int, tr, tg, tb, ta float64, visible bool) {
	pXB := math.Float32bits(float32(px))
	pYB := math.Float32bits(float32(py))
	pZB := math.Float32bits(float32(pz))
	rXB := math.Float32bits(float32(rx))
	rYB := math.Float32bits(float32(ry))
	rZB := math.Float32bits(float32(rz))
	rWB := math.Float32bits(float32(rw))
	sXB := math.Float32bits(float32(sx))
	sYB := math.Float32bits(float32(sy))
	sZB := math.Float32bits(float32(sz))
	tRB := math.Float32bits(float32(tr))
	tGB := math.Float32bits(float32(tg))
	tBB := math.Float32bits(float32(tb))
	tAB := math.Float32bits(float32(ta))
	visibleByte := byte(0)
	if visible {
		visibleByte = 1
	}
	w.buf = append(w.buf,
		byte(objectID), byte(objectID>>8), byte(objectID>>16), byte(objectID>>24),
		byte(shapeID), byte(shapeID>>8), byte(shapeID>>16), byte(shapeID>>24),
		byte(pXB), byte(pXB>>8), byte(pXB>>16), byte(pXB>>24),
		byte(pYB), byte(pYB>>8), byte(pYB>>16), byte(pYB>>24),
		byte(pZB), byte(pZB>>8), byte(pZB>>16), byte(pZB>>24),
		byte(rXB), byte(rXB>>8), byte(rXB>>16), byte(rXB>>24),
		byte(rYB), byte(rYB>>8), byte(rYB>>16), byte(rYB>>24),
		byte(rZB), byte(rZB>>8), byte(rZB>>16), byte(rZB>>24),
		byte(rWB), byte(rWB>>8), byte(rWB>>16), byte(rWB>>24),
		byte(sXB), byte(sXB>>8), byte(sXB>>16), byte(sXB>>24),
		byte(sYB), byte(sYB>>8), byte(sYB>>16), byte(sYB>>24),
		byte(sZB), byte(sZB>>8), byte(sZB>>16), byte(sZB>>24),
		byte(materialID), byte(materialID>>8), byte(materialID>>16), byte(materialID>>24),
		byte(tRB), byte(tRB>>8), byte(tRB>>16), byte(tRB>>24),
		byte(tGB), byte(tGB>>8), byte(tGB>>16), byte(tGB>>24),
		byte(tBB), byte(tBB>>8), byte(tBB>>16), byte(tBB>>24),
		byte(tAB), byte(tAB>>8), byte(tAB>>16), byte(tAB>>24),
		visibleByte,
	)
}

func (w *ByteWriter) WriteRawBytes(data []byte) {
	w.buf = append(w.buf, data...)
}

func (w *ByteWriter) WriteString(s string) {
	w.WriteU16(len(s))
	w.buf = append(w.buf, s...)
}

// ByteReader reads binary data from a byte slice.
type ByteReader struct {
	data []byte
	pos  int
}

func NewByteReader(data []byte) ByteReader {
	return ByteReader{data: data}
}

func (r *ByteReader) Remaining() int { return len(r.data) - r.pos }

func (r *ByteReader) ReadByte() byte {
	v := r.data[r.pos]
	r.pos++
	return v
}

func (r *ByteReader) ReadBool() bool {
	return r.ReadByte() != 0
}

func (r *ByteReader) ReadU16() int {
	d := r.data[r.pos:]
	v := int(d[0]) | int(d[1])<<8
	r.pos += 2
	return v
}

func (r *ByteReader) ReadU32() int {
	d := r.data[r.pos:]
	v := int(d[0]) | int(d[1])<<8 | int(d[2])<<16 | int(d[3])<<24
	r.pos += 4
	return v
}

func (r *ByteReader) ReadBytes(n int) []byte {
	b := make([]byte, n)
	copy(b, r.data[r.pos:r.pos+n])
	r.pos += n
	return b
}

func (r *ByteReader) ReadF64() float64 {
	d := r.data[r.pos:]
	bits := uint64(d[0]) | uint64(d[1])<<8 | uint64(d[2])<<16 | uint64(d[3])<<24 |
		uint64(d[4])<<32 | uint64(d[5])<<40 | uint64(d[6])<<48 | uint64(d[7])<<56
	r.pos += 8
	return math.Float64frombits(bits)
}

func (r *ByteReader) ReadF32() float64 {
	d := r.data[r.pos:]
	bits := int(d[0]) | int(d[1])<<8 | int(d[2])<<16 | int(d[3])<<24
	r.pos += 4
	return float64(math.Float32frombits(bits))
}

package voplay

// BodyType determines how the physics engine treats a body.
type BodyType int

const (
	Dynamic   BodyType = 0
	Static    BodyType = 1
	Kinematic BodyType = 2
)

const (
	CollisionLayerDefault = 1
	CollisionMaskAll     = 0xFFFF
)

func ValidateCollisionFilter(layer, mask int) {
	if layer < 0 || layer > CollisionMaskAll {
		panic("ValidateCollisionFilter: layer must be in range 0..65535")
	}
	if mask < 0 || mask > CollisionMaskAll {
		panic("ValidateCollisionFilter: mask must be in range 0..65535")
	}
}

// Color type and predefined constants for voplay.
package voplay

// Color represents an RGBA color with float64 components in [0, 1].
type Color struct {
	R, G, B, A float64
}

// RGBA creates a Color from 0-1 float components.
func RGBA(r, g, b, a float64) Color {
	return Color{r, g, b, a}
}

// RGB creates an opaque Color from 0-1 float components.
func RGB(r, g, b float64) Color {
	return Color{r, g, b, 1.0}
}

// Hex creates a Color from a 24-bit hex value (0xRRGGBB).
func Hex(v int) Color {
	return Color{
		float64((v>>16)&0xFF) / 255.0,
		float64((v>>8)&0xFF) / 255.0,
		float64(v&0xFF) / 255.0,
		1.0,
	}
}

// HexA creates a Color from a 32-bit hex value (0xRRGGBBAA).
func HexA(v int) Color {
	return Color{
		float64((v>>24)&0xFF) / 255.0,
		float64((v>>16)&0xFF) / 255.0,
		float64((v>>8)&0xFF) / 255.0,
		float64(v&0xFF) / 255.0,
	}
}

// WithAlpha returns a copy of this color with a different alpha.
func (c Color) WithAlpha(a float64) Color {
	return Color{c.R, c.G, c.B, a}
}

// Lerp linearly interpolates between two colors.
func (c Color) Lerp(other Color, t float64) Color {
	return Color{
		c.R + (other.R-c.R)*t,
		c.G + (other.G-c.G)*t,
		c.B + (other.B-c.B)*t,
		c.A + (other.A-c.A)*t,
	}
}

// Predefined colors.
var (
	White       = Color{1, 1, 1, 1}
	Black       = Color{0, 0, 0, 1}
	Red         = Color{1, 0, 0, 1}
	Green       = Color{0, 1, 0, 1}
	Blue        = Color{0, 0, 1, 1}
	Yellow      = Color{1, 1, 0, 1}
	Cyan        = Color{0, 1, 1, 1}
	Magenta     = Color{1, 0, 1, 1}
	Transparent = Color{0, 0, 0, 0}
	CornflowerBlue = Color{0.392, 0.584, 0.929, 1}
)

// Debug overlay: engine-level performance HUD for voplay games.
// Tracks frame metrics (FPS, frame time, logic time) and renders
// a translucent overlay on top of game content using DrawCtx primitives.
//
// Usage from game code:
//   g.ShowDebugOverlay()   // enable
//   g.HideDebugOverlay()   // disable
//   g.ToggleDebugOverlay() // toggle
package voplay

import "strconv"

const (
	debugSlowFrameCacheSize = 8
	debugSlowLogCooldownFrames = 120
)

type debugSlowFrame struct {
	Frame int
	Reason string
	FrameMs float64
	LogicMs float64
	InputMs float64
	AdvanceMs float64
	DrawMs float64
	OverlayMs float64
	DrawBytes int
	SubmitBytes int
	FixedSteps int
}

type DebugOverlayStats struct {
	Enabled bool
	TargetFrameRate int
	FrameBudgetMs float64
	SlowFrameThresholdMs float64
	SlowLogicThresholdMs float64
	FPS float64
	FrameMs float64
	LogicMs float64
	InputMs float64
	AdvanceMs float64
	DrawMs float64
	OverlayMs float64
	MaxFrameMs float64
	MaxLogicMs float64
	DrawBytes int
	SubmitBytes int
	FixedSteps int
	SlowFrames int
	SlowLogs int
	LastSlowFrameMs float64
	LastSlowLogicMs float64
	LastSlowReason string
}

// DebugOverlay tracks per-frame performance metrics and renders a HUD.
type DebugOverlay struct {
	enabled bool
	targetFrameRate int
	frameBudgetMs float64
	slowFrameThresholdMs float64
	slowLogicThresholdMs float64

	// Rolling window for FPS smoothing.
	frameTimes [60]float64
	frameIdx   int
	frameCount int
	frameSeq int

	// Latest computed metrics.
	fps       float64
	frameMs   float64 // total frame-to-frame time (ms)
	logicMs   float64 // logic processing time (ms): input + advance + draw
	inputMs float64
	advanceMs float64
	drawMs float64
	overlayMs float64
	maxFrameMs float64
	maxLogicMs float64
	drawBytes int
	submitBytes int
	fixedSteps int
	slowFrames int
	slowLogs int
	slowLogCooldown int
	slowCache [8]debugSlowFrame
	slowCacheNext int
	slowCacheCount int
	lastSlow debugSlowFrame

	// Display strings (updated every N frames to avoid flicker).
	dispFPS      string
	dispFrameMs  string
	dispLogicMs  string
	dispLogicFPS string
	dispBudget string
	dispBytes string
	dispFixed string
	dispPhases string
	dispSlow string
	dispMax string
	dispCounter  int
}

func newDebugOverlay(targetFrameRate int) *DebugOverlay {
	budgetMs := 16.6667
	if targetFrameRate > 0 {
		budgetMs = 1000.0 / float64(targetFrameRate)
	}
	slowFrameThresholdMs := budgetMs * 2.0
	if slowFrameThresholdMs < 18 {
		slowFrameThresholdMs = 18
	}
	slowLogicThresholdMs := budgetMs * 1.25
	if slowLogicThresholdMs < 10 {
		slowLogicThresholdMs = 10
	}
	return &DebugOverlay{
		targetFrameRate: targetFrameRate,
		frameBudgetMs: budgetMs,
		slowFrameThresholdMs: slowFrameThresholdMs,
		slowLogicThresholdMs: slowLogicThresholdMs,
		dispFPS:     "-- fps",
		dispFrameMs: "-- ms",
		dispLogicMs: "-- ms",
		dispLogicFPS: "-- hz",
		dispBudget: "budget " + formatDebugMs(budgetMs),
		dispBytes: "draw -- / submit --",
		dispFixed: "fixed --",
		dispPhases: "phase input/update/draw/overlay --",
		dispSlow: "slow 0",
		dispMax: "max -- / --",
	}
}

// recordFrame updates metrics after a frame completes.
// dt is the frame-to-frame interval in seconds.
// logicNs is the logic processing time in nanoseconds.
func (o *DebugOverlay) recordFrame(dt float64, logicNs int64, fixedSteps int, drawBytes int, inputNs int64, advanceNs int64, drawNs int64) {
	o.frameSeq++
	o.frameMs = dt * 1000.0
	o.logicMs = float64(logicNs) / 1e6
	o.inputMs = float64(inputNs) / 1e6
	o.advanceMs = float64(advanceNs) / 1e6
	o.drawMs = float64(drawNs) / 1e6
	o.fixedSteps = fixedSteps
	o.drawBytes = drawBytes
	if o.frameMs > o.maxFrameMs {
		o.maxFrameMs = o.frameMs
	}
	if o.logicMs > o.maxLogicMs {
		o.maxLogicMs = o.logicMs
	}

	// Rolling window.
	o.frameTimes[o.frameIdx] = dt
	o.frameIdx = (o.frameIdx + 1) % len(o.frameTimes)
	if o.frameCount < len(o.frameTimes) {
		o.frameCount++
	}

	// Average FPS over window.
	sum := 0.0
	for i := 0; i < o.frameCount; i++ {
		sum += o.frameTimes[i]
	}
	if sum > 0 {
		o.fps = float64(o.frameCount) / sum
	}

	// Throttle display string updates to every 10 frames.
	o.dispCounter++
	if o.dispCounter >= 10 {
		o.dispCounter = 0
		o.dispFPS = strconv.FormatFloat(o.fps, 'f', 1, 64) + " fps"
		o.dispFrameMs = strconv.FormatFloat(o.frameMs, 'f', 2, 64) + " ms"
		o.dispLogicMs = strconv.FormatFloat(o.logicMs, 'f', 2, 64) + " ms"
		if o.logicMs > 0 {
			logicFPS := 1000.0 / o.logicMs
			o.dispLogicFPS = strconv.FormatFloat(logicFPS, 'f', 0, 64) + " hz"
		}
		o.dispBudget = "budget " + formatDebugMs(o.frameBudgetMs) + " slow>" + formatDebugMs(o.slowFrameThresholdMs)
		o.dispBytes = "draw " + formatDebugBytes(o.drawBytes) + " / submit " + formatDebugBytes(o.submitBytes)
		o.dispFixed = "fixed steps " + strconv.Itoa(o.fixedSteps)
		o.dispPhases = "phase i/a/d/o " + formatDebugMs(o.inputMs) + "/" + formatDebugMs(o.advanceMs) + "/" + formatDebugMs(o.drawMs) + "/" + formatDebugMs(o.overlayMs)
		o.dispSlow = "slow " + strconv.Itoa(o.slowFrames) + " logs " + strconv.Itoa(o.slowLogs)
		if o.slowFrames > 0 {
			o.dispSlow = o.dispSlow + " last " + o.lastSlow.Reason + " " + formatDebugMs(o.lastSlow.FrameMs)
		}
		o.dispMax = "max frame " + formatDebugMs(o.maxFrameMs) + " logic " + formatDebugMs(o.maxLogicMs)
	}
}

func (o *DebugOverlay) recordOverlayTime(overlayNs int64) {
	o.overlayMs = float64(overlayNs) / 1e6
}

func (o *DebugOverlay) recordSubmittedBytes(submitBytes int) {
	o.submitBytes = submitBytes
	o.recordSlowFrameIfNeeded()
}

func (o *DebugOverlay) snapshot() DebugOverlayStats {
	return DebugOverlayStats{
		Enabled: o.enabled,
		TargetFrameRate: o.targetFrameRate,
		FrameBudgetMs: o.frameBudgetMs,
		SlowFrameThresholdMs: o.slowFrameThresholdMs,
		SlowLogicThresholdMs: o.slowLogicThresholdMs,
		FPS: o.fps,
		FrameMs: o.frameMs,
		LogicMs: o.logicMs,
		InputMs: o.inputMs,
		AdvanceMs: o.advanceMs,
		DrawMs: o.drawMs,
		OverlayMs: o.overlayMs,
		MaxFrameMs: o.maxFrameMs,
		MaxLogicMs: o.maxLogicMs,
		DrawBytes: o.drawBytes,
		SubmitBytes: o.submitBytes,
		FixedSteps: o.fixedSteps,
		SlowFrames: o.slowFrames,
		SlowLogs: o.slowLogs,
		LastSlowFrameMs: o.lastSlow.FrameMs,
		LastSlowLogicMs: o.lastSlow.LogicMs,
		LastSlowReason: o.lastSlow.Reason,
	}
}

func (o *DebugOverlay) recordSlowFrameIfNeeded() {
	if o.slowLogCooldown > 0 {
		o.slowLogCooldown--
	}
	frameSlow := o.frameMs > o.slowFrameThresholdMs
	logicSlow := o.logicMs > o.slowLogicThresholdMs
	if !frameSlow && !logicSlow {
		return
	}
	reason := "frame"
	if logicSlow {
		reason = "logic"
	}
	if frameSlow && logicSlow {
		reason = "frame+logic"
	}
	slow := debugSlowFrame{Frame: o.frameSeq, Reason: reason, FrameMs: o.frameMs, LogicMs: o.logicMs, DrawBytes: o.drawBytes, SubmitBytes: o.submitBytes, FixedSteps: o.fixedSteps}
	slow.InputMs = o.inputMs
	slow.AdvanceMs = o.advanceMs
	slow.DrawMs = o.drawMs
	slow.OverlayMs = o.overlayMs
	o.lastSlow = slow
	o.slowCache[o.slowCacheNext] = slow
	o.slowCacheNext = (o.slowCacheNext + 1) % debugSlowFrameCacheSize
	if o.slowCacheCount < debugSlowFrameCacheSize {
		o.slowCacheCount++
	}
	o.slowFrames++
	severe := slow.FrameMs >= 50 || slow.LogicMs >= 30
	if o.slowLogCooldown > 0 && !severe {
		return
	}
	o.slowLogs++
	if !severe {
		o.slowLogCooldown = debugSlowLogCooldownFrames
	}
	println("voplay slow frame frame=" + strconv.Itoa(slow.Frame) + " reason=" + slow.Reason + " frameMs=" + formatDebugMs(slow.FrameMs) + " logicMs=" + formatDebugMs(slow.LogicMs) + " inputMs=" + formatDebugMs(slow.InputMs) + " advanceMs=" + formatDebugMs(slow.AdvanceMs) + " drawMs=" + formatDebugMs(slow.DrawMs) + " overlayMs=" + formatDebugMs(slow.OverlayMs) + " drawBytes=" + strconv.Itoa(slow.DrawBytes) + " submitBytes=" + strconv.Itoa(slow.SubmitBytes) + " fixedSteps=" + strconv.Itoa(slow.FixedSteps) + " cached=" + strconv.Itoa(o.slowCacheCount))
}

// draw renders the overlay onto the DrawCtx.
// Called after game Draw, before the frame reply is sent.
func (o *DebugOverlay) draw(d *DrawCtx) {
	if !o.enabled {
		return
	}

	// Switch to screen-space coordinates, highest z-layer.
	d.ResetCamera()
	d.SetLayer(65535)

	// Background panel.
	panelX := 12.0
	panelY := 14.0
	panelW := 320.0
	panelH := 182.0
	d.DrawRect(panelX, panelY, panelW, panelH, Color{R: 0, G: 0, B: 0, A: 0.65})

	// Text layout.
	textX := panelX + 10.0
	fontSize := 14.0
	lineH := 18.0
	textColor := Color{R: 0.0, G: 1.0, B: 0.0, A: 1.0}

	y := panelY + 16.0
	d.DrawText("present: "+o.dispFPS, textX, y, fontSize, textColor)
	y += lineH
	d.DrawText("frame: "+o.dispFrameMs+"  "+o.dispBudget, textX, y, fontSize, textColor)
	y += lineH
	d.DrawText("logic: "+o.dispLogicMs, textX, y, fontSize, textColor)
	y += lineH
	d.DrawText("logic headroom: "+o.dispLogicFPS, textX, y, fontSize, textColor)
	y += lineH
	d.DrawText(o.dispBytes, textX, y, fontSize, textColor)
	y += lineH
	d.DrawText(o.dispFixed, textX, y, fontSize, textColor)
	y += lineH
	d.DrawText(o.dispPhases, textX, y, fontSize, textColor)
	y += lineH
	d.DrawText(o.dispMax, textX, y, fontSize, textColor)
	y += lineH
	d.DrawText(o.dispSlow, textX, y, fontSize, textColor)
}

func formatDebugMs(value float64) string {
	return strconv.FormatFloat(value, 'f', 2, 64) + "ms"
}

func formatDebugBytes(value int) string {
	if value >= 1024 * 1024 {
		return strconv.FormatFloat(float64(value) / (1024.0 * 1024.0), 'f', 2, 64) + "MB"
	}
	if value >= 1024 {
		return strconv.FormatFloat(float64(value) / 1024.0, 'f', 1, 64) + "KB"
	}
	return strconv.Itoa(value) + "B"
}

// DrawCtx encodes draw commands into a binary []byte buffer.
// No extern calls — pure Vo. Submitted once per frame via submitFrame.
//
// All methods use root-package types only (no sub-package references).
// Scene-aware convenience methods live in scene2d/draw.vo and scene3d/draw.vo.
package voplay

import "math"
import "github.com/vo-lang/voplay/codec"

// Draw command opcodes (must match Rust decoder in stream.rs).
// Unexported: sub-packages use DrawCtx methods, not raw opcodes.
const (
	opClear         = 0x01
	opSetCamera2D   = 0x02
	opSetCamera3D   = 0x03
	opResetCamera   = 0x04
	opSetLayer      = 0x05
	opSetFont       = 0x06
	opDrawSprite    = 0x10
	opDrawRect      = 0x11
	opDrawCircle    = 0x12
	opDrawLine      = 0x13
	opDrawText      = 0x14
	opDrawModel     = 0x20
	opDrawBillboard = 0x21
	opSetLights3D   = 0x23
	opSetFog3D      = 0x24
	opDrawSkybox    = 0x25
	opSetColorGrading3D = 0x26
	opSetShadow3D   = 0x27
	opSetRenderDebug3D = 0x28
	opScene3DUpsertObject  = 0x30
	opScene3DDestroyObject = 0x31
	opScene3DClear         = 0x32
	opScene3DDraw          = 0x33
	opPrimitive3DUpsertInstance = 0x34
	opPrimitive3DDestroyInstance = 0x35
	opPrimitive3DClearLayer = 0x36
	opPrimitive3DDestroyLayer = 0x37
	opPrimitive3DReplaceChunk = 0x38
	opPrimitive3DReplaceChunkRefs = 0x39
	opPrimitive3DUpsertMaterials = 0x3A
	opPrimitive3DUpsertShapes = 0x3B
	opPrimitive3DReplaceChunkKeys = 0x3C
	opPrimitive3DSetChunkVisible = 0x3D
)

// DrawCtx buffers binary draw commands for the current frame.
type DrawCtx struct {
	w codec.ByteWriter
}

type Primitive3DInstanceDraw struct {
	ObjectID int
	Model    ModelID
	Position Vec3
	Rotation Quat
	Scale    Vec3
	Material MaterialDesc
	Visible  bool
}

type Primitive3DMaterialDraw struct {
	ID       int
	Material MaterialDesc
}

type Primitive3DShapeDraw struct {
	ID    int
	Model ModelID
}

type Primitive3DInstanceRefDraw struct {
	ObjectID   int
	Model      ModelID
	Position   Vec3
	Rotation   Quat
	Scale      Vec3
	MaterialID int
	Visible    bool
}

type Primitive3DInstanceKeyDraw struct {
	ObjectID   int
	ShapeID    int
	Position   Vec3
	Rotation   Quat
	Scale      Vec3
	MaterialID int
	Tint       Color
	Visible    bool
}

// NewDrawCtx creates a new draw command context.
func NewDrawCtx() *DrawCtx {
	return &DrawCtx{
		w: codec.NewByteWriter(4096),
	}
}

func (d *DrawCtx) reset() {
	d.w.Reset()
}

// Bytes returns the encoded command buffer.
func (d *DrawCtx) Bytes() []byte {
	return d.w.Bytes()
}

// --- Public draw commands ---

// Clear sets the background color for this frame.
func (d *DrawCtx) Clear(r, g, b, a float64) {
	d.w.WriteByte(opClear)
	d.w.WriteF32(r)
	d.w.WriteF32(g)
	d.w.WriteF32(b)
	d.w.WriteF32(a)
}

// ClearColor sets the background color using a Color value.
func (d *DrawCtx) ClearColor(c Color) {
	d.Clear(c.R, c.G, c.B, c.A)
}

// ResetCamera switches to screen-space coordinates (for HUD).
func (d *DrawCtx) ResetCamera() {
	d.w.WriteByte(opResetCamera)
}

// SetCamera2D sets the 2D camera for world-space drawing.
func (d *DrawCtx) SetCamera2D(x, y, zoom, rotation float64) {
	d.w.WriteByte(opSetCamera2D)
	d.w.WriteF32(x)
	d.w.WriteF32(y)
	d.w.WriteF32(zoom)
	d.w.WriteF32(rotation)
}

// SetLayer sets the z-order layer (0–65535) for subsequent 2D draws.
func (d *DrawCtx) SetLayer(z int) {
	if z < 0 || z > 65535 {
		panic("SetLayer: z must be in range 0–65535")
	}
	d.w.WriteByte(opSetLayer)
	d.w.WriteU16(z)
}

// SetFont sets the active font for subsequent DrawText calls.
// Use FontID 0 for the default built-in font.
func (d *DrawCtx) SetFont(id FontID) {
	d.w.WriteByte(opSetFont)
	d.w.WriteU32(int(id))
}

// DrawRect draws a filled rectangle.
func (d *DrawCtx) DrawRect(x, y, w, h float64, c Color) {
	d.w.WriteByte(opDrawRect)
	d.w.WriteF32(x)
	d.w.WriteF32(y)
	d.w.WriteF32(w)
	d.w.WriteF32(h)
	d.w.WriteF32(c.R)
	d.w.WriteF32(c.G)
	d.w.WriteF32(c.B)
	d.w.WriteF32(c.A)
}

// DrawCircle draws a filled circle.
func (d *DrawCtx) DrawCircle(cx, cy, radius float64, c Color) {
	d.w.WriteByte(opDrawCircle)
	d.w.WriteF32(cx)
	d.w.WriteF32(cy)
	d.w.WriteF32(radius)
	d.w.WriteF32(c.R)
	d.w.WriteF32(c.G)
	d.w.WriteF32(c.B)
	d.w.WriteF32(c.A)
}

// DrawLine draws a line segment.
func (d *DrawCtx) DrawLine(x1, y1, x2, y2, thickness float64, c Color) {
	d.w.WriteByte(opDrawLine)
	d.w.WriteF32(x1)
	d.w.WriteF32(y1)
	d.w.WriteF32(x2)
	d.w.WriteF32(y2)
	d.w.WriteF32(thickness)
	d.w.WriteF32(c.R)
	d.w.WriteF32(c.G)
	d.w.WriteF32(c.B)
	d.w.WriteF32(c.A)
}

// DrawRectOutline draws a rectangle outline using 4 lines.
// Horizontal lines are extended by half the thickness to cover corner gaps.
func (d *DrawCtx) DrawRectOutline(x, y, w, h, thickness float64, c Color) {
	ht := thickness / 2
	x2 := x + w
	y2 := y + h
	d.DrawLine(x-ht, y, x2+ht, y, thickness, c)     // top
	d.DrawLine(x2, y, x2, y2, thickness, c)          // right
	d.DrawLine(x-ht, y2, x2+ht, y2, thickness, c)   // bottom
	d.DrawLine(x, y2, x, y, thickness, c)            // left
}

// DrawCircleOutline draws a circle outline using line segments.
func (d *DrawCtx) DrawCircleOutline(cx, cy, radius, thickness float64, segments int, c Color) {
	if segments < 3 {
		panic("DrawCircleOutline: segments must be >= 3")
	}
	step := (math.Pi * 2) / float64(segments)
	px := cx + radius
	py := cy
	for i := 1; i <= segments; i++ {
		angle := float64(i) * step
		nx := cx + radius*math.Cos(angle)
		ny := cy + radius*math.Sin(angle)
		d.DrawLine(px, py, nx, ny, thickness, c)
		px = nx
		py = ny
	}
}

// DrawText draws text at the given position.
func (d *DrawCtx) DrawText(text string, x, y, size float64, c Color) {
	d.w.WriteByte(opDrawText)
	d.w.WriteF32(x)
	d.w.WriteF32(y)
	d.w.WriteF32(size)
	d.w.WriteF32(c.R)
	d.w.WriteF32(c.G)
	d.w.WriteF32(c.B)
	d.w.WriteF32(c.A)
	d.w.WriteString(text)
}

// SpriteParams holds parameters for drawing a textured sprite.
type SpriteParams struct {
	Tex      TextureID
	Src      Rect     // source rectangle in texture pixels (zero = full texture)
	Dst      Rect     // destination rectangle in world/screen space
	FlipX    bool
	FlipY    bool
	Rotation float64
	Tint     Color    // color tint (use White for no tint)
}

// DrawSprite draws a textured quad using a SpriteParams struct.
// Zero Tint is treated as White (fully visible, no tint).
func (d *DrawCtx) DrawSprite(p SpriteParams) {
	tint := p.Tint
	if tint == (Color{}) {
		tint = White
	}
	d.writeSprite(p.Tex, p.Src.X, p.Src.Y, p.Src.W, p.Src.H, p.Dst.X, p.Dst.Y, p.Dst.W, p.Dst.H, p.FlipX, p.FlipY, p.Rotation, tint)
}

// writeSprite encodes a sprite draw command into the binary buffer.
func (d *DrawCtx) writeSprite(tex TextureID, srcX, srcY, srcW, srcH, dstX, dstY, dstW, dstH float64, flipX, flipY bool, rotation float64, tint Color) {
	d.w.WriteByte(opDrawSprite)
	d.w.WriteU32(int(tex))
	d.w.WriteF32(srcX)
	d.w.WriteF32(srcY)
	d.w.WriteF32(srcW)
	d.w.WriteF32(srcH)
	d.w.WriteF32(dstX)
	d.w.WriteF32(dstY)
	d.w.WriteF32(dstW)
	d.w.WriteF32(dstH)
	d.w.WriteBool(flipX)
	d.w.WriteBool(flipY)
	d.w.WriteF32(rotation)
	d.w.WriteF32(tint.R)
	d.w.WriteF32(tint.G)
	d.w.WriteF32(tint.B)
	d.w.WriteF32(tint.A)
}

type BillboardParams struct {
	Tex      TextureID
	Src      Rect
	WorldPos Vec3
	Width    float64
	Height   float64
	Tint     Color
}

func (d *DrawCtx) writeBillboard(tex TextureID, srcX, srcY, srcW, srcH float64, worldPos Vec3, w, h float64, tint Color) {
	d.w.WriteByte(opDrawBillboard)
	d.w.WriteU32(int(tex))
	d.w.WriteF32(srcX)
	d.w.WriteF32(srcY)
	d.w.WriteF32(srcW)
	d.w.WriteF32(srcH)
	d.w.WriteF32(worldPos.X)
	d.w.WriteF32(worldPos.Y)
	d.w.WriteF32(worldPos.Z)
	d.w.WriteF32(w)
	d.w.WriteF32(h)
	d.w.WriteF32(tint.R)
	d.w.WriteF32(tint.G)
	d.w.WriteF32(tint.B)
	d.w.WriteF32(tint.A)
}

// DrawTexture draws a full texture at the given position and size with no rotation or flipping.
func (d *DrawCtx) DrawTexture(tex TextureID, x, y, w, h float64) {
	d.writeSprite(tex, 0, 0, 0, 0, x, y, w, h, false, false, 0, White)
}

// DrawTextureColor draws a full texture at the given position and size, tinted with the given color.
func (d *DrawCtx) DrawTextureColor(tex TextureID, x, y, w, h float64, tint Color) {
	d.writeSprite(tex, 0, 0, 0, 0, x, y, w, h, false, false, 0, tint)
}

// SetCamera3D sets the 3D camera for subsequent 3D draw commands.
func (d *DrawCtx) SetCamera3D(pos, target, up Vec3, fov, near, far float64) {
	d.w.WriteByte(opSetCamera3D)
	d.w.WriteF32(pos.X)
	d.w.WriteF32(pos.Y)
	d.w.WriteF32(pos.Z)
	d.w.WriteF32(target.X)
	d.w.WriteF32(target.Y)
	d.w.WriteF32(target.Z)
	d.w.WriteF32(up.X)
	d.w.WriteF32(up.Y)
	d.w.WriteF32(up.Z)
	d.w.WriteF32(fov)
	d.w.WriteF32(near)
	d.w.WriteF32(far)
}

// Light type constants for LightDesc.
const (
	DirectionalLight = 0
	PointLight       = 1
)

const (
	FogNone       = 0
	FogLinear     = 1
	FogExp        = 2
	FogExpSquared = 3
)

const (
	ToneMapNone = 0
	ToneMapReinhard = 1
	ToneMapACES = 2
)

const (
	RenderDebugLit = 0
	RenderDebugAlbedo = 1
	RenderDebugNormal = 2
	RenderDebugRoughness = 3
	RenderDebugMetallic = 4
	RenderDebugShadow = 5
	RenderDebugDirect = 6
	RenderDebugAmbient = 7
)

// LightDesc describes a light for the SetLights3D draw command.
type LightDesc struct {
	Type      int // DirectionalLight or PointLight
	Position  Vec3
	Direction Vec3
	Color     Color
	Intensity float64
}

// SetLights3D encodes the lighting state for subsequent 3D draw commands.
// ambientSky and ambientGround form a simple hemisphere ambient model.
func (d *DrawCtx) SetLights3D(ambientSky, ambientGround Color, lights []LightDesc) {
	d.w.WriteByte(opSetLights3D)
	d.w.WriteF32(ambientSky.R)
	d.w.WriteF32(ambientSky.G)
	d.w.WriteF32(ambientSky.B)
	d.w.WriteF32(ambientGround.R)
	d.w.WriteF32(ambientGround.G)
	d.w.WriteF32(ambientGround.B)
	count := len(lights)
	if count > 8 {
		panic("SetLights3D: lights must not exceed 8")
	}
	d.w.WriteByte(byte(count))
	for i := 0; i < count; i++ {
		l := lights[i]
		d.w.WriteByte(byte(l.Type))
		d.w.WriteF32(l.Position.X)
		d.w.WriteF32(l.Position.Y)
		d.w.WriteF32(l.Position.Z)
		d.w.WriteF32(l.Direction.X)
		d.w.WriteF32(l.Direction.Y)
		d.w.WriteF32(l.Direction.Z)
		d.w.WriteF32(l.Color.R)
		d.w.WriteF32(l.Color.G)
		d.w.WriteF32(l.Color.B)
		d.w.WriteF32(l.Intensity)
	}
}

func (d *DrawCtx) SetFog3D(mode int, color Color, start, end, density float64) {
	d.w.WriteByte(opSetFog3D)
	d.w.WriteByte(byte(mode))
	d.w.WriteF32(color.R)
	d.w.WriteF32(color.G)
	d.w.WriteF32(color.B)
	d.w.WriteF32(start)
	d.w.WriteF32(end)
	d.w.WriteF32(density)
}

// SetColorGrading3D applies simple renderer-side color management to 3D mesh output.
func (d *DrawCtx) SetColorGrading3D(toneMap int, exposure, contrast, saturation float64) {
	if toneMap < ToneMapNone || toneMap > ToneMapACES {
		panic("SetColorGrading3D: unsupported tone map")
	}
	if exposure < 0 {
		panic("SetColorGrading3D: exposure must be >= 0")
	}
	if contrast < 0 {
		panic("SetColorGrading3D: contrast must be >= 0")
	}
	if saturation < 0 {
		panic("SetColorGrading3D: saturation must be >= 0")
	}
	d.w.WriteByte(opSetColorGrading3D)
	d.w.WriteByte(byte(toneMap))
	d.w.WriteF32(exposure)
	d.w.WriteF32(contrast)
	d.w.WriteF32(saturation)
}

func (d *DrawCtx) SetShadow3D(enabled bool, resolution int, strength float64) {
	if enabled && resolution <= 0 {
		panic("SetShadow3D: resolution must be > 0")
	}
	if strength < 0 || strength > 1 {
		panic("SetShadow3D: strength must be in range 0..1")
	}
	if resolution <= 0 {
		resolution = 1
	}
	d.w.WriteByte(opSetShadow3D)
	d.w.WriteBool(enabled)
	d.w.WriteU32(resolution)
	d.w.WriteF32(strength)
}

// SetRenderDebug3D selects a renderer debug output for subsequent 3D mesh draws.
// It is meant for material and lighting validation, not gameplay presentation.
func (d *DrawCtx) SetRenderDebug3D(mode int) {
	if mode < RenderDebugLit || mode > RenderDebugAmbient {
		panic("SetRenderDebug3D: unsupported mode")
	}
	d.w.WriteByte(opSetRenderDebug3D)
	d.w.WriteByte(byte(mode))
}

func (d *DrawCtx) DrawSkybox(cubemap CubemapID) {
	d.w.WriteByte(opDrawSkybox)
	d.w.WriteU32(int(cubemap))
}

// DrawModel draws a 3D model at the given transform.
func (d *DrawCtx) DrawModel(model ModelID, pos Vec3, rot Quat, scale Vec3, material MaterialDesc) {
	d.writeModel(model, pos, rot, scale, material, 0, 0)
}

func (d *DrawCtx) DrawSkinnedModel(model ModelID, pos Vec3, rot Quat, scale Vec3, material MaterialDesc, animationWorldID, animationTargetID int) {
	d.writeModel(model, pos, rot, scale, material, animationWorldID, animationTargetID)
}

func (d *DrawCtx) writeModel(model ModelID, pos Vec3, rot Quat, scale Vec3, material MaterialDesc, animationWorldID, animationTargetID int) {
	material = NormalizeMaterial(material)
	d.w.WriteByte(opDrawModel)
	d.w.WriteU32(int(model))
	d.w.WriteF32(pos.X)
	d.w.WriteF32(pos.Y)
	d.w.WriteF32(pos.Z)
	d.w.WriteF32(rot.X)
	d.w.WriteF32(rot.Y)
	d.w.WriteF32(rot.Z)
	d.w.WriteF32(rot.W)
	d.w.WriteF32(scale.X)
	d.w.WriteF32(scale.Y)
	d.w.WriteF32(scale.Z)
	d.writeMaterial(material)
	d.w.WriteU32(animationWorldID)
	d.w.WriteU32(animationTargetID)
}

func (d *DrawCtx) UpsertScene3DObject(sceneID, objectID int, model ModelID, pos Vec3, rot Quat, scale Vec3, material MaterialDesc, visible bool, animationWorldID, animationTargetID int) {
	material = NormalizeMaterial(material)
	d.w.WriteByte(opScene3DUpsertObject)
	d.w.WriteU32(sceneID)
	d.w.WriteU32(objectID)
	d.w.WriteU32(int(model))
	d.w.WriteF32(pos.X)
	d.w.WriteF32(pos.Y)
	d.w.WriteF32(pos.Z)
	d.w.WriteF32(rot.X)
	d.w.WriteF32(rot.Y)
	d.w.WriteF32(rot.Z)
	d.w.WriteF32(rot.W)
	d.w.WriteF32(scale.X)
	d.w.WriteF32(scale.Y)
	d.w.WriteF32(scale.Z)
	d.writeMaterial(material)
	d.w.WriteBool(visible)
	d.w.WriteU32(animationWorldID)
	d.w.WriteU32(animationTargetID)
}

func (d *DrawCtx) writeMaterial(material MaterialDesc) {
	d.w.WriteU32(int(material.ID))
	d.w.WriteF32(material.BaseColor.R)
	d.w.WriteF32(material.BaseColor.G)
	d.w.WriteF32(material.BaseColor.B)
	d.w.WriteF32(material.BaseColor.A)
	d.w.WriteU32(int(material.Albedo))
	d.w.WriteU32(int(material.Normal))
	d.w.WriteU32(int(material.MetallicRoughness))
	d.w.WriteU32(int(material.Emissive))
	d.w.WriteF32(material.EmissiveColor.R)
	d.w.WriteF32(material.EmissiveColor.G)
	d.w.WriteF32(material.EmissiveColor.B)
	d.w.WriteF32(material.EmissiveColor.A)
	d.w.WriteF32(material.Roughness)
	d.w.WriteF32(material.Metallic)
	d.w.WriteF32(material.NormalScale)
	d.w.WriteF32(material.UVScale)
	d.w.WriteU32(int(material.ToonRamp))
	d.w.WriteU32(material.ShadingMode)
	d.w.WriteU32(material.WrapMode)
	d.w.WriteU32(material.FilterMode)
}

func (d *DrawCtx) DestroyScene3DObject(sceneID, objectID int) {
	d.w.WriteByte(opScene3DDestroyObject)
	d.w.WriteU32(sceneID)
	d.w.WriteU32(objectID)
}

func (d *DrawCtx) UpsertPrimitive3DInstance(sceneID, layerID, objectID int, model ModelID, pos Vec3, rot Quat, scale Vec3, material MaterialDesc, visible bool) {
	material = NormalizeMaterial(material)
	d.w.WriteByte(opPrimitive3DUpsertInstance)
	d.w.WriteU32(sceneID)
	d.w.WriteU32(layerID)
	d.w.WriteU32(objectID)
	d.w.WriteU32(int(model))
	d.w.WriteF32(pos.X)
	d.w.WriteF32(pos.Y)
	d.w.WriteF32(pos.Z)
	d.w.WriteF32(rot.X)
	d.w.WriteF32(rot.Y)
	d.w.WriteF32(rot.Z)
	d.w.WriteF32(rot.W)
	d.w.WriteF32(scale.X)
	d.w.WriteF32(scale.Y)
	d.w.WriteF32(scale.Z)
	d.writeMaterial(material)
	d.w.WriteBool(visible)
}

func (d *DrawCtx) ReplacePrimitive3DChunk(sceneID, layerID, chunkID int, instances []Primitive3DInstanceDraw) {
	d.w.WriteByte(opPrimitive3DReplaceChunk)
	d.w.WriteU32(sceneID)
	d.w.WriteU32(layerID)
	d.w.WriteU32(chunkID)
	d.w.WriteU32(len(instances))
	for _, instance := range instances {
		d.writePrimitive3DInstanceDraw(instance)
	}
}

func (d *DrawCtx) UpsertPrimitive3DMaterials(sceneID, layerID int, materials []Primitive3DMaterialDraw) {
	d.w.WriteByte(opPrimitive3DUpsertMaterials)
	d.w.WriteU32(sceneID)
	d.w.WriteU32(layerID)
	d.w.WriteU32(len(materials))
	for _, entry := range materials {
		d.w.WriteU32(entry.ID)
		d.writeMaterial(NormalizeMaterial(entry.Material))
	}
}

func (d *DrawCtx) UpsertPrimitive3DShapes(sceneID, layerID int, shapes []Primitive3DShapeDraw) {
	d.w.WriteByte(opPrimitive3DUpsertShapes)
	d.w.WriteU32(sceneID)
	d.w.WriteU32(layerID)
	d.w.WriteU32(len(shapes))
	for _, entry := range shapes {
		d.w.WriteU32(entry.ID)
		d.w.WriteU32(int(entry.Model))
	}
}

func (d *DrawCtx) ReplacePrimitive3DChunkRefs(sceneID, layerID, chunkID int, instances []Primitive3DInstanceRefDraw) {
	d.w.WriteByte(opPrimitive3DReplaceChunkRefs)
	d.w.WriteU32(sceneID)
	d.w.WriteU32(layerID)
	d.w.WriteU32(chunkID)
	d.w.WriteU32(len(instances))
	for _, instance := range instances {
		d.writePrimitive3DInstanceRefDraw(instance)
	}
}

func (d *DrawCtx) ReplacePrimitive3DChunkKeys(sceneID, layerID, chunkID int, instances []Primitive3DInstanceKeyDraw) {
	d.w.WriteByte(opPrimitive3DReplaceChunkKeys)
	d.w.WriteU32(sceneID)
	d.w.WriteU32(layerID)
	d.w.WriteU32(chunkID)
	d.w.WriteU32(len(instances))
	for _, instance := range instances {
		d.writePrimitive3DInstanceKeyDraw(instance)
	}
}

func (d *DrawCtx) BeginPrimitive3DChunkKeys(sceneID, layerID, chunkID, count int) {
	d.w.WriteByte(opPrimitive3DReplaceChunkKeys)
	d.w.WriteU32(sceneID)
	d.w.WriteU32(layerID)
	d.w.WriteU32(chunkID)
	d.w.WriteU32(count)
}

func (d *DrawCtx) WritePrimitive3DChunkKey(objectID, shapeID int, position Vec3, rotation Quat, scale Vec3, materialID int, tint Color, visible bool) {
	d.w.WritePrimitive3DKey(
		objectID, shapeID,
		position.X, position.Y, position.Z,
		rotation.X, rotation.Y, rotation.Z, rotation.W,
		scale.X, scale.Y, scale.Z,
		materialID,
		tint.R, tint.G, tint.B, tint.A,
		visible,
	)
}

func (d *DrawCtx) SetPrimitive3DChunkVisible(sceneID, layerID, chunkID int, visible bool) {
	d.w.WriteByte(opPrimitive3DSetChunkVisible)
	d.w.WriteU32(sceneID)
	d.w.WriteU32(layerID)
	d.w.WriteU32(chunkID)
	d.w.WriteBool(visible)
}

func (d *DrawCtx) writePrimitive3DInstanceDraw(instance Primitive3DInstanceDraw) {
	material := NormalizeMaterial(instance.Material)
	d.w.WriteU32(instance.ObjectID)
	d.w.WriteU32(int(instance.Model))
	d.w.WriteF32(instance.Position.X)
	d.w.WriteF32(instance.Position.Y)
	d.w.WriteF32(instance.Position.Z)
	d.w.WriteF32(instance.Rotation.X)
	d.w.WriteF32(instance.Rotation.Y)
	d.w.WriteF32(instance.Rotation.Z)
	d.w.WriteF32(instance.Rotation.W)
	d.w.WriteF32(instance.Scale.X)
	d.w.WriteF32(instance.Scale.Y)
	d.w.WriteF32(instance.Scale.Z)
	d.writeMaterial(material)
	d.w.WriteBool(instance.Visible)
}

func (d *DrawCtx) writePrimitive3DInstanceRefDraw(instance Primitive3DInstanceRefDraw) {
	d.w.WriteU32(instance.ObjectID)
	d.w.WriteU32(int(instance.Model))
	d.w.WriteF32(instance.Position.X)
	d.w.WriteF32(instance.Position.Y)
	d.w.WriteF32(instance.Position.Z)
	d.w.WriteF32(instance.Rotation.X)
	d.w.WriteF32(instance.Rotation.Y)
	d.w.WriteF32(instance.Rotation.Z)
	d.w.WriteF32(instance.Rotation.W)
	d.w.WriteF32(instance.Scale.X)
	d.w.WriteF32(instance.Scale.Y)
	d.w.WriteF32(instance.Scale.Z)
	d.w.WriteU32(instance.MaterialID)
	d.w.WriteBool(instance.Visible)
}

func (d *DrawCtx) writePrimitive3DInstanceKeyDraw(instance Primitive3DInstanceKeyDraw) {
	d.WritePrimitive3DChunkKey(
		instance.ObjectID,
		instance.ShapeID,
		instance.Position,
		instance.Rotation,
		instance.Scale,
		instance.MaterialID,
		instance.Tint,
		instance.Visible,
	)
}

func (d *DrawCtx) DestroyPrimitive3DInstance(sceneID, layerID, objectID int) {
	d.w.WriteByte(opPrimitive3DDestroyInstance)
	d.w.WriteU32(sceneID)
	d.w.WriteU32(layerID)
	d.w.WriteU32(objectID)
}

func (d *DrawCtx) ClearPrimitive3DLayer(sceneID, layerID int) {
	d.w.WriteByte(opPrimitive3DClearLayer)
	d.w.WriteU32(sceneID)
