func (d *DrawCtx) DrawBillboard(tex TextureID, srcX, srcY, srcW, srcH float64, worldPos Vec3, w, h float64) {
	d.writeBillboard(tex, srcX, srcY, srcW, srcH, worldPos, w, h, White)
}

func (d *DrawCtx) DrawBillboardEx(p BillboardParams) {
	tint := p.Tint
	if tint == (Color{}) {
		tint = White
	}
	d.writeBillboard(p.Tex, p.Src.X, p.Src.Y, p.Src.W, p.Src.H, p.WorldPos, p.Width, p.Height, tint)
}

