type PrimitiveStressState struct {
	scene *scene3d.Scene
	fixture *primitive3d.StressFixture
	count int
	frame int
	elapsed float64
	cameraAngle float64
	lastBytes int
	maxBytes int
}

func main() {
	voplay.Run(voplay.Game{Width: 1280, Height: 720, Title: "voplay primitive stress", TargetFrameRate: 120, InitialState: &PrimitiveStressState{count: 10000}})
}

func (s *PrimitiveStressState) Enter(g *voplay.GameCtx) {
	g.ShowDebugOverlay()
	s.rebuild()
}

func (s *PrimitiveStressState) Exit(g *voplay.GameCtx) {
	if s.scene != nil {
		s.scene.Close()
	}
}

func (s *PrimitiveStressState) FixedUpdate(g *voplay.GameCtx, dt float64) {}

func (s *PrimitiveStressState) Update(g *voplay.GameCtx, dt float64) {
	s.frame++
	s.elapsed += dt
	s.cameraAngle += dt * 0.18
	s.updateCamera()
}

func (s *PrimitiveStressState) Draw(g *voplay.GameCtx) {
	g.Draw.ClearColor(voplay.Color{R: 0.49, G: 0.74, B: 0.96, A: 1})
	if s.scene != nil {
		s.scene.Draw(g.Draw)
	}
	s.lastBytes = len(g.Draw.Bytes())
	if s.lastBytes > s.maxBytes {
		s.maxBytes = s.lastBytes
	}
	s.drawHud(g)
}

func (s *PrimitiveStressState) OnResize(g *voplay.GameCtx, w int, h int) {}

func (s *PrimitiveStressState) rebuild() {
	if s.count <= 0 {
		s.count = 10000
	}
	if s.scene != nil {
		s.scene.Close()
	}
	s.fixture = primitive3d.NewStressFixture(primitive3d.StressConfig{
		Count: s.count,
		ShapeVariants: 8,
		MaterialVariants: 16,
		ChunkCellSize: 32,
	})
	s.scene = scene3d.New()
	s.scene.Ambient = voplay.Color{R: 0.52, G: 0.60, B: 0.66, A: 1}
	s.scene.AmbientGround = voplay.Color{R: 0.20, G: 0.24, B: 0.22, A: 1}
	s.scene.Lights = []scene3d.Light{
		scene3d.Light{Type: scene3d.DirectionalLight, Direction: voplay.Vec3{X: -0.45, Y: -0.9, Z: -0.25}, Color: voplay.White, Intensity: 2.6},
	}
	s.scene.AddPrimitiveLayer(s.fixture.Layer)
	s.updateCamera()
}

func (s *PrimitiveStressState) updateCamera() {
	if s.scene == nil || s.fixture == nil {
		return
	}
	center := s.fixture.Bounds.Center()
	size := s.fixture.Bounds.Size()
	span := size.X
	if size.Z > span {
		span = size.Z
	}
	if span < 20 {
		span = 20
	}
	radius := span*0.70 + 120
	height := span*0.55 + 90
	s.scene.Camera.Position = center.Add(voplay.Vec3{
		X: math.Cos(s.cameraAngle) * radius,
		Y: height,
		Z: math.Sin(s.cameraAngle) * radius,
	})
	s.scene.Camera.Target = center
	s.scene.Camera.Up = voplay.Vec3{Y: 1}
	s.scene.Camera.Fov = 92
	s.scene.Camera.Near = 0.1
	s.scene.Camera.Far = span*3.0 + 500
}

func (s *PrimitiveStressState) drawHud(g *voplay.GameCtx) {
	g.Draw.ResetCamera()
	g.Draw.SetLayer(65534)
	g.Draw.DrawRect(18, 132, 560, 154, voplay.Color{R: 0.04, G: 0.06, B: 0.08, A: 0.72})
	g.Draw.DrawRect(18, 132, 560, 5, voplay.Color{R: 0.20, G: 0.86, B: 0.35, A: 1})
	text := voplay.Color{R: 0.94, G: 0.98, B: 1.0, A: 1}
	muted := voplay.Color{R: 0.66, G: 0.78, B: 0.84, A: 1}
	stats := primitive3d.Stats{}
	renderStats := scene3d.SceneRenderStats{}
	if s.scene != nil {
		stats = s.scene.PrimitiveStats()
		renderStats = s.scene.RenderStats()
	}
	g.Draw.DrawText("primitive stress", 32, 162, 20, text)
	g.Draw.DrawText("instances " + strconv.Itoa(stats.TotalInstances) + "   chunks " + strconv.Itoa(stats.TotalChunks) + "   groups " + strconv.Itoa(stats.ShapeMaterialGroups), 32, 190, 15, muted)
	g.Draw.DrawText("upserts " + strconv.Itoa(renderStats.UpsertedObjects) + "   batch groups " + strconv.Itoa(renderStats.BatchGroups), 32, 216, 15, muted)
	g.Draw.DrawText("frame bytes " + strconv.Itoa(s.lastBytes) + "   max bytes " + strconv.Itoa(s.maxBytes), 32, 242, 15, muted)
	g.Draw.DrawText("orbit: Rust culls retained chunks; Vo sends no reupload", 32, 268, 13, muted)
}

// Game lifecycle: Game, GameCtx, Run, Advance.
package voplay

// Game defines a voplay game application.
type Game struct {
	Width           int
	Height          int
	Title           string
	FixedStep       float64
	MaxCatchUpSteps int
	TargetFrameRate int
	UncappedFrameRate bool
	InitialState    State
	OnClose         func(g *GameCtx) // optional; called when the game loop exits
}

// GameCtx is the game context passed to all callbacks.
type GameCtx struct {
	Input   *InputState
	Actions *ActionMap
	Assets  *Assets
	Draw    *DrawCtx
	States  *StateStack
	Width   int     // current viewport width (updated on resize)
	Height  int     // current viewport height (updated on resize)
	FixedStep float64
	Alpha     float64

	MaxCatchUpSteps  int // 0 = use default (8); sets a ceiling on fixed steps per frame

	// Internal lifecycle state (managed by host, not for game code).
	gameInitialized  bool
	closed           bool
	accumulator      float64
	lastFixedSteps   int
	overlay          *DebugOverlay
}

// ShowDebugOverlay enables the engine performance HUD (FPS, frame time, logic time).
func (g *GameCtx) ShowDebugOverlay() {
	if g.overlay == nil {
		g.overlay = newDebugOverlay(0)
	}
	g.overlay.enabled = true
}

// HideDebugOverlay disables the engine performance HUD.
func (g *GameCtx) HideDebugOverlay() {
	if g.overlay == nil {
		return
	}
	g.overlay.enabled = false
}

// ToggleDebugOverlay toggles the engine performance HUD.
func (g *GameCtx) ToggleDebugOverlay() {
	if g.overlay == nil {
		g.overlay = newDebugOverlay(0)
	}
	g.overlay.enabled = !g.overlay.enabled
}

// DebugOverlayStats returns cached F3 performance metrics from the last frame.
func (g *GameCtx) DebugOverlayStats() DebugOverlayStats {
	if g.overlay == nil {
		return DebugOverlayStats{}
	}
	return g.overlay.snapshot()
}

func resolveFixedStep(step float64) float64 {
	if step == 0 {
		return 1.0 / 60.0
	}
	if step < 0 {
		panic("Game.FixedStep must be > 0")
	}
	return step
}

// handleResize checks for size change and updates GameCtx dimensions.
// Returns true if a resize occurred.
func (g *GameCtx) handleResize(w, h int) bool {
	if w == g.Width && h == g.Height {
		return false
	}
	g.Width = w
	g.Height = h
	g.States.Resize(w, h)
	return true
}

func (g *GameCtx) start(initial State) {
	if initial == nil {
		panic("Run: InitialState must not be nil")
	}
	g.closed = false
	g.accumulator = 0
	g.Alpha = 0
	g.States.Reset(initial)
	g.gameInitialized = true
}

func (g *GameCtx) Quit() {
	g.closed = true
}

func (g *GameCtx) Advance(dt float64) {
	if dt < 0 {
		panic("Advance: dt must not be negative")
	}
	if g.closed {
		return
	}
	fixedStep := g.FixedStep
	maxCatchUpSteps := g.MaxCatchUpSteps
	if maxCatchUpSteps <= 0 {
		maxCatchUpSteps = 8
	}
	maxAccumulated := fixedStep * float64(maxCatchUpSteps)
	frameDt := dt
	if frameDt > maxAccumulated {
		frameDt = maxAccumulated
	}
	g.accumulator += frameDt
	if g.accumulator > maxAccumulated {
		g.accumulator = maxAccumulated
	}
	steps := 0
	for g.accumulator >= fixedStep && steps < maxCatchUpSteps {
		g.States.FixedUpdate(fixedStep)
		if g.closed {
			g.Alpha = 0
			return
		}
		g.accumulator -= fixedStep
		steps++
	}
	g.lastFixedSteps = steps
	if g.accumulator < 0 {
		g.accumulator = 0
	}
	g.Alpha = g.accumulator / fixedStep
	if g.Alpha > 1 {
		g.Alpha = 1
	}
	g.States.Update(frameDt)
}

// Run starts the game with split-island rendering.
// The render island owns the GPU surface and submits frames.
// The logic island runs game state, update, and draw command generation.
// Communication happens via ports (draw commands, input events, resource proxy).
func Run(game Game) {
	if game.InitialState == nil {
		panic("Run: InitialState must not be nil")
	}
	runSplitMode(game)
}

// runSplitMode runs the game with rendering on a separate island.
// Logic island: game state, update, draw command generation.
// Render island: GPU init, frame submission, input polling.
func runSplitMode(game Game) {
	// Create ports for inter-island communication.
	ports := splitPorts{
		frameReq:   make(port []byte, 1), // render→logic: frame requests (input snapshots)
		frameReply: make(port []byte, 1), // logic→render: draw command replies
		resReq:     make(port []byte, 8), // logic→render: resource requests
		resResp:    make(port []byte, 8), // render→logic: resource responses
	}

	// Build game context with proxy asset loaders that forward to render island.
	ctx := newSplitGameCtx(game, ports.resReq, ports.resResp)

	// Run the split game loop via vogui platform.
	// Render worker is spawned inside Init (see host.vo) after canvas exists.
	runGameSplit(ctx, &game, ports)
}

// newSplitGameCtx creates a GameCtx with proxy asset loaders for split-island mode.
func newSplitGameCtx(game Game, resReqPort, resRespPort port []byte) *GameCtx {
	ctx := &GameCtx{
		Input:           NewInputState(),
		Draw:            NewDrawCtx(),
		Width:           game.Width,
		Height:          game.Height,
		FixedStep:       resolveFixedStep(game.FixedStep),
		MaxCatchUpSteps: game.MaxCatchUpSteps,
		overlay:         newDebugOverlay(game.TargetFrameRate),
	}
	ctx.Actions = NewActionMap(ctx.Input)
	ctx.Assets = NewAssetsWithLoaders(proxyAssetLoaders(resReqPort, resRespPort))
	ctx.States = NewStateStack(ctx)

	// Override model backend to proxy bounds queries to render island.
	SetModelBackend(&proxyModelBackendImpl{
		reqPort:  resReqPort,
		respPort: resRespPort,
	})
	SetPrimitiveMeshBackend(&proxyPrimitiveMeshBackendImpl{
		reqPort:  resReqPort,
		respPort: resRespPort,
	})
	SetModelMeshDataBackend(&proxyModelMeshDataBackendImpl{
		reqPort:  resReqPort,
		respPort: resRespPort,
	})
	SetAnimationRuntimeBackend(&proxyAnimationRuntimeBackendImpl{
		reqPort:  resReqPort,
		respPort: resRespPort,
	})

	return ctx
}

