// Game loop host: logic island side of the split-island architecture.
// The render island drives the frame clock. The logic island responds to
// frame requests: applying input, advancing game state, and returning
// draw commands.
package voplay

import (
	"encoding/json"
	"time"
	"github.com/vo-lang/vogui"
)

// splitPorts bundles all inter-island ports.
type splitPorts struct {
	frameReq   port []byte
	frameReply port []byte
	resReq     port []byte
	resResp    port []byte
}

type splitHostState struct {
	Started bool
	Starting bool
}

type splitWidgetEvent struct {
	Type   string `json:"type"`
	Width  int    `json:"width"`
	Height int    `json:"height"`
	CanvasId string `json:"canvasId"`
}

type renderWorkerConfig struct {
	UncappedFrameRate bool
	TargetFrameRate int
}

func useRenderIslandHost() bool {
	return vogui.HasHostCapability("render_island_host")
}

func startRenderIslandSplit(state *splitHostState, ctx *GameCtx, game *Game, ports splitPorts, canvasId string) {
	if state.Started || state.Starting {
		return
	}
	state.Starting = true
	renderIsland := make(island)
	go @(renderIsland) runRenderWorker(canvasId, renderWorkerConfig{
		UncappedFrameRate: game.UncappedFrameRate,
		TargetFrameRate: game.TargetFrameRate,
	}, renderWorkerPorts{
		frameReq:   ports.frameReq,
		frameReply: ports.frameReply,
		resReq:     ports.resReq,
		resResp:    ports.resResp,
	})
	if useRenderIslandHost() {
		go func() {
			waitRenderIslandReady(state, ctx, game, ports)
		}()
		return
	}
	waitRenderIslandReady(state, ctx, game, ports)
}

func waitRenderIslandReady(state *splitHostState, ctx *GameCtx, game *Game, ports splitPorts) {
	_, ok := <-ports.frameReq
	if !ok {
		state.Starting = false
		return
	}
	state.Started = true
	state.Starting = false
	ctx.start(game.InitialState)
	go runFrameDrivenGameLoop(ctx, game, ports.frameReq, ports.frameReply)
}

func runGameSplit(ctx *GameCtx, game *Game, ports splitPorts) {
	vogui.Run(vogui.App{
		Init: func() any {
			state := &splitHostState{}
			if !useRenderIslandHost() {
				startRenderIslandSplit(state, ctx, game, ports, "canvas")
			}
			return state
		},
		View: func(state any) vogui.Node {
			hostState := state.(*splitHostState)
			if useRenderIslandHost() {
				handler := vogui.OnWidget(func(s *splitHostState, payload string) {
					var evt splitWidgetEvent
					err := json.Unmarshal([]byte(payload), &evt)
					if err != nil {
						return
					}
					if evt.Width > 0 && evt.Height > 0 {
						ctx.handleResize(evt.Width, evt.Height)
					}
					if evt.Type == "mount" {
						startRenderIslandSplit(s, ctx, game, ports, evt.CanvasId)
					}
				})
				return vogui.HostWidget(
					"voplay-render-island",
					map[string]any{},
				).ObserveWidget(handler).W("100%").H("100%").Display("block").Overflow("hidden")
			}
			_ = hostState
			return vogui.Canvas(vogui.CanvasProps{
				Fullscreen: true,
				OnResize: vogui.OnResize(func(_ any, e vogui.ResizeEvent) {
					ctx.handleResize(e.Width, e.Height)
				}),
			}).Ref("canvas").Attr("id", "canvas")
		},
	})
}

// runFrameDrivenGameLoop runs the game logic in lockstep with the render
// island's frame clock. Each iteration: receive a frame request carrying
// the latest input snapshot, advance game state, generate draw commands,
// and reply. No tick provider, no select, no backlog.
func runFrameDrivenGameLoop(ctx *GameCtx, game *Game, frameReqPort, frameReplyPort port []byte) {
	lastTime := time.Now()
	firstFrame := true

	for {
		// Block until render island sends next frame request.
		inputBytes, ok := <-frameReqPort
		if !ok {
			// Render island closed (surface lost or shutdown).
			ctx.closed = true
			if game.OnClose != nil {
				game.OnClose(ctx)
			}
			return
		}

		// Compute dt from logic island clock.
		now := time.Now()
		dt := 0.0
		if !firstFrame {
			dt = float64(now.Sub(lastTime).Nanoseconds()) / 1e9
		}
		firstFrame = false
		lastTime = now

		// Check if game has been closed (e.g. by a previous frame's callback).
		if ctx.closed {
			close(frameReplyPort)
			if game.OnClose != nil {
				game.OnClose(ctx)
			}
			return
		}

		// --- Begin logic processing (timed for overlay) ---
		logicStart := time.Now()

		// Apply input from render island.
		inputStart := time.Now()
		if len(inputBytes) > 0 {
			ctx.Input.unpackEvents(inputBytes)
		}
		inputNs := time.Now().Sub(inputStart).Nanoseconds()

		// Advance game logic with fixed-step simulation.
		advanceStart := time.Now()
		ctx.Advance(dt)
		advanceNs := time.Now().Sub(advanceStart).Nanoseconds()

		if ctx.closed {
			ctx.Input.endFrame()
			close(frameReplyPort)
			if game.OnClose != nil {
				game.OnClose(ctx)
			}
			return
		}

		// Generate draw commands.
		drawStart := time.Now()
		ctx.Draw.reset()
		ctx.States.Draw()
		drawNs := time.Now().Sub(drawStart).Nanoseconds()

		// --- End logic processing ---
		logicNs := time.Now().Sub(logicStart).Nanoseconds()
		drawBytes := len(ctx.Draw.Bytes())

		// Record metrics and draw debug overlay (if enabled).
		ctx.overlay.recordFrame(dt, logicNs, ctx.lastFixedSteps, drawBytes, inputNs, advanceNs, drawNs)
		overlayStart := time.Now()
		ctx.overlay.draw(ctx.Draw)
		ctx.overlay.recordOverlayTime(time.Now().Sub(overlayStart).Nanoseconds())

		cmds := ctx.Draw.Bytes()
		ctx.overlay.recordSubmittedBytes(len(cmds))
		frameReplyPort <- cmds

		ctx.Input.endFrame()
	}
}

// --- Extern declarations for the render island (implemented in Rust) ---
// These are called by render_worker.vo on the render island, not by logic island code.

// Surface
func initSurface(canvasRef string, uncappedFrameRate bool) error
func submitFrame(cmds []byte) error
func waitDisplayPulse()

// Input
func pollInput() []byte

// Runtime query
func isRendererReady() (bool, error)

// InputState provides polling-based input for keyboard and pointer.
// Events are unpacked from binary data returned by pollInput extern.
package voplay

import "strings"
import "github.com/vo-lang/voplay/codec"

// Input event kinds (must match Rust encoder in input.rs).
const (
	inputKeyDown     = 0x01
	inputKeyUp       = 0x02
	inputPointerDown = 0x03
	inputPointerUp   = 0x04
	inputPointerMove = 0x05
	inputScroll      = 0x06
	inputBindingKey     = 0x01
	inputBindingPointer = 0x02
	inputBindingGamepadButton = 0x03
	inputBindingGamepadAxis   = 0x04
)

func normalizeKeyName(key string) string {
	if key == "" {
		panic("normalizeKeyName: key must not be empty")
	}
	if len(key) == 1 {
		return strings.ToLower(key)
	}
	if len(key) == 4 && strings.HasPrefix(key, "Key") {
		suffix := key[3:]
		if len(suffix) == 1 {
			return strings.ToLower(suffix)
		}
	}
	return key
}

// InputState holds the current state of keyboard, pointer, and gamepad input.
type InputState struct {
	// Keyboard state: key string → state
	keysDown     map[string]bool // currently held
	keysPressed  map[string]bool // pressed this frame
	keysReleased map[string]bool // released this frame

	// Pointer state
	pointerX, pointerY     float64
	prevPointerX, prevPointerY float64
	pointerButtons         int   // bitmask of held buttons
	pointerPressed         int   // buttons pressed this frame
	pointerReleased        int   // buttons released this frame
	pointerContacts        map[int]*PointerContact
	pointerOrder           []int
	pointerSeen            bool

	// Scroll wheel
	scrollX, scrollY float64

	gamepads map[int]*GamepadState
}

type PointerContact struct {
	ID int
	X, Y float64
	PrevX, PrevY float64
	Button int
	Down bool
	Pressed bool
	Released bool
}

type InputBinding struct {
	kind   byte
	key    string
	button int
	gamepad int
	axis string
	axisSign int
	deadzone float64
	gamepadButton string
}

type ActionMap struct {
	input   *InputState
	actions map[string][]InputBinding
}

type GamepadState struct {
	Connected bool
	Axes map[string]float64
	ButtonsDown map[string]bool
	ButtonsPressed map[string]bool
	ButtonsReleased map[string]bool
	RumbleLow float64
	RumbleHigh float64
}

// NewInputState creates a new InputState with empty state.
func NewInputState() *InputState {
	return &InputState{
		keysDown:     map[string]bool{},
		keysPressed:  map[string]bool{},
		keysReleased: map[string]bool{},
		pointerContacts: map[int]*PointerContact{},
		gamepads:     map[int]*GamepadState{},
	}
}

func NewActionMap(input *InputState) *ActionMap {
	if input == nil {
		panic("NewActionMap: input must not be nil")
	}
	return &ActionMap{
		input:   input,
		actions: map[string][]InputBinding{},
	}
}

func KeyBinding(key string) InputBinding {
	if key == "" {
		panic("KeyBinding: key must not be empty")
	}
	return InputBinding{kind: inputBindingKey, key: normalizeKeyName(key)}
}

func PointerBinding(button int) InputBinding {
	if button < 0 {
		panic("PointerBinding: button must be >= 0")
	}
	return InputBinding{kind: inputBindingPointer, button: button}
}

func GamepadButtonBinding(gamepad int, button string) InputBinding {
	if gamepad < 0 {
		panic("GamepadButtonBinding: gamepad must be >= 0")
	}
	if button == "" {
		panic("GamepadButtonBinding: button must not be empty")
	}
	return InputBinding{kind: inputBindingGamepadButton, gamepad: gamepad, gamepadButton: button}
}

func GamepadAxisBinding(gamepad int, axis string, sign int, deadzone float64) InputBinding {
	if gamepad < 0 {
		panic("GamepadAxisBinding: gamepad must be >= 0")
	}
	if axis == "" {
		panic("GamepadAxisBinding: axis must not be empty")
	}
	if sign < 0 {
		sign = -1
	} else {
		sign = 1
	}
	return InputBinding{kind: inputBindingGamepadAxis, gamepad: gamepad, axis: axis, axisSign: sign, deadzone: inputClamp(deadzone, 0, 0.99)}
}

func (m *ActionMap) Bind(action string, bindings ...InputBinding) {
	validateActionBindingArgs(action, bindings)
	m.actions[action] = append(m.actions[action], cloneInputBindings(bindings)...)
}

func (m *ActionMap) Rebind(action string, bindings ...InputBinding) {
	validateActionBindingArgs(action, bindings)
	m.actions[action] = cloneInputBindings(bindings)
}

func (m *ActionMap) Unbind(action string) {
	if action == "" {
		panic("Unbind: action must not be empty")
	}
	delete(m.actions, action)
}

func (m *ActionMap) IsDown(action string) bool {
	bindings := m.mustBindings(action)
	for _, binding := range bindings {
		if binding.isDown(m.input) {
			return true
		}
	}
	return false
}

func (m *ActionMap) IsPressed(action string) bool {
	bindings := m.mustBindings(action)
	for _, binding := range bindings {
		if binding.isPressed(m.input) {
			return true
		}
	}
	return false
}

func (m *ActionMap) IsReleased(action string) bool {
	bindings := m.mustBindings(action)
	for _, binding := range bindings {
		if binding.isReleased(m.input) {
			return true
		}
	}
	return false
}

func (m *ActionMap) Axis(negativeAction, positiveAction string) float64 {
	return inputClamp(m.Value(positiveAction)-m.Value(negativeAction), -1, 1)
}

func (m *ActionMap) Value(action string) float64 {
	bindings := m.mustBindings(action)
	best := 0.0
	for _, binding := range bindings {
		v := binding.value(m.input)
		if v > best {
			best = v
		}
	}
	return inputClamp(best, 0, 1)
}

func (m *ActionMap) mustBindings(action string) []InputBinding {
	if action == "" {
		panic("ActionMap: action must not be empty")
	}
	bindings := m.actions[action]
	if len(bindings) == 0 {
		panic("ActionMap: action is not bound: " + action)
	}
	return bindings
}

func validateActionBindingArgs(action string, bindings []InputBinding) {
	if action == "" {
		panic("ActionMap: action must not be empty")
	}
	if len(bindings) == 0 {
		panic("ActionMap: bindings must not be empty")
	}
}

func cloneInputBindings(bindings []InputBinding) []InputBinding {
	cloned := make([]InputBinding, len(bindings))
	copy(cloned, bindings)
	return cloned
}

func (binding InputBinding) isDown(input *InputState) bool {
	switch binding.kind {
	case inputBindingKey:
		return input.IsKeyDown(binding.key)
	case inputBindingPointer:
		return input.IsPointerDown(binding.button)
	case inputBindingGamepadButton:
		return input.IsGamepadButtonDown(binding.gamepad, binding.gamepadButton)
	case inputBindingGamepadAxis:
		return binding.value(input) > 0
	default:
		panic("InputBinding: unsupported binding kind")
	}
}

func (binding InputBinding) isPressed(input *InputState) bool {
	switch binding.kind {
	case inputBindingKey:
		return input.IsKeyPressed(binding.key)
	case inputBindingPointer:
		return input.IsPointerPressed(binding.button)
	case inputBindingGamepadButton:
		return input.IsGamepadButtonPressed(binding.gamepad, binding.gamepadButton)
	case inputBindingGamepadAxis:
		return false
	default:
		panic("InputBinding: unsupported binding kind")
	}
}

func (binding InputBinding) isReleased(input *InputState) bool {
	switch binding.kind {
	case inputBindingKey:
		return input.IsKeyReleased(binding.key)
	case inputBindingPointer:
		return input.IsPointerReleased(binding.button)
	case inputBindingGamepadButton:
		return input.IsGamepadButtonReleased(binding.gamepad, binding.gamepadButton)
	case inputBindingGamepadAxis:
		return false
	default:
		panic("InputBinding: unsupported binding kind")
	}
}

func (binding InputBinding) value(input *InputState) float64 {
	switch binding.kind {
	case inputBindingKey:
		if input.IsKeyDown(binding.key) {
			return 1
		}
		return 0
	case inputBindingPointer:
		if input.IsPointerDown(binding.button) {
			return 1
		}
		return 0
	case inputBindingGamepadButton:
		if input.IsGamepadButtonDown(binding.gamepad, binding.gamepadButton) {
			return 1
		}
		return 0
	case inputBindingGamepadAxis:
		raw := input.GamepadAxis(binding.gamepad, binding.axis)
		if binding.axisSign < 0 {
			raw = -raw
		}
		return inputApplyDeadzone(raw, binding.deadzone)
	default:
		panic("InputBinding: unsupported binding kind")
	}
}

func (inp *InputState) KeyDown(key string) {
	if key == "" {
		panic("KeyDown: key must not be empty")
	}
	key = normalizeKeyName(key)
	if !inp.keysDown[key] {
		inp.keysPressed[key] = true
	}
	inp.keysDown[key] = true
}

func (inp *InputState) KeyUp(key string) {
	if key == "" {
		panic("KeyUp: key must not be empty")
	}
	key = normalizeKeyName(key)
	inp.keysDown[key] = false
	inp.keysReleased[key] = true
