func (inp *InputState) PointerDownID(id int, x, y float64, button int) {
	validatePointerID(id)
	if button < 0 {
		panic("PointerDownID: button must be >= 0")
	}
	inp.pointerSeen = true
	inp.pointerX = x
	inp.pointerY = y
	contact := inp.pointerContact(id, x, y)
	if !contact.Down {
		contact.Pressed = true
		inp.pointerPressed |= 1 << button
	}
	contact.X = x
	contact.Y = y
	contact.Button = button
	contact.Down = true
	contact.Released = false
	inp.recomputePointerButtons()
}

func (inp *InputState) PointerUp(x, y float64, button int) {
