// unpackEvents decodes binary input events from pollInput.
func (inp *InputState) unpackEvents(data []byte) {
	r := codec.NewByteReader(data)
	for r.Remaining() > 0 {
		kind := r.ReadByte()
		switch kind {
		case inputKeyDown:
			key := decodeKeyEvent(&r)
			inp.KeyDown(key)
		case inputKeyUp:
			key := decodeKeyEvent(&r)
			inp.KeyUp(key)
		case inputPointerDown:
			id := r.ReadU32()
			x := r.ReadF64()
			y := r.ReadF64()
			btn := int(r.ReadByte())
			inp.PointerDownID(id, x, y, btn)
		case inputPointerUp:
			id := r.ReadU32()
			x := r.ReadF64()
			y := r.ReadF64()
			btn := int(r.ReadByte())
			inp.PointerUpID(id, x, y, btn)
		case inputPointerMove:
			id := r.ReadU32()
			x := r.ReadF64()
			y := r.ReadF64()
			inp.PointerMoveID(id, x, y)
			_ = r.ReadByte() // button byte present in wire format but ignored for move events
		case inputScroll:
			inp.ScrollBy(r.ReadF64(), r.ReadF64())
		default:
			return // unknown event, stop parsing
		}
	}
}

// endFrame clears per-frame flags (pressed/released) and snapshots pointer for delta.
func (inp *InputState) endFrame() {
	for k := range inp.keysPressed {
		delete(inp.keysPressed, k)
	}
	for k := range inp.keysReleased {
		delete(inp.keysReleased, k)
	}
	inp.pointerPressed = 0
	inp.pointerReleased = 0
	inp.prevPointerX = inp.pointerX
	inp.prevPointerY = inp.pointerY
	nextOrder := inp.pointerOrder[:0]
	for _, id := range inp.pointerOrder {
		contact := inp.pointerContacts[id]
		if contact == nil {
			continue
		}
		contact.Pressed = false
		contact.Released = false
		contact.PrevX = contact.X
		contact.PrevY = contact.Y
		if contact.Down {
			nextOrder = append(nextOrder, id)
		} else {
			delete(inp.pointerContacts, id)
		}
	}
	inp.pointerOrder = nextOrder
	inp.scrollX = 0
	inp.scrollY = 0
	for _, gp := range inp.gamepads {
		for b := range gp.ButtonsPressed {
			delete(gp.ButtonsPressed, b)
		}
		for b := range gp.ButtonsReleased {
			delete(gp.ButtonsReleased, b)
		}
	}
}

func (inp *InputState) EndFrame() {
	inp.endFrame()
}

