func (inp *InputState) AnyPointerDownInRect(rect Rect) bool {
	for _, contact := range inp.pointerContacts {
		if contact.Down && rect.Contains(contact.X, contact.Y) {
			return true
		}
	}
	return false
}

func (inp *InputState) AnyPointerPressedInRect(rect Rect) bool {
	for _, contact := range inp.pointerContacts {
		if contact.Pressed && rect.Contains(contact.X, contact.Y) {
			return true
		}
	}
	return false
}

func (inp *InputState) AnyPointerReleasedInRect(rect Rect) bool {
	for _, contact := range inp.pointerContacts {
		if contact.Released && rect.Contains(contact.X, contact.Y) {
			return true
		}
	}
	return false
}

// ScrollDelta returns the accumulated scroll wheel delta for this frame.
// Positive Y = scroll up/forward, negative Y = scroll down/backward.
func (inp *InputState) ScrollDelta() (float64, float64) {
	return inp.scrollX, inp.scrollY
}

// PointerDelta returns the pointer movement since the last frame.
func (inp *InputState) PointerDelta() (float64, float64) {
	return inp.pointerX - inp.prevPointerX, inp.pointerY - inp.prevPointerY
}

func (inp *InputState) gamepad(gamepad int) *GamepadState {
	if gamepad < 0 {
		panic("InputState: gamepad must be >= 0")
	}
	gp := inp.gamepads[gamepad]
	if gp == nil {
		gp = &GamepadState{
			Axes: map[string]float64{},
			ButtonsDown: map[string]bool{},
			ButtonsPressed: map[string]bool{},
			ButtonsReleased: map[string]bool{},
		}
		inp.gamepads[gamepad] = gp
	}
	return gp
}

func (inp *InputState) pointerContact(id int, x, y float64) *PointerContact {
	if inp.pointerContacts == nil {
		inp.pointerContacts = map[int]*PointerContact{}
	}
	contact := inp.pointerContacts[id]
	if contact == nil {
		contact = &PointerContact{ID: id, X: x, Y: y, PrevX: x, PrevY: y}
		inp.pointerContacts[id] = contact
		inp.pointerOrder = append(inp.pointerOrder, id)
	}
	return contact
}

func (inp *InputState) recomputePointerButtons() {
	buttons := 0
	for _, contact := range inp.pointerContacts {
		if contact.Down {
			buttons |= 1 << contact.Button
		}
	}
	inp.pointerButtons = buttons
}

func validatePointerID(id int) {
	if id < 0 {
		panic("InputState: pointer id must be >= 0")
	}
}

func inputApplyDeadzone(v, deadzone float64) float64 {
	if v <= deadzone {
		return 0
	}
	return inputClamp((v-deadzone)/(1.0-deadzone), 0, 1)
}

func inputClamp(v, lo, hi float64) float64 {
	if v < lo {
		return lo
	}
	if v > hi {
		return hi
	}
	return v
}

// --- binary decode helpers ---

func decodeKeyEvent(r *codec.ByteReader) string {
	nameLen := int(r.ReadByte())
	return string(r.ReadBytes(nameLen))
}

