    fail(context, error) {
        let message = this.normalizeVmPanic(`${context}: ${this.describeError(error)}`);
        const captured = this.drainCapturedErrors();
        if (captured.length > 0) {
            message += `\nRust panic: ${captured.join('\n')}`;
