package primitive3d

import "math"
import "strconv"
import "github.com/vo-lang/voplay"

const primitiveInstanceUploadBytes = 160

type Layer struct {
	kind      LayerKind
	shapes    *ShapeRegistry
	materials *MaterialPalette
	chunking  ChunkingDesc
	name      string
	nextObjectID int
	instances map[int]Instance
	order     []ObjectID
	dirty     map[int]bool
	removed   []ObjectID
	dirtyAll  bool
	built     bool
	chunks    []Chunk
	chunksDirty bool
	shapeMaterialGroups int
	shapeMaterialGroupsDirty bool
}

type Changes struct {
	All     bool
	Upserts []Instance
	Removes []ObjectID
}

func NewLayer(desc LayerDesc) *Layer {
	kind := desc.Kind
	if kind == 0 {
		kind = StaticLayer
	}
	shapes := desc.Shapes
	if shapes == nil {
		shapes = NewShapeRegistry()
	}
	materials := desc.Materials
	if materials == nil {
		materials = NewMaterialPalette()
	}
	return &Layer{
		kind: kind,
		shapes: shapes,
		materials: materials,
		chunking: desc.Chunking,
		name: desc.Name,
		nextObjectID: 1,
		instances: map[int]Instance{},
		order: []ObjectID{},
		dirty: map[int]bool{},
		chunksDirty: true,
		shapeMaterialGroupsDirty: true,
	}
}

func (l *Layer) Kind() LayerKind {
	l.ensureReady()
	return l.kind
}

func (l *Layer) Name() string {
	l.ensureReady()
	return l.name
}

func (l *Layer) Add(instance Instance) ObjectID {
	l.ensureReady()
	l.validateInstance(instance)
	id := instance.Object
	if id == 0 {
		id = ObjectID(l.nextObjectID)
		l.nextObjectID++
	} else if int(id) >= l.nextObjectID {
		l.nextObjectID = int(id) + 1
	}
	if _, exists := l.instances[int(id)]; exists {
		panic("primitive3d.Layer.Add: duplicate object id")
	}
	instance.Object = id
	l.instances[int(id)] = instance
	l.order = append(l.order, id)
	l.dirty[int(id)] = true
	l.chunksDirty = true
	l.shapeMaterialGroupsDirty = true
	return id
}

func (l *Layer) Set(id ObjectID, instance Instance) {
	l.ensureReady()
	if id == 0 {
		panic("primitive3d.Layer.Set: object id must not be zero")
	}
	if _, exists := l.instances[int(id)]; !exists {
		panic("primitive3d.Layer.Set: unknown object id")
	}
	l.validateInstance(instance)
	instance.Object = id
	l.instances[int(id)] = instance
	l.dirty[int(id)] = true
	l.chunksDirty = true
	l.shapeMaterialGroupsDirty = true
}

func (l *Layer) Remove(id ObjectID) {
	l.ensureReady()
	if id == 0 {
		panic("primitive3d.Layer.Remove: object id must not be zero")
	}
	if _, exists := l.instances[int(id)]; !exists {
		return
	}
	delete(l.instances, int(id))
	l.removeFromOrder(id)
	delete(l.dirty, int(id))
	l.removed = append(l.removed, id)
	l.chunksDirty = true
	l.shapeMaterialGroupsDirty = true
}

func (l *Layer) Clear() {
	l.ensureReady()
	for _, id := range l.order {
		if _, exists := l.instances[int(id)]; exists {
			l.removed = append(l.removed, id)
		}
	}
	l.instances = map[int]Instance{}
	l.order = []ObjectID{}
	l.dirty = map[int]bool{}
	l.dirtyAll = false
	l.chunks = nil
	l.chunksDirty = false
	l.shapeMaterialGroups = 0
	l.shapeMaterialGroupsDirty = false
}

func (l *Layer) Build() {
	l.ensureReady()
	l.rebuildChunks()
	l.built = true
	l.dirtyAll = true
	l.dirty = map[int]bool{}
}

func (l *Layer) Invalidate() {
	l.ensureReady()
	l.dirtyAll = true
	l.dirty = map[int]bool{}
}

func (l *Layer) DrainChanges() Changes {
	l.ensureReady()
	changes := Changes{Upserts: []Instance{}, Removes: []ObjectID{}}
	if !l.dirtyAll && len(l.dirty) == 0 && len(l.removed) == 0 {
		return changes
	}
	for _, id := range l.removed {
		changes.Removes = append(changes.Removes, id)
	}
	if l.dirtyAll {
		changes.All = true
		for _, id := range l.order {
			if instance, ok := l.instances[int(id)]; ok {
				changes.Upserts = append(changes.Upserts, instance)
			}
		}
	} else {
		for _, id := range l.order {
			if !l.dirty[int(id)] {
				continue
			}
			if instance, ok := l.instances[int(id)]; ok {
				changes.Upserts = append(changes.Upserts, instance)
			}
		}
	}
	l.removed = nil
	l.dirty = map[int]bool{}
	l.dirtyAll = false
	return changes
}

func (l *Layer) DrainStaticChanges() Changes {
	l.ensureReady()
	changes := Changes{Upserts: []Instance{}, Removes: []ObjectID{}}
	if !l.dirtyAll && len(l.dirty) == 0 && len(l.removed) == 0 {
		return changes
	}
	for _, id := range l.removed {
		changes.Removes = append(changes.Removes, id)
	}
	changes.All = l.dirtyAll || len(l.dirty) > 0 || len(l.removed) > 0
	l.removed = nil
	l.dirty = map[int]bool{}
	l.dirtyAll = false
	return changes
}

func (l *Layer) Instances() []Instance {
	l.ensureReady()
	instances := make([]Instance, 0, len(l.order))
	for _, id := range l.order {
		if instance, ok := l.instances[int(id)]; ok {
			instances = append(instances, instance)
		}
	}
	return instances
}

func (l *Layer) Instance(id ObjectID) (Instance, bool) {
	l.ensureReady()
	instance, ok := l.instances[int(id)]
	return instance, ok
}

func (l *Layer) Chunks() []Chunk {
	l.ensureReady()
	l.ensureChunks()
	chunks := make([]Chunk, 0, len(l.chunks))
	for _, chunk := range l.chunks {
		objects := make([]ObjectID, len(chunk.Objects))
		copy(objects, chunk.Objects)
		chunks = append(chunks, Chunk{ID: chunk.ID, Bounds: chunk.Bounds, Objects: objects})
	}
	return chunks
}

func (l *Layer) Stats() Stats {
	l.ensureReady()
	l.ensureChunks()
	total := len(l.order)
	chunkCount := len(l.chunks)
	dirtyRanges := len(l.dirty) + len(l.removed)
	if l.dirtyAll && total > 0 {
		dirtyRanges = chunkCount + len(l.removed)
	}
	groups := l.shapeMaterialGroupCount()
	return Stats{
		TotalInstances: total,
		VisibleInstances: total,
		TotalChunks: chunkCount,
		VisibleChunks: chunkCount,
		DirtyRanges: dirtyRanges,
		ShapeMaterialGroups: groups,
		DrawCalls: groups,
		UploadBytes: dirtyRanges * primitiveInstanceUploadBytes,
	}
}

func (l *Layer) Model(shape ShapeID) voplay.ModelID {
	l.ensureReady()
	return l.shapes.Model(shape)
}

func (l *Layer) ShapeRevision() int {
	l.ensureReady()
	return l.shapes.Revision()
}

func (l *Layer) ShapeEntries() []ShapeEntry {
	l.ensureReady()
	return l.shapes.Entries()
}

func (l *Layer) Material(material MaterialID) voplay.MaterialDesc {
	l.ensureReady()
	return l.materials.Desc(material)
}

func (l *Layer) MaterialRevision() int {
	l.ensureReady()
	return l.materials.Revision()
}

func (l *Layer) MaterialEntries() []MaterialEntry {
	l.ensureReady()
	return l.materials.Entries()
}

func (l *Layer) ensureReady() {
	if l == nil {
		panic("primitive3d.Layer: layer must not be nil")
	}
	if l.kind == 0 {
		l.kind = StaticLayer
	}
	if l.shapes == nil {
		l.shapes = NewShapeRegistry()
	}
	if l.materials == nil {
		l.materials = NewMaterialPalette()
	}
	if l.nextObjectID == 0 {
		l.nextObjectID = 1
	}
	if l.instances == nil {
		l.instances = map[int]Instance{}
	}
	if l.order == nil {
		l.order = []ObjectID{}
	}
	if l.dirty == nil {
		l.dirty = map[int]bool{}
	}
	if l.chunks == nil && len(l.order) > 0 {
		l.chunksDirty = true
	}
}

func (l *Layer) validateInstance(instance Instance) {
	if instance.Shape == 0 {
		panic("primitive3d.Layer: instance shape must not be zero")
	}
	if instance.Material == 0 {
		panic("primitive3d.Layer: instance material must not be zero")
	}
	l.shapes.Desc(instance.Shape)
	l.materials.Desc(instance.Material)
}

func (l *Layer) removeFromOrder(id ObjectID) {
	for i, existing := range l.order {
		if existing != id {
			continue
		}
		last := len(l.order) - 1
		l.order[i] = l.order[last]
		l.order[last] = 0
		l.order = l.order[:last]
		return
	}
}

func (l *Layer) shapeMaterialGroupCount() int {
	if !l.shapeMaterialGroupsDirty {
		return l.shapeMaterialGroups
	}
	groups := map[string]bool{}
	for _, id := range l.order {
		instance, ok := l.instances[int(id)]
		if !ok {
			continue
		}
		key := strconv.Itoa(int(instance.Shape)) + ":" + strconv.Itoa(int(instance.Material))
		groups[key] = true
	}
	l.shapeMaterialGroups = len(groups)
	l.shapeMaterialGroupsDirty = false
	return l.shapeMaterialGroups
}

func (l *Layer) ensureChunks() {
	if l.chunksDirty {
		l.rebuildChunks()
	}
}

func (l *Layer) rebuildChunks() {
	l.chunks = nil
	if len(l.order) == 0 {
		l.shapeMaterialGroups = 0
		l.shapeMaterialGroupsDirty = false
		l.chunksDirty = false
		return
	}
	cellSize := l.chunking.CellSize
	groups := map[string]bool{}
	if l.kind != StaticLayer || cellSize <= 0 {
		chunk := Chunk{ID: 1, Objects: []ObjectID{}}
		for _, id := range l.order {
			instance, ok := l.instances[int(id)]
			if !ok {
				continue
			}
			groups[shapeMaterialKey(instance)] = true
			bounds := instanceBounds(instance)
			if len(chunk.Objects) == 0 {
				chunk.Bounds = bounds
			} else {
				chunk.Bounds = mergeBounds(chunk.Bounds, bounds)
			}
			chunk.Objects = append(chunk.Objects, id)
		}
		if len(chunk.Objects) > 0 {
			l.chunks = append(l.chunks, chunk)
		}
		l.shapeMaterialGroups = len(groups)
		l.shapeMaterialGroupsDirty = false
		l.chunksDirty = false
		return
	}
	indexByKey := map[string]int{}
	for _, id := range l.order {
		instance, ok := l.instances[int(id)]
		if !ok {
			continue
		}
		groups[shapeMaterialKey(instance)] = true
		key := chunkKey(instance.Position, cellSize)
		index, exists := indexByKey[key]
		if !exists {
			index = len(l.chunks)
			indexByKey[key] = index
			l.chunks = append(l.chunks, Chunk{ID: index + 1, Objects: []ObjectID{}})
		}
		bounds := instanceBounds(instance)
		if len(l.chunks[index].Objects) == 0 {
			l.chunks[index].Bounds = bounds
		} else {
			l.chunks[index].Bounds = mergeBounds(l.chunks[index].Bounds, bounds)
		}
		l.chunks[index].Objects = append(l.chunks[index].Objects, id)
	}
	l.shapeMaterialGroups = len(groups)
	l.shapeMaterialGroupsDirty = false
	l.chunksDirty = false
}

func shapeMaterialKey(instance Instance) string {
	return strconv.Itoa(int(instance.Shape)) + ":" + strconv.Itoa(int(instance.Material))
}

func chunkKey(pos voplay.Vec3, cellSize float64) string {
	x := int(math.Floor(pos.X / cellSize))
	y := int(math.Floor(pos.Y / cellSize))
	z := int(math.Floor(pos.Z / cellSize))
	return strconv.Itoa(x) + ":" + strconv.Itoa(y) + ":" + strconv.Itoa(z)
}

func instanceBounds(instance Instance) voplay.AABB {
	scale := instance.Scale
	if scale == (voplay.Vec3{}) {
		scale = voplay.Vec3{1, 1, 1}
	}
	half := voplay.Vec3{X: math.Abs(scale.X) * 0.5, Y: math.Abs(scale.Y) * 0.5, Z: math.Abs(scale.Z) * 0.5}
	if half.X <= 0 {
		half.X = 0.5
	}
	if half.Y <= 0 {
		half.Y = 0.5
	}
	if half.Z <= 0 {
		half.Z = 0.5
	}
	return voplay.AABB{Min: instance.Position.Sub(half), Max: instance.Position.Add(half)}
}

func mergeBounds(a, b voplay.AABB) voplay.AABB {
	return voplay.AABB{
		Min: voplay.Vec3{
			X: math.Min(a.Min.X, b.Min.X),
			Y: math.Min(a.Min.Y, b.Min.Y),
			Z: math.Min(a.Min.Z, b.Min.Z),
		},
		Max: voplay.Vec3{
			X: math.Max(a.Max.X, b.Max.X),
			Y: math.Max(a.Max.Y, b.Max.Y),
			Z: math.Max(a.Max.Z, b.Max.Z),
		},
	}
}

package primitive3d

import "strconv"
import "github.com/vo-lang/voplay"

type MaterialPalette struct {
	nextID int
	revision int
	keys      map[string]MaterialID
	materials map[int]voplay.MaterialDesc
	names     map[int]string
}

func NewMaterialPalette() *MaterialPalette {
	return &MaterialPalette{
		nextID: 1,
		keys:      map[string]MaterialID{},
		materials: map[int]voplay.MaterialDesc{},
		names:     map[int]string{},
	}
}

func (p *MaterialPalette) Material(desc MaterialDesc) MaterialID {
	p.ensureReady()
	material := normalizePrimitiveMaterial(desc)
	key := materialKey(material)
	if id, ok := p.keys[key]; ok {
		return id
	}
	id := MaterialID(p.nextID)
	p.nextID++
	p.keys[key] = id
	p.materials[int(id)] = material
	p.names[int(id)] = desc.Name
	p.revision++
	return id
}

func (p *MaterialPalette) Desc(id MaterialID) voplay.MaterialDesc {
	p.ensureReady()
	material, ok := p.materials[int(id)]
	if !ok {
		panic("primitive3d.MaterialPalette.Desc: unknown material")
	}
	return material
}

func (p *MaterialPalette) Name(id MaterialID) string {
	p.ensureReady()
	return p.names[int(id)]
}

func (p *MaterialPalette) Revision() int {
	p.ensureReady()
	return p.revision
}

func (p *MaterialPalette) Entries() []MaterialEntry {
	p.ensureReady()
	entries := []MaterialEntry{}
	for id := 1; id < p.nextID; id++ {
		material, ok := p.materials[id]
		if !ok {
			continue
		}
		entries = append(entries, MaterialEntry{ID: MaterialID(id), Material: material, Name: p.names[id]})
	}
	return entries
}

func (p *MaterialPalette) ensureReady() {
	if p == nil {
		panic("primitive3d.MaterialPalette: palette must not be nil")
	}
	if p.nextID == 0 {
		p.nextID = 1
	}
	if p.keys == nil {
		p.keys = map[string]MaterialID{}
	}
	if p.materials == nil {
		p.materials = map[int]voplay.MaterialDesc{}
	}
	if p.names == nil {
		p.names = map[int]string{}
	}
}

func normalizePrimitiveMaterial(desc MaterialDesc) voplay.MaterialDesc {
	preset := desc.Preset
	if preset == 0 {
		preset = MaterialToyPlastic
	}
	base := presetMaterial(preset)
	if desc.Base != (voplay.MaterialDesc{}) {
		base = mergeMaterial(base, desc.Base)
	}
	return voplay.NormalizeMaterial(base)
}

func mergeMaterial(base, override voplay.MaterialDesc) voplay.MaterialDesc {
	out := base
	if override.ID != 0 {
		out.ID = override.ID
	}
	if override.BaseColor != (voplay.Color{}) {
		out.BaseColor = override.BaseColor
	}
	if override.Albedo != 0 {
		out.Albedo = override.Albedo
	}
	if override.Normal != 0 {
		out.Normal = override.Normal
	}
	if override.MetallicRoughness != 0 {
		out.MetallicRoughness = override.MetallicRoughness
	}
	if override.Emissive != 0 {
		out.Emissive = override.Emissive
	}
	if override.EmissiveColor != (voplay.Color{}) {
		out.EmissiveColor = override.EmissiveColor
	}
	if override.Roughness > 0 {
		out.Roughness = override.Roughness
	}
	if override.Metallic > 0 {
		out.Metallic = override.Metallic
	}
	if override.NormalScale > 0 {
		out.NormalScale = override.NormalScale
	}
	if override.UVScale > 0 {
		out.UVScale = override.UVScale
	}
	if override.ToonRamp != 0 {
		out.ToonRamp = override.ToonRamp
	}
	if override.ShadingMode != 0 {
		out.ShadingMode = override.ShadingMode
	}
	if override.WrapMode != 0 {
		out.WrapMode = override.WrapMode
	}
	if override.FilterMode != 0 {
		out.FilterMode = override.FilterMode
	}
	return out
}

func presetMaterial(preset MaterialPreset) voplay.MaterialDesc {
	switch preset {
	case MaterialToyPlastic:
		return voplay.MaterialDesc{BaseColor: voplay.Color{R: 0.95, G: 0.18, B: 0.12, A: 1}, Roughness: 0.38, Metallic: 0, UVScale: 1}
	case MaterialRubber:
		return voplay.MaterialDesc{BaseColor: voplay.Color{R: 0.025, G: 0.025, B: 0.025, A: 1}, Roughness: 0.88, Metallic: 0, UVScale: 1}
	case MaterialRoadAsphalt:
		return voplay.MaterialDesc{BaseColor: voplay.Color{R: 0.08, G: 0.085, B: 0.09, A: 1}, Roughness: 0.78, Metallic: 0, UVScale: 3}
	case MaterialGrass:
		return voplay.MaterialDesc{BaseColor: voplay.Color{R: 0.33, G: 0.72, B: 0.18, A: 1}, Roughness: 0.7, Metallic: 0, UVScale: 2}
	case MaterialStone:
		return voplay.MaterialDesc{BaseColor: voplay.Color{R: 0.58, G: 0.55, B: 0.5, A: 1}, Roughness: 0.82, Metallic: 0, UVScale: 1.6}
	case MaterialWater:
		return voplay.MaterialDesc{BaseColor: voplay.Color{R: 0.18, G: 0.55, B: 0.95, A: 0.72}, Roughness: 0.12, Metallic: 0, UVScale: 1}
	case MaterialGlow:
		return voplay.MaterialDesc{BaseColor: voplay.Color{R: 0.18, G: 0.58, B: 1, A: 1}, EmissiveColor: voplay.Color{R: 0.18, G: 0.58, B: 1, A: 1}, Roughness: 0.28, Metallic: 0, UVScale: 1}
	case MaterialWood:
		return voplay.MaterialDesc{BaseColor: voplay.Color{R: 0.58, G: 0.34, B: 0.16, A: 1}, Roughness: 0.62, Metallic: 0, UVScale: 1.4}
	}
	panic("primitive3d.MaterialPalette.Material: unknown material preset")
}

func materialKey(m voplay.MaterialDesc) string {
	return strconv.Itoa(int(m.ID)) + ":" +
		colorKey(m.BaseColor) + ":" +
		strconv.Itoa(int(m.Albedo)) + ":" +
		strconv.Itoa(int(m.Normal)) + ":" +
		strconv.Itoa(int(m.MetallicRoughness)) + ":" +
		strconv.Itoa(int(m.Emissive)) + ":" +
		colorKey(m.EmissiveColor) + ":" +
		floatKey(m.Roughness) + ":" +
		floatKey(m.Metallic) + ":" +
		floatKey(m.NormalScale) + ":" +
		floatKey(m.UVScale) + ":" +
		strconv.Itoa(int(m.ToonRamp)) + ":" +
		strconv.Itoa(m.ShadingMode) + ":" +
		strconv.Itoa(m.WrapMode) + ":" +
		strconv.Itoa(m.FilterMode)
}

func colorKey(c voplay.Color) string {
	return floatKey(c.R) + "," + floatKey(c.G) + "," + floatKey(c.B) + "," + floatKey(c.A)
}

package primitive3d

import "strconv"
import "github.com/vo-lang/voplay"

const (
	defaultSegments = 16
	defaultPlaneSize = 1.0
	defaultSubdivs = 1
	defaultCapsuleHalfHeight = 0.5
	defaultCapsuleRadius = 0.5
)

type ShapeRegistry struct {
	nextID int
	revision int
	keys   map[string]ShapeID
	descs  map[int]ShapeDesc
	models map[int]voplay.ModelID
	order  []ShapeID
}

func NewShapeRegistry() *ShapeRegistry {
	return &ShapeRegistry{
		nextID: 1,
		keys:   map[string]ShapeID{},
		descs:  map[int]ShapeDesc{},
		models: map[int]voplay.ModelID{},
		order:  []ShapeID{},
	}
}

func (r *ShapeRegistry) Shape(desc ShapeDesc) ShapeID {
	r.ensureReady()
	desc = normalizeShapeDesc(desc)
	key := shapeKey(desc)
	if id, ok := r.keys[key]; ok {
		return id
	}
	id := ShapeID(r.nextID)
	r.nextID++
	r.keys[key] = id
	r.descs[int(id)] = desc
	r.order = append(r.order, id)
	r.revision++
	return id
}

func (r *ShapeRegistry) Desc(id ShapeID) ShapeDesc {
	r.ensureReady()
	desc, ok := r.descs[int(id)]
	if !ok {
		panic("primitive3d.ShapeRegistry.Desc: unknown shape")
	}
	return desc
}

func (r *ShapeRegistry) Model(id ShapeID) voplay.ModelID {
	r.ensureReady()
	if model, ok := r.models[int(id)]; ok {
		return model
	}
	desc := r.Desc(id)
	model := createShapeModel(desc)
	r.models[int(id)] = model
	return model
}

func (r *ShapeRegistry) Revision() int {
	r.ensureReady()
	return r.revision
}

func (r *ShapeRegistry) Entries() []ShapeEntry {
	r.ensureReady()
	entries := []ShapeEntry{}
	for _, id := range r.order {
		entries = append(entries, ShapeEntry{ID: id, Model: r.Model(id)})
	}
	return entries
}

func (r *ShapeRegistry) ensureReady() {
	if r == nil {
		panic("primitive3d.ShapeRegistry: registry must not be nil")
	}
	if r.nextID == 0 {
		r.nextID = 1
	}
	if r.keys == nil {
		r.keys = map[string]ShapeID{}
	}
	if r.descs == nil {
		r.descs = map[int]ShapeDesc{}
	}
	if r.models == nil {
		r.models = map[int]voplay.ModelID{}
	}
	if r.order == nil {
		r.order = []ShapeID{}
	}
}

func normalizeShapeDesc(desc ShapeDesc) ShapeDesc {
	if desc.Kind == 0 {
		desc.Kind = ShapeRoundedBox
	}
	desc.Segments = normalizePositiveInt(desc.Segments, defaultSegments)
	desc.Radius = normalizeNonNegativeFloat(desc.Radius)
	desc.BevelRadius = normalizeNonNegativeFloat(desc.BevelRadius)
	desc.Width = normalizePositiveFloat(desc.Width, defaultPlaneSize)
	desc.Height = normalizePositiveFloat(desc.Height, defaultCapsuleHalfHeight*2)
	desc.Depth = normalizePositiveFloat(desc.Depth, defaultPlaneSize)
	desc.SubX = normalizePositiveInt(desc.SubX, defaultSubdivs)
	desc.SubZ = normalizePositiveInt(desc.SubZ, defaultSubdivs)
	return desc
}

func createShapeModel(desc ShapeDesc) voplay.ModelID {
	switch desc.Kind {
	case ShapeRoundedBox:
		bevelRadius := desc.BevelRadius
		if bevelRadius <= 0 {
			bevelRadius = 0.08
		}
		return voplay.CreateRoundedBoxMesh(bevelRadius, desc.Segments)
	case ShapeBox:
		return voplay.CreateCubeMesh()
	case ShapeSphere:
		return voplay.CreateSphereMesh(desc.Segments)
	case ShapeCylinder:
		return voplay.CreateCylinderMesh(desc.Segments)
	case ShapeCone:
		return voplay.CreateConeMesh(desc.Segments)
	case ShapeCapsule:
		radius := desc.Radius
		if radius <= 0 {
			radius = defaultCapsuleRadius
		}
		halfHeight := desc.Height * 0.5
		if halfHeight <= 0 {
			halfHeight = defaultCapsuleHalfHeight
		}
		return voplay.CreateCapsuleMesh(desc.Segments, halfHeight, radius)
	case ShapePlane:
		return voplay.CreatePlaneMesh(desc.Width, desc.Depth, desc.SubX, desc.SubZ)
	case ShapeWedge:
		return voplay.CreateWedgeMesh()
	}
	panic("primitive3d.ShapeRegistry.Model: unknown shape kind")
}

func shapeKey(desc ShapeDesc) string {
	return strconv.Itoa(int(desc.Kind)) + ":" +
		strconv.Itoa(desc.Segments) + ":" +
		floatKey(desc.Radius) + ":" +
		floatKey(desc.BevelRadius) + ":" +
		floatKey(desc.Width) + ":" +
		floatKey(desc.Height) + ":" +
		floatKey(desc.Depth) + ":" +
		strconv.Itoa(desc.SubX) + ":" +
		strconv.Itoa(desc.SubZ)
}

func normalizePositiveInt(value, fallback int) int {
	if value <= 0 {
		return fallback
	}
	return value
}

func normalizePositiveFloat(value, fallback float64) float64 {
	if value <= 0 {
		return fallback
	}
	return value
}

func normalizeNonNegativeFloat(value float64) float64 {
	if value < 0 {
		return 0
	}
	return value
}

func floatKey(value float64) string {
	return strconv.FormatFloat(value, 'g', -1, 64)
}

package primitive3d

import "math"
import "github.com/vo-lang/voplay"

type StressConfig struct {
	Count            int
	ShapeVariants    int
	MaterialVariants int
	Columns          int
	Spacing          float64
	ChunkCellSize    float64
}

type StressFixture struct {
	Shapes      *ShapeRegistry
	Materials   *MaterialPalette
	Layer       *Layer
	ShapeIDs    []ShapeID
	MaterialIDs []MaterialID
	Bounds      voplay.AABB
}

func DefaultStressConfig() StressConfig {
	return StressConfig{
		Count:            10000,
		ShapeVariants:    8,
		MaterialVariants: 16,
		Spacing:          2.4,
		ChunkCellSize:    32,
	}
}

func NewStressFixture(config StressConfig) *StressFixture {
	config = normalizeStressConfig(config)
	shapes := NewShapeRegistry()
	materials := NewMaterialPalette()
	shapeIDs := stressShapeIDs(shapes, config.ShapeVariants)
	materialIDs := stressMaterialIDs(materials, config.MaterialVariants)
	layer := NewLayer(LayerDesc{
		Kind: StaticLayer,
		Shapes: shapes,
		Materials: materials,
		Chunking: ChunkingDesc{CellSize: config.ChunkCellSize},
		Name: "primitive_stress",
	})
	rows := int(math.Ceil(float64(config.Count) / float64(config.Columns)))
	originX := float64(config.Columns - 1) * config.Spacing * 0.5
	originZ := float64(rows - 1) * config.Spacing * 0.5
	for i := 0; i < config.Count; i++ {
		col := i % config.Columns
		row := i / config.Columns
		layer.Add(Instance{
			Shape: shapeIDs[i % len(shapeIDs)],
			Material: materialIDs[(i / len(shapeIDs)) % len(materialIDs)],
			Position: voplay.Vec3{
				X: float64(col)*config.Spacing - originX,
				Y: stressHeight(i),
				Z: float64(row)*config.Spacing - originZ,
			},
			Rotation: voplay.QuatFromEuler(0, float64(i % 360) * math.Pi / 180.0, 0),
			Scale: stressScale(i),
		})
	}
	layer.Build()
	return &StressFixture{
		Shapes: shapes,
		Materials: materials,
		Layer: layer,
		ShapeIDs: shapeIDs,
		MaterialIDs: materialIDs,
		Bounds: stressLayerBounds(layer),
	}
}

func normalizeStressConfig(config StressConfig) StressConfig {
	if config.Count <= 0 {
		config.Count = 10000
	}
	if config.ShapeVariants <= 0 {
		config.ShapeVariants = 8
	}
	if config.ShapeVariants > 8 {
		config.ShapeVariants = 8
	}
	if config.MaterialVariants <= 0 {
		config.MaterialVariants = 16
	}
	if config.Spacing <= 0 {
		config.Spacing = 2.4
	}
	if config.ChunkCellSize <= 0 {
		config.ChunkCellSize = 32
	}
	if config.Columns <= 0 {
		config.Columns = int(math.Ceil(math.Sqrt(float64(config.Count))))
	}
	if config.Columns <= 0 {
		config.Columns = 1
	}
	return config
}

func stressShapeIDs(registry *ShapeRegistry, count int) []ShapeID {
	descs := []ShapeDesc{
		{Kind: ShapeRoundedBox, BevelRadius: 0.09, Segments: 10},
		{Kind: ShapeBox},
		{Kind: ShapeSphere, Segments: 12},
		{Kind: ShapeCylinder, Segments: 12},
		{Kind: ShapeCone, Segments: 12},
		{Kind: ShapeCapsule, Segments: 10, Height: 1.2, Radius: 0.45},
		{Kind: ShapePlane, Width: 1, Depth: 1, SubX: 1, SubZ: 1},
		{Kind: ShapeWedge},
	}
	ids := []ShapeID{}
	for i := 0; i < count && i < len(descs); i++ {
		ids = append(ids, registry.Shape(descs[i]))
	}
	return ids
}

func stressMaterialIDs(palette *MaterialPalette, count int) []MaterialID {
	presets := []MaterialPreset{
		MaterialToyPlastic,
		MaterialRubber,
		MaterialRoadAsphalt,
		MaterialGrass,
		MaterialStone,
		MaterialWater,
		MaterialGlow,
		MaterialWood,
	}
	colors := []voplay.Color{
		voplay.RGB(0.96, 0.20, 0.13),
		voplay.RGB(0.10, 0.18, 0.95),
		voplay.RGB(1.00, 0.66, 0.10),
		voplay.RGB(0.18, 0.72, 0.26),
		voplay.RGB(0.98, 0.96, 0.88),
		voplay.RGB(0.52, 0.56, 0.64),
		voplay.RGB(0.22, 0.76, 0.96),
		voplay.RGB(0.72, 0.38, 0.16),
		voplay.RGB(0.86, 0.10, 0.36),
		voplay.RGB(0.45, 0.24, 0.82),
		voplay.RGB(0.06, 0.11, 0.16),
		voplay.RGB(0.74, 0.85, 0.38),
		voplay.RGB(0.18, 0.58, 0.52),
		voplay.RGB(0.96, 0.44, 0.18),
		voplay.RGB(0.80, 0.82, 0.88),
		voplay.RGB(0.30, 0.20, 0.14),
	}
	ids := []MaterialID{}
	for i := 0; i < count; i++ {
		preset := presets[i % len(presets)]
		color := colors[i % len(colors)]
		ids = append(ids, palette.Material(MaterialDesc{
			Preset: preset,
			Base: voplay.MaterialDesc{BaseColor: color},
		}))
	}
	return ids
}

func stressHeight(i int) float64 {
	return 0.35 + float64((i / 97) % 5) * 0.035
}

func stressScale(i int) voplay.Vec3 {
	s := 0.82 + float64(i % 7) * 0.035
	return voplay.Vec3{X: s, Y: s, Z: s}
}

func stressLayerBounds(layer *Layer) voplay.AABB {
	chunks := layer.Chunks()
	if len(chunks) == 0 {
		return voplay.AABB{}
	}
	bounds := chunks[0].Bounds
	for i := 1; i < len(chunks); i++ {
		bounds = mergeBounds(bounds, chunks[i].Bounds)
	}
	return bounds
}

// Render worker: runs on the render island in split-island mode.
// Owns the GPU surface and frame clock. Drives the game loop by sending
// frame requests to the logic island and submitting the returned draw commands.
package voplay

import (
	"strconv"
	"time"
)

const (
	renderSlowFrameCacheSize = 8
	renderSlowLogCooldownFrames = 120
)

type renderSlowFrame struct {
	Frame int
	Reason string
	LoopMs float64
	SubmitMs float64
	DrawBytes int
}

type renderSlowLogCache struct {
	next int
	count int
	cooldown int
	frames [8]renderSlowFrame
}

func (c *renderSlowLogCache) record(frame int, reason string, loopMs float64, submitMs float64, drawBytes int) {
	if c.cooldown > 0 {
		c.cooldown--
	}
	slow := renderSlowFrame{Frame: frame, Reason: reason, LoopMs: loopMs, SubmitMs: submitMs, DrawBytes: drawBytes}
	c.frames[c.next] = slow
	c.next = (c.next + 1) % renderSlowFrameCacheSize
	if c.count < renderSlowFrameCacheSize {
		c.count++
	}
	severe := slow.LoopMs >= 50 || slow.SubmitMs >= 30
	if c.cooldown > 0 && !severe {
		return
	}
	if !severe {
		c.cooldown = renderSlowLogCooldownFrames
	}
	println("voplay render slow frame frame=" + strconv.Itoa(slow.Frame) + " reason=" + slow.Reason + " loopMs=" + formatRenderSlowMs(slow.LoopMs) + " submitMs=" + formatRenderSlowMs(slow.SubmitMs) + " drawBytes=" + strconv.Itoa(slow.DrawBytes) + " cached=" + strconv.Itoa(c.count))
}

// renderWorkerPorts holds the port endpoints for the render worker.
type renderWorkerPorts struct {
	frameReq   port []byte // send frame requests (input snapshots) to logic island
	frameReply port []byte // recv draw command replies from logic island
	resReq     port []byte // recv resource requests from logic island
	resResp    port []byte // send resource responses to logic island
}

// runRenderWorker is the render island's main loop.
// The render island owns the frame clock: each iteration samples input,
// sends a frame request to the logic island, waits for the draw reply,
// and submits to the GPU. On native, AutoVsync present naturally paces
// the loop to the display refresh rate.
func runRenderWorker(canvasRef string, config renderWorkerConfig, ports renderWorkerPorts) {
	// Phase 1: Init surface (may be async on WASM).
	// Normal games pace on the display pulse. Only explicit uncapped runs opt
	// out of vsync; a target frame rate is a budget/cap, not permission to use
	// timer-driven presentation.
	initSurface(canvasRef, config.UncappedFrameRate)?

	// Wait for renderer async init without hammering the browser main thread.
	waitFrames := 0
	for {
		ready, err := isRendererReady()
		if err != nil {
			panic("voplay renderer init failed: " + err.Error())
		}
		if ready {
			break
		}
		waitFrames++
		if waitFrames > 600 {
			panic("voplay renderer init timed out")
		}
		waitDisplayPulse()
	}

	go func() {
		serviceResourceRequestsLoop(ports.resReq, ports.resResp)
	}()

	// Phase 2: Signal ready by sending an empty frame request.
	// The logic island waits for this before initializing the game.
	ports.frameReq <- []byte{}

	// Phase 3: Main render loop — render island drives the frame clock.
	// Each iteration: sample input → request → wait reply → submit → present.
	// Present with AutoVsync blocks until the next display refresh,
	// making the GPU vsync the natural frame pacer.
	frameInterval := targetFrameInterval(config.TargetFrameRate)
	lastFrameTime := time.Now()
	frameSeq := 0
	lastLoopTime := time.Now()
	slowLog := &renderSlowLogCache{}
	for {
		// On wasm, normal games follow requestAnimationFrame. If a target frame
		// rate is below the display refresh rate, skip pulses instead of using
		// setTimeout; timer pacing causes visible long-tail stutters in browsers.
		if config.UncappedFrameRate {
			// Deliberately unpaced.
		} else {
			lastFrameTime = waitPacedDisplayPulse(lastFrameTime, frameInterval)
		}
		frameSeq++
		loopNow := time.Now()
		loopMs := float64(loopNow.Sub(lastLoopTime).Nanoseconds()) / 1e6
		lastLoopTime = loopNow
		if loopMs >= 50 {
			slowLog.record(frameSeq, "loop", loopMs, 0, 0)
		}

		// Sample latest input from the host (keyboard, pointer, scroll).
		inputBytes := pollInput()

		// Send frame request carrying the input snapshot.
		ports.frameReq <- inputBytes

		// Block until logic island replies with draw commands.
		drawCmds, ok := <-ports.frameReply
		if !ok {
			return
		}

		// Submit draw commands to GPU and present.
		if len(drawCmds) > 0 {
			submitStart := time.Now()
			submitFrame(drawCmds)?
			submitMs := float64(time.Now().Sub(submitStart).Nanoseconds()) / 1e6
			if submitMs >= 16 {
				slowLog.record(frameSeq, "submit", loopMs, submitMs, len(drawCmds))
			}
		}
	}
}

func formatRenderSlowMs(value float64) string {
	return strconv.FormatFloat(value, 'f', 2, 64) + "ms"
}

func targetFrameInterval(fps int) time.Duration {
	if fps <= 0 {
		return 0
	}
	if fps > 1000 {
		fps = 1000
	}
	return time.Duration(int64(1000000000) / int64(fps))
}

func waitPacedDisplayPulse(lastFrameTime time.Time, interval time.Duration) time.Time {
	for {
		waitDisplayPulse()
		now := time.Now()
		if interval <= 0 {
			return now
		}
		// Browser rAF timestamps jitter by fractions of a millisecond. A small
		// tolerance prevents a 120Hz display from accidentally skipping every
		// other pulse because a frame arrived slightly early.
		if now.Sub(lastFrameTime) + time.Millisecond >= interval {
			return now
		}
	}
}

func serviceResourceRequestsLoop(reqPort, respPort port []byte) {
	for {
		req, ok := <-reqPort
		if !ok {
			return
		}
		resp := handleResourceRequest(req)
		respPort <- resp
	}
}


// handleResourceRequest dispatches a single resource request and returns the response.
func handleResourceRequest(req []byte) []byte {
	if len(req) == 0 {
		return encodeResError("empty request")
	}
	tag := req[0]
	payload := req[1:]
	switch tag {
	case resTagLoadTexture:
		return handleLoadTexture(payload)
	case resTagLoadTextureBytes:
		return handleLoadTextureBytes(payload)
	case resTagFreeTexture:
		return handleFreeTexture(payload)
	case resTagLoadFont:
		return handleLoadFont(payload)
	case resTagLoadFontBytes:
		return handleLoadFontBytes(payload)
	case resTagFreeFont:
		return handleFreeFont(payload)
	case resTagMeasureText:
		return handleMeasureText(payload)
	case resTagLoadModel:
		return handleLoadModel(payload)
	case resTagLoadModelBytes:
		return handleLoadModelBytes(payload)
	case resTagFreeModel:
		return handleFreeModel(payload)
	case resTagModelBounds:
		return handleModelBounds(payload)
	case resTagModelMeshData:
		return handleModelMeshData(payload)
	case resTagLoadCubemap:
		return handleLoadCubemap(payload)
	case resTagLoadCubemapBytes:
		return handleLoadCubemapBytes(payload)
	case resTagFreeCubemap:
		return handleFreeCubemap(payload)
	case resTagCreatePlaneMesh:
		return handleCreatePlaneMesh(payload)
	case resTagCreateCubeMesh:
		return handleCreateCubeMesh(payload)
	case resTagCreateRoundedBoxMesh:
		return handleCreateRoundedBoxMesh(payload)
	case resTagCreateSphereMesh:
		return handleCreateSphereMesh(payload)
	case resTagCreateCylinderMesh:
		return handleCreateCylinderMesh(payload)
	case resTagCreateConeMesh:
		return handleCreateConeMesh(payload)
	case resTagCreateWedgeMesh:
		return handleCreateWedgeMesh(payload)
	case resTagCreateCapsuleMesh:
		return handleCreateCapsuleMesh(payload)
	case resTagAnimationInit:
		return handleAnimationInit(payload)
	case resTagAnimationDestroy:
		return handleAnimationDestroy(payload)
	case resTagAnimationPlay:
		return handleAnimationPlay(payload)
	case resTagAnimationStop:
		return handleAnimationStop(payload)
	case resTagAnimationCrossfade:
		return handleAnimationCrossfade(payload)
	case resTagAnimationSetSpeed:
		return handleAnimationSetSpeed(payload)
	case resTagAnimationRemoveTarget:
		return handleAnimationRemoveTarget(payload)
	case resTagAnimationTick:
		return handleAnimationTick(payload)
	case resTagAnimationProgress:
		return handleAnimationProgress(payload)
	case resTagAnimationModelInfo:
		return handleAnimationModelInfo(payload)
	default:
		return encodeResError("unknown resource tag")
	}
}

// Resource proxy: protocol tags, request/response encoding, and proxy
// AssetLoaders for the logic island in split-island mode.
//
// In split mode, resource externs (loadTexture, loadModel, etc.) live on the
// render island. The logic island uses proxy loaders that encode requests,
// send them to the render island via resPort, and block until the reply arrives.
package voplay

import "github.com/vo-lang/voplay/codec"
import "github.com/vo-lang/vogui"

// --- Resource command tags ---

const (
	resTagLoadTexture      byte = 1
	resTagLoadTextureBytes byte = 2
	resTagFreeTexture      byte = 3
	resTagLoadFont         byte = 4
	resTagLoadFontBytes    byte = 5
	resTagFreeFont         byte = 6
	resTagMeasureText      byte = 7
	resTagLoadModel        byte = 8
	resTagLoadModelBytes   byte = 9
	resTagFreeModel        byte = 10
	resTagModelBounds      byte = 11
	resTagLoadCubemap      byte = 12
	resTagLoadCubemapBytes byte = 13
	resTagFreeCubemap      byte = 14
	resTagCreatePlaneMesh  byte = 15
	resTagCreateCubeMesh   byte = 16
	resTagCreateSphereMesh byte = 17
	resTagCreateCylinderMesh byte = 18
	resTagCreateCapsuleMesh  byte = 19
	resTagModelMeshData      byte = 20
	resTagAnimationInit      byte = 21
	resTagAnimationDestroy   byte = 22
	resTagAnimationPlay      byte = 23
	resTagAnimationStop      byte = 24
	resTagAnimationCrossfade byte = 25
	resTagAnimationSetSpeed  byte = 26
	resTagAnimationRemoveTarget byte = 27
	resTagAnimationTick      byte = 28
	resTagAnimationProgress  byte = 29
	resTagAnimationModelInfo byte = 30
	resTagCreateRoundedBoxMesh byte = 31
	resTagCreateConeMesh byte = 32
	resTagCreateWedgeMesh byte = 33

	resRespOK    byte = 0
	resRespError byte = 1
)

// --- Request encoding (logic island side) ---

func encodeResString(tag byte, s string) []byte {
	w := codec.NewByteWriter(1 + 2 + len(s))
	w.WriteByte(tag)
	w.WriteString(s)
	return w.Bytes()
}

func encodeResBytes(tag byte, data []byte) []byte {
	n := len(data)
	out := make([]byte, 0, 1+4+n)
	out = append(out, tag)
	out = append(out, byte(n), byte(n>>8), byte(n>>16), byte(n>>24))
	out = append(out, data...)
	return out
}

func encodeResU32(tag byte, id int) []byte {
	w := codec.NewByteWriter(5)
	w.WriteByte(tag)
	w.WriteU32(id)
	return w.Bytes()
}

func encodeResU32x2(tag byte, a, b int) []byte {
	w := codec.NewByteWriter(9)
	w.WriteByte(tag)
	w.WriteU32(a)
	w.WriteU32(b)
	return w.Bytes()
}

func encodeResU32x3(tag byte, a, b, c int) []byte {
	w := codec.NewByteWriter(13)
	w.WriteByte(tag)
	w.WriteU32(a)
	w.WriteU32(b)
	w.WriteU32(c)
	return w.Bytes()
}

func encodeResU32x3F64(tag byte, a, b, c int, value float64) []byte {
	w := codec.NewByteWriter(21)
	w.WriteByte(tag)
	w.WriteU32(a)
	w.WriteU32(b)
	w.WriteU32(c)
	w.WriteF64(value)
	return w.Bytes()
}

func encodeResU32x2F64(tag byte, a, b int, value float64) []byte {
	w := codec.NewByteWriter(17)
	w.WriteByte(tag)
	w.WriteU32(a)
	w.WriteU32(b)
	w.WriteF64(value)
	return w.Bytes()
}

func encodeResU32x3BoolF64(tag byte, a, b, c int, flag bool, value float64) []byte {
	w := codec.NewByteWriter(22)
	w.WriteByte(tag)
	w.WriteU32(a)
	w.WriteU32(b)
	w.WriteU32(c)
	w.WriteBool(flag)
	w.WriteF64(value)
	return w.Bytes()
}

func encodeResTag(tag byte) []byte {
	return []byte{tag}
}

func encodeResMeasureText(fontID int, text string, size float64) []byte {
	w := codec.NewByteWriter(1 + 4 + 2 + len(text) + 8)
	w.WriteByte(resTagMeasureText)
	w.WriteU32(fontID)
	w.WriteString(text)
	w.WriteF64(size)
	return w.Bytes()
}

func encodeResCubemap(paths [6]string) []byte {
	total := 1
	for i := 0; i < 6; i++ {
		total += 2 + len(paths[i])
	}
	w := codec.NewByteWriter(total)
	w.WriteByte(resTagLoadCubemap)
	for i := 0; i < 6; i++ {
		w.WriteString(paths[i])
	}
	return w.Bytes()
}

func encodeResCubemapBytes(faces [6][]byte) []byte {
	total := 1
	for i := 0; i < 6; i++ {
		total += 4 + len(faces[i])
	}
	out := make([]byte, 0, total)
	out = append(out, resTagLoadCubemapBytes)
	for i := 0; i < 6; i++ {
		n := len(faces[i])
		out = append(out, byte(n), byte(n>>8), byte(n>>16), byte(n>>24))
		out = append(out, faces[i]...)
	}
	return out
}

func encodeResPlaneMesh(width, depth float64, subX, subZ int) []byte {
	w := codec.NewByteWriter(1 + 8 + 8 + 4 + 4)
	w.WriteByte(resTagCreatePlaneMesh)
	w.WriteF64(width)
	w.WriteF64(depth)
	w.WriteU32(subX)
	w.WriteU32(subZ)
	return w.Bytes()
}

func encodeResRoundedBoxMesh(bevelRadius float64, segments int) []byte {
	w := codec.NewByteWriter(1 + 8 + 4)
	w.WriteByte(resTagCreateRoundedBoxMesh)
	w.WriteF64(bevelRadius)
	w.WriteU32(segments)
	return w.Bytes()
}

func encodeResCapsuleMesh(segments int, halfHeight, radius float64) []byte {
	w := codec.NewByteWriter(1 + 4 + 8 + 8)
	w.WriteByte(resTagCreateCapsuleMesh)
	w.WriteU32(segments)
	w.WriteF64(halfHeight)
	w.WriteF64(radius)
	return w.Bytes()
}

func encodeResAnimationTick(worldID int, dt float64, entityModelMap []byte) []byte {
	w := codec.NewByteWriter(1 + 4 + 8 + 4 + len(entityModelMap))
	w.WriteByte(resTagAnimationTick)
	w.WriteU32(worldID)
	w.WriteF64(dt)
	w.WriteU32(len(entityModelMap))
	w.WriteRawBytes(entityModelMap)
	return w.Bytes()
}

// --- Response encoding (render island side) ---

func encodeResOKU32(id int) []byte {
	w := codec.NewByteWriter(5)
	w.WriteByte(resRespOK)
	w.WriteU32(id)
	return w.Bytes()
}

func encodeResOKUnit() []byte {
	return []byte{resRespOK}
}

func encodeResOKBytes(data []byte) []byte {
	n := len(data)
	out := make([]byte, 0, 1+4+n)
	out = append(out, resRespOK)
	out = append(out, byte(n), byte(n>>8), byte(n>>16), byte(n>>24))
	out = append(out, data...)
	return out
}

func encodeResOKF64(value float64) []byte {
	w := codec.NewByteWriter(1 + 8)
	w.WriteByte(resRespOK)
	w.WriteF64(value)
	return w.Bytes()
}

func encodeResError(msg string) []byte {
	w := codec.NewByteWriter(1 + 2 + len(msg))
	w.WriteByte(resRespError)
	w.WriteString(msg)
	return w.Bytes()
}

func encodeResOKMeasureText(width, height float64) []byte {
	w := codec.NewByteWriter(1 + 16)
	w.WriteByte(resRespOK)
	w.WriteF64(width)
	w.WriteF64(height)
	return w.Bytes()
}

func encodeResOKModelBounds(minX, minY, minZ, maxX, maxY, maxZ float64, ok bool) []byte {
	w := codec.NewByteWriter(1 + 1 + 48)
	w.WriteByte(resRespOK)
	w.WriteBool(ok)
	w.WriteF64(minX)
	w.WriteF64(minY)
	w.WriteF64(minZ)
	w.WriteF64(maxX)
	w.WriteF64(maxY)
	w.WriteF64(maxZ)
	return w.Bytes()
}

// --- Response decoding (logic island side) ---

func decodeResU32(resp []byte) (int, error) {
	if resp[0] == resRespError {
		return 0, decodeResErrorMsg(resp)
	}
	r := codec.NewByteReader(resp[1:])
	return r.ReadU32(), nil
}

func decodeResUnit(resp []byte) error {
	if resp[0] == resRespError {
		return decodeResErrorMsg(resp)
	}
	return nil
}

func decodeResBytes(resp []byte) []byte {
	if resp[0] == resRespError {
		panic("split-island: bytes resource failed: " + decodeResErrorMsg(resp).Error())
	}
	r := codec.NewByteReader(resp[1:])
	n := r.ReadU32()
	data := make([]byte, n)
	copy(data, r.ReadBytes(n))
	return data
}

func decodeResMeasureText(resp []byte) (float64, float64) {
	if resp[0] == resRespError {
		panic("split-island: measureText failed: " + string(resp[3:]))
	}
	r := codec.NewByteReader(resp[1:])
	return r.ReadF64(), r.ReadF64()
}

func decodeResF64(resp []byte) float64 {
	if resp[0] == resRespError {
		panic("split-island: numeric resource failed: " + decodeResErrorMsg(resp).Error())
	}
	r := codec.NewByteReader(resp[1:])
	return r.ReadF64()
}

func decodeResModelBounds(resp []byte) (float64, float64, float64, float64, float64, float64, bool) {
	if resp[0] == resRespError {
		return 0, 0, 0, 0, 0, 0, false
	}
	r := codec.NewByteReader(resp[1:])
	ok := r.ReadByte() != 0
	return r.ReadF64(), r.ReadF64(), r.ReadF64(), r.ReadF64(), r.ReadF64(), r.ReadF64(), ok
}

type resError struct {
	msg string
}

func (e *resError) Error() string {
	return e.msg
}

func decodeResErrorMsg(resp []byte) error {
	r := codec.NewByteReader(resp[1:])
	msgLen := r.ReadU16()
	msg := string(r.ReadBytes(msgLen))
	return &resError{msg: msg}
}

