func handleLoadCubemap(payload []byte) []byte {
	r := codec.NewByteReader(payload)
	paths := [6]string{}
	for i := 0; i < 6; i++ {
		pathLen := r.ReadU16()
		paths[i] = string(r.ReadBytes(pathLen))
	}
	id, err := loadCubemap(paths[0], paths[1], paths[2], paths[3], paths[4], paths[5])
	if err != nil {
		return encodeResError(err.Error())
	}
	return encodeResOKU32(id)
}

func handleLoadCubemapBytes(payload []byte) []byte {
	faces := [6][]byte{}
	pos := 0
	for i := 0; i < 6; i++ {
		n := int(payload[pos]) | int(payload[pos+1])<<8 | int(payload[pos+2])<<16 | int(payload[pos+3])<<24
		pos += 4
		faces[i] = make([]byte, n)
		copy(faces[i], payload[pos:pos+n])
		pos += n
	}
	id, err := loadCubemapBytes(faces[0], faces[1], faces[2], faces[3], faces[4], faces[5])
	if err != nil {
		return encodeResError(err.Error())
	}
	return encodeResOKU32(id)
}

func handleFreeCubemap(payload []byte) []byte {
	r := codec.NewByteReader(payload)
	id := r.ReadU32()
	freeCubemap(id)
	return encodeResOKUnit()
}

func decodeBytesPayload(payload []byte) []byte {
	n := int(payload[0]) | int(payload[1])<<8 | int(payload[2])<<16 | int(payload[3])<<24
	data := make([]byte, n)
	copy(data, payload[4:4+n])
	return data
}

// --- Proxy: logic island sends requests and blocks for reply ---

// resProxyRoundTrip sends a request to the render island and blocks until
// the response arrives. This is the core mechanism for resource proxy.
func resProxyRoundTrip(reqPort, respPort port []byte, req []byte) []byte {
	reqPort <- req
	resp := <-respPort
	return resp
}

// proxyAssetLoaders returns AssetLoaders that forward all resource operations
// to the render island via the given resource ports.
// reqPort: logic→render requests. respPort: render→logic responses.
func proxyAssetLoaders(reqPort, respPort port []byte) AssetLoaders {
	return AssetLoaders{
		Texture: AssetLoader{
			LoadFile: func(path string) (int, error) {
				req := encodeResString(resTagLoadTexture, path)
				resp := resProxyRoundTrip(reqPort, respPort, req)
				return decodeResU32(resp)
			},
			LoadBytes: func(data []byte) (int, error) {
				req := encodeResBytes(resTagLoadTextureBytes, data)
				resp := resProxyRoundTrip(reqPort, respPort, req)
				return decodeResU32(resp)
			},
			Free: func(id int) {
				req := encodeResU32(resTagFreeTexture, id)
				resp := resProxyRoundTrip(reqPort, respPort, req)
				_ = decodeResUnit(resp)
			},
		},
		Font: AssetLoader{
			LoadFile: func(path string) (int, error) {
				req := encodeResString(resTagLoadFont, path)
				resp := resProxyRoundTrip(reqPort, respPort, req)
				return decodeResU32(resp)
			},
			LoadBytes: func(data []byte) (int, error) {
				req := encodeResBytes(resTagLoadFontBytes, data)
				resp := resProxyRoundTrip(reqPort, respPort, req)
				return decodeResU32(resp)
			},
			Free: func(id int) {
				req := encodeResU32(resTagFreeFont, id)
				resp := resProxyRoundTrip(reqPort, respPort, req)
				_ = decodeResUnit(resp)
			},
		},
		Model: AssetLoader{
			LoadFile: func(path string) (int, error) {
				req := encodeResString(resTagLoadModel, path)
				resp := resProxyRoundTrip(reqPort, respPort, req)
				return decodeResU32(resp)
			},
			LoadBytes: func(data []byte) (int, error) {
				req := encodeResBytes(resTagLoadModelBytes, data)
				resp := resProxyRoundTrip(reqPort, respPort, req)
				return decodeResU32(resp)
			},
			Free: func(id int) {
				req := encodeResU32(resTagFreeModel, id)
				resp := resProxyRoundTrip(reqPort, respPort, req)
				_ = decodeResUnit(resp)
			},
		},
		Audio: AssetLoader{
			// Audio goes through vogui, not through the render island.
			// In split mode, audio remains on the logic island.
			LoadFile: func(path string) (int, error) { return audioLoadFile(path) },
			LoadBytes: func(data []byte) (int, error) {
				clip := vogui.LoadAudioBytes(data)?
				return int(clip), nil
			},
			Free: func(id int) { vogui.AudioClipID(id).Free() },
		},
		Cubemap: CubemapLoader{
			LoadFiles: func(paths [6]string) (int, error) {
				req := encodeResCubemap(paths)
				resp := resProxyRoundTrip(reqPort, respPort, req)
				return decodeResU32(resp)
			},
			LoadBytes: func(faces [6][]byte) (int, error) {
				req := encodeResCubemapBytes(faces)
				resp := resProxyRoundTrip(reqPort, respPort, req)
				return decodeResU32(resp)
			},
			Free: func(id int) {
				req := encodeResU32(resTagFreeCubemap, id)
				resp := resProxyRoundTrip(reqPort, respPort, req)
				_ = decodeResUnit(resp)
			},
		},
	}
}

