func proxyAnimationTick(reqPort, respPort port []byte, worldID int, dt float64, entityModelMap []byte) {
	resp := resProxyRoundTrip(reqPort, respPort, encodeResAnimationTick(worldID, dt, entityModelMap))
	err := decodeResUnit(resp)
	if err != nil {
