// MaterialID is an optional stable handle for a material owned by game code or
// assets. MaterialID(0) means the renderer should use the model's source
// material with the explicit fields in MaterialDesc applied as overrides.
type MaterialID int

const (
	MaterialShadingDefault = 0
	MaterialShadingToon = 1
)

const (
	MaterialWrapSource = 0
	MaterialWrapRepeat = 1
	MaterialWrapClamp = 2
	MaterialWrapMirror = 3
)

const (
	MaterialFilterSource = 0
	MaterialFilterLinear = 1
	MaterialFilterNearest = 2
)

// MaterialDesc is the engine-level 3D material contract passed through the
// draw stream. Optional texture IDs use 0 as "not overridden".
type MaterialDesc struct {
	ID MaterialID
	BaseColor Color
	Albedo TextureID
	Normal TextureID
	MetallicRoughness TextureID
	Emissive TextureID
	EmissiveColor Color
	Roughness float64
	Metallic float64
	NormalScale float64
	UVScale float64
	ToonRamp TextureID
	ShadingMode int
	WrapMode int
	FilterMode int
}

func DefaultMaterial() MaterialDesc {
	return MaterialDesc{BaseColor: White, Roughness: 0.55, Metallic: 0, UVScale: 1}
}

func MaterialColor(c Color) MaterialDesc {
	m := DefaultMaterial()
	m.BaseColor = c
	return m
}

func NormalizeMaterial(m MaterialDesc) MaterialDesc {
	if m.BaseColor == (Color{}) && m.ID == 0 {
		m.BaseColor = White
	}
	if m.UVScale <= 0 {
		m.UVScale = 1
	}
	return m
}

