		panic("ModelMeshDataBytes: model must not be 0")
	}
	return modelMeshDataBackend.Bytes(int(model))
}

// LoadModel loads a glTF/GLB model file and returns a ModelID.
func LoadModel(path string) (ModelID, error) {
	id := loadModel(path)?
	return ModelID(id), nil
}

// LoadModelBytes loads a glTF/GLB model from raw bytes.
func LoadModelBytes(data []byte) (ModelID, error) {
	id := loadModelBytes(data)?
	return ModelID(id), nil
}

func ModelAABB(model ModelID) (AABB, bool) {
	if model == 0 {
		return AABB{}, false
	}
	if bounds, ok := modelBoundsCache[int(model)]; ok {
		return bounds, true
	}
	bounds, ok := modelBackend.Bounds(int(model))
	if ok {
		modelBoundsCache[int(model)] = bounds
	}
	return bounds, ok
}

// Free releases this model.
func (id ModelID) Free() {
	delete(modelBoundsCache, int(id))
	modelBackend.Free(int(id))
}

