// AnimController manages named animation clips with explicit state transitions.
// It replaces direct Animation use on Sprite for entities with multiple animation states
// (idle, walk, run, attack, death, etc.).
package scene2d

// AnimClip defines a named animation sequence: a set of frame indices into a SpriteSheet
// played at a given FPS, optionally looping.
type AnimClip struct {
	Sheet  *SpriteSheet
	Frames []int
	FPS    float64
	Loop   bool
}

// AnimController manages a named set of AnimClips and tracks the currently active state.
// Call SetState to transition, Update each frame to advance playback, and
// ApplyToSprite or CurrentFrame to obtain the current source rect.
type AnimController struct {
	clips   map[string]*AnimClip
	current string
	time    float64
	frame   int
	done    bool
	onDone  func()
}

// NewAnimController creates an empty AnimController with no clips registered.
func NewAnimController() *AnimController {
	return &AnimController{clips: map[string]*AnimClip{}}
}

// AddClip registers a named clip. Panics if the name is already registered or any field is invalid.
func (ac *AnimController) AddClip(name string, clip *AnimClip) {
	if name == "" {
		panic("AnimController.AddClip: name must not be empty")
	}
	if clip == nil {
		panic("AnimController.AddClip: clip must not be nil")
	}
	if clip.Sheet == nil {
		panic("AnimController.AddClip: clip.Sheet must not be nil")
	}
	if len(clip.Frames) == 0 {
		panic("AnimController.AddClip: clip.Frames must not be empty")
	}
	if clip.FPS <= 0 {
		panic("AnimController.AddClip: clip.FPS must be > 0")
	}
	if ac.clips[name] != nil {
		panic("AnimController.AddClip: clip already registered: " + name)
	}
	ac.clips[name] = clip
}

// SetState transitions to the named clip, restarting from frame 0.
// If name is already the current clip, this is a no-op (no restart).
// Panics if name is not registered.
func (ac *AnimController) SetState(name string) {
	if name == "" {
		panic("AnimController.SetState: name must not be empty")
	}
	if ac.clips[name] == nil {
		panic("AnimController.SetState: unknown clip: " + name)
	}
	if ac.current == name {
		return
	}
	ac.current = name
	ac.time = 0
	ac.frame = 0
	ac.done = false
}

// SetStateForce transitions to the named clip and always restarts from frame 0,
// even if it is already the current clip. Panics if name is not registered.
func (ac *AnimController) SetStateForce(name string) {
	if name == "" {
		panic("AnimController.SetStateForce: name must not be empty")
	}
	if ac.clips[name] == nil {
		panic("AnimController.SetStateForce: unknown clip: " + name)
	}
	ac.current = name
	ac.time = 0
	ac.frame = 0
	ac.done = false
}

// HasClip reports whether a clip with the given name has been registered.
func (ac *AnimController) HasClip(name string) bool {
	return ac.clips[name] != nil
}

// WithOnDone registers a callback that fires once each time a non-looping clip plays
// through its last frame. Inspect CurrentClip() inside the callback to chain into
// the next animation. Pass nil to clear an existing callback.
// Returns ac for builder-style chaining.
func (ac *AnimController) WithOnDone(fn func()) *AnimController {
	ac.onDone = fn
	return ac
}

// CurrentClip returns the name of the currently active clip, or "" if none has been set.
func (ac *AnimController) CurrentClip() string {
	return ac.current
}

// Done returns true if the current non-looping clip has played through its last frame.
func (ac *AnimController) Done() bool {
	return ac.done
}

// Update advances the current clip by dt seconds.
// Has no effect if no state is set or the current clip is a non-looping clip that has finished.
func (ac *AnimController) Update(dt float64) {
	if dt < 0 {
		panic("AnimController.Update: dt must not be negative")
	}
	if ac.current == "" || ac.done {
		return
	}
	clip := ac.clips[ac.current]
	ac.time += dt
	frameDur := 1.0 / clip.FPS
	for ac.time >= frameDur {
		ac.time -= frameDur
		ac.frame++
		if ac.frame >= len(clip.Frames) {
			if clip.Loop {
				ac.frame = 0
			} else {
				ac.frame = len(clip.Frames) - 1
				ac.done = true
				if ac.onDone != nil {
					ac.onDone()
				}
				return
			}
		}
	}
}

// CurrentFrame returns the source rect (x, y, w, h) in texture pixels for the active frame.
// Returns (0, 0, 0, 0) if no state has been set.
func (ac *AnimController) CurrentFrame() (float64, float64, float64, float64) {
	if ac.current == "" {
		return 0, 0, 0, 0
	}
	clip := ac.clips[ac.current]
	return clip.Sheet.Frame(clip.Frames[ac.frame])
}

// ApplyToSprite updates spr's Texture, SrcX, SrcY, SrcW, SrcH to match the current frame.
// Call this after Update each frame to keep the entity sprite in sync with the controller.
// Panics if spr is nil.
func (ac *AnimController) ApplyToSprite(spr *Sprite) {
	if spr == nil {
		panic("AnimController.ApplyToSprite: spr must not be nil")
	}
	if ac.current == "" {
		return
	}
	clip := ac.clips[ac.current]
	sx, sy, sw, sh := clip.Sheet.Frame(clip.Frames[ac.frame])
	spr.Texture = clip.Sheet.Texture
	spr.SrcX = sx
	spr.SrcY = sy
	spr.SrcW = sw
	spr.SrcH = sh
}

// Camera manages the 2D viewport: position, zoom, rotation, bounds clamping, and screen shake.
package scene2d

import "math"
import "github.com/vo-lang/voplay"

type Camera struct {
	X, Y     float64 // center position
	Zoom     float64 // 1.0 = no zoom
	Rotation float64 // radians
	Bounds   voplay.Rect
	shakeIntensity float64
	shakeDuration  float64
	shakeTimer     float64
	shakePhase     float64
}

func (c *Camera) Follow(x, y float64) {
	c.X = x
	c.Y = y
}

func (c *Camera) LerpFollow(x, y, t float64) {
	c.X += (x - c.X) * t
	c.Y += (y - c.Y) * t
}

func (c *Camera) FollowWithDeadzone(x, y, deadzoneW, deadzoneH, t float64) {
	halfW := deadzoneW / 2
	halfH := deadzoneH / 2
	targetX := c.X
	targetY := c.Y
	if x < c.X-halfW {
		targetX = x + halfW
	} else if x > c.X+halfW {
		targetX = x - halfW
	}
	if y < c.Y-halfH {
		targetY = y + halfH
	} else if y > c.Y+halfH {
		targetY = y - halfH
	}
	c.X += (targetX - c.X) * t
	c.Y += (targetY - c.Y) * t
}

func (c *Camera) Shake(intensity, duration float64) {
	if intensity < 0 {
		panic("Camera.Shake: intensity must be >= 0")
	}
	if duration < 0 {
		panic("Camera.Shake: duration must be >= 0")
	}
	c.shakeIntensity = intensity
	c.shakeDuration = duration
	c.shakeTimer = duration
	if duration == 0 || intensity == 0 {
		c.shakePhase = 0
	}
}

func (c *Camera) Update(dt float64) {
	if dt < 0 {
		panic("Camera.Update: dt must not be negative")
	}
	if c.shakeTimer <= 0 {
		c.shakeTimer = 0
		return
	}
	c.shakeTimer -= dt
	if c.shakeTimer < 0 {
		c.shakeTimer = 0
	}
	c.shakePhase += dt
	if c.shakeTimer == 0 {
		c.shakePhase = 0
	}
}

func (c *Camera) clampCenter(x, y, screenW, screenH float64) (float64, float64) {
	if c.Bounds.W <= 0 || c.Bounds.H <= 0 {
		return x, y
	}
	halfW := screenW / c.Zoom / 2
	halfH := screenH / c.Zoom / 2
	minX := c.Bounds.X + halfW
	maxX := c.Bounds.X + c.Bounds.W - halfW
	minY := c.Bounds.Y + halfH
	maxY := c.Bounds.Y + c.Bounds.H - halfH
	if minX > maxX {
		x = c.Bounds.X + c.Bounds.W/2
	} else {
		if x < minX {
			x = minX
		}
		if x > maxX {
			x = maxX
		}
	}
	if minY > maxY {
		y = c.Bounds.Y + c.Bounds.H/2
	} else {
		if y < minY {
			y = minY
		}
		if y > maxY {
			y = maxY
		}
	}
	return x, y
}

func (c *Camera) renderCenter(screenW, screenH float64) (float64, float64) {
	x, y := c.clampCenter(c.X, c.Y, screenW, screenH)
	if c.shakeTimer <= 0 || c.shakeIntensity == 0 || c.shakeDuration == 0 {
		return x, y
	}
	strength := c.shakeIntensity * (c.shakeTimer / c.shakeDuration)
	renderX := x + math.Sin(c.shakePhase*13.0)*strength
	renderY := y + math.Cos(c.shakePhase*17.0)*strength
	return c.clampCenter(renderX, renderY, screenW, screenH)
}

func (c *Camera) ScreenToWorld(screenX, screenY, screenW, screenH float64) (float64, float64) {
	if c.Zoom == 0 {
		panic("Camera.Zoom must not be 0")
	}
	centerX, centerY := c.renderCenter(screenW, screenH)
	rx := (screenX - screenW/2) / c.Zoom
	ry := (screenY - screenH/2) / c.Zoom
	cos := math.Cos(-c.Rotation)
	sin := math.Sin(-c.Rotation)
	wx := rx*cos - ry*sin + centerX
	wy := rx*sin + ry*cos + centerY
	return wx, wy
}

func (c *Camera) WorldToScreen(worldX, worldY, screenW, screenH float64) (float64, float64) {
	if c.Zoom == 0 {
		panic("Camera.Zoom must not be 0")
	}
	centerX, centerY := c.renderCenter(screenW, screenH)
	dx := worldX - centerX
	dy := worldY - centerY
	cos := math.Cos(c.Rotation)
	sin := math.Sin(c.Rotation)
	rx := dx*cos - dy*sin
	ry := dx*sin + dy*cos
	sx := rx*c.Zoom + screenW/2
	sy := ry*c.Zoom + screenH/2
	return sx, sy
}

func (c *Camera) ViewRect(screenW, screenH float64) voplay.Rect {
	if c.Zoom == 0 {
		panic("Camera.Zoom must not be 0")
	}
	w := screenW / c.Zoom
	h := screenH / c.Zoom
	centerX, centerY := c.renderCenter(screenW, screenH)
	return voplay.Rect{
		X: centerX - w/2,
		Y: centerY - h/2,
		W: w,
		H: h,
	}
}

// Debug rendering for scene2d.
// Draws physics collider outlines, contact midpoints, entity labels,
// camera view rect, camera bounds rect, and occupied spatial hash cells.
// All drawing happens in world space; DrawDebugFull sets the camera internally.
package scene2d

import "math"
import "github.com/vo-lang/voplay"

// DebugColors holds the colors used for each debug layer.
type DebugColors struct {
	Collider     voplay.Color
	Contact      voplay.Color
	CameraView   voplay.Color
	CameraBounds voplay.Color
	SpatialGrid  voplay.Color
	Label        voplay.Color
}

// DefaultDebugColors returns a sensible default color scheme.
func DefaultDebugColors() DebugColors {
	return DebugColors{
		Collider:     voplay.Color{R: 0, G: 1, B: 0, A: 0.8},
		Contact:      voplay.Color{R: 1, G: 0, B: 0, A: 1},
		CameraView:   voplay.Color{R: 1, G: 1, B: 0, A: 0.5},
		CameraBounds: voplay.Color{R: 0, G: 0.5, B: 1, A: 0.5},
		SpatialGrid:  voplay.Color{R: 0.3, G: 0.3, B: 0.3, A: 0.4},
		Label:        voplay.Color{R: 1, G: 1, B: 1, A: 1},
	}
}

// DrawDebugOptions controls which debug layers are rendered.
type DrawDebugOptions struct {
	Colliders    bool
	Contacts     bool
	Labels       bool
	CameraView   bool
	CameraBounds bool
	SpatialGrid  bool
}

// DrawDebugAll returns DrawDebugOptions with the standard layers enabled.
// SpatialGrid is off by default because it is visually noisy for large scenes.
func DrawDebugAll() DrawDebugOptions {
	return DrawDebugOptions{
		Colliders:    true,
		Contacts:     true,
		Labels:       true,
		CameraView:   true,
		CameraBounds: true,
		SpatialGrid:  false,
	}
}

// DrawDebug draws a standard debug overlay using DrawDebugAll and DefaultDebugColors.
// It sets its own camera (camX/camY from scene) and resets it at the end.
func (s *Scene) DrawDebug(d *voplay.DrawCtx, screenW, screenH float64) {
	s.DrawDebugFull(d, screenW, screenH, DrawDebugAll(), DefaultDebugColors())
}

// DrawDebugFull draws the debug overlay with full control over options and colors.
// This method sets its own camera transform and resets it at the end, so it may
// be called independently of Scene.Draw.
func (s *Scene) DrawDebugFull(d *voplay.DrawCtx, screenW, screenH float64, opts DrawDebugOptions, colors DebugColors) {
	zoom := s.Camera.Zoom
	lineW := 1.5 / zoom

	camX, camY := s.Camera.renderCenter(screenW, screenH)
	d.SetCamera2D(camX, camY, zoom, s.Camera.Rotation)

	if opts.SpatialGrid {
		drawDebugSpatialGrid(d, s, screenW, screenH, lineW, colors.SpatialGrid)
	}
	if opts.Colliders {
		drawDebugColliders(d, s, lineW, colors.Collider)
	}
	if opts.Contacts {
		drawDebugContacts(d, s, zoom, colors.Contact)
	}
	if opts.Labels {
		drawDebugLabels(d, s, zoom, colors.Label)
	}
	if opts.CameraView {
		vr := s.Camera.ViewRect(screenW, screenH)
		d.DrawRectOutline(vr.X, vr.Y, vr.W, vr.H, lineW, colors.CameraView)
	}
	if opts.CameraBounds && s.Camera.Bounds.W > 0 && s.Camera.Bounds.H > 0 {
		b := s.Camera.Bounds
		d.DrawRectOutline(b.X, b.Y, b.W, b.H, lineW, colors.CameraBounds)
	}

	d.ResetCamera()
}

func drawRotatedRectOutline(d *voplay.DrawCtx, cx, cy, halfW, halfH, angle, lineW float64, color voplay.Color) {
	cos := math.Cos(angle)
	sin := math.Sin(angle)
	rotate := func(lx, ly float64) (float64, float64) {
		return cx + lx*cos - ly*sin, cy + lx*sin + ly*cos
	}
	x0, y0 := rotate(-halfW, -halfH)
	x1, y1 := rotate(halfW, -halfH)
	x2, y2 := rotate(halfW, halfH)
	x3, y3 := rotate(-halfW, halfH)
	d.DrawLine(x0, y0, x1, y1, lineW, color)
	d.DrawLine(x1, y1, x2, y2, lineW, color)
	d.DrawLine(x2, y2, x3, y3, lineW, color)
	d.DrawLine(x3, y3, x0, y0, lineW, color)
}

func drawDebugColliders(d *voplay.DrawCtx, s *Scene, lineW float64, color voplay.Color) {
	for _, e := range s.entities {
		if !e.Active || e.Physics == nil {
			continue
		}
		p := e.Physics
		switch p.Collider.kind {
		case colliderBox2D:
			halfW := p.Collider.args[0]
			halfH := p.Collider.args[1]
			drawRotatedRectOutline(d, e.position.X, e.position.Y, halfW, halfH, e.rotation, lineW, color)
		case colliderCircle2D:
			radius := p.Collider.args[0]
			d.DrawCircleOutline(e.position.X, e.position.Y, radius, lineW, 24, color)
		case colliderCapsule:
			halfH := p.Collider.args[0]
			radius := p.Collider.args[1]
			// Draw the rectangular shaft rotated along the capsule axis.
			drawRotatedRectOutline(d, e.position.X, e.position.Y, radius, halfH, e.rotation, lineW, color)
			// End caps: circles at ±halfH along the rotated Y axis.
			dx := -math.Sin(e.rotation) * halfH
			dy := math.Cos(e.rotation) * halfH
			d.DrawCircleOutline(e.position.X+dx, e.position.Y+dy, radius, lineW, 16, color)
			d.DrawCircleOutline(e.position.X-dx, e.position.Y-dy, radius, lineW, 16, color)
		}
	}
}

func drawDebugContacts(d *voplay.DrawCtx, s *Scene, zoom float64, color voplay.Color) {
	contacts := s.Contacts()
	dotRadius := 3.0 / zoom
	for _, c := range contacts {
		mx := (c.A.position.X + c.B.position.X) / 2
		my := (c.A.position.Y + c.B.position.Y) / 2
		d.DrawCircle(mx, my, dotRadius, color)
	}
}

func drawDebugLabels(d *voplay.DrawCtx, s *Scene, zoom float64, color voplay.Color) {
	labelSize := 12.0 / zoom
	for _, e := range s.entities {
		if !e.Active || e.Tag == "" {
			continue
		}
		b := e.Bounds()
		yOffset := b.H/2 + labelSize*1.2
		d.DrawText(e.Tag, e.position.X, e.position.Y-yOffset, labelSize, color)
	}
}

func drawDebugSpatialGrid(d *voplay.DrawCtx, s *Scene, screenW, screenH, lineW float64, color voplay.Color) {
	vr := s.Camera.ViewRect(screenW, screenH)
	cellSize := s.spatialCellSize
	minCX := int(math.Floor(vr.X/cellSize)) - 1
	maxCX := int(math.Floor((vr.X+vr.W)/cellSize)) + 1
	minCY := int(math.Floor(vr.Y/cellSize)) - 1
	maxCY := int(math.Floor((vr.Y+vr.H)/cellSize)) + 1
	for cx := minCX; cx <= maxCX; cx++ {
		for cy := minCY; cy <= maxCY; cy++ {
			key := spatialCellKey(cx, cy)
			if len(s.spatialBuckets[key]) > 0 {
				wx := float64(cx) * cellSize
				wy := float64(cy) * cellSize
				d.DrawRectOutline(wx, wy, cellSize, cellSize, lineW, color)
			}
		}
	}
}

// Scene2D draw convenience functions.
// These wrap voplay.DrawCtx methods with scene2d types (Sprite, Tilemap, Scene).
package scene2d

import "github.com/vo-lang/voplay"
import "sort"

// entityByZOrder implements sort.Interface to sort []*Entity by ZOrder.
type entityByZOrder []*Entity

func (e entityByZOrder) Len() int           { return len(e) }
func (e entityByZOrder) Less(i, j int) bool { return e[i].ZOrder < e[j].ZOrder }
func (e entityByZOrder) Swap(i, j int)      { e[i], e[j] = e[j], e[i] }

// DrawSprite draws a sprite at the given position and size using its current animation frame.
func DrawSprite(d *voplay.DrawCtx, spr *Sprite, x, y, w, h float64) {
	DrawSpriteRotated(d, spr, x, y, w, h, spr.Rotation)
}

// DrawSpriteRotated draws a sprite with an explicit rotation (radians).
func DrawSpriteRotated(d *voplay.DrawCtx, spr *Sprite, x, y, w, h, rotation float64) {
	srcX, srcY, srcW, srcH := spr.SrcX, spr.SrcY, spr.SrcW, spr.SrcH
	if spr.Anim != nil {
		srcX, srcY, srcW, srcH = spr.Anim.CurrentFrame()
	}
	d.DrawSprite(voplay.SpriteParams{
		Tex:      spr.Texture,
		Src:      voplay.Rect{srcX, srcY, srcW, srcH},
		Dst:      voplay.Rect{x, y, w, h},
		FlipX:    spr.FlipX,
		FlipY:    spr.FlipY,
		Rotation: rotation,
		Tint:     spr.Tint,
	})
}

// DrawTilemap draws visible tiles of a tilemap layer within the given viewport.
// viewX, viewY, viewW, viewH define the visible world-space rect (use Camera.ViewRect).
func DrawTilemap(d *voplay.DrawCtx, tm *Tilemap, layerIdx int, viewX, viewY, viewW, viewH float64) {
	ts := tm.TileSet
	tw := float64(ts.TileW)
	th := float64(ts.TileH)
	layer := tm.Layers[layerIdx]

	// Compute visible tile range (clamped to tilemap bounds)
	colStart := int(viewX / tw)
	rowStart := int(viewY / th)
	colEnd := int((viewX + viewW) / tw) + 1
	rowEnd := int((viewY + viewH) / th) + 1
	if colStart < 0 {
		colStart = 0
	}
	if rowStart < 0 {
		rowStart = 0
	}
	if colEnd > tm.Width {
		colEnd = tm.Width
	}
	if rowEnd > tm.Height {
		rowEnd = tm.Height
	}

	for row := rowStart; row < rowEnd; row++ {
		for col := colStart; col < colEnd; col++ {
			tileIdx := layer.Tiles[row*tm.Width+col]
			if tileIdx < 0 {
				continue // empty tile
			}
			// Compute source rect in tileset
			srcCol := tileIdx % ts.Columns
			srcRow := tileIdx / ts.Columns
			srcX := float64(srcCol * ts.TileW)
			srcY := float64(srcRow * ts.TileH)
			// Destination position in world space
			dx := float64(col) * tw
			dy := float64(row) * th
			d.DrawSprite(voplay.SpriteParams{
				Tex: ts.Texture,
				Src: voplay.Rect{srcX, srcY, tw, th},
				Dst: voplay.Rect{dx, dy, tw, th},
			})
		}
	}
}

// Draw renders the entire 2D scene: camera, tilemap (if set), then entities sorted by ZOrder.
// screenW and screenH are the current viewport dimensions (used for tilemap culling).
func (s *Scene) Draw(d *voplay.DrawCtx, screenW, screenH float64) {
	camX, camY := s.Camera.renderCenter(screenW, screenH)
	d.SetCamera2D(camX, camY, s.Camera.Zoom, s.Camera.Rotation)

	// Draw tilemap layers (bottom to top, before entities)
	if s.Tilemap != nil && screenW > 0 {
		vr := s.Camera.ViewRect(screenW, screenH)
		for i := range s.Tilemap.Layers {
			DrawTilemap(d, s.Tilemap, i, vr.X, vr.Y, vr.W, vr.H)
		}
	}

	// Collect visible entities in view and sort by ZOrder (stable merge sort)
	sorted := s.visibleInView(screenW, screenH)
	sort.Stable(entityByZOrder(sorted))

	for _, e := range sorted {
		if e.Sprite == nil {
			continue
		}
		w := e.size.X * e.scale.X
		h := e.size.Y * e.scale.Y
		x := e.position.X - w/2
		y := e.position.Y - h/2
		DrawSpriteRotated(d, e.Sprite, x, y, w, h, e.rotation+e.Sprite.Rotation)
	}

	d.ResetCamera()
}

// Entity is a 2D game object managed by a Scene.
// Supports parent-child transform hierarchy and per-entity sprite/animation.
package scene2d

import "math"
import "github.com/vo-lang/voplay"

func rotateVec2(v voplay.Vec2, angle float64) voplay.Vec2 {
	if angle == 0 {
		return v
	}
	cos := math.Cos(angle)
	sin := math.Sin(angle)
	return voplay.Vec2{
		X: v.X*cos - v.Y*sin,
		Y: v.X*sin + v.Y*cos,
	}
}

type EntityDesc struct {
	Position voplay.Vec2
	Size     voplay.Vec2
	Rotation float64
	Scale    voplay.Vec2
	Sprite   *Sprite
	AnimCtrl *AnimController
	Tag      string
	ZOrder   int
	Data     any
	Physics  *Physics
}

type Entity struct {
	id            int
	localPosition voplay.Vec2
	position      voplay.Vec2
	size          voplay.Vec2
	localRotation float64
	rotation      float64
	localScale    voplay.Vec2
	scale         voplay.Vec2
	Sprite        *Sprite
	AnimCtrl      *AnimController
	Tag           string
	Active        bool
	Visible       bool
	ZOrder        int
	Data          any
	Physics       *Physics
	scene         *Scene
	parentID      int
	childIDs      []int
	spatialCells     []int64
	spatialQueryTick int
}

// ID returns the entity's unique identifier within its scene.
func (e *Entity) ID() int {
	return e.id
}

// --- Transform hierarchy ---

func (e *Entity) localPositionFromWorld(world voplay.Vec2) voplay.Vec2 {
	parent := e.parentEntity()
	if parent == nil {
		return world
	}
	delta := world.Sub(parent.position)
	local := rotateVec2(delta, -parent.rotation)
	if parent.scale.X == 0 || parent.scale.Y == 0 {
		panic("Entity: parent scale must not contain 0")
	}
	return voplay.Vec2{X: local.X / parent.scale.X, Y: local.Y / parent.scale.Y}
}

func (e *Entity) localRotationFromWorld(rotation float64) float64 {
	parent := e.parentEntity()
	if parent == nil {
		return rotation
	}
	return rotation - parent.rotation
}

func (e *Entity) localScaleFromWorld(scale voplay.Vec2) voplay.Vec2 {
	parent := e.parentEntity()
	if parent == nil {
		return scale
	}
	if parent.scale.X == 0 || parent.scale.Y == 0 {
		panic("Entity: parent scale must not contain 0")
	}
	return voplay.Vec2{X: scale.X / parent.scale.X, Y: scale.Y / parent.scale.Y}
}

func (e *Entity) syncHierarchyWorldTransform(updateSpatial bool) {
	parent := e.parentEntity()
	if parent == nil {
		e.position = e.localPosition
		e.rotation = e.localRotation
		e.scale = e.localScale
	} else {
		scaledLocal := voplay.Vec2{X: e.localPosition.X * parent.scale.X, Y: e.localPosition.Y * parent.scale.Y}
		e.position = parent.position.Add(rotateVec2(scaledLocal, parent.rotation))
		e.rotation = parent.rotation + e.localRotation
		e.scale = voplay.Vec2{X: parent.scale.X * e.localScale.X, Y: parent.scale.Y * e.localScale.Y}
	}
	if updateSpatial && e.scene != nil {
		e.scene.spatialUpdate(e)
	}
	for _, childID := range e.childIDs {
		child := e.scene.entityByID[childID]
		if child != nil {
			child.syncHierarchyWorldTransform(updateSpatial)
		}
	}
}

func (e *Entity) removeChild(child *Entity) {
	for i, childID := range e.childIDs {
		if childID == child.id {
			last := len(e.childIDs) - 1
			e.childIDs[i] = e.childIDs[last]
			e.childIDs = e.childIDs[:last]
			return
		}
	}
}

func (e *Entity) parentEntity() *Entity {
	if e.parentID == 0 {
		return nil
	}
	return e.scene.entityByID[e.parentID]
}

func (e *Entity) Parent() *Entity {
	return e.parentEntity()
}

func (e *Entity) Children() []*Entity {
	result := make([]*Entity, 0, len(e.childIDs))
	for _, childID := range e.childIDs {
		child := e.scene.entityByID[childID]
		if child != nil {
			result = append(result, child)
		}
	}
	return result
}

func (e *Entity) SetParent(parent *Entity, keepWorld bool) {
	if parent == e {
		panic("Entity.SetParent: entity cannot parent itself")
	}
	if parent != nil {
		if e.scene == nil || parent.scene != e.scene {
			panic("Entity.SetParent: parent must belong to the same scene")
		}
		if e.Physics != nil {
			panic("Entity.SetParent: physics entities cannot be parented")
		}
		if parent.Physics != nil {
			panic("Entity.SetParent: physics parents are not supported")
		}
		visited := make(map[*Entity]bool)
		current := parent
		for current != nil {
			if visited[current] {
				panic("Entity.SetParent: cycle detected")
			}
			visited[current] = true
			if current == e {
				panic("Entity.SetParent: cycle detected")
			}
			current = current.Parent()
		}
	}
	currentParent := e.parentEntity()
	if currentParent == parent {
		return
	}
	worldPosition := e.position
	worldRotation := e.rotation
	worldScale := e.scale
	if currentParent != nil {
		currentParent.removeChild(e)
	}
	e.parentID = 0
	if parent != nil {
		e.parentID = parent.id
		parent.childIDs = append(parent.childIDs, e.id)
	}
	if keepWorld {
		e.localPosition = e.localPositionFromWorld(worldPosition)
		e.localRotation = e.localRotationFromWorld(worldRotation)
		e.localScale = e.localScaleFromWorld(worldScale)
	}
	e.syncHierarchyWorldTransform(true)
}

func (e *Entity) Detach(keepWorld bool) {
	e.SetParent(nil, keepWorld)
}

// --- Accessors ---

// Position returns the entity's world position.
func (e *Entity) Position() voplay.Vec2 {
	return e.position
}

func (e *Entity) LocalPosition() voplay.Vec2 {
	return e.localPosition
}

// Size returns the entity's size.
func (e *Entity) Size() voplay.Vec2 {
	return e.size
}

// Scale returns the entity's world scale.
func (e *Entity) Scale() voplay.Vec2 {
	return e.scale
}

func (e *Entity) LocalScale() voplay.Vec2 {
	return e.localScale
}

// Rotation returns the entity's world rotation.
func (e *Entity) Rotation() float64 {
	return e.rotation
}

func (e *Entity) LocalRotation() float64 {
	return e.localRotation
}

// --- Mutators ---

// SetSize sets the entity's size.
func (e *Entity) SetSize(w, h float64) {
	if e.Physics != nil {
		panic("Entity.SetSize: physics collider resize is not supported")
	}
	e.size = voplay.Vec2{w, h}
	if e.scene != nil {
		e.scene.spatialUpdate(e)
	}
}

// SetScale sets the entity's world scale.
func (e *Entity) SetScale(x, y float64) {
	if e.Physics != nil {
		panic("Entity.SetScale: physics collider resize is not supported")
	}
	e.localScale = e.localScaleFromWorld(voplay.Vec2{x, y})
	e.syncHierarchyWorldTransform(true)
}

func (e *Entity) SetLocalPosition(x, y float64) {
	e.localPosition = voplay.Vec2{x, y}
	e.syncHierarchyWorldTransform(true)
}

func (e *Entity) SetLocalRotation(rotation float64) {
	e.localRotation = rotation
	e.syncHierarchyWorldTransform(true)
}

func (e *Entity) SetLocalScale(x, y float64) {
	if e.Physics != nil {
		panic("Entity.SetLocalScale: physics collider resize is not supported")
	}
	e.localScale = voplay.Vec2{x, y}
	e.syncHierarchyWorldTransform(true)
}

// SetPosition teleports the entity to the given world position.
// For physics entities, also buffers a position command for the next physics step.
func (e *Entity) SetPosition(x, y float64) {
	e.localPosition = e.localPositionFromWorld(voplay.Vec2{x, y})
	e.syncHierarchyWorldTransform(true)
	if e.scene != nil && e.Physics != nil {
		e.scene.writePhysCmd(physicsCmdSetPos, e.Physics.bodyID, x, y)
	}
}

// SetRotation sets the entity's world rotation.
// For physics entities, also buffers a rotation command for the next physics step.
func (e *Entity) SetRotation(rotation float64) {
	e.localRotation = e.localRotationFromWorld(rotation)
	e.syncHierarchyWorldTransform(true)
	if e.scene != nil && e.Physics != nil {
		e.scene.writePhysCmd(physicsCmdSetRot, e.Physics.bodyID, rotation, 0)
	}
}

// --- Geometry ---

// Center returns the entity's center position.
func (e *Entity) Center() voplay.Vec2 {
	return e.position
}

// Bounds returns the entity's axis-aligned bounding rect (centered on position).
func (e *Entity) Bounds() voplay.Rect {
	w := e.size.X * e.scale.X
	h := e.size.Y * e.scale.Y
	if w < 0 {
		w = -w
	}
	if h < 0 {
		h = -h
	}
	return voplay.Rect{e.position.X - w/2, e.position.Y - h/2, w, h}
}

// Overlaps returns true if this entity's bounding rect intersects another's.
func (e *Entity) Overlaps(other *Entity) bool {
	return e.Bounds().Intersects(other.Bounds())
}

// DistanceTo returns the distance between the centers of two entities.
func (e *Entity) DistanceTo(other *Entity) float64 {
	return e.Center().Distance(other.Center())
}

// Physics types, colliders, and extern declarations for 2D physics.
package scene2d

import "github.com/vo-lang/voplay"
import "github.com/vo-lang/voplay/codec"

// BodyType determines how the physics engine treats a body.
type BodyType = voplay.BodyType

const (
	Dynamic   = voplay.Dynamic
	Static    = voplay.Static
	Kinematic = voplay.Kinematic
)

// Physics is the physics configuration and runtime state for a 2D entity.
type Physics struct {
	Type          BodyType
	Collider      Collider
	Layer         int
	Mask          int
	Density       float64
	Friction      float64
	Restitution   float64
	LinearDamping float64
	FixedRotation bool

	// Runtime state (managed by Scene, not user-set).
	bodyID   int
	velocity voplay.Vec2
}

// Collider is a tagged value type for 2D physics shapes.
type Collider struct {
	kind int
	args [3]float64
}

// Collider kind constants (must match Rust ColliderKind in physics.rs).
const (
	colliderBox2D    = 1
	colliderCircle2D = 2
	colliderCapsule  = 3
)

// Collider shape type constants.
const (
	ColliderBox     = colliderBox2D
	ColliderCircle  = colliderCircle2D
	ColliderCapsule = colliderCapsule
)

// 2D collider constructors.
func Box(halfW, halfH float64) Collider {
	return Collider{kind: colliderBox2D, args: [3]float64{halfW, halfH, 0}}
}
func Circle(radius float64) Collider {
	return Collider{kind: colliderCircle2D, args: [3]float64{radius, 0, 0}}
}
func Capsule(halfHeight, radius float64) Collider {
	return Collider{kind: colliderCapsule, args: [3]float64{halfHeight, radius, 0}}
}

// Kind returns the collider shape type (ColliderBox, ColliderCircle, or ColliderCapsule).
func (c Collider) Kind() int {
	return c.kind
}

// Args returns the raw shape arguments.
// Box: [halfW, halfH, 0], Circle: [radius, 0, 0], Capsule: [halfHeight, radius, 0].
func (c Collider) Args() [3]float64 {
	return c.args
}

// Contact represents an active collision pair between two entities.
type Contact struct {
	A *Entity
	B *Entity
}

// RayCastHit describes a ray cast hit in the 2D physics world.
type RayCastHit struct {
	Entity   *Entity
	Point    voplay.Vec2
	Normal   voplay.Vec2
	Distance float64
}

// Physics command opcodes (must match Rust physics.rs).
const (
	physicsCmdForce   byte = 1
	physicsCmdImpulse byte = 2
	physicsCmdSetVel  byte = 3
	physicsCmdSetPos  byte = 4
	physicsCmdSetRot  byte = 5
)

// writePhysCmd appends a physics command to this scene's command buffer.
func (s *Scene) writePhysCmd(cmd byte, bodyID int, v1, v2 float64) {
	s.physCmds.WriteByte(cmd)
	s.physCmds.WriteU32(bodyID)
	s.physCmds.WriteF64(v1)
	s.physCmds.WriteF64(v2)
}

// ApplyForce applies a force to a physics entity (buffered until next step).
func (e *Entity) ApplyForce(fx, fy float64) {
	e.scene.writePhysCmd(physicsCmdForce, e.Physics.bodyID, fx, fy)
}

// ApplyImpulse applies an impulse to a physics entity (buffered until next step).
func (e *Entity) ApplyImpulse(ix, iy float64) {
	e.scene.writePhysCmd(physicsCmdImpulse, e.Physics.bodyID, ix, iy)
}

// SetVelocity sets the linear velocity of a physics entity (buffered until next step).
func (e *Entity) SetVelocity(vx, vy float64) {
	e.scene.writePhysCmd(physicsCmdSetVel, e.Physics.bodyID, vx, vy)
}

// Velocity returns the current linear velocity (updated after each physics step).
// Panics if the entity has no Physics component.
func (e *Entity) Velocity() voplay.Vec2 {
	return e.Physics.velocity
}

// serializeBodyDesc encodes a body description for the physics extern.
func serializeBodyDesc(e *Entity) []byte {
	p := e.Physics
	voplay.ValidateCollisionFilter(p.Layer, p.Mask)
	w := codec.NewByteWriter(87)
	w.WriteByte(byte(p.Type))
	w.WriteByte(byte(p.Collider.kind))
	w.WriteBool(p.FixedRotation)
	w.WriteU16(p.Layer)
	w.WriteU16(p.Mask)
	w.WriteF64(e.position.X)
	w.WriteF64(e.position.Y)
	w.WriteF64(e.rotation)
	w.WriteF64(p.Collider.args[0])
	w.WriteF64(p.Collider.args[1])
	w.WriteF64(p.Collider.args[2])
	w.WriteF64(p.Density)
	w.WriteF64(p.Friction)
	w.WriteF64(p.Restitution)
	w.WriteF64(p.LinearDamping)
	return w.Bytes()
}

// PhysicsBackend abstracts 2D physics world operations so they can be
// replaced in tests without per-function hook boilerplate.
type PhysicsBackend interface {
	Init(gravityX, gravityY float64) int
	Destroy(worldID int)
	SpawnBody(worldID, bodyID int, data []byte)
	DestroyBody(worldID, bodyID int)
	Step(worldID int, dt float64, cmds []byte) []byte
	Contacts(worldID int) []byte
	SetGravity(worldID int, gx, gy float64)
	RayCast(worldID int, ox, oy, dx, dy, maxDist float64) []byte
	QueryRect(worldID int, minX, minY, maxX, maxY float64) []byte
}

type defaultPhysicsBackend struct{}

func (defaultPhysicsBackend) Init(gravityX, gravityY float64) int {
	return physicsInit(gravityX, gravityY)
}

func (defaultPhysicsBackend) Destroy(worldID int) {
	physicsDestroy(worldID)
}

func (defaultPhysicsBackend) SpawnBody(worldID, bodyID int, data []byte) {
	physicsSpawnBody(worldID, bodyID, data)
}

func (defaultPhysicsBackend) DestroyBody(worldID, bodyID int) {
	physicsDestroyBody(worldID, bodyID)
}

func (defaultPhysicsBackend) Step(worldID int, dt float64, cmds []byte) []byte {
	return physicsStep(worldID, dt, cmds)
}

func (defaultPhysicsBackend) Contacts(worldID int) []byte {
	return physicsContacts(worldID)
}

func (defaultPhysicsBackend) SetGravity(worldID int, gx, gy float64) {
	physicsSetGravity(worldID, gx, gy)
}

func (defaultPhysicsBackend) RayCast(worldID int, ox, oy, dx, dy, maxDist float64) []byte {
	return physicsRayCast(worldID, ox, oy, dx, dy, maxDist)
}

func (defaultPhysicsBackend) QueryRect(worldID int, minX, minY, maxX, maxY float64) []byte {
	return physicsQueryRect(worldID, minX, minY, maxX, maxY)
}

var physBackend PhysicsBackend = defaultPhysicsBackend{}

// SetPhysicsBackend replaces the active physics backend and returns the previous one.
func SetPhysicsBackend(b PhysicsBackend) PhysicsBackend {
	prev := physBackend
	physBackend = b
	return prev
}

