// Scene manages 2D entities, camera, and physics.
// Entity types are in entity.vo, camera in camera.vo, spatial index in spatial.vo.
package scene2d

import "github.com/vo-lang/voplay"
import "github.com/vo-lang/voplay/codec"

type Scene struct {
	Camera  Camera
	Tilemap *Tilemap
	Gravity voplay.Vec2

	entities         []*Entity
	visibleBuf       []*Entity
	nextEntityID     int
	entityByID       map[int]*Entity
	worldID          int
	nextBodyID       int
	physCmds         codec.ByteWriter
	bodyMap          map[int]*Entity
	spatialCellSize  float64
	spatialBuckets   map[int64][]*Entity
	spatialQueryTick int
	cellScratch      []int64 // reusable scratch for per-frame spatial queries
}

func New() *Scene {
	return &Scene{
		Camera:          Camera{Zoom: 1.0},
		Gravity:         voplay.Vec2{0, 9.8},
		nextEntityID:    1,
		entityByID:      make(map[int]*Entity),
		nextBodyID:      1,
		physCmds:        codec.NewByteWriter(256),
		bodyMap:         make(map[int]*Entity),
		spatialCellSize: defaultSpatialCellSize,
		spatialBuckets:  map[int64][]*Entity{},
	}
}

// --- Entity lifecycle ---

func (s *Scene) Spawn(desc EntityDesc) *Entity {
	scale := desc.Scale
	if scale.X == 0 {
		scale.X = 1
	}
	if scale.Y == 0 {
		scale.Y = 1
	}
	ent := &Entity{
		id:            s.nextEntityID,
		localPosition: desc.Position,
		position:      desc.Position,
		size:          desc.Size,
		localRotation: desc.Rotation,
		rotation:      desc.Rotation,
		localScale:    scale,
		scale:         scale,
		Sprite:        desc.Sprite,
		AnimCtrl:      desc.AnimCtrl,
		Tag:           desc.Tag,
		Active:        true,
		Visible:       true,
		ZOrder:        desc.ZOrder,
		Data:          desc.Data,
		Physics:       desc.Physics,
		scene:         s,
	}
	s.nextEntityID++
	if ent.Physics != nil {
		s.ensurePhysics()
		ent.Physics.bodyID = s.nextBodyID
		s.nextBodyID++
	}
	s.entities = append(s.entities, ent)
	s.entityByID[ent.id] = ent
	s.spatialInsert(ent)
	if ent.Physics != nil {
		s.bodyMap[ent.Physics.bodyID] = ent
		physBackend.SpawnBody(s.worldID, ent.Physics.bodyID, serializeBodyDesc(ent))
	}
	return ent
}

func (s *Scene) destroyEntityRecursive(e *Entity) {
	children := e.Children()
	for _, child := range children {
		s.destroyEntityRecursive(child)
	}
	e.Active = false
	s.spatialRemove(e)
	if parent := e.parentEntity(); parent != nil {
		parent.removeChild(e)
		e.parentID = 0
	}
	if e.Physics != nil {
		delete(s.bodyMap, e.Physics.bodyID)
		physBackend.DestroyBody(s.worldID, e.Physics.bodyID)
		e.Physics.bodyID = 0
	}
	e.childIDs = nil
	e.scene = nil
	delete(s.entityByID, e.id)
	for i, ent := range s.entities {
		if ent == e {
			last := len(s.entities) - 1
			s.entities[i] = s.entities[last]
			s.entities[last] = nil
			s.entities = s.entities[:last]
			return
		}
	}
}

func (s *Scene) Destroy(e *Entity) {
	if e.scene != s {
		panic("Scene.Destroy: entity does not belong to this scene")
	}
	s.destroyEntityRecursive(e)
}

func (s *Scene) Clear() {
	for _, e := range s.entities {
		if e.Physics != nil {
			physBackend.DestroyBody(s.worldID, e.Physics.bodyID)
		}
		e.parentID = 0
		e.childIDs = nil
		e.scene = nil
		e.Active = false
		e.spatialCells = nil
	}
	s.entities = s.entities[:0]
	for id := range s.entityByID {
		delete(s.entityByID, id)
	}
	for k := range s.bodyMap {
		delete(s.bodyMap, k)
	}
	for cell := range s.spatialBuckets {
		delete(s.spatialBuckets, cell)
	}
	s.physCmds.Reset()
}

func (s *Scene) Close() {
	s.Clear()
	if s.worldID != 0 {
		physBackend.Destroy(s.worldID)
		s.worldID = 0
	}
}

// --- Entity queries ---

// FindByID returns the entity with the given ID, or nil if not found.
func (s *Scene) FindByID(id int) *Entity {
	e := s.entityByID[id]
	if e != nil && e.Active {
		return e
	}
	return nil
}

func (s *Scene) FindByTag(tag string) *Entity {
	for _, e := range s.entities {
		if e.Active && e.Tag == tag {
			return e
		}
	}
	return nil
}

func (s *Scene) FindAllByTag(tag string) []*Entity {
	var result []*Entity
	for _, e := range s.entities {
		if e.Active && e.Tag == tag {
			result = append(result, e)
		}
	}
	return result
}

func (s *Scene) ForEach(fn func(e *Entity)) {
	for _, e := range s.entities {
		if e.Active {
			fn(e)
		}
	}
}

func (s *Scene) VisibleEntities() []*Entity {
	s.visibleBuf = s.visibleBuf[:0]
	for _, e := range s.entities {
		if e.Active && e.Visible {
			s.visibleBuf = append(s.visibleBuf, e)
		}
	}
	return s.visibleBuf
}

// EntityCount returns the number of active entities in the scene.
// Note: scene2d supports deactivating entities via SetActive without removing them.
func (s *Scene) EntityCount() int {
	n := 0
	for _, e := range s.entities {
		if e.Active {
			n++
		}
	}
	return n
}

// SetActive sets an entity's active state and updates the spatial index accordingly.
// Prefer this over setting e.Active directly when the entity may have moved while inactive.
func (s *Scene) SetActive(e *Entity, active bool) {
	if e.scene != s {
		panic("Scene.SetActive: entity does not belong to this scene")
	}
	if e.Active == active {
		return
	}
	e.Active = active
	if active {
		s.spatialInsert(e)
	} else {
		s.spatialRemove(e)
	}
}

func (s *Scene) Entities() []*Entity {
	result := make([]*Entity, 0, len(s.entities))
	for _, e := range s.entities {
		if e.Active {
			result = append(result, e)
		}
	}
	return result
}

// --- Animation ---

func (s *Scene) UpdateAnimations(dt float64) {
	for _, e := range s.entities {
		if !e.Active {
			continue
		}
		if e.AnimCtrl != nil {
			e.AnimCtrl.Update(dt)
			if e.Sprite != nil {
				e.AnimCtrl.ApplyToSprite(e.Sprite)
			}
		} else if e.Sprite != nil && e.Sprite.Anim != nil {
			e.Sprite.Anim.Update(dt)
		}
	}
}

// --- Physics bridge ---

func (s *Scene) HasPhysics() bool {
	return s.worldID != 0
}

func (s *Scene) ensurePhysics() {
	if s.worldID != 0 {
		return
	}
	s.worldID = physBackend.Init(s.Gravity.X, s.Gravity.Y)
}

func (s *Scene) SetGravity(g voplay.Vec2) {
	s.Gravity = g
	if s.worldID != 0 {
		physBackend.SetGravity(s.worldID, g.X, g.Y)
	}
}

func (s *Scene) StepAndSyncPhysics(dt float64) {
	if s.worldID == 0 {
		return
	}
	state := physBackend.Step(s.worldID, dt, s.physCmds.Bytes())
	s.physCmds.Reset()
	r := codec.NewByteReader(state)
	if r.Remaining() < 4 {
		return
	}

	count := r.ReadU32()

	for i := 0; i < count; i++ {
		if r.Remaining() < 44 {
			break
		}
		bodyID := r.ReadU32()
		x := r.ReadF64()
		y := r.ReadF64()
		rotation := r.ReadF64()
		vx := r.ReadF64()
		vy := r.ReadF64()

		if e, ok := s.bodyMap[bodyID]; ok && e.Active {
			e.position = voplay.Vec2{x, y}
			e.rotation = rotation
			e.Physics.velocity = voplay.Vec2{vx, vy}
			s.spatialUpdate(e)
		}
	}
}

func (s *Scene) Contacts() []Contact {
	if s.worldID == 0 {
		return nil
	}
	data := physBackend.Contacts(s.worldID)
	r := codec.NewByteReader(data)
	if r.Remaining() < 4 {
		return nil
	}
	count := r.ReadU32()
	var contacts []Contact
	for i := 0; i < count; i++ {
		if r.Remaining() < 8 {
			break
		}
		idA := r.ReadU32()
		idB := r.ReadU32()
		a, okA := s.bodyMap[idA]
		b, okB := s.bodyMap[idB]
		if okA && okB && a.Active && b.Active {
			contacts = append(contacts, Contact{A: a, B: b})
		}
	}
	return contacts
}

func (s *Scene) RayCast(origin, dir voplay.Vec2, maxDist float64) *RayCastHit {
	if s.worldID == 0 {
		return nil
	}
	data := physBackend.RayCast(s.worldID, origin.X, origin.Y, dir.X, dir.Y, maxDist)
	if len(data) < 1 || data[0] == 0 {
		return nil
	}
	r := codec.NewByteReader(data[1:])
	bodyID := r.ReadU32()
	hx := r.ReadF64()
	hy := r.ReadF64()
	nx := r.ReadF64()
	ny := r.ReadF64()
	dist := r.ReadF64()
	ent, ok := s.bodyMap[bodyID]
	if !ok {
		return nil
	}
	return &RayCastHit{
		Entity:   ent,
		Point:    voplay.Vec2{hx, hy},
		Normal:   voplay.Vec2{nx, ny},
		Distance: dist,
	}
}

func (s *Scene) QueryRect(rect voplay.Rect) []*Entity {
	if s.worldID == 0 {
		return nil
	}
	data := physBackend.QueryRect(s.worldID, rect.X, rect.Y, rect.X+rect.W, rect.Y+rect.H)
	r := codec.NewByteReader(data)
	if r.Remaining() < 4 {
		return nil
	}
	count := r.ReadU32()
	var result []*Entity
	for i := 0; i < count; i++ {
		if r.Remaining() < 4 {
			break
		}
		bodyID := r.ReadU32()
		if ent, ok := s.bodyMap[bodyID]; ok && ent.Active {
			result = append(result, ent)
		}
	}
	return result
}

// Spatial hash index for efficient 2D entity queries.
// Entities are bucketed by their axis-aligned bounding rect into a uniform grid.
package scene2d

import "math"
import "github.com/vo-lang/voplay"

const defaultSpatialCellSize = 128.0

func spatialCellKey(x, y int) int64 {
	return (int64(x) << 32) ^ int64(int32(y))
}

// spatialCellsIntoBuf fills s.cellScratch with the cell keys covering bounds,
// growing it only when needed. The returned slice aliases s.cellScratch;
// callers must not retain it across any call that reuses s.cellScratch.
func (s *Scene) spatialCellsIntoBuf(bounds voplay.Rect) []int64 {
	cellSize := s.spatialCellSize
	minX := int(math.Floor(bounds.X / cellSize))
	minY := int(math.Floor(bounds.Y / cellSize))
	maxXEdge := bounds.X + bounds.W
	maxYEdge := bounds.Y + bounds.H
	if bounds.W > 0 {
		maxXEdge -= 0.000001
	}
	if bounds.H > 0 {
		maxYEdge -= 0.000001
	}
	if maxXEdge < bounds.X {
		maxXEdge = bounds.X
	}
	if maxYEdge < bounds.Y {
		maxYEdge = bounds.Y
	}
	maxX := int(math.Floor(maxXEdge / cellSize))
	maxY := int(math.Floor(maxYEdge / cellSize))
	n := (maxX - minX + 1) * (maxY - minY + 1)
	if cap(s.cellScratch) < n {
		s.cellScratch = make([]int64, 0, n)
	} else {
		s.cellScratch = s.cellScratch[:0]
	}
	for cy := minY; cy <= maxY; cy++ {
		for cx := minX; cx <= maxX; cx++ {
			s.cellScratch = append(s.cellScratch, spatialCellKey(cx, cy))
		}
	}
	return s.cellScratch
}

// spatialCellsForBounds allocates a fresh slice owned by the caller (used in spatialInsert
// where the entity needs to retain the cells slice).
func (s *Scene) spatialCellsForBounds(bounds voplay.Rect) []int64 {
	result := s.spatialCellsIntoBuf(bounds)
	out := make([]int64, len(result))
	copy(out, result)
	return out
}

func spatialCellsEqual(a, b []int64) bool {
	if len(a) != len(b) {
		return false
	}
	for i := range a {
		if a[i] != b[i] {
			return false
		}
	}
	return true
}

// spatialInsert inserts an entity into the spatial index.
func (s *Scene) spatialInsert(e *Entity) {
	if !e.Active {
		return
	}
	cells := s.spatialCellsForBounds(e.Bounds())
	e.spatialCells = cells
	for _, cell := range cells {
		s.spatialBuckets[cell] = append(s.spatialBuckets[cell], e)
	}
}

// spatialRemove removes an entity from the spatial index.
func (s *Scene) spatialRemove(e *Entity) {
	for _, cell := range e.spatialCells {
		bucket := s.spatialBuckets[cell]
		for i, candidate := range bucket {
			if candidate == e {
				last := len(bucket) - 1
				bucket[i] = bucket[last]
				bucket[last] = nil
				bucket = bucket[:last]
				if len(bucket) == 0 {
					delete(s.spatialBuckets, cell)
				} else {
					s.spatialBuckets[cell] = bucket
				}
				break
			}
		}
	}
	e.spatialCells = nil
}

// spatialUpdate updates the spatial index for an entity.
func (s *Scene) spatialUpdate(e *Entity) {
	if e.scene != s || !e.Active {
		return
	}
	// Use scratch buffer to check if cells changed — avoids allocation in the common case
	newCells := s.spatialCellsIntoBuf(e.Bounds())
	if spatialCellsEqual(e.spatialCells, newCells) {
		return
	}
	s.spatialRemove(e)
	// Copy scratch to a permanent slice owned by the entity.
	e.spatialCells = make([]int64, len(newCells))
	copy(e.spatialCells, newCells)
	for _, cell := range e.spatialCells {
		s.spatialBuckets[cell] = append(s.spatialBuckets[cell], e)
	}
}

func (s *Scene) rebuildSpatialIndex() {
	for cell := range s.spatialBuckets {
		delete(s.spatialBuckets, cell)
	}
	for _, e := range s.entities {
		e.spatialCells = nil
		if e.Active {
			s.spatialInsert(e)
		}
	}
}

// nextSpatialQueryTick returns the next spatial query tick.
func (s *Scene) nextSpatialQueryTick() int {
	s.spatialQueryTick++
	if s.spatialQueryTick == 0 {
		s.spatialQueryTick = 1
		for _, e := range s.entities {
			e.spatialQueryTick = 0
		}
	}
	return s.spatialQueryTick
}

// visibleInRect returns the visible entities in the given rect.
func (s *Scene) visibleInRect(rect voplay.Rect) []*Entity {
	queryTick := s.nextSpatialQueryTick()
	s.visibleBuf = s.visibleBuf[:0]
	for _, cell := range s.spatialCellsIntoBuf(rect) {
		bucket := s.spatialBuckets[cell]
		for _, e := range bucket {
			if !e.Active || !e.Visible || e.spatialQueryTick == queryTick {
				continue
			}
			e.spatialQueryTick = queryTick
			if e.Bounds().Intersects(rect) {
				s.visibleBuf = append(s.visibleBuf, e)
			}
		}
	}
	return s.visibleBuf
}

func (s *Scene) visibleInView(screenW, screenH float64) []*Entity {
	return s.visibleInRect(s.Camera.ViewRect(screenW, screenH))
}

// --- Public spatial API ---

func (s *Scene) SetSpatialCellSize(size float64) {
	if size <= 0 {
		panic("Scene.SetSpatialCellSize: size must be > 0")
	}
	s.spatialCellSize = size
	s.rebuildSpatialIndex()
}

func (s *Scene) SpatialCellSize() float64 {
	return s.spatialCellSize
}

func (s *Scene) FindInRadius(x, y, radius float64) []*Entity {
	rSq := radius * radius
	queryRect := voplay.Rect{X: x - radius, Y: y - radius, W: radius * 2, H: radius * 2}
	queryTick := s.nextSpatialQueryTick()
	var result []*Entity
	for _, cell := range s.spatialCellsIntoBuf(queryRect) {
		bucket := s.spatialBuckets[cell]
		for _, e := range bucket {
			if !e.Active || e.spatialQueryTick == queryTick {
				continue
			}
			e.spatialQueryTick = queryTick
			dx := e.position.X - x
			dy := e.position.Y - y
			if dx*dx+dy*dy <= rSq {
				result = append(result, e)
			}
		}
	}
	return result
}

func (s *Scene) FindInRect(rect voplay.Rect) []*Entity {
	queryTick := s.nextSpatialQueryTick()
	var result []*Entity
	for _, cell := range s.spatialCellsIntoBuf(rect) {
		bucket := s.spatialBuckets[cell]
		for _, e := range bucket {
			if !e.Active || e.spatialQueryTick == queryTick {
				continue
			}
			e.spatialQueryTick = queryTick
			if e.Bounds().Intersects(rect) {
				result = append(result, e)
			}
		}
	}
	return result
}

// Sprite, SpriteSheet, and Animation types for 2D rendering.
package scene2d

import "github.com/vo-lang/voplay"

// Sprite represents a 2D image or animation frame.
type Sprite struct {
	Texture  voplay.TextureID
	SrcX     float64 // source rect within texture (pixels)
	SrcY     float64
	SrcW     float64
	SrcH     float64
	FlipX    bool
	FlipY    bool
	Rotation float64 // radians
	Tint     voplay.Color   // multiply tint (default: White = no tint)
	Anim     *Animation
}

// NewSprite creates a sprite using the full texture with no tint.
func NewSprite(tex voplay.TextureID, w, h float64) *Sprite {
	return &Sprite{
		Texture: tex,
		SrcW:    w,
		SrcH:    h,
		Tint:    voplay.White,
	}
}

// SpriteSheet describes a grid-based atlas for animation frames.
type SpriteSheet struct {
	Texture voplay.TextureID
	FrameW  int
	FrameH  int
	Columns int
}

// NewSpriteSheet creates a sprite sheet descriptor.
func NewSpriteSheet(tex voplay.TextureID, frameW, frameH, columns int) *SpriteSheet {
	return &SpriteSheet{
		Texture: tex,
		FrameW:  frameW,
		FrameH:  frameH,
		Columns: columns,
	}
}

// Frame returns the source rect for frame index i.
func (ss *SpriteSheet) Frame(i int) (float64, float64, float64, float64) {
	col := i % ss.Columns
	row := i / ss.Columns
	x := float64(col * ss.FrameW)
	y := float64(row * ss.FrameH)
	return x, y, float64(ss.FrameW), float64(ss.FrameH)
}

// Animation plays through a sequence of sprite sheet frames.
type Animation struct {
	Sheet  *SpriteSheet
	Frames []int   // frame indices within the sheet
	FPS    float64
	Loop   bool

	time    float64
	current int
	done    bool
}

// Update advances the animation by dt seconds.
func (a *Animation) Update(dt float64) {
	if len(a.Frames) == 0 {
		panic("Animation.Update: Frames must not be empty")
	}
	if a.FPS <= 0 {
		panic("Animation.Update: FPS must be > 0")
	}
	if a.done {
		return
	}
	a.time += dt
	frameDur := 1.0 / a.FPS
	for a.time >= frameDur {
		a.time -= frameDur
		a.current++
		if a.current >= len(a.Frames) {
			if a.Loop {
				a.current = 0
			} else {
				a.current = len(a.Frames) - 1
				a.done = true
				return
			}
		}
	}
}

// CurrentFrame returns the source rect of the current animation frame.
func (a *Animation) CurrentFrame() (float64, float64, float64, float64) {
	return a.Sheet.Frame(a.Frames[a.current])
}

// Done returns true if a non-looping animation has finished.
func (a *Animation) Done() bool {
	return a.done
}

// Reset restarts the animation from the beginning.
func (a *Animation) Reset() {
	a.time = 0
	a.current = 0
	a.done = false
}

// Tilemap, TileSet, and TileLayer types for 2D tile-based rendering.
package scene2d

import "math"
import "github.com/vo-lang/voplay"

// TileSet describes the texture atlas used by a tilemap.
// Tiles are arranged in a grid: tile index 0 = first tile, wrapping by Columns.
// Tile index -1 means empty (transparent).
type TileSet struct {
	Texture voplay.TextureID
	TileW   int
	TileH   int
	Columns int
}

// TileLayer holds a single layer of tile indices.
type TileLayer struct {
	Tiles []int // row-major: index = row * width + col; -1 = empty
}

// Tilemap is a multi-layer grid of tiles.
type Tilemap struct {
	TileSet *TileSet
	Width   int // in tiles
	Height  int // in tiles
	Layers  []*TileLayer

	dirty bool // true if tile data changed since last upload
}

// NewTilemap creates a tilemap with the given dimensions and one default layer.
func NewTilemap(ts *TileSet, width, height int) *Tilemap {
	layer := &TileLayer{
		Tiles: make([]int, width*height),
	}
	// Initialize all tiles to -1 (empty)
	for i := range layer.Tiles {
		layer.Tiles[i] = -1
	}
	return &Tilemap{
		TileSet: ts,
		Width:   width,
		Height:  height,
		Layers:  []*TileLayer{layer},
		dirty:   true,
	}
}

// AddLayer adds a new empty layer and returns its index.
func (t *Tilemap) AddLayer() int {
	layer := &TileLayer{
		Tiles: make([]int, t.Width*t.Height),
	}
	for i := range layer.Tiles {
		layer.Tiles[i] = -1
	}
	t.Layers = append(t.Layers, layer)
	t.dirty = true
	return len(t.Layers) - 1
}

// SetTile sets the tile index at (col, row) in the given layer.
func (t *Tilemap) SetTile(layer, col, row, tileIdx int) {
	if layer < 0 || layer >= len(t.Layers) {
		panic("SetTile: layer index out of range")
	}
	if col < 0 || col >= t.Width || row < 0 || row >= t.Height {
		panic("SetTile: col/row out of range")
	}
	t.Layers[layer].Tiles[row*t.Width+col] = tileIdx
	t.dirty = true
}

// GetTile returns the tile index at (col, row) in the given layer.
func (t *Tilemap) GetTile(layer, col, row int) int {
	if layer < 0 || layer >= len(t.Layers) {
		panic("GetTile: layer index out of range")
	}
	if col < 0 || col >= t.Width || row < 0 || row >= t.Height {
		panic("GetTile: col/row out of range")
	}
	return t.Layers[layer].Tiles[row*t.Width+col]
}

// Fill sets all tiles in a layer to the given index.
func (t *Tilemap) Fill(layer, tileIdx int) {
	if layer < 0 || layer >= len(t.Layers) {
		panic("Fill: layer index out of range")
	}
	for i := range t.Layers[layer].Tiles {
		t.Layers[layer].Tiles[i] = tileIdx
	}
	t.dirty = true
}

// FillRect fills a rectangular region in a layer with a tile index.
func (t *Tilemap) FillRect(layer, col, row, w, h, tileIdx int) {
	if layer < 0 || layer >= len(t.Layers) {
		panic("FillRect: layer index out of range")
	}
	startRow := row
	if startRow < 0 {
		startRow = 0
	}
	endRow := row + h
	if endRow > t.Height {
		endRow = t.Height
	}
	startCol := col
	if startCol < 0 {
		startCol = 0
	}
	endCol := col + w
	if endCol > t.Width {
		endCol = t.Width
	}
	for r := startRow; r < endRow; r++ {
		for c := startCol; c < endCol; c++ {
			t.Layers[layer].Tiles[r*t.Width+c] = tileIdx
		}
	}
	t.dirty = true
}

// PixelWidth returns the tilemap width in pixels.
func (t *Tilemap) PixelWidth() int {
	return t.Width * t.TileSet.TileW
}

// PixelHeight returns the tilemap height in pixels.
func (t *Tilemap) PixelHeight() int {
	return t.Height * t.TileSet.TileH
}

// WorldToTile converts world coordinates to tile coordinates.
// Uses math.Floor so that negative world coordinates map to the correct tile
// (e.g. wx = -0.5, TileW = 32 → col = -1, not 0).
func (t *Tilemap) WorldToTile(wx, wy float64) (int, int) {
	col := int(math.Floor(wx / float64(t.TileSet.TileW)))
	row := int(math.Floor(wy / float64(t.TileSet.TileH)))
	return col, row
}

// TileToWorld converts tile coordinates to world coordinates (top-left of tile).
func (t *Tilemap) TileToWorld(col, row int) (float64, float64) {
	return float64(col * t.TileSet.TileW), float64(row * t.TileSet.TileH)
}

// IsDirty returns true if tile data needs re-upload.
func (t *Tilemap) IsDirty() bool {
	return t.dirty
}

// MarkClean clears the dirty flag after upload.
func (t *Tilemap) MarkClean() {
	t.dirty = false
}

package scene3d

import "github.com/vo-lang/voplay"
import "github.com/vo-lang/voplay/codec"

type AnimationClipID int

type AnimationClipInfo struct {
	Name     string
	Duration float64
}

type AnimationModelInfo struct {
	HasSkeleton bool
	JointCount  int
	Clips       []AnimationClipInfo
}

// AnimationBackend abstracts animation system operations so they can be
// replaced in tests without per-function hook boilerplate.
type AnimationBackend interface {
	Init() int
	Destroy(worldID int)
	Play(worldID, targetID int, clip AnimationClipID, loop bool, speed float64)
	Stop(worldID, targetID int)
	Crossfade(worldID, targetID int, clip AnimationClipID, duration float64)
	SetSpeed(worldID, targetID int, speed float64)
	RemoveTarget(worldID, targetID int)
	Tick(worldID int, dt float64, entityModelMap []byte)
	Progress(worldID, targetID int, model voplay.ModelID) float64
	ModelInfo(model voplay.ModelID) AnimationModelInfo
}

type defaultAnimationBackend struct{}

func (defaultAnimationBackend) Init() int                { return voplay.AnimationRuntimeInit() }
func (defaultAnimationBackend) Destroy(worldID int)      { voplay.AnimationRuntimeDestroy(worldID) }

func (defaultAnimationBackend) Play(worldID, targetID int, clip AnimationClipID, loop bool, speed float64) {
	voplay.AnimationRuntimePlay(worldID, targetID, int(clip), loop, speed)
}

func (defaultAnimationBackend) Stop(worldID, targetID int) {
	voplay.AnimationRuntimeStop(worldID, targetID)
}

func (defaultAnimationBackend) Crossfade(worldID, targetID int, clip AnimationClipID, duration float64) {
	voplay.AnimationRuntimeCrossfade(worldID, targetID, int(clip), duration)
}

func (defaultAnimationBackend) SetSpeed(worldID, targetID int, speed float64) {
	voplay.AnimationRuntimeSetSpeed(worldID, targetID, speed)
}

func (defaultAnimationBackend) RemoveTarget(worldID, targetID int) {
	voplay.AnimationRuntimeRemoveTarget(worldID, targetID)
}

func (defaultAnimationBackend) Tick(worldID int, dt float64, entityModelMap []byte) {
	voplay.AnimationRuntimeTick(worldID, dt, entityModelMap)
}

func (defaultAnimationBackend) Progress(worldID, targetID int, model voplay.ModelID) float64 {
	return voplay.AnimationRuntimeProgress(worldID, targetID, int(model))
}

func (defaultAnimationBackend) ModelInfo(model voplay.ModelID) AnimationModelInfo {
	return decodeAnimationModelInfo(voplay.AnimationRuntimeModelInfo(int(model)))
}

var animBackend AnimationBackend = defaultAnimationBackend{}

// SetAnimationBackend replaces the active animation backend and returns the previous one.
func SetAnimationBackend(b AnimationBackend) AnimationBackend {
	prev := animBackend
	animBackend = b
	return prev
}

func (s *Scene) ensureAnimation() {
	if s.animationWorldID != 0 {
		return
	}
	s.animationWorldID = animBackend.Init()
}

func (s *Scene) ensureAnimationTarget(e *Entity) int {
	if e.scene != s {
		panic("Scene.ensureAnimationTarget: entity does not belong to this scene")
	}
	if e.animationTargetID != 0 {
		return e.animationTargetID
	}
	s.ensureAnimation()
	e.animationTargetID = s.nextAnimationTargetID
	s.nextAnimationTargetID++
	return e.animationTargetID
}

func decodeAnimationModelInfo(data []byte) AnimationModelInfo {
	r := codec.NewByteReader(data)
	info := AnimationModelInfo{}
	info.HasSkeleton = r.ReadByte() != 0
	info.JointCount = r.ReadU32()
	clipCount := r.ReadU32()
	if clipCount > 0 {
		info.Clips = make([]AnimationClipInfo, 0, clipCount)
	}
	for i := 0; i < clipCount; i++ {
		duration := r.ReadF32()
		nameLen := r.ReadU16()
		name := string(r.ReadBytes(nameLen))
		info.Clips = append(info.Clips, AnimationClipInfo{
			Name:     name,
			Duration: duration,
		})
	}
	return info
}

func (s *Scene) AnimationModelInfo(model voplay.ModelID) AnimationModelInfo {
	if info, ok := s.animationInfoCache[int(model)]; ok {
		return info
	}
	info := animBackend.ModelInfo(model)
	s.animationInfoCache[int(model)] = info
	return info
}

func (e *Entity) AnimationModelInfo() AnimationModelInfo {
	if e.scene == nil {
		panic("Entity.AnimationModelInfo: entity does not belong to a scene")
	}
	return e.scene.AnimationModelInfo(e.Model)
}

func (e *Entity) requireAnimationModel(method string) AnimationModelInfo {
	if e.scene == nil || !e.Active {
		panic(method + ": entity must belong to an active scene")
	}
	if e.Model == 0 {
		panic(method + ": entity must have a model")
	}
	info := e.scene.AnimationModelInfo(e.Model)
	if !info.HasSkeleton {
		panic(method + ": model has no skeleton")
	}
	if len(info.Clips) == 0 {
		panic(method + ": model has no animation clips")
	}
	return info
}

func validateAnimationClip(method string, info AnimationModelInfo, clip AnimationClipID) {
	index := int(clip)
	if index < 0 || index >= len(info.Clips) {
		panic(method + ": clip index out of range")
	}
}

func (e *Entity) requireAnimationState(method string) int {
	if e.scene == nil || !e.Active {
		panic(method + ": entity must belong to an active scene")
	}
	if e.animationTargetID == 0 || e.scene.animationWorldID == 0 {
		panic(method + ": entity has no active animation state")
	}
	return e.animationTargetID
}

func (e *Entity) PlayAnimation(clip AnimationClipID, loop bool) {
	info := e.requireAnimationModel("Entity.PlayAnimation")
	validateAnimationClip("Entity.PlayAnimation", info, clip)
	targetID := e.scene.ensureAnimationTarget(e)
	animBackend.Play(e.scene.animationWorldID, targetID, clip, loop, 1.0)
}

func (e *Entity) PlayAnimationEx(clip AnimationClipID, loop bool, speed float64) {
	info := e.requireAnimationModel("Entity.PlayAnimationEx")
	validateAnimationClip("Entity.PlayAnimationEx", info, clip)
	targetID := e.scene.ensureAnimationTarget(e)
	animBackend.Play(e.scene.animationWorldID, targetID, clip, loop, speed)
}

func (e *Entity) StopAnimation() {
	if e.scene == nil || e.animationTargetID == 0 || e.scene.animationWorldID == 0 {
		return
	}
	animBackend.Stop(e.scene.animationWorldID, e.animationTargetID)
}

func (e *Entity) CrossfadeTo(clip AnimationClipID, duration float64) {
	info := e.requireAnimationModel("Entity.CrossfadeTo")
	validateAnimationClip("Entity.CrossfadeTo", info, clip)
	targetID := e.requireAnimationState("Entity.CrossfadeTo")
	animBackend.Crossfade(e.scene.animationWorldID, targetID, clip, duration)
}

func (e *Entity) SetAnimationSpeed(speed float64) {
	e.requireAnimationModel("Entity.SetAnimationSpeed")
	targetID := e.requireAnimationState("Entity.SetAnimationSpeed")
	animBackend.SetSpeed(e.scene.animationWorldID, targetID, speed)
}

func (e *Entity) AnimationProgress() float64 {
	if e.scene == nil || e.animationTargetID == 0 || e.scene.animationWorldID == 0 || e.Model == 0 {
		return 0
	}
	return animBackend.Progress(e.scene.animationWorldID, e.animationTargetID, e.Model)
}

func (s *Scene) serializeAnimatedEntityModelMap() []byte {
	count := 0
	for _, e := range s.entities {
		if e.Active && e.Model != 0 && e.animationTargetID != 0 {
			count++
		}
	}
	w := codec.NewByteWriter(4 + count*8)
	w.WriteU32(count)
	for _, e := range s.entities {
		if e.Active && e.Model != 0 && e.animationTargetID != 0 {
			w.WriteU32(e.animationTargetID)
			w.WriteU32(int(e.Model))
		}
	}
	return w.Bytes()
}

func (s *Scene) TickAnimations(dt float64) {
	if s.animationWorldID == 0 {
		return
	}
	animBackend.Tick(s.animationWorldID, dt, s.serializeAnimatedEntityModelMap())
}

// Camera defines the 3D viewport: position, target, field of view, and clip planes.
package scene3d

import "math"
import "github.com/vo-lang/voplay"

type Camera struct {
	Position voplay.Vec3
	Target   voplay.Vec3    // look-at point
	Up       voplay.Vec3    // up vector (default: 0, 1, 0)
	Fov      float64 // field of view in degrees (default: 60)
	Near     float64 // near clip plane (default: 0.1)
	Far      float64 // far clip plane (default: 1000)
}

// LookAt sets the camera position and target.
func (c *Camera) LookAt(position, target voplay.Vec3) {
	c.Position = position
	c.Target = target
}

// Orbit positions the camera at a given distance from center,
// looking at center, using spherical coordinates (yaw, pitch in radians).
func (c *Camera) Orbit(center voplay.Vec3, distance, yaw, pitch float64) {
	// Clamp pitch to avoid flipping
	if pitch > 1.5 {
		pitch = 1.5
	}
	if pitch < -1.5 {
		pitch = -1.5
	}
	cp := math.Cos(pitch)
	c.Position = voplay.Vec3{
		center.X + distance*math.Cos(yaw)*cp,
		center.Y + distance*math.Sin(pitch),
		center.Z + distance*math.Sin(yaw)*cp,
	}
	c.Target = center
}

// ScreenToRay returns a ray origin and direction for a screen-space pixel.
// screenW, screenH are the window dimensions.
func (c *Camera) ScreenToRay(screenX, screenY, screenW, screenH float64) (voplay.Vec3, voplay.Vec3) {
	// Compute normalized device coordinates (-1 to 1)
	nx := (2.0*screenX/screenW - 1.0)
	ny := (1.0 - 2.0*screenY/screenH)

	// Build camera basis vectors
	forward := c.Target.Sub(c.Position).Normalize()
	right := forward.Cross(c.Up).Normalize()
	up := right.Cross(forward)

	// Compute half-extents based on FOV and aspect
	fovRad := c.Fov * math.Pi / 180.0
	halfH := math.Tan(fovRad / 2.0)
	aspect := screenW / screenH
	halfW := halfH * aspect

	// Ray direction in world space
	dir := forward.Add(right.Scale(nx * halfW)).Add(up.Scale(ny * halfH)).Normalize()
	return c.Position, dir
}

package scene3d

import (
	"errors"
	"github.com/vo-lang/voplay"
)

type DecalDesc struct {
	Position voplay.Vec3
	Yaw float64
	Width float64
	Height float64
	SurfaceOffset float64
	Material voplay.MaterialDesc
	Model voplay.ModelID
	Tag string
}

type Decal struct {
	Entity *Entity
	model voplay.ModelID
	ownedModel bool
}

func SpawnDecal(scene *Scene, desc DecalDesc) (*Decal, error) {
	if scene == nil {
		return nil, errors.New("scene3d.SpawnDecal: scene is nil")
	}
	desc = normalizeDecalDesc(desc)
	model := desc.Model
	owned := false
	if model == 0 {
		model = PlaneMesh(desc.Width, desc.Height, 1, 1)
		owned = true
	}
	tag := desc.Tag
	if tag == "" {
		tag = "decal"
	}
	entity := scene.Spawn(EntityDesc{Position: desc.Position.Add(voplay.Vec3{Y: desc.SurfaceOffset}), Rotation: voplay.QuatFromAxisAngle(voplay.Vec3{Y: 1}, desc.Yaw), Scale: voplay.Vec3{X: 1, Y: 1, Z: 1}, Model: model, Material: desc.Material, Tag: tag, PickMode: PickDisabled})
	return &Decal{Entity: entity, model: model, ownedModel: owned}, nil
}

func SpawnTrackDecal(scene *Scene, track *Track, distance, lateral float64, desc DecalDesc) (*Decal, error) {
	if track == nil {
		return nil, errors.New("scene3d.SpawnTrackDecal: track is nil")
	}
	pose := track.PoseAt(distance)
	desc.Position = pose.Position.Add(pose.Right.Scale(lateral))
	desc.Yaw = pose.Yaw
	return SpawnDecal(scene, desc)
}

func (d *Decal) Destroy(scene *Scene) {
	if d == nil {
		return
	}
	if d.Entity != nil && scene != nil && d.Entity.scene == scene && d.Entity.Active {
		scene.Destroy(d.Entity)
	}
	d.Entity = nil
	if d.ownedModel && d.model != 0 {
		d.model.Free()
		d.model = 0
		d.ownedModel = false
	}
}

func normalizeDecalDesc(desc DecalDesc) DecalDesc {
	if desc.Width <= 0 {
		desc.Width = 1
	}
	if desc.Height <= 0 {
		desc.Height = 1
	}
	if desc.SurfaceOffset <= 0 {
		desc.SurfaceOffset = 0.035
	}
	desc.Material = voplay.NormalizeMaterial(desc.Material)
	return desc
}

// Scene3D draw convenience functions.
// These wrap voplay.DrawCtx methods with scene3d types (Scene, Light).
package scene3d

import "math"
import "strconv"
import "time"
import "github.com/vo-lang/voplay"

// SetLights encodes the lighting state for subsequent 3D draw commands.
func SetLights(d *voplay.DrawCtx, ambientSky, ambientGround voplay.Color, lights []Light) {
	d.SetLights3D(ambientSky, ambientGround, lights)
}

func (s *Scene) writeFrame3DState(d *voplay.DrawCtx) {
	c := &s.Camera
	d.SetCamera3D(c.Position, c.Target, c.Up, c.Fov, c.Near, c.Far)
	d.SetShadow3D(s.ShadowsEnabled, s.ShadowResolution, normalizeShadowStrength(s.ShadowStrength))
	if s.Skybox != 0 {
		d.DrawSkybox(s.Skybox)
	}
	SetLights(d, s.Ambient, normalizeAmbientGround(s.Ambient, s.AmbientGround), s.Lights)
	if s.Fog.Mode != voplay.FogNone {
		d.SetFog3D(s.Fog.Mode, s.Fog.Color, s.Fog.Start, s.Fog.End, s.Fog.Density)
	}
	grading := normalizeColorGrading(s.ColorGrading)
	d.SetColorGrading3D(grading.ToneMap, grading.Exposure, grading.Contrast, grading.Saturation)
	d.SetRenderDebug3D(s.RenderDebugMode)
}

func (e *Entity) renderObjectNeedsUpsert(model voplay.ModelID, visible bool, animationWorldID, animationTargetID int) bool {
	return !e.renderObjectCreated ||
		e.renderLastModel != model ||
		e.renderLastMaterial != e.Material ||
		e.renderLastPosition != e.position ||
		e.renderLastRotation != e.rotation ||
		e.renderLastScale != e.scale ||
		e.renderLastTint != e.Tint ||
		e.renderLastVisible != visible ||
		e.renderLastAnimationWorldID != animationWorldID ||
		e.renderLastAnimationTargetID != animationTargetID
}

func (e *Entity) rememberRenderedObject(model voplay.ModelID, visible bool, animationWorldID, animationTargetID int) {
	e.renderObjectCreated = true
	e.renderLastModel = model
	e.renderLastMaterial = e.Material
	e.renderLastPosition = e.position
	e.renderLastRotation = e.rotation
	e.renderLastScale = e.scale
	e.renderLastTint = e.Tint
	e.renderLastVisible = visible
	e.renderLastAnimationWorldID = animationWorldID
	e.renderLastAnimationTargetID = animationTargetID
}

func (s *Scene) flushRenderScene(d *voplay.DrawCtx) {
	start := time.Now()
	stats := SceneRenderStats{}
	batchGroups := map[string]bool{}
	if !s.renderSceneCreated {
		s.renderSceneCreated = true
	}
	if s.renderSceneCleared {
		d.ClearScene3D(s.renderSceneID)
		s.renderSceneCleared = false
	}
	for _, id := range s.renderDestroyedIDs {
		d.DestroyScene3DObject(s.renderSceneID, id)
		stats.DestroyedObjects++
	}
	s.renderDestroyedIDs = s.renderDestroyedIDs[:0]

	for _, n := range s.entities {
		if !n.Active {
			continue
		}
		stats.ActiveEntities++
		if n.Model == 0 {
			if n.renderObjectCreated {
				d.DestroyScene3DObject(s.renderSceneID, n.id)
				n.renderObjectCreated = false
				stats.DestroyedObjects++
			}
			continue
		}
		stats.ModelEntities++

		n.ensureHasSkeleton()
		animationWorldID := 0
		animationTargetID := 0
		if n.hasSkeleton && s.animationWorldID != 0 && n.animationTargetID != 0 {
			animationWorldID = s.animationWorldID
			animationTargetID = n.animationTargetID
		}
		culled := s.entityCulled(n)
		visible := n.Visible && !culled
		if visible {
			stats.VisibleEntities++
		}
		if culled {
			stats.CulledEntities++
		}
		if visible && n.StaticRenderable && !n.hasSkeleton {
			stats.BatchEligibleObjects++
			batchGroups[sceneRenderBatchKey(n)] = true
		}
		if !n.renderObjectNeedsUpsert(n.Model, visible, animationWorldID, animationTargetID) {
			continue
		}
		d.UpsertScene3DObject(
			s.renderSceneID,
			n.id,
			n.Model,
			n.position,
			n.rotation,
			n.scale,
			n.Material,
			visible,
			animationWorldID,
			animationTargetID,
		)
		stats.UpsertedObjects++
		n.rememberRenderedObject(n.Model, visible, animationWorldID, animationTargetID)
	}
	s.flushPrimitiveLayers(d, &stats, batchGroups)
	stats.BatchGroups = len(batchGroups)
	stats.FlushCpuMs = float64(time.Now().Sub(start).Nanoseconds()) / 1000000.0
	s.renderStats = stats
}

func (s *Scene) entityCulled(e *Entity) bool {
	if e == nil {
		return true
	}
	if e.CullDistance > 0 && e.position.Distance(s.Camera.Position)-e.CullRadius > e.CullDistance {
		return true
	}
	if e.FrustumCull && !s.cameraSeesSphere(e.position, e.CullRadius) {
		return true
	}
	return false
}

func (s *Scene) cameraSeesSphere(center voplay.Vec3, radius float64) bool {
	forward := s.Camera.Target.Sub(s.Camera.Position).Normalize()
	if forward.LengthSq() <= 0.000001 {
		return true
	}
	toCenter := center.Sub(s.Camera.Position)
	dist := toCenter.Length()
	if dist <= radius {
		return true
	}
	depth := toCenter.Dot(forward)
	if depth < -radius || depth > s.Camera.Far+radius {
		return false
	}
	halfFov := s.Camera.Fov * math.Pi / 360.0
	if halfFov <= 0 {
		halfFov = math.Pi / 6
	}
	dir := toCenter.Normalize()
	angle := math.Acos(sceneClamp(dir.Dot(forward), -1, 1))
	padding := math.Asin(sceneClamp(radius/dist, 0, 1))
	return angle <= halfFov*1.35+padding
}

func sceneRenderBatchKey(e *Entity) string {
	m := e.Material
	return strconv.Itoa(int(e.Model)) + ":" +
		strconv.Itoa(int(m.ID)) + ":" +
		strconv.Itoa(int(m.Albedo)) + ":" +
		strconv.Itoa(int(m.Normal)) + ":" +
		strconv.Itoa(int(m.MetallicRoughness)) + ":" +
		strconv.Itoa(int(m.Emissive)) + ":" +
		strconv.Itoa(int(m.ToonRamp)) + ":" +
		strconv.FormatFloat(m.NormalScale, 'f', 3, 64) + ":" +
		strconv.Itoa(m.ShadingMode) + ":" +
		strconv.Itoa(m.WrapMode) + ":" +
		strconv.Itoa(m.FilterMode)
}

func sceneClamp(v, lo, hi float64) float64 {
	if v < lo {
		return lo
	}
	if v > hi {
		return hi
	}
	return v
}

func normalizeShadowStrength(strength float64) float64 {
	if strength <= 0 {
		return 1
	}
	return sceneClamp(strength, 0, 1)
}

// Draw renders the entire 3D scene: camera, lights, then all visible entities.
// Resets the camera at the end so subsequent 2D draws (HUD etc.) use screen-space.
func (s *Scene) Draw(d *voplay.DrawCtx) {
	start := time.Now()
	s.writeFrame3DState(d)
	s.flushRenderScene(d)
	d.DrawScene3D(s.renderSceneID)
	for _, emitter := range s.Emitters {
		emitter.Draw(d)
	}
	d.ResetCamera()
	stats := s.renderStats
	stats.FrameCpuMs = float64(time.Now().Sub(start).Nanoseconds()) / 1000000.0
	s.renderStats = stats
}

package scene3d

import (
	"math"
	"github.com/vo-lang/voplay"
)

type KartInput struct {
	Throttle float64
	Steer    float64
	Drift    bool
	Boost    bool
	Reset    bool
}

type KartControllerConfig struct {
	Vehicle              VehicleConfig
	OffroadSpeedScale    float64
	OffroadEngineScale   float64
	MinTurboCharge       float64
	SuperTurboCharge     float64
	MaxDriftCharge       float64
	DriftChargeRate      float64
	MiniTurboDuration    float64
	SuperTurboDuration   float64
	BoostDuration        float64
	Recovery             VehicleRecoveryConfig
}

type KartControllerState struct {
	SurfaceID          string
	SurfaceFriction    float64
	Boosting           bool
	Drifting           bool
	DriftCharge        float64
	MiniTurboReleased  bool
	SuperTurboReleased bool
	Stuck              bool
	UpsideDown         bool
	ShouldRespawn     bool
	Speed              float64
}

type KartController struct {
	Vehicle    *Vehicle
	Track      *Track
	Config     KartControllerConfig
	Recovery   *VehicleRecovery
	BoostTimer float64
	DriftCharge float64
	wasDrifting bool
	state KartControllerState
}

func DefaultKartControllerConfig() KartControllerConfig {
	return KartControllerConfig{
		Vehicle:            DefaultKartVehicleConfig(),
		OffroadSpeedScale:  0.58,
		OffroadEngineScale: 0.72,
		MinTurboCharge:     0.55,
		SuperTurboCharge:   1.08,
		MaxDriftCharge:     1.35,
		DriftChargeRate:    1.05,
		MiniTurboDuration:  0.75,
		SuperTurboDuration: 1.35,
		BoostDuration:      1.0,
		Recovery:           DefaultVehicleRecoveryConfig(),
	}
}

func NewKartController(vehicle *Vehicle, track *Track, config KartControllerConfig) *KartController {
	if vehicle == nil {
		panic("scene3d.NewKartController: vehicle must not be nil")
	}
	config = normalizeKartControllerConfig(config)
	vehicle.Config = config.Vehicle
	vehicle.BindTrack(track)
	return &KartController{Vehicle: vehicle, Track: track, Config: config, Recovery: NewVehicleRecovery(vehicle, track, config.Recovery)}
}

func (k *KartController) BindTrack(track *Track) {
	if k == nil {
		return
	}
	k.Track = track
	if k.Vehicle != nil {
		k.Vehicle.BindTrack(track)
	}
	if k.Recovery != nil {
		k.Recovery.BindTrack(track)
	}
}

func (k *KartController) Update(input KartInput, dt float64) KartControllerState {
	if k == nil || k.Vehicle == nil || dt <= 0 {
		return KartControllerState{}
	}
	k.Vehicle.BindTrack(k.Track)
	surface := k.currentSurface()
	adjusted := k.adjustedVehicleConfig(surface)
	k.Vehicle.Config = adjusted
	if input.Boost {
		k.ActivateBoost(k.Config.BoostDuration)
	}
	boosting := k.BoostTimer > 0
	k.Vehicle.Update(VehicleInput{Throttle: input.Throttle, Steer: input.Steer, Drift: input.Drift, Boost: boosting}, dt)
	k.updateDrift(input, dt)
	recovery := k.updateRecovery(input, dt)
	k.BoostTimer = vehicleMoveTowards(k.BoostTimer, 0, dt)
	k.state.SurfaceID = surface.Name
	k.state.SurfaceFriction = surface.Friction
	k.state.Boosting = boosting
	k.state.Drifting = k.Vehicle.Drifting
	k.state.DriftCharge = k.DriftCharge
	k.state.Speed = math.Abs(k.Vehicle.Speed)
	k.state.Stuck = recovery.Stuck
	k.state.UpsideDown = recovery.UpsideDown
	k.state.ShouldRespawn = recovery.ShouldRespawn
	return k.state
}

func (k *KartController) State() KartControllerState {
	if k == nil {
		return KartControllerState{}
	}
	return k.state
}

func (k *KartController) ActivateBoost(duration float64) {
	if k == nil || duration <= 0 {
		return
	}
	if duration > k.BoostTimer {
		k.BoostTimer = duration
	}
}

func (k *KartController) Respawn(pose TrackPose) {
	if k == nil || k.Vehicle == nil {
		return
	}
	k.Vehicle.SetPose(pose.Position, pose.Yaw)
	k.BoostTimer = 0
	k.DriftCharge = 0
	k.wasDrifting = false
	if k.Recovery != nil {
		k.Recovery.Reset()
	}
	k.state = KartControllerState{}
}

func (k *KartController) RespawnNear(pos voplay.Vec3) {
	if k == nil || k.Track == nil {
		return
	}
	k.Respawn(k.Track.RespawnPoseNear(pos))
}

func (k *KartController) currentSurface() TrackSurfaceHit {
	if k == nil || k.Track == nil || k.Vehicle == nil || k.Vehicle.Body == nil {
		return TrackSurfaceHit{Name: TrackSurfaceRoad, Kind: TrackSurfaceRoad, Friction: 1, OnSurface: true, OnRoad: true}
	}
	return k.Track.SurfaceAt(k.Vehicle.Body.Position())
}

func (k *KartController) adjustedVehicleConfig(surface TrackSurfaceHit) VehicleConfig {
	cfg := cloneVehicleConfig(k.Config.Vehicle)
	friction := surface.Friction
	if friction <= 0 {
		friction = 1
	}
	speedScale := friction
	engineScale := friction
	if !surface.OnRoad {
		speedScale *= k.Config.OffroadSpeedScale
		engineScale *= k.Config.OffroadEngineScale
	}
	cfg.MaxForwardSpeed *= speedScale
	cfg.MaxReverseSpeed *= speedScale
	cfg.EngineForce *= engineScale
	cfg.ReverseEngineForce *= engineScale
	for i := 0; i < len(cfg.Wheels); i++ {
		cfg.Wheels[i].FrictionSlip *= friction
		cfg.Wheels[i].SideFrictionStiffness *= friction
	}
	return cfg
}

func (k *KartController) updateDrift(input KartInput, dt float64) {
	k.state.MiniTurboReleased = false
	k.state.SuperTurboReleased = false
	drifting := k.Vehicle.Drifting
	charging := drifting && math.Abs(input.Steer) > 0.08 && input.Throttle > 0
	if drifting {
		if charging {
			gain := k.Config.DriftChargeRate * (0.55 + math.Abs(input.Steer)*0.65) * dt
			k.DriftCharge = vehicleClamp(k.DriftCharge+gain, 0, k.Config.MaxDriftCharge)
		}
		k.wasDrifting = true
		return
	}
	if k.wasDrifting {
		if k.DriftCharge >= k.Config.SuperTurboCharge {
			k.ActivateBoost(k.Config.SuperTurboDuration)
			k.state.SuperTurboReleased = true
		} else if k.DriftCharge >= k.Config.MinTurboCharge {
			k.ActivateBoost(k.Config.MiniTurboDuration)
			k.state.MiniTurboReleased = true
		}
		k.DriftCharge = 0
		k.wasDrifting = false
		return
	}
	k.DriftCharge = vehicleMoveTowards(k.DriftCharge, 0, dt*1.5)
}

func (k *KartController) updateRecovery(input KartInput, dt float64) VehicleRecoveryState {
	if k.Recovery == nil {
		return VehicleRecoveryState{ShouldRespawn: input.Reset}
	}
	k.Recovery.Config = normalizeVehicleRecoveryConfig(k.Config.Recovery)
	return k.Recovery.Update(VehicleRecoveryInput{Throttle: input.Throttle, Reset: input.Reset}, dt)
}

func normalizeKartControllerConfig(config KartControllerConfig) KartControllerConfig {
	defaults := DefaultKartControllerConfig()
	if len(config.Vehicle.Wheels) == 0 {
		config.Vehicle = defaults.Vehicle
	} else {
		config.Vehicle = normalizeVehicleConfig(config.Vehicle)
	}
	if config.OffroadSpeedScale <= 0 {
		config.OffroadSpeedScale = defaults.OffroadSpeedScale
	}
	if config.OffroadEngineScale <= 0 {
		config.OffroadEngineScale = defaults.OffroadEngineScale
	}
	if config.MinTurboCharge <= 0 {
		config.MinTurboCharge = defaults.MinTurboCharge
	}
	if config.SuperTurboCharge <= 0 {
		config.SuperTurboCharge = defaults.SuperTurboCharge
	}
	if config.MaxDriftCharge <= 0 {
		config.MaxDriftCharge = defaults.MaxDriftCharge
	}
	if config.DriftChargeRate <= 0 {
		config.DriftChargeRate = defaults.DriftChargeRate
	}
	if config.MiniTurboDuration <= 0 {
		config.MiniTurboDuration = defaults.MiniTurboDuration
	}
	if config.SuperTurboDuration <= 0 {
		config.SuperTurboDuration = defaults.SuperTurboDuration
	}
	if config.BoostDuration <= 0 {
		config.BoostDuration = defaults.BoostDuration
	}
	config.Recovery = normalizeVehicleRecoveryConfig(config.Recovery)
	return config
}

func cloneVehicleConfig(config VehicleConfig) VehicleConfig {
	cloned := config
	if len(config.Wheels) > 0 {
		cloned.Wheels = make([]VehicleWheelConfig, len(config.Wheels))
		for i := range config.Wheels {
			cloned.Wheels[i] = config.Wheels[i]
		}
	}
	return cloned
}

package scene3d

import "errors"
import "math"
import "strings"
import "github.com/vo-lang/voplay"
import "github.com/vo-lang/voplay/codec"

const (
	levelNodeEntity  = 0
	levelNodeTerrain = 1
)

type LevelTerrainInfo struct {
	Rows        int
	Cols        int
	Scale       voplay.Vec3
	HeightData  []byte
	Layer       int
	Mask        int
	Friction    float64
	Restitution float64
}

type LevelNodeInfo struct {
	Kind     int
	Name     string
	ModelID  voplay.ModelID
	Position voplay.Vec3
	Rotation voplay.Quat
	Scale    voplay.Vec3
	AABBMin  voplay.Vec3
	AABBMax  voplay.Vec3
	Terrain  *LevelTerrainInfo
}

type LevelNodePlan struct {
	Desc    EntityDesc
	Visible bool
}

type LevelSpawnResult struct {
	Entities []*Entity
	Terrains map[string]*Terrain
}

type levelNodePlanKind int

const (
	levelNodePlanDefault         levelNodePlanKind = 0
	levelNodePlanSpawnMarker     levelNodePlanKind = 1
	levelNodePlanBoxCollider     levelNodePlanKind = 2
	levelNodePlanSphereCollider  levelNodePlanKind = 3
	levelNodePlanCapsuleCollider levelNodePlanKind = 4
	levelNodePlanTrimeshVisible  levelNodePlanKind = 5
	levelNodePlanTrimeshHidden   levelNodePlanKind = 6
)

type levelNodeSpawnResult struct {
	Entity                    *Entity
	Terrain                   *Terrain
	ModelOwnershipTransferred bool
}

func LoadLevel(scene *Scene, path string) ([]*Entity, error) {
	result, err := LoadLevelDetailed(scene, path)
	if err != nil {
		return nil, err
	}
	return result.Entities, nil
}

func LoadLevelDetailed(scene *Scene, path string) (*LevelSpawnResult, error) {
	data := loadLevel(path)?
	return SpawnLevelNodesDetailed(scene, DecodeLevelNodes(data))
}

func SpawnLevelNodesDetailed(scene *Scene, nodes []LevelNodeInfo) (*LevelSpawnResult, error) {
	result := &LevelSpawnResult{
		Entities: make([]*Entity, 0, len(nodes)),
		Terrains: map[string]*Terrain{},
	}
	modelHandled := make([]bool, len(nodes))
	errdefer func() {
		for _, e := range result.Entities {
			if e != nil && e.scene == scene && e.Active {
				scene.Destroy(e)
			}
		}
		for i := 0; i < len(nodes); i++ {
			if !modelHandled[i] {
				releaseLevelNodeModel(nodes[i])
			}
		}
	}()
	validateLevelNodes(nodes)?
	for i := 0; i < len(nodes); i++ {
		spawned, err := spawnLevelNode(scene, nodes[i])
		if err != nil {
			return nil, err
		}
		result.Entities = append(result.Entities, spawned.Entity)
		if spawned.Terrain != nil {
			result.Terrains[nodes[i].Name] = spawned.Terrain
		}
		if spawned.ModelOwnershipTransferred {
			modelHandled[i] = true
			continue
		}
		if nodes[i].ModelID != 0 {
			releaseLevelNodeModel(nodes[i])
			modelHandled[i] = true
		}
	}
	return result, nil
}

func validateLevelNodes(nodes []LevelNodeInfo) error {
	seen := map[string]bool{}
	for i := 0; i < len(nodes); i++ {
		name := nodes[i].Name
		if name == "" {
			return errors.New("scene3d.LoadLevel: level node name must not be empty")
		}
		if seen[name] {
			return errors.New("scene3d.LoadLevel: duplicate level node name: " + name)
		}
		seen[name] = true
	}
	return nil
}

func DecodeLevelNodes(data []byte) []LevelNodeInfo {
	r := codec.NewByteReader(data)
	count := r.ReadU32()
	nodes := make([]LevelNodeInfo, 0, count)
	for i := 0; i < count; i++ {
		nameLen := r.ReadU16()
		name := string(r.ReadBytes(nameLen))
		kind := int(r.ReadByte())
		modelID := voplay.ModelID(r.ReadU32())
		node := LevelNodeInfo{
			Kind:     kind,
			Name:     name,
			ModelID:  modelID,
			Position: voplay.Vec3{X: r.ReadF64(), Y: r.ReadF64(), Z: r.ReadF64()},
			Rotation: voplay.Quat{X: r.ReadF64(), Y: r.ReadF64(), Z: r.ReadF64(), W: r.ReadF64()},
			Scale:    voplay.Vec3{X: r.ReadF64(), Y: r.ReadF64(), Z: r.ReadF64()},
			AABBMin:  voplay.Vec3{X: r.ReadF64(), Y: r.ReadF64(), Z: r.ReadF64()},
			AABBMax:  voplay.Vec3{X: r.ReadF64(), Y: r.ReadF64(), Z: r.ReadF64()},
		}
		if kind == levelNodeTerrain {
			rows := r.ReadU32()
			cols := r.ReadU32()
			node.Terrain = &LevelTerrainInfo{
				Rows:        rows,
				Cols:        cols,
				Scale:       voplay.Vec3{X: r.ReadF64(), Y: r.ReadF64(), Z: r.ReadF64()},
				Layer:       r.ReadU16(),
				Mask:        r.ReadU16(),
				Friction:    r.ReadF64(),
				Restitution: r.ReadF64(),
			}
			heightLen := r.ReadU32()
			node.Terrain.HeightData = r.ReadBytes(heightLen)
		}
		nodes = append(nodes, node)
	}
	return nodes
}

func spawnLevelTerrainNode(scene *Scene, node LevelNodeInfo) (*Terrain, error) {
	if node.ModelID == 0 {
		return nil, errors.New("scene3d.LoadLevel: terrain node requires generated model: " + node.Name)
	}
	if node.Terrain == nil {
		return nil, errors.New("scene3d.LoadLevel: terrain node missing terrain payload: " + node.Name)
	}
	info := node.Terrain
	physics, err := buildTerrainPhysics(&Physics{
		Type:        Static,
		Layer:       info.Layer,
		Mask:        info.Mask,
		Friction:    info.Friction,
		Restitution: info.Restitution,
	})
	if err != nil {
		return nil, err
	}
	return spawnTerrain(scene, TerrainDesc{
		Position: node.Position,
		Width:    info.Scale.X,
		Height:   info.Scale.Y,
		Depth:    info.Scale.Z,
		Tag:      node.Name,
		Physics:  physics,
	}, physics, int(node.ModelID), info.Rows, info.Cols, info.HeightData), nil
}

func classifyLevelNode(node LevelNodeInfo) levelNodePlanKind {
	switch {
	case strings.HasPrefix(node.Name, "spawn_"):
		return levelNodePlanSpawnMarker
	case strings.HasPrefix(node.Name, "col_box_"):
		return levelNodePlanBoxCollider
	case strings.HasPrefix(node.Name, "col_sphere_"):
		return levelNodePlanSphereCollider
	case strings.HasPrefix(node.Name, "col_capsule_"):
		return levelNodePlanCapsuleCollider
	case strings.HasPrefix(node.Name, "col_trimesh_"):
		return levelNodePlanTrimeshVisible
	case strings.HasPrefix(node.Name, "col_"):
		return levelNodePlanTrimeshHidden
	default:
		return levelNodePlanDefault
	}
}

func newLevelNodePlan(node LevelNodeInfo) LevelNodePlan {
	plan := LevelNodePlan{Desc: EntityDesc{
		Position: node.Position,
		Rotation: node.Rotation,
		Scale:    node.Scale,
		Model:    node.ModelID,
		Tag:      node.Name,
	}}
	if plan.Desc.Model != 0 {
		plan.Desc.OwnedModel = plan.Desc.Model
	}
	return plan
}

func requireLevelNodeMesh(node LevelNodeInfo, kind string) error {
	if node.ModelID == 0 {
		return errors.New("scene3d.LoadLevel: " + kind + " node requires mesh: " + node.Name)
	}
	return nil
}

func releaseLevelNodeModel(node LevelNodeInfo) {
	if node.ModelID == 0 {
		return
	}
	node.ModelID.Free()
}

func spawnLevelNode(scene *Scene, node LevelNodeInfo) (levelNodeSpawnResult, error) {
	if node.Kind == levelNodeTerrain {
		terrain, err := spawnLevelTerrainNode(scene, node)
		if err != nil {
			return levelNodeSpawnResult{}, err
		}
		return levelNodeSpawnResult{
			Entity:                    terrain.Entity(),
			Terrain:                   terrain,
			ModelOwnershipTransferred: true,
		}, nil
	}
	plan, err := PlanLevelNode(node)
	if err != nil {
		return levelNodeSpawnResult{}, err
	}
	ent := scene.Spawn(plan.Desc)
	ent.Visible = plan.Visible
	return levelNodeSpawnResult{
		Entity:                    ent,
		ModelOwnershipTransferred: plan.Desc.OwnedModel != 0,
	}, nil
}

func PlanLevelNode(node LevelNodeInfo) (LevelNodePlan, error) {
	plan := newLevelNodePlan(node)
	switch classifyLevelNode(node) {
	case levelNodePlanSpawnMarker:
		plan.Desc.Model = 0
		plan.Desc.OwnedModel = 0
		plan.Visible = false
		return plan, nil
	case levelNodePlanBoxCollider:
		collider, err := levelBoxCollider(node)
		if err != nil {
			return LevelNodePlan{}, err
		}
		plan.Desc.Physics = levelPhysics(collider)
		plan.Visible = true
		return plan, nil
	case levelNodePlanSphereCollider:
		collider, err := levelSphereCollider(node)
		if err != nil {
			return LevelNodePlan{}, err
		}
		plan.Desc.Physics = levelPhysics(collider)
		plan.Visible = true
		return plan, nil
	case levelNodePlanCapsuleCollider:
		collider, err := levelCapsuleCollider(node)
		if err != nil {
			return LevelNodePlan{}, err
		}
		plan.Desc.Physics = levelPhysics(collider)
		plan.Visible = true
		return plan, nil
	case levelNodePlanTrimeshVisible:
		requireLevelNodeMesh(node, "col_trimesh")?
		plan.Desc.Physics = TrimeshPhysics(node.ModelID)
		plan.Visible = true
		return plan, nil
	case levelNodePlanTrimeshHidden:
		requireLevelNodeMesh(node, "col")?
		plan.Desc.Physics = TrimeshPhysics(node.ModelID)
		plan.Visible = false
		return plan, nil
	default:
		plan.Visible = true
		return plan, nil
	}
}

func levelPhysics(c Collider) *Physics {
	return &Physics{
		Type:        Static,
		Collider:    c,
		Layer:       voplay.CollisionLayerDefault,
		Mask:        voplay.CollisionMaskAll,
		Friction:    0.5,
		Restitution: 0.0,
	}
}

func levelBoxCollider(node LevelNodeInfo) (Collider, error) {
	requireLevelNodeMesh(node, "col_box")?
	half := scaledHalfExtents(node)
	center := scaledCenter(node)
	return Collider{
		kind:   colliderBox3D,
		args:   [3]float64{half.X, half.Y, half.Z},
		offset: center,
	}, nil
}

func levelSphereCollider(node LevelNodeInfo) (Collider, error) {
	requireLevelNodeMesh(node, "col_sphere")?
	half := scaledHalfExtents(node)
	radius := math.Max(half.X, math.Max(half.Y, half.Z))
	return Collider{
		kind:   colliderSphere,
		args:   [3]float64{radius, 0, 0},
		offset: scaledCenter(node),
	}, nil
}

func levelCapsuleCollider(node LevelNodeInfo) (Collider, error) {
	requireLevelNodeMesh(node, "col_capsule")?
	half := scaledHalfExtents(node)
	radius := math.Max(half.X, half.Z)
	halfHeight := half.Y - radius
	if halfHeight < 0 {
		halfHeight = 0
	}
	return Collider{
		kind:   colliderCapsule3D,
		args:   [3]float64{halfHeight, radius, 0},
		offset: scaledCenter(node),
	}, nil
}

func scaledHalfExtents(node LevelNodeInfo) voplay.Vec3 {
	size := node.AABBMax.Sub(node.AABBMin)
	return voplay.Vec3{
		X: math.Abs(size.X*node.Scale.X) * 0.5,
		Y: math.Abs(size.Y*node.Scale.Y) * 0.5,
		Z: math.Abs(size.Z*node.Scale.Z) * 0.5,
	}
}

func scaledCenter(node LevelNodeInfo) voplay.Vec3 {
	center := node.AABBMin.Add(node.AABBMax).Scale(0.5)
	return voplay.Vec3{
		X: center.X * node.Scale.X,
		Y: center.Y * node.Scale.Y,
		Z: center.Z * node.Scale.Z,
	}
}

