package scene3d

import "github.com/vo-lang/voplay"

type LightingProfile struct {
	Ambient voplay.Color
	AmbientGround voplay.Color
	Lights []Light
	Fog FogConfig
	ColorGrading ColorGradingConfig
	ShadowsEnabled bool
	ShadowResolution int
	ShadowStrength float64
}

func DefaultColorGradingConfig() ColorGradingConfig {
	return ColorGradingConfig{ToneMap: ToneMapNone, Exposure: 1, Contrast: 1, Saturation: 1}
}

func KartRacingLightingProfile() LightingProfile {
	return LightingProfile{
		Ambient: voplay.Color{R: 0.52, G: 0.64, B: 0.70, A: 1},
		AmbientGround: voplay.Color{R: 0.22, G: 0.30, B: 0.30, A: 1},
		Lights: []Light{
			{Type: DirectionalLight, Direction: voplay.Vec3{X: -0.36, Y: 0.58, Z: -0.73}.Normalize(), Color: voplay.Hex(0xfff2d2), Intensity: 0.92},
			{Type: DirectionalLight, Direction: voplay.Vec3{X: 0.48, Y: 0.34, Z: 0.2}.Normalize(), Color: voplay.Hex(0x8fc8ff), Intensity: 0.14},
		},
		Fog: FogConfig{Mode: FogLinear, Color: voplay.Hex(0xb8e3ef), Start: 180, End: 420},
		ColorGrading: ColorGradingConfig{ToneMap: ToneMapNone, Exposure: 1.04, Contrast: 1.04, Saturation: 1.08},
		ShadowsEnabled: false,
		ShadowResolution: 2048,
		ShadowStrength: 0.58,
	}
}

func (s *Scene) ApplyLightingProfile(profile LightingProfile) {
	if s == nil {
		return
	}
	s.Ambient = profile.Ambient
	s.AmbientGround = normalizeAmbientGround(profile.Ambient, profile.AmbientGround)
	s.Lights = append([]Light{}, profile.Lights...)
	s.Fog = profile.Fog
	s.ColorGrading = normalizeColorGrading(profile.ColorGrading)
	s.ShadowsEnabled = profile.ShadowsEnabled
	if profile.ShadowResolution > 0 {
		s.ShadowResolution = profile.ShadowResolution
	}
	s.ShadowStrength = normalizeShadowStrength(profile.ShadowStrength)
}

func normalizeAmbientGround(ambientSky, ambientGround voplay.Color) voplay.Color {
	if ambientGround == (voplay.Color{}) {
		return ambientSky
	}
	return ambientGround
}

func normalizeColorGrading(config ColorGradingConfig) ColorGradingConfig {
	if config.Exposure <= 0 {
		config.Exposure = 1
	}
	if config.Contrast <= 0 {
		config.Contrast = 1
	}
	if config.Saturation <= 0 {
		config.Saturation = 1
	}
	if config.ToneMap < ToneMapNone || config.ToneMap > ToneMapACES {
		config.ToneMap = ToneMapNone
	}
	return config
}

package scene3d

import (
	"encoding/json"
	"errors"
	"os"
	"path/filepath"
	"github.com/vo-lang/voplay"
)

type MapVec3 struct {
	X float64 `json:"x"`
	Y float64 `json:"y"`
	Z float64 `json:"z"`
}

type MapColor struct {
	R float64 `json:"r"`
	G float64 `json:"g"`
	B float64 `json:"b"`
	A float64 `json:"a"`
}

type MapTerrainSplatLayer struct {
	Texture string `json:"texture"`
	Normal string `json:"normal,omitempty"`
	MetallicRoughness string `json:"metallicRoughness,omitempty"`
	UVScale float64 `json:"uvScale,omitempty"`
	NormalScale float64 `json:"normalScale,omitempty"`
}

type MapTerrainSplat struct {
	Control string `json:"control"`
	Layers []MapTerrainSplatLayer `json:"layers"`
}

type MapTerrain struct {
	Heightmap string   `json:"heightmap"`
	Texture   string   `json:"texture,omitempty"`
	Normal    string   `json:"normal,omitempty"`
	MetallicRoughness string `json:"metallicRoughness,omitempty"`
	Splat     *MapTerrainSplat `json:"splat,omitempty"`
	Position  MapVec3  `json:"position,omitempty"`
	Width     float64  `json:"width"`
	Height    float64  `json:"height"`
	Depth     float64  `json:"depth"`
	UVScale   float64  `json:"uvScale,omitempty"`
	NormalScale float64 `json:"normalScale,omitempty"`
	Roughness float64 `json:"roughness,omitempty"`
	Metallic float64 `json:"metallic,omitempty"`
	Tint      MapColor `json:"tint,omitempty"`
	TintSet   bool     `json:"tintSet,omitempty"`
	Tag       string   `json:"tag,omitempty"`
	Friction  float64  `json:"friction,omitempty"`
}

type MapMesh struct {
	Name      string   `json:"name"`
	Model     string   `json:"model"`
	Collision string   `json:"collision,omitempty"`
	Hidden    bool     `json:"hidden,omitempty"`
	Position  MapVec3  `json:"position,omitempty"`
	Rotation  MapVec3  `json:"rotation,omitempty"`
	Scale     MapVec3  `json:"scale,omitempty"`
	Tint      MapColor `json:"tint,omitempty"`
	TintSet   bool     `json:"tintSet,omitempty"`
	Friction  float64  `json:"friction,omitempty"`
}

type MapSpawn struct {
	Name     string  `json:"name"`
	Position MapVec3 `json:"position"`
	Yaw      float64 `json:"yaw,omitempty"`
}

type MapAsset struct {
	Version int          `json:"version"`
	Name    string       `json:"name"`
	Terrain *MapTerrain  `json:"terrain,omitempty"`
	Meshes  []MapMesh    `json:"meshes,omitempty"`
	Spawns  []MapSpawn   `json:"spawns,omitempty"`
}

type MapSpawnResult struct {
	Asset    *MapAsset
	Terrain  *Terrain
	Entities []*Entity
	Meshes   map[string]*Entity
	Spawns   map[string]MapSpawn
	Textures []voplay.TextureID
}

func LoadMapAsset(path string) (*MapAsset, error) {
	if path == "" {
		return nil, errors.New("scene3d.LoadMapAsset: path must not be empty")
	}
	data := os.ReadFile(path)?
	var asset MapAsset
	json.Unmarshal(data, &asset)?
	validateMapAsset(&asset)?
	return &asset, nil
}

func LoadMap(scene *Scene, path string) (*MapSpawnResult, error) {
	asset, err := LoadMapAsset(path)
	if err != nil {
		return nil, err
	}
	return SpawnMapWithAssets(scene, nil, asset, filepath.Dir(path))
}

func LoadMapWithAssets(scene *Scene, assets *voplay.Assets, path string) (*MapSpawnResult, error) {
	if assets == nil {
		return LoadMap(scene, path)
	}
	if path == "" {
		return nil, errors.New("scene3d.LoadMapWithAssets: path must not be empty")
	}
	data := assets.Bytes(path)?
	var asset MapAsset
	json.Unmarshal(data, &asset)?
	validateMapAsset(&asset)?
	return SpawnMapWithAssets(scene, assets, &asset, filepath.Dir(path))
}

func SpawnMap(scene *Scene, asset *MapAsset, baseDir string) (*MapSpawnResult, error) {
	return SpawnMapWithAssets(scene, nil, asset, baseDir)
}

func SpawnMapWithAssets(scene *Scene, assets *voplay.Assets, asset *MapAsset, baseDir string) (*MapSpawnResult, error) {
	if scene == nil {
		return nil, errors.New("scene3d.SpawnMap: scene is nil")
	}
	if asset == nil {
		return nil, errors.New("scene3d.SpawnMap: asset is nil")
	}
	validateMapAsset(asset)?
	result := &MapSpawnResult{
		Asset:    asset,
		Entities: []*Entity{},
		Meshes:   map[string]*Entity{},
		Spawns:   map[string]MapSpawn{},
		Textures: []voplay.TextureID{},
	}
	success := false
	errdefer func() {
		if success {
			return
		}
		result.Destroy(scene)
		result.ReleaseTextures()
	}()
	if asset.Terrain != nil {
		terrain, err := spawnMapTerrain(scene, assets, *asset.Terrain, baseDir, result)
		if err != nil {
			return nil, err
		}
		result.Terrain = terrain
		result.Entities = append(result.Entities, terrain.Entity())
	}
	for _, mesh := range asset.Meshes {
		ent, err := spawnMapMesh(scene, assets, mesh, baseDir)
		if err != nil {
			return nil, err
		}
		result.Entities = append(result.Entities, ent)
		result.Meshes[mesh.Name] = ent
	}
	for _, spawn := range asset.Spawns {
		result.Spawns[spawn.Name] = spawn
	}
	success = true
	return result, nil
}

func (r *MapSpawnResult) Destroy(scene *Scene) {
	if r == nil || scene == nil {
		return
	}
	for _, e := range r.Entities {
		if e != nil && e.scene == scene && e.Active {
			scene.Destroy(e)
		}
	}
	r.Entities = nil
	r.Terrain = nil
	r.Meshes = map[string]*Entity{}
}

func (r *MapSpawnResult) ReleaseTextures() {
	if r == nil {
		return
	}
	for _, texture := range r.Textures {
		if texture != 0 {
			texture.Free()
		}
	}
	r.Textures = nil
}

func validateMapAsset(asset *MapAsset) error {
	if asset.Version != 1 {
		return errors.New("scene3d.LoadMapAsset: unsupported map version")
	}
	if asset.Terrain != nil {
		validateMapTerrain(*asset.Terrain)?
	}
	seenMeshes := map[string]bool{}
	for _, mesh := range asset.Meshes {
		validateMapMesh(mesh)?
		if seenMeshes[mesh.Name] {
			return errors.New("scene3d.LoadMapAsset: duplicate mesh name: " + mesh.Name)
		}
		seenMeshes[mesh.Name] = true
	}
	seenSpawns := map[string]bool{}
	for _, spawn := range asset.Spawns {
		if spawn.Name == "" {
			return errors.New("scene3d.LoadMapAsset: spawn name must not be empty")
		}
		if seenSpawns[spawn.Name] {
			return errors.New("scene3d.LoadMapAsset: duplicate spawn name: " + spawn.Name)
		}
		seenSpawns[spawn.Name] = true
	}
	return nil
}

func validateMapTerrain(terrain MapTerrain) error {
	if terrain.Heightmap == "" {
		return errors.New("scene3d.LoadMapAsset: terrain heightmap is required")
	}
	if terrain.Width <= 0 || terrain.Height <= 0 || terrain.Depth <= 0 {
		return errors.New("scene3d.LoadMapAsset: terrain width, height, and depth must be > 0")
	}
	if terrain.UVScale < 0 {
		return errors.New("scene3d.LoadMapAsset: terrain uvScale must be >= 0")
	}
	if terrain.NormalScale < 0 {
		return errors.New("scene3d.LoadMapAsset: terrain normalScale must be >= 0")
	}
	if terrain.Roughness < 0 {
		return errors.New("scene3d.LoadMapAsset: terrain roughness must be >= 0")
	}
	if terrain.Metallic < 0 || terrain.Metallic > 1 {
		return errors.New("scene3d.LoadMapAsset: terrain metallic must be in range 0..1")
	}
	if terrain.Splat != nil {
		if terrain.Texture != "" || terrain.Normal != "" || terrain.MetallicRoughness != "" || terrain.UVScale != 0 || terrain.NormalScale != 0 || terrain.Roughness != 0 || terrain.Metallic != 0 {
			return errors.New("scene3d.LoadMapAsset: terrain single-material fields cannot be mixed with splat")
		}
		if terrain.Splat.Control == "" {
			return errors.New("scene3d.LoadMapAsset: terrain splat control is required")
		}
		if len(terrain.Splat.Layers) != 4 {
			return errors.New("scene3d.LoadMapAsset: terrain splat requires exactly 4 layers")
		}
		for _, layer := range terrain.Splat.Layers {
			if layer.Texture == "" {
				return errors.New("scene3d.LoadMapAsset: terrain splat layer texture is required")
			}
			if layer.UVScale < 0 {
				return errors.New("scene3d.LoadMapAsset: terrain splat layer uvScale must be >= 0")
			}
			if layer.NormalScale < 0 {
				return errors.New("scene3d.LoadMapAsset: terrain splat layer normalScale must be >= 0")
			}
		}
	}
	return nil
}

func validateMapMesh(mesh MapMesh) error {
	if mesh.Name == "" {
		return errors.New("scene3d.LoadMapAsset: mesh name must not be empty")
	}
	if mesh.Model == "" {
		return errors.New("scene3d.LoadMapAsset: mesh model is required: " + mesh.Name)
	}
	if mesh.Collision != "" && mesh.Collision != "none" && mesh.Collision != "trimesh" {
		return errors.New("scene3d.LoadMapAsset: unsupported mesh collision: " + mesh.Name)
	}
	return nil
}

func spawnMapTerrain(scene *Scene, assets *voplay.Assets, terrain MapTerrain, baseDir string, result *MapSpawnResult) (*Terrain, error) {
	desc := TerrainDesc{
		Position:      terrain.Position.Vec3(),
		Width:         terrain.Width,
		Height:        terrain.Height,
		Depth:         terrain.Depth,
		UVScale:       terrain.UVScale,
		NormalScale:   terrain.NormalScale,
		Roughness:     terrain.Roughness,
		Metallic:      terrain.Metallic,
		Tag:           terrain.Tag,
		Tint:          terrain.Tint.Color(),
		TintSet:       terrain.TintSet,
		Physics:       mapTerrainPhysics(terrain),
	}
	heightmapPath := mapResolvePath(baseDir, terrain.Heightmap)
	if assets != nil {
		data, err := assets.Bytes(heightmapPath)
		if err != nil {
			return nil, err
		}
		desc.HeightmapData = data
	} else {
		desc.HeightmapPath = heightmapPath
	}
	if terrain.Splat != nil {
		splat := &TerrainSplatMaterial{Layers: make([]TerrainLayer, 4)}
		control, err := loadMapTexture(assets, mapResolvePath(baseDir, terrain.Splat.Control), result)
		if err != nil {
			return nil, err
		}
		splat.Control = control
		for i := 0; i < 4; i++ {
			layer := terrain.Splat.Layers[i]
			texture, textureErr := loadMapTexture(assets, mapResolvePath(baseDir, layer.Texture), result)
			if textureErr != nil {
				return nil, textureErr
			}
			splat.Layers[i].Texture = texture
			if layer.Normal != "" {
				normal, normalErr := loadMapTexture(assets, mapResolvePath(baseDir, layer.Normal), result)
				if normalErr != nil {
					return nil, normalErr
				}
				splat.Layers[i].Normal = normal
			}
			if layer.MetallicRoughness != "" {
				mr, mrErr := loadMapTexture(assets, mapResolvePath(baseDir, layer.MetallicRoughness), result)
				if mrErr != nil {
					return nil, mrErr
				}
				splat.Layers[i].MetallicRoughness = mr
			}
			splat.Layers[i].UVScale = layer.UVScale
			splat.Layers[i].NormalScale = layer.NormalScale
		}
		desc.Splat = splat
		return NewTerrain(scene, desc)
	}
	if terrain.Texture != "" {
		texture, err := loadMapTexture(assets, mapResolvePath(baseDir, terrain.Texture), result)
		if err != nil {
			return nil, err
		}
		desc.Texture = texture
	}
	if terrain.Normal != "" {
		normal, err := loadMapTexture(assets, mapResolvePath(baseDir, terrain.Normal), result)
		if err != nil {
			return nil, err
		}
		desc.Normal = normal
	}
	if terrain.MetallicRoughness != "" {
		mr, err := loadMapTexture(assets, mapResolvePath(baseDir, terrain.MetallicRoughness), result)
		if err != nil {
			return nil, err
		}
		desc.MetallicRoughness = mr
	}
	return NewTerrain(scene, desc)
}

func loadMapTexture(assets *voplay.Assets, path string, result *MapSpawnResult) (voplay.TextureID, error) {
	if assets != nil {
		return assets.Texture(path)
	}
	texture, err := voplay.LoadTexture(path)
	if err != nil {
		return 0, err
	}
	if result != nil {
		result.Textures = append(result.Textures, texture)
	}
	return texture, nil
}

func spawnMapMesh(scene *Scene, assets *voplay.Assets, mesh MapMesh, baseDir string) (*Entity, error) {
	modelPath := mapResolvePath(baseDir, mesh.Model)
	var model voplay.ModelID
	var err error
	if assets != nil {
		model, err = assets.Model(modelPath)
	} else {
		model, err = voplay.LoadModel(modelPath)
	}
	if err != nil {
		return nil, err
	}
	spawned := false
	defer func() {
		if !spawned && assets == nil && model != 0 {
			model.Free()
		}
	}()
	desc := EntityDesc{
		Position:   mesh.Position.Vec3(),
		Rotation:   mapRotation(mesh.Rotation),
		Scale:      mapScale(mesh.Scale),
		Model:      model,
		Tag:        mesh.Name,
	}
	if mesh.TintSet {
		desc.Tint = mesh.Tint.Color()
		desc.TintSet = true
	}
	if assets == nil {
		desc.OwnedModel = model
	}
	if mesh.Collision == "trimesh" {
		desc.Physics = TrimeshPhysics(model)
		if mesh.Friction > 0 {
			desc.Physics.Friction = mesh.Friction
		}
	}
	ent := scene.Spawn(desc)
	spawned = true
	ent.Visible = !mesh.Hidden
	return ent, nil
}

func mapTerrainPhysics(terrain MapTerrain) *Physics {
	physics := &Physics{
		Type:        Static,
		Layer:       voplay.CollisionLayerDefault,
		Mask:        voplay.CollisionMaskAll,
		Friction:    0.8,
		Restitution: 0,
	}
	if terrain.Friction > 0 {
		physics.Friction = terrain.Friction
	}
	return physics
}

func mapResolvePath(baseDir, child string) string {
	if child == "" || filepath.IsAbs(child) {
		return child
	}
	if baseDir == "" || baseDir == "." {
		return child
	}
	return filepath.Join([]string{baseDir, child})
}

func mapRotation(r MapVec3) voplay.Quat {
	return voplay.QuatFromEuler(r.X, r.Y, r.Z)
}

func mapScale(s MapVec3) voplay.Vec3 {
	if s.X == 0 && s.Y == 0 && s.Z == 0 {
		return voplay.Vec3{X: 1, Y: 1, Z: 1}
	}
	return s.Vec3()
}

func (v MapVec3) Vec3() voplay.Vec3 {
	return voplay.Vec3{X: v.X, Y: v.Y, Z: v.Z}
}

func (c MapColor) Color() voplay.Color {
	a := c.A
	if a <= 0 {
		a = 1
	}
	return voplay.Color{R: c.R, G: c.G, B: c.B, A: a}
}

package scene3d

import "math"
import "math/rand"
import "github.com/vo-lang/voplay"

type EmitterShape int

const (
	EmitPoint EmitterShape = 0
	EmitCone  EmitterShape = 1
)

type Particle struct {
	position voplay.Vec3
	velocity voplay.Vec3
	age      float64
	lifetime float64
	size0    float64
	size1    float64
	color0   voplay.Color
	color1   voplay.Color
	alive    bool
}

type ParticleEmitter struct {
	Position voplay.Vec3
	Attached *Entity

	Rate      float64
	Shape     EmitterShape
	Direction voplay.Vec3
	Spread    float64

	LifetimeMin float64
	LifetimeMax float64
	SpeedMin    float64
	SpeedMax    float64

	StartColor voplay.Color
	EndColor   voplay.Color
	StartSize  float64
	EndSize    float64

	Gravity voplay.Vec3
	Damping float64
	Texture voplay.TextureID

	MaxParticles int
	Enabled      bool

	particles   []Particle
	cursor      int
	accumulator float64
	scene       *Scene
}

func NewParticleEmitter(maxParticles int) *ParticleEmitter {
	if maxParticles <= 0 {
		panic("NewParticleEmitter: maxParticles must be > 0")
	}
	return &ParticleEmitter{
		Rate:         50,
		Shape:        EmitPoint,
		Direction:    voplay.Vec3{Y: 1},
		Spread:       0.5,
		LifetimeMin:  0.5,
		LifetimeMax:  1.5,
		SpeedMin:     1.0,
		SpeedMax:     3.0,
		StartColor:   voplay.White,
		EndColor:     voplay.Color{R: 1, G: 1, B: 1, A: 0},
		StartSize:    0.2,
		EndSize:      0.05,
		Gravity:      voplay.Vec3{Y: -9.8},
		Damping:      1.0,
		MaxParticles: maxParticles,
		Enabled:      true,
		particles:    make([]Particle, maxParticles),
	}
}

func FireEmitter(texture voplay.TextureID, pos voplay.Vec3) *ParticleEmitter {
	e := NewParticleEmitter(200)
	e.Texture = texture
	e.Position = pos
	e.Shape = EmitCone
	e.Direction = voplay.Vec3{Y: 1}
	e.Spread = 0.3
	e.Rate = 80
	e.SpeedMin = 1.0
	e.SpeedMax = 2.5
	e.LifetimeMin = 0.3
	e.LifetimeMax = 0.8
	e.StartColor = voplay.Color{R: 1, G: 0.8, B: 0.2, A: 1}
	e.EndColor = voplay.Color{R: 0.8, G: 0.2, B: 0, A: 0}
	e.StartSize = 0.3
	e.EndSize = 0.05
	e.Gravity = voplay.Vec3{Y: 2}
	return e
}

func DustEmitter(texture voplay.TextureID, pos voplay.Vec3) *ParticleEmitter {
	e := NewParticleEmitter(50)
	e.Texture = texture
	e.Position = pos
	e.Shape = EmitPoint
	e.Rate = 30
	e.SpeedMin = 0.5
	e.SpeedMax = 1.5
	e.LifetimeMin = 0.3
	e.LifetimeMax = 0.6
	e.StartColor = voplay.Color{R: 0.8, G: 0.75, B: 0.6, A: 0.6}
	e.EndColor = voplay.Color{R: 0.8, G: 0.75, B: 0.6, A: 0}
	e.StartSize = 0.1
	e.EndSize = 0.4
	e.Gravity = voplay.Vec3{Y: 0.5}
	e.Damping = 0.9
	return e
}

func (e *ParticleEmitter) LiveCount() int {
	count := 0
	for i := range e.particles {
		if e.particles[i].alive {
			count++
		}
	}
	return count
}

func (e *ParticleEmitter) Clear() {
	for i := range e.particles {
		e.particles[i].alive = false
	}
	e.cursor = 0
	e.accumulator = 0
}

func (e *ParticleEmitter) EmitBurst(count int) {
	if count < 0 {
		panic("ParticleEmitter.EmitBurst: count must be >= 0")
	}
	e.validate()
	for i := 0; i < count; i++ {
		e.emit()
	}
}

func (e *ParticleEmitter) Update(dt float64) {
	if dt < 0 {
		panic("ParticleEmitter.Update: dt must be >= 0")
	}
	e.validate()
	if e.Enabled {
		e.accumulator += e.Rate * dt
		for e.accumulator >= 1.0 {
			e.emit()
			e.accumulator -= 1.0
		}
	}
	dampFactor := math.Pow(e.Damping, dt)
	for i := range e.particles {
		p := &e.particles[i]
		if !p.alive {
			continue
		}
		p.age += dt
		if p.age >= p.lifetime {
			p.alive = false
			continue
		}
		p.velocity = p.velocity.Add(e.Gravity.Scale(dt))
		p.velocity = p.velocity.Scale(dampFactor)
		p.position = p.position.Add(p.velocity.Scale(dt))
	}
}

func (e *ParticleEmitter) Draw(d *voplay.DrawCtx) {
	if e.Texture == 0 {
		panic("ParticleEmitter.Draw: Texture must be non-zero")
	}
	for i := range e.particles {
		p := &e.particles[i]
		if !p.alive {
			continue
		}
		t := p.age / p.lifetime
		size := p.size0 + (p.size1-p.size0)*t
		color := p.color0.Lerp(p.color1, t)
		if size <= 0 || color.A <= 0 {
			continue
		}
		d.DrawBillboardEx(voplay.BillboardParams{
			Tex:      e.Texture,
			WorldPos: p.position,
			Width:    size,
			Height:   size,
			Tint:     color,
		})
	}
}

func (e *ParticleEmitter) validate() {
	if e.MaxParticles <= 0 {
		panic("ParticleEmitter: MaxParticles must be > 0")
	}
	if len(e.particles) != e.MaxParticles {
		panic("ParticleEmitter: particle pool size mismatch")
	}
	if e.Rate < 0 {
		panic("ParticleEmitter: Rate must be >= 0")
	}
	if e.LifetimeMin <= 0 || e.LifetimeMax < e.LifetimeMin {
		panic("ParticleEmitter: invalid lifetime range")
	}
	if e.SpeedMin < 0 || e.SpeedMax < e.SpeedMin {
		panic("ParticleEmitter: invalid speed range")
	}
	if e.StartSize < 0 || e.EndSize < 0 {
		panic("ParticleEmitter: size must be >= 0")
	}
	if e.Damping <= 0 {
		panic("ParticleEmitter: Damping must be > 0")
	}
	if e.Shape == EmitCone {
		if e.Direction.LengthSq() == 0 {
			panic("ParticleEmitter: cone Direction must be non-zero")
		}
		if e.Spread < 0 || e.Spread > math.Pi {
			panic("ParticleEmitter: Spread must be in [0, pi]")
		}
		return
	}
	if e.Shape != EmitPoint {
		panic("ParticleEmitter: unknown Shape")
	}
}

func (e *ParticleEmitter) emit() {
	origin := e.Position
	if e.Attached != nil {
		origin = e.Attached.Position().Add(e.Position)
	}
	velocity := e.randomDirection().Scale(randRange(e.SpeedMin, e.SpeedMax))
	p := &e.particles[e.cursor]
	p.position = origin
	p.velocity = velocity
	p.age = 0
	p.lifetime = randRange(e.LifetimeMin, e.LifetimeMax)
	p.size0 = e.StartSize
	p.size1 = e.EndSize
	p.color0 = e.StartColor
	p.color1 = e.EndColor
	p.alive = true
	e.cursor = (e.cursor + 1) % e.MaxParticles
}

func (e *ParticleEmitter) randomDirection() voplay.Vec3 {
	if e.Shape == EmitPoint {
		return randomUnitSphere()
	}
	return randomInCone(e.Direction, e.Spread)
}

func randRange(lo, hi float64) float64 {
	if hi == lo {
		return lo
	}
	return lo + rand.Float64()*(hi-lo)
}

func randomUnitSphere() voplay.Vec3 {
	z := randRange(-1, 1)
	phi := rand.Float64() * math.Pi * 2
	r := math.Sqrt(1 - z*z)
	return voplay.Vec3{
		X: r * math.Cos(phi),
		Y: z,
		Z: r * math.Sin(phi),
	}
}

func randomInCone(axis voplay.Vec3, halfAngle float64) voplay.Vec3 {
	axis = axis.Normalize()
	cosMin := math.Cos(halfAngle)
	cosTheta := 1 - rand.Float64()*(1-cosMin)
	sinTheta := math.Sqrt(1 - cosTheta*cosTheta)
	phi := rand.Float64() * math.Pi * 2
	helper := voplay.Vec3{Y: 1}
	if math.Abs(axis.Y) > 0.999 {
		helper = voplay.Vec3{X: 1}
	}
	tangent := helper.Cross(axis).Normalize()
	bitangent := axis.Cross(tangent)
	return tangent.Scale(math.Cos(phi) * sinTheta).
		Add(bitangent.Scale(math.Sin(phi) * sinTheta)).
		Add(axis.Scale(cosTheta)).
		Normalize()
}

// Physics types, colliders, and extern declarations for 3D physics.
package scene3d

import "github.com/vo-lang/voplay"
import "github.com/vo-lang/voplay/codec"

// BodyType determines how the physics engine treats a body.
type BodyType = voplay.BodyType

const (
	Dynamic   = voplay.Dynamic
	Static    = voplay.Static
	Kinematic = voplay.Kinematic
)

// Physics is the physics configuration and runtime state for a 3D entity.
type Physics struct {
	Type          BodyType
	Collider      Collider
	Trimesh       *Trimesh
	Heightfield   *Heightfield
	Layer         int
	Mask          int
	Density       float64
	Friction      float64
	Restitution   float64
	LinearDamping float64
	AngularDamping float64
	FixedRotation bool
	LockRotationX bool
	LockRotationY bool
	LockRotationZ bool

	// Runtime state (managed by Scene, not user-set).
	bodyID   int
	velocity voplay.Vec3
	angularVelocity voplay.Vec3
}

type Trimesh struct {
	Model voplay.ModelID
}

type Heightfield struct {
	heightData []byte
	rows       int
	cols       int
	scale      voplay.Vec3
}

// HeightfieldSpawnDesc groups all parameters needed to spawn a heightfield physics body.
type HeightfieldSpawnDesc struct {
	HeightData  []byte
	Rows        int
	Cols        int
	Scale       voplay.Vec3
	Position    voplay.Vec3
	Layer       int
	Mask        int
	Friction    float64
	Restitution float64
}

// Collider is a tagged value type for 3D physics shapes.
type Collider struct {
	kind int
	args [3]float64
	offset voplay.Vec3
}

// Collider kind constants (must match Rust ColliderKind3D in physics3d.rs).
const (
	colliderCapsule3D = 3
	colliderBox3D     = 4
	colliderSphere    = 5
)

// Collider shape type constants.
const (
	ColliderBox     = colliderBox3D
	ColliderSphere  = colliderSphere
	ColliderCapsule = colliderCapsule3D
)

// 3D collider constructors.
func Box(halfX, halfY, halfZ float64) Collider {
	return Collider{kind: colliderBox3D, args: [3]float64{halfX, halfY, halfZ}}
}
func Sphere(radius float64) Collider {
	return Collider{kind: colliderSphere, args: [3]float64{radius, 0, 0}}
}
func Capsule(halfHeight, radius float64) Collider {
	return Collider{kind: colliderCapsule3D, args: [3]float64{halfHeight, radius, 0}}
}

func TrimeshPhysics(model voplay.ModelID) *Physics {
	return &Physics{
		Type:        Static,
		Trimesh:     &Trimesh{Model: model},
		Layer:       voplay.CollisionLayerDefault,
		Mask:        voplay.CollisionMaskAll,
		Friction:    0.5,
		Restitution: 0.0,
	}
}

// Kind returns the collider shape type (ColliderBox, ColliderSphere, or ColliderCapsule).
func (c Collider) Kind() int {
	return c.kind
}

// Args returns the raw shape arguments.
// Box: [halfX, halfY, halfZ], Sphere: [radius, 0, 0], Capsule: [halfHeight, radius, 0].
func (c Collider) Args() [3]float64 {
	return c.args
}

func (c Collider) Offset() voplay.Vec3 {
	return c.offset
}

// WithOffset returns a copy of the collider with the given local-space offset.
func (c Collider) WithOffset(offset voplay.Vec3) Collider {
	c.offset = offset
	return c
}

// Contact represents an active collision pair between two entities.
type Contact struct {
	A *Entity
	B *Entity
}

// RayCastHit describes a ray cast hit in the 3D physics world.
type RayCastHit struct {
	Entity   *Entity
	Point    voplay.Vec3
	Normal   voplay.Vec3
	Distance float64
}

// Physics 3D command opcodes (must match Rust physics3d.rs).
const (
	physicsCmdForce   byte = 1
	physicsCmdImpulse byte = 2
	physicsCmdSetVel  byte = 3
	physicsCmdSetPos  byte = 4
	physicsCmdSetRot  byte = 5
	physicsCmdSetAngVel byte = 6
)

// writePhysCmd appends a 3D physics command to this scene's command buffer.
func (s *Scene) writePhysCmd(cmd byte, bodyID int, v1, v2, v3 float64) {
	s.physCmds.WriteByte(cmd)
	s.physCmds.WriteU32(bodyID)
	s.physCmds.WriteF64(v1)
	s.physCmds.WriteF64(v2)
	s.physCmds.WriteF64(v3)
}

// writePhysCmdQuat appends a quaternion-valued physics command (rotation teleport).
func (s *Scene) writePhysCmdQuat(cmd byte, bodyID int, q voplay.Quat) {
	s.physCmds.WriteByte(cmd)
	s.physCmds.WriteU32(bodyID)
	s.physCmds.WriteF64(q.X)
	s.physCmds.WriteF64(q.Y)
	s.physCmds.WriteF64(q.Z)
	s.physCmds.WriteF64(q.W)
}

// ApplyForce applies a force to a 3D physics entity (buffered until next step).
func (e *Entity) ApplyForce(force voplay.Vec3) {
	e.scene.writePhysCmd(physicsCmdForce, e.Physics.bodyID, force.X, force.Y, force.Z)
}

// ApplyImpulse applies an impulse to a 3D physics entity (buffered until next step).
func (e *Entity) ApplyImpulse(impulse voplay.Vec3) {
	e.scene.writePhysCmd(physicsCmdImpulse, e.Physics.bodyID, impulse.X, impulse.Y, impulse.Z)
}

// SetVelocity sets the linear velocity of a 3D physics entity (buffered until next step).
func (e *Entity) SetVelocity(vel voplay.Vec3) {
	e.Physics.velocity = vel
	e.scene.writePhysCmd(physicsCmdSetVel, e.Physics.bodyID, vel.X, vel.Y, vel.Z)
}

// SetAngularVelocity sets the angular velocity of a 3D physics entity (buffered until next step).
func (e *Entity) SetAngularVelocity(vel voplay.Vec3) {
	e.Physics.angularVelocity = vel
	e.scene.writePhysCmd(physicsCmdSetAngVel, e.Physics.bodyID, vel.X, vel.Y, vel.Z)
}

// SetPosition teleports the entity to the given world position.
// For physics entities, also buffers a position command for the next physics step.
func (e *Entity) SetPosition(pos voplay.Vec3) {
	e.position = pos
	if e.scene != nil && e.Physics != nil {
		e.scene.writePhysCmd(physicsCmdSetPos, e.Physics.bodyID, pos.X, pos.Y, pos.Z)
	}
}

// SetRotation sets the entity's world rotation.
// For physics entities, also buffers a rotation command for the next physics step.
func (e *Entity) SetRotation(rot voplay.Quat) {
	e.rotation = rot
	if e.scene != nil && e.Physics != nil {
		e.scene.writePhysCmdQuat(physicsCmdSetRot, e.Physics.bodyID, rot)
	}
}

// SetScale sets the entity's world scale.
// Panics if the entity has a physics collider (collider resize is not supported).
func (e *Entity) SetScale(s voplay.Vec3) {
	if e.Physics != nil {
		panic("Entity.SetScale: physics collider resize is not supported")
	}
	e.scale = s
}

// Velocity returns the current linear velocity (updated after each physics step).
// Panics if the entity has no Physics component.
func (e *Entity) Velocity() voplay.Vec3 {
	return e.Physics.velocity
}

// AngularVelocity returns the current angular velocity (updated after each physics step).
// Panics if the entity has no Physics component.
func (e *Entity) AngularVelocity() voplay.Vec3 {
	return e.Physics.angularVelocity
}

// serializeBodyDesc encodes a 3D body description for the physics extern.
func serializeBodyDesc(e *Entity) []byte {
	p := e.Physics
	voplay.ValidateCollisionFilter(p.Layer, p.Mask)
	w := codec.NewByteWriter(154)
	w.WriteByte(byte(p.Type))
	w.WriteByte(byte(p.Collider.kind))
	w.WriteBool(p.FixedRotation)
	w.WriteBool(p.LockRotationX)
	w.WriteBool(p.LockRotationY)
	w.WriteBool(p.LockRotationZ)
	w.WriteU16(p.Layer)
	w.WriteU16(p.Mask)
	w.WriteF64(e.position.X)
	w.WriteF64(e.position.Y)
	w.WriteF64(e.position.Z)
	w.WriteF64(e.rotation.X)
	w.WriteF64(e.rotation.Y)
	w.WriteF64(e.rotation.Z)
	w.WriteF64(e.rotation.W)
	w.WriteF64(p.Collider.args[0])
	w.WriteF64(p.Collider.args[1])
	w.WriteF64(p.Collider.args[2])
	w.WriteF64(p.Collider.offset.X)
	w.WriteF64(p.Collider.offset.Y)
	w.WriteF64(p.Collider.offset.Z)
	w.WriteF64(p.Density)
	w.WriteF64(p.Friction)
	w.WriteF64(p.Restitution)
	w.WriteF64(p.LinearDamping)
	w.WriteF64(p.AngularDamping)
	return w.Bytes()
}

func serializeTrimeshDesc(e *Entity) []byte {
	p := e.Physics
	voplay.ValidateCollisionFilter(p.Layer, p.Mask)
	w := codec.NewByteWriter(100)
	w.WriteF64(e.position.X)
	w.WriteF64(e.position.Y)
	w.WriteF64(e.position.Z)
	w.WriteF64(e.rotation.X)
	w.WriteF64(e.rotation.Y)
	w.WriteF64(e.rotation.Z)
	w.WriteF64(e.rotation.W)
	w.WriteF64(e.scale.X)
	w.WriteF64(e.scale.Y)
	w.WriteF64(e.scale.Z)
	w.WriteU16(p.Layer)
	w.WriteU16(p.Mask)
	w.WriteF64(p.Friction)
	w.WriteF64(p.Restitution)
	return w.Bytes()
}

// PhysicsBackend abstracts 3D physics world operations so they can be
// replaced in tests without per-function hook boilerplate.
type PhysicsBackend interface {
	Init(gravity voplay.Vec3) int
	Destroy(worldID int)
	SpawnBody(worldID, bodyID int, data []byte)
	SpawnTrimeshBody(worldID, bodyID, modelID int, data []byte)
	SpawnHeightfield(worldID, bodyID int, desc HeightfieldSpawnDesc)
	DestroyBody(worldID, bodyID int)
	CreateRaycastVehicle(worldID, vehicleID, bodyID int)
	DestroyRaycastVehicle(worldID, vehicleID int)
	AddRaycastVehicleWheel(worldID, vehicleID int, data []byte)
	SetRaycastVehicleWheelControl(worldID, vehicleID, wheelID int, steering, engineForce, brake float64)
	RaycastVehicleState(worldID, vehicleID int) []byte
	Step(worldID int, dt float64, cmds []byte) []byte
	Contacts(worldID int) []byte
	SetGravity(worldID int, gravity voplay.Vec3)
	RayCast(worldID int, origin, dir voplay.Vec3, maxDist float64) []byte
	QueryAABB(worldID int, min, max voplay.Vec3) []byte
}

