package scene3d

import (
	"math"
	"github.com/vo-lang/voplay"
)

type RacingCameraTarget struct {
	Position voplay.Vec3
	Forward voplay.Vec3
	Velocity voplay.Vec3
	Speed float64
	Drift float64
	Boost bool
	LandingShake float64
}

type RacingCamera struct {
	BaseDistance float64
	MaxDistance float64
	Height float64
	TargetHeight float64
	LookaheadBase float64
	LookaheadSpeedScale float64
	DistanceSpeedScale float64
	DriftOffset float64
	Smoothing float64
	TargetSmoothing float64
	Fov float64
	SpeedFov float64
	BoostFovKick float64
	BoostSmoothing float64
	CollisionEnabled bool
	CollisionOffset float64
	ShakeScale float64

	currentPos voplay.Vec3
	currentTarget voplay.Vec3
	currentFov float64
	boostAmount float64
	initialized bool
}

func NewRacingCamera() *RacingCamera {
	return &RacingCamera{
		BaseDistance: 7.5,
		MaxDistance: 11.5,
		Height: 3.0,
		TargetHeight: 1.2,
		LookaheadBase: 4.0,
		LookaheadSpeedScale: 0.16,
		DistanceSpeedScale: 0.055,
		DriftOffset: 1.15,
		Smoothing: 8.5,
		TargetSmoothing: 12.0,
		Fov: 58.0,
		SpeedFov: 0.18,
		BoostFovKick: 7.0,
		BoostSmoothing: 10.0,
		CollisionEnabled: true,
		CollisionOffset: 0.35,
		ShakeScale: 0.28,
	}
}

func RacingCameraTargetFromVehicle(vehicle *Vehicle) RacingCameraTarget {
	if vehicle == nil || vehicle.Body == nil {
		return RacingCameraTarget{Forward: voplay.Vec3{Z: -1}}
	}
	vel := vehicle.Body.Velocity()
	return RacingCameraTarget{
		Position: vehicle.Body.Position(),
		Forward: vehicle.Forward(),
		Velocity: vel,
		Speed: math.Abs(vehicle.Speed),
		Drift: racingCameraBoolAmount(vehicle.Drifting),
		Boost: false,
	}
}

func (c *RacingCamera) Update(scene *Scene, target RacingCameraTarget, dt float64) {
	c.normalize()
	forward := target.Forward
	forward.Y = 0
	if forward.LengthSq() <= 0.000001 {
		if target.Velocity.LengthSq() > 0.000001 {
			forward = voplay.Vec3{X: target.Velocity.X, Z: target.Velocity.Z}
		} else {
			forward = voplay.Vec3{Z: -1}
		}
	}
	forward = forward.Normalize()
	right := forward.Cross(voplay.Vec3{Y: 1}).Normalize()
	speed := target.Speed
	if speed <= 0 {
		speed = target.Velocity.Length()
	}
	if speed < 0 {
		speed = -speed
	}
	boostTarget := 0.0
	if target.Boost {
		boostTarget = 1.0
	}
	c.boostAmount = racingCameraSmoothScalar(c.boostAmount, boostTarget, c.BoostSmoothing, dt)
	drift := racingCameraClamp(target.Drift, -1, 1)
	pivot := target.Position.Add(voplay.Vec3{Y: c.TargetHeight})
	lookahead := c.LookaheadBase + speed*c.LookaheadSpeedScale
	desiredTarget := pivot.Add(forward.Scale(lookahead)).Add(right.Scale(drift * c.DriftOffset * 0.35))
	distance := c.BaseDistance + speed*c.DistanceSpeedScale + c.boostAmount*0.8
	if distance > c.MaxDistance {
		distance = c.MaxDistance
	}
	shake := racingCameraClamp(target.LandingShake, 0, 1) * c.ShakeScale
	desiredPos := pivot.Sub(forward.Scale(distance)).Add(right.Scale(drift * c.DriftOffset)).Add(voplay.Vec3{Y: c.Height + shake})
	if c.CollisionEnabled && scene != nil {
		desiredPos = c.resolveCollision(scene, pivot, desiredPos)
	}
	desiredFov := c.Fov + speed*c.SpeedFov + c.boostAmount*c.BoostFovKick
	if !c.initialized || dt <= 0 {
		c.currentPos = desiredPos
		c.currentTarget = desiredTarget
		c.currentFov = desiredFov
		c.initialized = true
		return
	}
	c.currentPos = c.currentPos.Lerp(desiredPos, racingCameraSmoothT(c.Smoothing, dt))
	c.currentTarget = c.currentTarget.Lerp(desiredTarget, racingCameraSmoothT(c.TargetSmoothing, dt))
	c.currentFov = racingCameraLerp(c.currentFov, desiredFov, racingCameraSmoothT(c.TargetSmoothing, dt))
	if c.CollisionEnabled && scene != nil {
		c.currentPos = c.resolveCollision(scene, pivot, c.currentPos)
	}
}

func (c *RacingCamera) Apply(cam *Camera) {
	cam.Position = c.currentPos
	cam.Target = c.currentTarget
	cam.Up = voplay.Vec3{Y: 1}
	cam.Fov = c.currentFov
}

func (c *RacingCamera) UpdateCamera(cam *Camera, scene *Scene, target RacingCameraTarget, dt float64) {
	c.Update(scene, target, dt)
	c.Apply(cam)
}

func (c *RacingCamera) Position() voplay.Vec3 {
	return c.currentPos
}

func (c *RacingCamera) Target() voplay.Vec3 {
	return c.currentTarget
}

func (c *RacingCamera) CurrentFov() float64 {
	return c.currentFov
}

func (c *RacingCamera) resolveCollision(scene *Scene, pivot, desiredPos voplay.Vec3) voplay.Vec3 {
	dir := desiredPos.Sub(pivot)
	dist := dir.Length()
	if dist <= 0.000001 {
		return desiredPos
	}
	dir = dir.Scale(1.0 / dist)
	hit := scene.RayCast(pivot, dir, dist)
	if hit == nil {
		return desiredPos
	}
	pullDist := hit.Distance - c.CollisionOffset
	if pullDist < 0 {
		pullDist = 0
	}
	if pullDist > dist {
		pullDist = dist
	}
	return pivot.Add(dir.Scale(pullDist))
}

func (c *RacingCamera) normalize() {
	defaults := NewRacingCamera()
	if c.BaseDistance <= 0 {
		c.BaseDistance = defaults.BaseDistance
	}
	if c.MaxDistance < c.BaseDistance {
		c.MaxDistance = defaults.MaxDistance
	}
	if c.Height <= 0 {
		c.Height = defaults.Height
	}
	if c.TargetHeight <= 0 {
		c.TargetHeight = defaults.TargetHeight
	}
	if c.LookaheadBase <= 0 {
		c.LookaheadBase = defaults.LookaheadBase
	}
	if c.Smoothing < 0 {
		c.Smoothing = defaults.Smoothing
	}
	if c.TargetSmoothing < 0 {
		c.TargetSmoothing = defaults.TargetSmoothing
	}
	if c.Fov <= 0 {
		c.Fov = defaults.Fov
	}
	if c.BoostSmoothing < 0 {
		c.BoostSmoothing = defaults.BoostSmoothing
	}
	if c.CollisionOffset <= 0 {
		c.CollisionOffset = defaults.CollisionOffset
	}
	if c.ShakeScale <= 0 {
		c.ShakeScale = defaults.ShakeScale
	}
}

func racingCameraSmoothT(smoothing, dt float64) float64 {
	if smoothing <= 0 || dt <= 0 {
		return 1
	}
	return 1.0 - math.Exp(-smoothing*dt)
}

func racingCameraSmoothScalar(current, target, smoothing, dt float64) float64 {
	return racingCameraLerp(current, target, racingCameraSmoothT(smoothing, dt))
}

func racingCameraLerp(a, b, t float64) float64 {
	return a + (b-a)*t
}

func racingCameraClamp(v, lo, hi float64) float64 {
	if v < lo {
		return lo
	}
	if v > hi {
		return hi
	}
	return v
}

func racingCameraBoolAmount(v bool) float64 {
	if v {
		return 1
	}
	return 0
}

package scene3d

import "github.com/vo-lang/voplay"

const (
	RacingActionSteerLeft = "racing.steer_left"
	RacingActionSteerRight = "racing.steer_right"
	RacingActionThrottle = "racing.throttle"
	RacingActionBrake = "racing.brake"
	RacingActionDrift = "racing.drift"
	RacingActionBoost = "racing.boost"
)

type RacingInput struct {
	Steer float64
	Throttle float64
	Brake float64
	Drift bool
	Boost bool
}

type RacingInputProfile struct {
	Actions *voplay.ActionMap
	Gamepad int
	Deadzone float64
}

func NewRacingInputProfile(input *voplay.InputState) *RacingInputProfile {
	if input == nil {
		panic("scene3d.NewRacingInputProfile: input must not be nil")
	}
	p := &RacingInputProfile{
		Actions: voplay.NewActionMap(input),
		Gamepad: 0,
		Deadzone: 0.18,
	}
	p.BindDefaults()
	return p
}

func (p *RacingInputProfile) BindDefaults() {
	if p == nil || p.Actions == nil {
		panic("scene3d.RacingInputProfile.BindDefaults: profile is not initialized")
	}
	p.Actions.Rebind(RacingActionSteerLeft, voplay.KeyBinding("ArrowLeft"), voplay.KeyBinding("a"), voplay.GamepadAxisBinding(p.Gamepad, "left_x", -1, p.Deadzone))
	p.Actions.Rebind(RacingActionSteerRight, voplay.KeyBinding("ArrowRight"), voplay.KeyBinding("d"), voplay.GamepadAxisBinding(p.Gamepad, "left_x", 1, p.Deadzone))
	p.Actions.Rebind(RacingActionThrottle, voplay.KeyBinding("ArrowUp"), voplay.KeyBinding("w"), voplay.GamepadAxisBinding(p.Gamepad, "right_trigger", 1, 0.04))
	p.Actions.Rebind(RacingActionBrake, voplay.KeyBinding("ArrowDown"), voplay.KeyBinding("s"), voplay.GamepadAxisBinding(p.Gamepad, "left_trigger", 1, 0.04))
	p.Actions.Rebind(RacingActionDrift, voplay.KeyBinding(" "), voplay.GamepadButtonBinding(p.Gamepad, "right_shoulder"))
	p.Actions.Rebind(RacingActionBoost, voplay.KeyBinding("Shift"), voplay.GamepadButtonBinding(p.Gamepad, "south"))
}

func (p *RacingInputProfile) Rebind(action string, bindings ...voplay.InputBinding) {
	if p == nil || p.Actions == nil {
		panic("scene3d.RacingInputProfile.Rebind: profile is not initialized")
	}
	p.Actions.Rebind(action, bindings...)
}

func (p *RacingInputProfile) Read() RacingInput {
	if p == nil || p.Actions == nil {
		panic("scene3d.RacingInputProfile.Read: profile is not initialized")
	}
	return RacingInput{
		Steer: racingInputClamp(p.Actions.Axis(RacingActionSteerLeft, RacingActionSteerRight), -1, 1),
		Throttle: racingInputClamp(p.Actions.Value(RacingActionThrottle), 0, 1),
		Brake: racingInputClamp(p.Actions.Value(RacingActionBrake), 0, 1),
		Drift: p.Actions.IsDown(RacingActionDrift),
		Boost: p.Actions.IsDown(RacingActionBoost),
	}
}

func (i RacingInput) VehicleInput() VehicleInput {
	throttle := i.Throttle
	if i.Brake > throttle {
		throttle = -i.Brake
	}
	return VehicleInput{
		Throttle: racingInputClamp(throttle, -1, 1),
		Steer: racingInputClamp(i.Steer, -1, 1),
		Drift: i.Drift,
		Boost: i.Boost,
	}
}

func racingInputClamp(v, lo, hi float64) float64 {
	if v < lo {
		return lo
	}
	if v > hi {
		return hi
	}
	return v
}

package scene3d

import (
	"encoding/json"
	"errors"
	"github.com/vo-lang/voplay"
)

const RacingReplayFormatVersion = 1
const RacingReplayEngineVersion = "voplay-racing-1"

type RacingReplay struct {
	FormatVersion int `json:"formatVersion"`
	EngineVersion string `json:"engineVersion"`
	FixedStep float64 `json:"fixedStep"`
	Inputs []RacingReplayInputSample `json:"inputs"`
	Transforms []RacingReplayTransformSample `json:"transforms,omitempty"`
	Checkpoints []RacingReplayCheckpoint `json:"checkpoints,omitempty"`
}

type RacingReplayInputSample struct {
	Step int `json:"step"`
	Input RacingInput `json:"input"`
}

type RacingReplayTransformSample struct {
	Step int `json:"step"`
	Position voplay.Vec3 `json:"position"`
	Rotation voplay.Quat `json:"rotation"`
}

type RacingReplayCheckpoint struct {
	Step int `json:"step"`
	Name string `json:"name"`
	Distance float64 `json:"distance,omitempty"`
}

type RacingReplayRecorder struct {
	replay RacingReplay
}

type RacingReplayCursor struct {
	replay *RacingReplay
	inputIndex int
	checkpointIndex int
}

func NewRacingReplayRecorder(fixedStep float64) *RacingReplayRecorder {
	if fixedStep <= 0 {
		panic("scene3d.NewRacingReplayRecorder: fixedStep must be > 0")
	}
	return &RacingReplayRecorder{replay: RacingReplay{FormatVersion: RacingReplayFormatVersion, EngineVersion: RacingReplayEngineVersion, FixedStep: fixedStep, Inputs: []RacingReplayInputSample{}, Transforms: []RacingReplayTransformSample{}, Checkpoints: []RacingReplayCheckpoint{}}}
}

func (r *RacingReplayRecorder) RecordInput(step int, input RacingInput) {
	r.requireStep(step)
	r.replay.Inputs = append(r.replay.Inputs, RacingReplayInputSample{Step: step, Input: normalizeReplayInput(input)})
}

func (r *RacingReplayRecorder) RecordTransform(step int, position voplay.Vec3, rotation voplay.Quat) {
	r.requireStep(step)
	r.replay.Transforms = append(r.replay.Transforms, RacingReplayTransformSample{Step: step, Position: position, Rotation: rotation})
}

func (r *RacingReplayRecorder) RecordCheckpoint(step int, name string, distance float64) {
	r.requireStep(step)
	if name == "" {
		panic("scene3d.RacingReplayRecorder.RecordCheckpoint: name must not be empty")
	}
	r.replay.Checkpoints = append(r.replay.Checkpoints, RacingReplayCheckpoint{Step: step, Name: name, Distance: distance})
}

func (r *RacingReplayRecorder) Replay() RacingReplay {
	return cloneRacingReplay(r.replay)
}

func (r *RacingReplayRecorder) MarshalJSON() ([]byte, error) {
	replay := r.Replay()
	return MarshalRacingReplay(replay)
}

func (r *RacingReplayRecorder) requireStep(step int) {
	if r == nil {
		panic("scene3d.RacingReplayRecorder: recorder is nil")
	}
	if step < 0 {
		panic("scene3d.RacingReplayRecorder: step must be >= 0")
	}
}

func MarshalRacingReplay(replay RacingReplay) ([]byte, error) {
	if err := ValidateRacingReplay(replay); err != nil {
		return nil, err
	}
	return json.MarshalIndent(replay, "", "  ")
}

func UnmarshalRacingReplay(data []byte) (RacingReplay, error) {
	var replay RacingReplay
	json.Unmarshal(data, &replay)?
	if err := ValidateRacingReplay(replay); err != nil {
		return RacingReplay{}, err
	}
	return replay, nil
}

func ValidateRacingReplay(replay RacingReplay) error {
	if replay.FormatVersion != RacingReplayFormatVersion {
		return errors.New("scene3d.ValidateRacingReplay: unsupported format version")
	}
	if replay.EngineVersion == "" {
		return errors.New("scene3d.ValidateRacingReplay: engineVersion must not be empty")
	}
	if replay.FixedStep <= 0 {
		return errors.New("scene3d.ValidateRacingReplay: fixedStep must be > 0")
	}
	if !replayStepsIncreasingInputs(replay.Inputs) {
		return errors.New("scene3d.ValidateRacingReplay: input steps must be non-decreasing")
	}
	if !replayStepsIncreasingTransforms(replay.Transforms) {
		return errors.New("scene3d.ValidateRacingReplay: transform steps must be non-decreasing")
	}
	if !replayStepsIncreasingCheckpoints(replay.Checkpoints) {
		return errors.New("scene3d.ValidateRacingReplay: checkpoint steps must be non-decreasing")
	}
	return nil
}

func NewRacingReplayCursor(replay *RacingReplay) (*RacingReplayCursor, error) {
	if replay == nil {
		return nil, errors.New("scene3d.NewRacingReplayCursor: replay is nil")
	}
	if err := ValidateRacingReplay(*replay); err != nil {
		return nil, err
	}
	return &RacingReplayCursor{replay: replay}, nil
}

func (c *RacingReplayCursor) InputAt(step int) (RacingInput, bool) {
	if c == nil || c.replay == nil {
		return RacingInput{}, false
	}
	for c.inputIndex < len(c.replay.Inputs) && c.replay.Inputs[c.inputIndex].Step < step {
		c.inputIndex++
	}
	if c.inputIndex < len(c.replay.Inputs) && c.replay.Inputs[c.inputIndex].Step == step {
		return c.replay.Inputs[c.inputIndex].Input, true
	}
	return RacingInput{}, false
}

func (c *RacingReplayCursor) CheckpointsAt(step int) []RacingReplayCheckpoint {
	result := []RacingReplayCheckpoint{}
	if c == nil || c.replay == nil {
		return result
	}
	for c.checkpointIndex < len(c.replay.Checkpoints) && c.replay.Checkpoints[c.checkpointIndex].Step < step {
		c.checkpointIndex++
	}
	for c.checkpointIndex < len(c.replay.Checkpoints) && c.replay.Checkpoints[c.checkpointIndex].Step == step {
		result = append(result, c.replay.Checkpoints[c.checkpointIndex])
		c.checkpointIndex++
	}
	return result
}

func CheckpointSequence(replay RacingReplay) []string {
	result := make([]string, 0, len(replay.Checkpoints))
	for _, checkpoint := range replay.Checkpoints {
		result = append(result, checkpoint.Name)
	}
	return result
}

func normalizeReplayInput(input RacingInput) RacingInput {
	input.Steer = racingInputClamp(input.Steer, -1, 1)
	input.Throttle = racingInputClamp(input.Throttle, 0, 1)
	input.Brake = racingInputClamp(input.Brake, 0, 1)
	return input
}

func cloneRacingReplay(replay RacingReplay) RacingReplay {
	out := replay
	out.Inputs = append([]RacingReplayInputSample{}, replay.Inputs...)
	out.Transforms = append([]RacingReplayTransformSample{}, replay.Transforms...)
	out.Checkpoints = append([]RacingReplayCheckpoint{}, replay.Checkpoints...)
	return out
}

func replayStepsIncreasingInputs(samples []RacingReplayInputSample) bool {
	prev := -1
	for _, sample := range samples {
		if sample.Step < prev {
			return false
		}
		prev = sample.Step
	}
	return true
}

func replayStepsIncreasingTransforms(samples []RacingReplayTransformSample) bool {
	prev := -1
	for _, sample := range samples {
		if sample.Step < prev {
			return false
		}
		prev = sample.Step
	}
	return true
}

func replayStepsIncreasingCheckpoints(samples []RacingReplayCheckpoint) bool {
	prev := -1
	for _, sample := range samples {
		if sample.Step < prev {
			return false
		}
		prev = sample.Step
	}
	return true
}

// Scene manages 3D entities, camera, lighting, and physics.
// Camera is in camera.vo, physics types in physics.vo.
package scene3d

import "errors"
import "math"
import "github.com/vo-lang/voplay"
import "github.com/vo-lang/voplay/codec"
import "github.com/vo-lang/voplay/primitive3d"

// Light is a light source in the 3D scene (alias for voplay.LightDesc).
type Light = voplay.LightDesc

// Light type constants (re-exported from voplay for convenience).
const (
	DirectionalLight = voplay.DirectionalLight
	PointLight       = voplay.PointLight
)

const (
	FogNone       = voplay.FogNone
	FogLinear     = voplay.FogLinear
	FogExp        = voplay.FogExp
	FogExpSquared = voplay.FogExpSquared
)

const (
	ToneMapNone = voplay.ToneMapNone
	ToneMapReinhard = voplay.ToneMapReinhard
	ToneMapACES = voplay.ToneMapACES
)

const (
	RenderDebugLit = voplay.RenderDebugLit
	RenderDebugAlbedo = voplay.RenderDebugAlbedo
	RenderDebugNormal = voplay.RenderDebugNormal
	RenderDebugRoughness = voplay.RenderDebugRoughness
	RenderDebugMetallic = voplay.RenderDebugMetallic
	RenderDebugShadow = voplay.RenderDebugShadow
	RenderDebugDirect = voplay.RenderDebugDirect
	RenderDebugAmbient = voplay.RenderDebugAmbient
)

const (
	PickDefault  = 0
	PickEnabled  = 1
	PickDisabled = 2
	physics3DBodyStateBytes = 4 + 13*8
)

var nextRenderSceneID = 1

func allocateRenderSceneID() int {
	id := nextRenderSceneID
	nextRenderSceneID++
	return id
}

type FogConfig struct {
	Mode    int
	Color   voplay.Color
	Start   float64
	End     float64
	Density float64
}

type ColorGradingConfig struct {
	ToneMap int
	Exposure float64
	Contrast float64
	Saturation float64
}

// Scene holds the 3D scene state.
type Scene struct {
	Camera  Camera
	Skybox  voplay.CubemapID
	Lights  []Light
	Ambient voplay.Color
	AmbientGround voplay.Color
	ShadowsEnabled bool
	ShadowResolution int
	ShadowStrength float64
	Fog     FogConfig
	ColorGrading ColorGradingConfig
	RenderDebugMode int
	Gravity voplay.Vec3
	Emitters []*ParticleEmitter

	entities     []*Entity
	visibleBuf   []*Entity
	nextEntityID int
	entityByID   map[int]*Entity
	worldID      int
	animationWorldID      int
	nextBodyID   int
	nextVehicleID int
	nextAnimationTargetID int
	physCmds     codec.ByteWriter
	bodyMap      map[int]*Entity
	vehicles     []*Vehicle
	animationInfoCache map[int]AnimationModelInfo
	renderSceneID int
	renderSceneCreated bool
	renderSceneCleared bool
	renderDestroyedIDs []int
	renderStats SceneRenderStats
	primitiveLayers []*primitiveLayerAttachment
	primitiveDestroyedLayerHandles []primitive3d.LayerHandle
	nextPrimitiveLayerHandle int
	primitiveStats primitive3d.Stats
}

// New creates a new 3D scene with default camera and gravity.
func New() *Scene {
	return &Scene{
		Camera: Camera{
			Position: voplay.Vec3{0, 5, 10},
			Target:   voplay.Vec3{0, 0, 0},
			Up:       voplay.Vec3{0, 1, 0},
			Fov:      60,
			Near:     0.1,
			Far:      1000,
		},
		Ambient:      voplay.Color{0.1, 0.1, 0.1, 1},
		AmbientGround: voplay.Color{0.1, 0.1, 0.1, 1},
		ShadowsEnabled: false,
		ShadowResolution: 2048,
		ShadowStrength: 1.0,
		Gravity:      voplay.Vec3{0, -9.8, 0},
		nextEntityID: 1,
		entityByID:   make(map[int]*Entity),
		nextBodyID:   1,
		nextVehicleID: 1,
		nextAnimationTargetID: 1,
		physCmds:     codec.NewByteWriter(256),
		bodyMap:      make(map[int]*Entity),
		animationInfoCache: make(map[int]AnimationModelInfo),
		renderSceneID: allocateRenderSceneID(),
		nextPrimitiveLayerHandle: 1,
	}
}

// EntityDesc describes a new 3D entity to spawn.
type EntityDesc struct {
	Position voplay.Vec3
	Rotation voplay.Quat
	Scale    voplay.Vec3
	Model    voplay.ModelID
	OwnedModel voplay.ModelID
	Material voplay.MaterialDesc
	PickMode int
	Tint     voplay.Color
	TintSet  bool
	Tag      string
	Data     any
	Physics  *Physics
	StaticRenderable bool
	CullDistance float64
	CullRadius float64
	FrustumCull bool
}

type SceneRenderStats struct {
	ActiveEntities int
	VisibleEntities int
	CulledEntities int
	ModelEntities int
	UpsertedObjects int
	DestroyedObjects int
	BatchEligibleObjects int
	BatchGroups int
	FlushCpuMs float64
	FrameCpuMs float64
}

// Entity is a 3D game object managed by the scene.
// Transform fields are always present. Optional components (Model, Physics)
// are zero/nil when not used. Physics runtime state (bodyID, velocity) lives
// in the Physics struct, not on Entity.
type Entity struct {
	id       int
	position voplay.Vec3
	rotation voplay.Quat
	scale    voplay.Vec3
	Model    voplay.ModelID
	ownedModel voplay.ModelID
	Material voplay.MaterialDesc
	Pickable bool
	Tint     voplay.Color
	Tag      string
	Active   bool
	Visible  bool
	Data     any
	Physics  *Physics
	audioSources []voplay.AudioSourceID
	animationTargetID int
	hasSkeleton     bool
	hasSkeletonInit bool
	scene    *Scene
	renderObjectCreated bool
	renderLastModel voplay.ModelID
	renderLastMaterial voplay.MaterialDesc
	renderLastPosition voplay.Vec3
	renderLastRotation voplay.Quat
	renderLastScale voplay.Vec3
	renderLastTint voplay.Color
	renderLastVisible bool
	renderLastAnimationWorldID int
	renderLastAnimationTargetID int
	StaticRenderable bool
	CullDistance float64
	CullRadius float64
	FrustumCull bool
}

// Position returns the entity's world position.
func (e *Entity) Position() voplay.Vec3 {
	return e.position
}

// Rotation returns the entity's world rotation.
func (e *Entity) Rotation() voplay.Quat {
	return e.rotation
}

// Scale returns the entity's world scale.
func (e *Entity) Scale() voplay.Vec3 {
	return e.scale
}

// ID returns the entity's unique identifier within its scene.
func (e *Entity) ID() int {
	return e.id
}

// HasSkeleton returns true if the entity's model has a skeleton for animation.
// This is determined lazily on first access and cached.
func (e *Entity) HasSkeleton() bool {
	e.ensureHasSkeleton()
	return e.hasSkeleton
}

func (e *Entity) SetCullDistance(distance float64) {
	if distance < 0 {
		panic("scene3d.Entity.SetCullDistance: distance must be >= 0")
	}
	e.CullDistance = distance
}

func (e *Entity) SetFrustumCull(enabled bool) {
	e.FrustumCull = enabled
}

func (e *Entity) ensureHasSkeleton() {
	if e.hasSkeletonInit || e.Model == 0 || e.scene == nil {
		return
	}
	e.hasSkeletonInit = true
	e.hasSkeleton = e.scene.AnimationModelInfo(e.Model).HasSkeleton
}

func (e *Entity) PlaySound3D(clip voplay.AudioClipID, volume float64) {
	if e.scene == nil || !e.Active {
		panic("scene3d.Entity.PlaySound3D: entity must belong to an active scene")
	}
	clip.PlaySound3D(e.position, volume, 1.0, 50.0)
}

func (e *Entity) AttachAudioSource(clip voplay.AudioClipID, volume, refDistance, maxDistance float64) (voplay.AudioSourceID, error) {
	if e.scene == nil || !e.Active {
		return 0, errors.New("scene3d.Entity.AttachAudioSource: entity must belong to an active scene")
	}
	source, err := voplay.CreateAudioSource3D(clip, e.position, volume, refDistance, maxDistance)
	if err != nil {
		return 0, err
	}
	e.audioSources = append(e.audioSources, source)
	return source, nil
}

func (e *Entity) RemoveAudioSource(source voplay.AudioSourceID) {
	if e.scene == nil || !e.Active {
		panic("scene3d.Entity.RemoveAudioSource: entity must belong to an active scene")
	}
	for i, existing := range e.audioSources {
		if existing != source {
			continue
		}
		last := len(e.audioSources) - 1
		e.audioSources[i] = e.audioSources[last]
		e.audioSources[last] = 0
		e.audioSources = e.audioSources[:last]
		source.Remove()
		return
	}
	panic("scene3d.Entity.RemoveAudioSource: source is not attached to entity")
}

func normalizeEntityModels(desc EntityDesc) (voplay.ModelID, voplay.ModelID) {
	model := desc.Model
	ownedModel := desc.OwnedModel
	if ownedModel == 0 {
		return model, 0
	}
	if model != 0 && model != ownedModel {
		panic("Scene.Spawn: Model and OwnedModel must match when both are set")
	}
	return ownedModel, ownedModel
}

func resolveEntityPickable(desc EntityDesc, model voplay.ModelID) bool {
	pickable := model != 0
	if desc.PickMode == PickEnabled {
		return true
	}
	if desc.PickMode == PickDisabled {
		return false
	}
	return pickable
}

func isZeroColor(c voplay.Color) bool {
	return c.R == 0 && c.G == 0 && c.B == 0 && c.A == 0
}

func isZeroQuat(q voplay.Quat) bool {
	return q.X == 0 && q.Y == 0 && q.Z == 0 && q.W == 0
}

func isIdentityQuat(q voplay.Quat) bool {
	return q.X == 0 && q.Y == 0 && q.Z == 0 && q.W == 1
}

func resolveEntityTint(desc EntityDesc) voplay.Color {
	if desc.TintSet || !isZeroColor(desc.Tint) {
		return desc.Tint
	}
	return voplay.White
}

func resolveEntityMaterial(desc EntityDesc) voplay.MaterialDesc {
	if desc.Material != (voplay.MaterialDesc{}) {
		return voplay.NormalizeMaterial(desc.Material)
	}
	if desc.TintSet || !isZeroColor(desc.Tint) {
		return voplay.MaterialColor(resolveEntityTint(desc))
	}
	return voplay.MaterialDesc{}
}

func normalizeEntityScale(scale voplay.Vec3) voplay.Vec3 {
	if scale.X == 0 && scale.Y == 0 && scale.Z == 0 {
		return voplay.Vec3{1, 1, 1}
	}
	return scale
}

func normalizeEntityRotation(rotation voplay.Quat) voplay.Quat {
	if isZeroQuat(rotation) {
		return voplay.QuatIdentity()
	}
	return rotation
}

func (s *Scene) newEntity(desc EntityDesc) *Entity {
	model, ownedModel := normalizeEntityModels(desc)
	scale := normalizeEntityScale(desc.Scale)
	ent := &Entity{
		id:       s.nextEntityID,
		position: desc.Position,
		rotation: normalizeEntityRotation(desc.Rotation),
		scale:    scale,
		Model:    model,
		ownedModel: ownedModel,
		Material: resolveEntityMaterial(desc),
		Pickable: resolveEntityPickable(desc, model),
		Tint:     resolveEntityTint(desc),
		Tag:      desc.Tag,
		Active:   true,
		Visible:  true,
		Data:     desc.Data,
		Physics:  desc.Physics,
		StaticRenderable: desc.StaticRenderable,
		CullDistance: desc.CullDistance,
		CullRadius: desc.CullRadius,
		FrustumCull: desc.FrustumCull,
		scene:    s,
	}
	if ent.Physics != nil && ent.Physics.Type == Static {
		ent.StaticRenderable = true
	}
	if ent.CullRadius <= 0 {
		ent.CullRadius = estimateEntityCullRadius(scale)
	}
	s.nextEntityID++
	return ent
}

func validateEntityPhysicsSpawn(ent *Entity) {
	p := ent.Physics
	if p == nil {
		return
	}
	if p.Trimesh != nil && p.Heightfield != nil {
		panic("Scene.Spawn: physics cannot use both trimesh and heightfield")
	}
	if p.Trimesh != nil && p.Type != Static {
		panic("Scene.Spawn: trimesh collider requires Static body type")
	}
	if p.Heightfield != nil && p.Type != Static {
		panic("Scene.Spawn: heightfield collider requires Static body type")
	}
	if p.Heightfield != nil && !isIdentityQuat(ent.rotation) {
		panic("Scene.Spawn: heightfield collider does not support rotation")
	}
	if p.Heightfield != nil && (ent.scale.X != 1 || ent.scale.Y != 1 || ent.scale.Z != 1) {
		panic("Scene.Spawn: heightfield collider uses baked terrain scale, entity scale must remain 1")
	}
	if p.Trimesh == nil && p.Heightfield == nil && p.Collider.kind != colliderBox3D && p.Collider.kind != colliderSphere && p.Collider.kind != colliderCapsule3D {
		panic("Scene.Spawn: physics entity requires a valid Collider (use Box, Sphere, or Capsule), or set Trimesh/Heightfield")
	}
}

func (s *Scene) spawnEntityPhysics(ent *Entity) bool {
	p := ent.Physics
	if p == nil {
		return false
	}
	validateEntityPhysicsSpawn(ent)
	s.ensurePhysics()
	p.bodyID = s.nextBodyID
	s.nextBodyID++
	if p.Trimesh != nil {
		physBackend.SpawnTrimeshBody(
			s.worldID,
			p.bodyID,
			int(p.Trimesh.Model),
			serializeTrimeshDesc(ent),
		)
		return true
	}
	if p.Heightfield != nil {
		physBackend.SpawnHeightfield(
			s.worldID,
			p.bodyID,
			HeightfieldSpawnDesc{
				HeightData:  p.Heightfield.heightData,
				Rows:        p.Heightfield.rows,
				Cols:        p.Heightfield.cols,
				Scale:       p.Heightfield.scale,
				Position:    ent.position,
				Layer:       p.Layer,
				Mask:        p.Mask,
				Friction:    p.Friction,
				Restitution: p.Restitution,
			},
		)
		return true
	}
	physBackend.SpawnBody(s.worldID, p.bodyID, serializeBodyDesc(ent))
	return true
}

func (s *Scene) registerEntity(ent *Entity) {
	s.entities = append(s.entities, ent)
	s.entityByID[ent.id] = ent
	if ent.Physics != nil {
		s.bodyMap[ent.Physics.bodyID] = ent
	}
}

func (s *Scene) cleanupSpawnFailure(ent *Entity, nextEntityID, nextBodyID int, hadWorld bool) {
	if ent != nil {
		if ent.Physics != nil && ent.Physics.bodyID != 0 {
			physBackend.DestroyBody(s.worldID, ent.Physics.bodyID)
			ent.Physics.bodyID = 0
		}
		s.releaseOwnedModel(ent)
		ent.scene = nil
	}
	if !hadWorld && s.worldID != 0 {
		physBackend.Destroy(s.worldID)
		s.worldID = 0
	}
	s.nextEntityID = nextEntityID
	s.nextBodyID = nextBodyID
}

func (s *Scene) releaseEntityState(e *Entity, removeEmitters bool, removeAnimationTarget bool) {
	if removeEmitters {
		s.removeAttachedEmitters(e)
	}
	s.removeAttachedAudioSources(e)
	e.Active = false
	if e.Physics != nil && e.Physics.bodyID != 0 {
		s.destroyVehiclesForBody(e)
		delete(s.bodyMap, e.Physics.bodyID)
		physBackend.DestroyBody(s.worldID, e.Physics.bodyID)
		e.Physics.bodyID = 0
		e.Physics.velocity = voplay.Vec3{}
	}
	if removeAnimationTarget && e.animationTargetID != 0 && s.animationWorldID != 0 {
		animBackend.RemoveTarget(s.animationWorldID, e.animationTargetID)
	}
	if e.renderObjectCreated {
		s.renderDestroyedIDs = append(s.renderDestroyedIDs, e.id)
		e.renderObjectCreated = false
	}
	e.animationTargetID = 0
	s.releaseOwnedModel(e)
	e.scene = nil
}

func (s *Scene) removeEntityFromList(target *Entity) {
	for i, ent := range s.entities {
		if ent != target {
			continue
		}
		last := len(s.entities) - 1
		s.entities[i] = s.entities[last]
		s.entities[last] = nil
		s.entities = s.entities[:last]
		return
	}
}

// Spawn creates an entity in the scene from a descriptor.
// If Physics is set, a Rapier3D body is created via extern.
func (s *Scene) Spawn(desc EntityDesc) *Entity {
	nextEntityID := s.nextEntityID
	nextBodyID := s.nextBodyID
	hadWorld := s.worldID != 0
	ent := s.newEntity(desc)
	defer func() {
		if r := recover(); r != nil {
			s.cleanupSpawnFailure(ent, nextEntityID, nextBodyID, hadWorld)
			panic(r)
		}
	}()
	s.spawnEntityPhysics(ent)
	s.registerEntity(ent)
	return ent
}

func (s *Scene) releaseOwnedModel(e *Entity) {
	if e.ownedModel == 0 {
		return
	}
	ownedModel := e.ownedModel
	delete(s.animationInfoCache, int(e.ownedModel))
	e.ownedModel.Free()
	e.ownedModel = 0
	if e.Model == ownedModel {
		e.Model = 0
	}
}

func (s *Scene) removeAttachedEmitters(target *Entity) {
	if len(s.Emitters) == 0 {
		return
	}
	write := 0
	for _, emitter := range s.Emitters {
		if emitter != nil && emitter.Attached == target {
			emitter.scene = nil
			emitter.Attached = nil
			continue
		}
		s.Emitters[write] = emitter
		write++
	}
	for i := write; i < len(s.Emitters); i++ {
		s.Emitters[i] = nil
	}
	s.Emitters = s.Emitters[:write]
}

func (s *Scene) removeAttachedAudioSources(target *Entity) {
	if target == nil || len(target.audioSources) == 0 {
		return
	}
	for _, source := range target.audioSources {
		source.Remove()
	}
	target.audioSources = nil
}

// Destroy removes an entity from the scene.
func (s *Scene) Destroy(e *Entity) {
	if e.scene != s {
		panic("Scene.Destroy: entity does not belong to this scene")
	}
	s.releaseEntityState(e, true, true)
	delete(s.entityByID, e.id)
	s.removeEntityFromList(e)
}

// Clear removes all entities from the scene.
func (s *Scene) Clear() {
	for _, e := range s.entities {
		s.releaseEntityState(e, false, false)
	}
	s.entities = s.entities[:0]
	for id := range s.entityByID {
		delete(s.entityByID, id)
	}
	for k := range s.bodyMap {
		delete(s.bodyMap, k)
	}
	if s.animationWorldID != 0 {
		animBackend.Destroy(s.animationWorldID)
		s.animationWorldID = 0
	}
	for _, emitter := range s.Emitters {
		if emitter != nil {
			emitter.scene = nil
			emitter.Attached = nil
		}
	}
	s.Emitters = nil
	s.nextAnimationTargetID = 1
	s.nextVehicleID = 1
	s.vehicles = nil
	s.physCmds.Reset()
	if s.renderSceneCreated {
		s.renderSceneCleared = true
		s.renderDestroyedIDs = nil
		s.primitiveDestroyedLayerHandles = nil
	}
	s.invalidatePrimitiveLayers()
}

// EntityCount returns the number of entities in the scene.
// All entities in the scene are active; Destroy removes them immediately.
func (s *Scene) EntityCount() int {
	return len(s.entities)
}

// FindByID returns the entity with the given ID, or nil if not found.
func (s *Scene) FindByID(id int) *Entity {
	e := s.entityByID[id]
	if e != nil && e.Active {
		return e
	}
	return nil
}

// FindByTag returns the first active entity with the given tag, or nil if not found.
func (s *Scene) FindByTag(tag string) *Entity {
	for _, e := range s.entities {
		if e.Active && e.Tag == tag {
			return e
		}
	}
	return nil
}

// FindAllByTag returns all active entities with the given tag.
func (s *Scene) FindAllByTag(tag string) []*Entity {
	var result []*Entity
	for _, e := range s.entities {
		if e.Active && e.Tag == tag {
			result = append(result, e)
		}
	}
	return result
}

// Entities returns a copy of the active entity list.
func (s *Scene) Entities() []*Entity {
	result := make([]*Entity, 0, len(s.entities))
	for _, e := range s.entities {
		if e.Active {
			result = append(result, e)
		}
	}
	return result
}

// VisibleEntities returns a slice of active+visible entities (for rendering).
// The returned slice is reused across calls; callers must not retain it.
func (s *Scene) VisibleEntities() []*Entity {
	s.visibleBuf = s.visibleBuf[:0]
	for _, e := range s.entities {
		if e.Active && e.Visible {
			s.visibleBuf = append(s.visibleBuf, e)
		}
	}
	return s.visibleBuf
}

func (s *Scene) RenderStats() SceneRenderStats {
	return s.renderStats
}

func estimateEntityCullRadius(scale voplay.Vec3) float64 {
	r := math.Sqrt(scale.X*scale.X + scale.Y*scale.Y + scale.Z*scale.Z) * 0.5
	if r <= 0 {
		return 0.5
	}
	return r
}

// ForEach calls fn for every active entity in the scene.
func (s *Scene) ForEach(fn func(e *Entity)) {
	for _, e := range s.entities {
		if e.Active {
			fn(e)
		}
	}
}

// AddLight adds a light to the scene.
func (s *Scene) AddLight(l Light) {
	s.Lights = append(s.Lights, l)
}

// ClearLights removes all lights from the scene.
func (s *Scene) ClearLights() {
	s.Lights = nil
}

func (s *Scene) AddEmitter(emitter *ParticleEmitter) {
	if emitter == nil {
		panic("Scene.AddEmitter: emitter must not be nil")
	}
	if emitter.scene != nil && emitter.scene != s {
		panic("Scene.AddEmitter: emitter already belongs to another scene")
	}
	if emitter.Attached != nil && emitter.Attached.scene != s {
		panic("Scene.AddEmitter: attached entity must belong to this scene")
	}
	for _, existing := range s.Emitters {
		if existing == emitter {
			panic("Scene.AddEmitter: emitter already added")
		}
	}
	emitter.scene = s
	s.Emitters = append(s.Emitters, emitter)
}

func (s *Scene) RemoveEmitter(emitter *ParticleEmitter) {
	if emitter == nil {
		panic("Scene.RemoveEmitter: emitter must not be nil")
	}
	if emitter.scene != nil && emitter.scene != s {
		panic("Scene.RemoveEmitter: emitter belongs to another scene")
	}
	for i, existing := range s.Emitters {
		if existing == emitter {
			last := len(s.Emitters) - 1
			s.Emitters[i] = s.Emitters[last]
			s.Emitters[last] = nil
			s.Emitters = s.Emitters[:last]
			emitter.scene = nil
			emitter.Attached = nil
			return
		}
	}
	panic("Scene.RemoveEmitter: emitter not found")
}

func (s *Scene) UpdateEmitters(dt float64) {
	if dt < 0 {
		panic("Scene.UpdateEmitters: dt must be >= 0")
	}
	for _, emitter := range s.Emitters {
		emitter.Update(dt)
	}
}

// HasPhysics returns true if a physics world is initialized.
func (s *Scene) HasPhysics() bool {
	return s.worldID != 0
}

// Close destroys the physics world and releases all resources.
func (s *Scene) Close() {
	s.Clear()
	s.primitiveLayers = nil
	s.primitiveStats = primitive3d.Stats{}
	if s.worldID != 0 {
		physBackend.Destroy(s.worldID)
		s.worldID = 0
	}
}

// ensurePhysics lazily initializes the Rapier3D physics world for this scene.
func (s *Scene) ensurePhysics() {
	if s.worldID != 0 {
		return
	}
	s.worldID = physBackend.Init(s.Gravity)
}

// SetGravity changes the 3D physics gravity at runtime.
func (s *Scene) SetGravity(g voplay.Vec3) {
	s.Gravity = g
	if s.worldID != 0 {
		physBackend.SetGravity(s.worldID, g)
	}
}

func (s *Scene) UpdateAudio() {
	for _, e := range s.entities {
		if !e.Active || len(e.audioSources) == 0 {
			continue
		}
		for _, source := range e.audioSources {
			source.SetPosition(e.position)
		}
	}
	voplay.SetAudioListener(s.Camera.Position, s.Camera.Target, s.Camera.Up)
	voplay.UpdateSpatialAudio()
}

// StepAndSyncPhysics runs one 3D physics step and syncs body state back to entities.
func (s *Scene) StepAndSyncPhysics(dt float64) {
	if s.worldID == 0 {
		return
	}
	cmdBytes := s.physCmds.Bytes()
	state := physBackend.Step(s.worldID, dt, cmdBytes)
	s.physCmds.Reset()

	// Decode state: count(u32), then per body:
	// body_id(u32), x/y/z, qx/qy/qz/qw, linear velocity, angular velocity.
	r := codec.NewByteReader(state)
	if r.Remaining() < 4 {
		return
	}
	count := r.ReadU32()

	for i := 0; i < count; i++ {
		if r.Remaining() < physics3DBodyStateBytes {
			break
		}
		bodyID := r.ReadU32()
		x := r.ReadF64()
		y := r.ReadF64()
		z := r.ReadF64()
		qx := r.ReadF64()
		qy := r.ReadF64()
		qz := r.ReadF64()
		qw := r.ReadF64()
		vx := r.ReadF64()
		vy := r.ReadF64()
		vz := r.ReadF64()
		avx := r.ReadF64()
		avy := r.ReadF64()
		avz := r.ReadF64()

		if ent, ok := s.bodyMap[bodyID]; ok {
			ent.position = voplay.Vec3{x, y, z}
			ent.rotation = voplay.Quat{qx, qy, qz, qw}
			ent.Physics.velocity = voplay.Vec3{vx, vy, vz}
			ent.Physics.angularVelocity = voplay.Vec3{avx, avy, avz}
		}
	}
	s.syncVehicles()
}

// RayCast casts a ray into the 3D physics world and returns the first hit.
func (s *Scene) RayCast(origin, dir voplay.Vec3, maxDist float64) *RayCastHit {
	if s.worldID == 0 {
		return nil
	}
	data := physBackend.RayCast(s.worldID, origin, dir, maxDist)
	if len(data) < 1 || data[0] == 0 {
		return nil
	}
	r := codec.NewByteReader(data[1:])
	bodyID := r.ReadU32()
	hx := r.ReadF64()
	hy := r.ReadF64()
	hz := r.ReadF64()
	nx := r.ReadF64()
	ny := r.ReadF64()
	nz := r.ReadF64()
	dist := r.ReadF64()
	ent, ok := s.bodyMap[bodyID]
	if !ok {
		return nil
	}
	return &RayCastHit{
		Entity:   ent,
		Point:    voplay.Vec3{hx, hy, hz},
		Normal:   voplay.Vec3{nx, ny, nz},
		Distance: dist,
	}
}

// QueryAABB returns all physics entities whose colliders intersect the given axis-aligned bounding box.
func (s *Scene) QueryAABB(min, max voplay.Vec3) []*Entity {
	if s.worldID == 0 {
		return nil
	}
	data := physBackend.QueryAABB(s.worldID, min, max)
	r := codec.NewByteReader(data)
	if r.Remaining() < 4 {
		return nil
	}
	count := r.ReadU32()
	var result []*Entity
	for i := 0; i < count; i++ {
		if r.Remaining() < 4 {
			break
		}
		bodyID := r.ReadU32()
		if ent, ok := s.bodyMap[bodyID]; ok && ent.Active {
			result = append(result, ent)
		}
	}
	return result
}

// Contacts returns active collision pairs from the 3D physics world.
func (s *Scene) Contacts() []Contact {
	if s.worldID == 0 {
		return nil
	}
	data := physBackend.Contacts(s.worldID)
	r := codec.NewByteReader(data)
	if r.Remaining() < 4 {
		return nil
	}
	count := r.ReadU32()
	var contacts []Contact
	for i := 0; i < count; i++ {
		if r.Remaining() < 8 {
			break
		}
		idA := r.ReadU32()
		idB := r.ReadU32()
		a, okA := s.bodyMap[idA]
		b, okB := s.bodyMap[idB]
		if okA && okB && a.Active && b.Active {
			contacts = append(contacts, Contact{A: a, B: b})
		}
	}
	return contacts
}

package scene3d

import "errors"
import "github.com/vo-lang/voplay"
import "github.com/vo-lang/voplay/codec"

type TerrainLayer struct {
	Texture voplay.TextureID
	Normal voplay.TextureID
	MetallicRoughness voplay.TextureID
	UVScale float64
	NormalScale float64
}

type TerrainSplatMaterial struct {
	Control voplay.TextureID
	Layers  []TerrainLayer
}

type TerrainDesc struct {
	HeightmapPath string
	HeightmapData []byte
	Texture       voplay.TextureID
	Normal        voplay.TextureID
	MetallicRoughness voplay.TextureID
	NormalScale   float64
	Roughness      float64
	Metallic       float64
	Splat         *TerrainSplatMaterial
	Position      voplay.Vec3
	Width         float64
	Height        float64
	Depth         float64
	UVScale       float64
	Tint          voplay.Color
	TintSet       bool
	Tag           string
	Data          any
	Physics       *Physics
}

type Terrain struct {
	entity *Entity
	rows   int
	cols   int
}

// TerrainCreateDesc groups all parameters for terrain mesh creation.
type TerrainCreateDesc struct {
	Path    string
	Data    []byte
	Scale   voplay.Vec3
	UVScale float64
	Texture voplay.TextureID
	Normal  voplay.TextureID
	MetallicRoughness voplay.TextureID
	NormalScale float64
	Roughness float64
	Metallic float64
	Splat   *TerrainSplatMaterial
}

// TerrainCreateResult holds the outputs from terrain mesh creation.
type TerrainCreateResult struct {
	ModelID    int
	Rows       int
	Cols       int
	HeightData []byte
}

// TerrainBackend abstracts terrain resource creation and height queries so
// they can be replaced in tests without per-function hook boilerplate.
type TerrainBackend interface {
	Create(desc TerrainCreateDesc) (TerrainCreateResult, error)
	HeightAt(worldID, bodyID int, x, z float64) (float64, bool)
}

type defaultTerrainBackend struct{}

func (defaultTerrainBackend) Create(desc TerrainCreateDesc) (TerrainCreateResult, error) {
	if desc.Splat != nil {
		layerData := encodeTerrainSplatLayers(desc.Splat)
		if desc.Path != "" {
			modelID, rows, cols, hd := createTerrainSplat(
				desc.Path, desc.Scale.X, desc.Scale.Y, desc.Scale.Z,
				int(desc.Splat.Control), layerData,
			)?
			return TerrainCreateResult{ModelID: modelID, Rows: rows, Cols: cols, HeightData: hd}, nil
		}
		modelID, rows, cols, hd := createTerrainBytesSplat(
			desc.Data, desc.Scale.X, desc.Scale.Y, desc.Scale.Z,
			int(desc.Splat.Control), layerData,
		)?
		return TerrainCreateResult{ModelID: modelID, Rows: rows, Cols: cols, HeightData: hd}, nil
	}
	if desc.Path != "" {
		modelID, rows, cols, hd := createTerrain(desc.Path, desc.Scale.X, desc.Scale.Y, desc.Scale.Z, desc.UVScale, int(desc.Texture), int(desc.Normal), int(desc.MetallicRoughness), desc.NormalScale, desc.Roughness, desc.Metallic)?
		return TerrainCreateResult{ModelID: modelID, Rows: rows, Cols: cols, HeightData: hd}, nil
	}
	modelID, rows, cols, hd := createTerrainBytes(desc.Data, desc.Scale.X, desc.Scale.Y, desc.Scale.Z, desc.UVScale, int(desc.Texture), int(desc.Normal), int(desc.MetallicRoughness), desc.NormalScale, desc.Roughness, desc.Metallic)?
	return TerrainCreateResult{ModelID: modelID, Rows: rows, Cols: cols, HeightData: hd}, nil
}

func (defaultTerrainBackend) HeightAt(worldID, bodyID int, x, z float64) (float64, bool) {
	return terrainHeightAt(worldID, bodyID, x, z)
}

var terrBackend TerrainBackend = defaultTerrainBackend{}

// SetTerrainBackend replaces the active terrain backend and returns the previous one.
func SetTerrainBackend(b TerrainBackend) TerrainBackend {
	prev := terrBackend
	terrBackend = b
	return prev
}

func (t *Terrain) Entity() *Entity {
	return t.entity
}

func (t *Terrain) Rows() int {
	return t.rows
}

func (t *Terrain) Cols() int {
	return t.cols
}

func (t *Terrain) HeightAt(x, z float64) (float64, bool) {
	if t == nil || t.entity == nil || t.entity.scene == nil || t.entity.Physics == nil {
		return 0, false
	}
	if t.entity.scene.worldID == 0 || t.entity.Physics.bodyID == 0 {
		return 0, false
	}
	return terrBackend.HeightAt(t.entity.scene.worldID, t.entity.Physics.bodyID, x, z)
}

func spawnTerrain(scene *Scene, desc TerrainDesc, physics *Physics, modelID, rows, cols int, heightData []byte) *Terrain {
	physics.Heightfield = &Heightfield{
		heightData: heightData,
		rows:       rows,
		cols:       cols,
		scale:      voplay.Vec3{desc.Width, desc.Height, desc.Depth},
	}
	ent := scene.Spawn(EntityDesc{
		Position:   desc.Position,
		Model:      voplay.ModelID(modelID),
		OwnedModel: voplay.ModelID(modelID),
		Tint:       desc.Tint,
		TintSet:    desc.TintSet,
		Tag:        desc.Tag,
		Data:       desc.Data,
		Physics:    physics,
	})
	return &Terrain{entity: ent, rows: rows, cols: cols}
}

func NewTerrain(scene *Scene, desc TerrainDesc) (*Terrain, error) {
	if scene == nil {
		return nil, errors.New("scene3d.NewTerrain: scene is nil")
	}
	if desc.HeightmapPath == "" && len(desc.HeightmapData) == 0 {
		return nil, errors.New("scene3d.NewTerrain: heightmap path or bytes required")
	}
	if desc.HeightmapPath != "" && len(desc.HeightmapData) != 0 {
		return nil, errors.New("scene3d.NewTerrain: choose either heightmap path or bytes")
	}
	if desc.Width <= 0 {
		return nil, errors.New("scene3d.NewTerrain: Width must be > 0")
	}
	if desc.Height <= 0 {
		return nil, errors.New("scene3d.NewTerrain: Height must be > 0")
	}
	if desc.Depth <= 0 {
		return nil, errors.New("scene3d.NewTerrain: Depth must be > 0")
	}
	if desc.Splat != nil && desc.Texture != 0 {
		return nil, errors.New("scene3d.NewTerrain: Texture and Splat are mutually exclusive")
	}
	physics, err := buildTerrainPhysics(desc.Physics)
	if err != nil {
		return nil, err
	}
	createDesc := TerrainCreateDesc{
		Path:    desc.HeightmapPath,
		Data:    desc.HeightmapData,
		Scale:   voplay.Vec3{desc.Width, desc.Height, desc.Depth},
		Texture: desc.Texture,
		Normal:  desc.Normal,
		MetallicRoughness: desc.MetallicRoughness,
		NormalScale: desc.NormalScale,
		Roughness: desc.Roughness,
		Metallic: desc.Metallic,
	}
	if desc.Splat != nil {
		if desc.Normal != 0 || desc.MetallicRoughness != 0 || desc.NormalScale != 0 || desc.Roughness != 0 || desc.Metallic != 0 {
			return nil, errors.New("scene3d.NewTerrain: single-material terrain fields cannot be mixed with Splat")
		}
		splat, splatErr := validateAndNormalizeSplat(desc.Splat)
		if splatErr != nil {
			return nil, splatErr
		}
		createDesc.Splat = splat
	} else {
		uvScale := desc.UVScale
		if uvScale < 0 {
			return nil, errors.New("scene3d.NewTerrain: UVScale must be >= 0 (0 defaults to 1)")
		}
		if uvScale == 0 {
			uvScale = 1
		}
		if desc.NormalScale < 0 {
			return nil, errors.New("scene3d.NewTerrain: NormalScale must be >= 0")
		}
		if desc.Roughness < 0 {
			return nil, errors.New("scene3d.NewTerrain: Roughness must be >= 0")
		}
		if desc.Metallic < 0 || desc.Metallic > 1 {
			return nil, errors.New("scene3d.NewTerrain: Metallic must be in range 0..1")
		}
		createDesc.UVScale = uvScale
	}
	result, createErr := terrBackend.Create(createDesc)
	if createErr != nil {
		return nil, createErr
	}
	return spawnTerrain(scene, desc, physics, result.ModelID, result.Rows, result.Cols, result.HeightData), nil
}

func validateAndNormalizeSplat(splat *TerrainSplatMaterial) (*TerrainSplatMaterial, error) {
	if splat.Control == 0 {
		return nil, errors.New("scene3d.NewTerrain: Splat control texture must be non-zero")
	}
	if len(splat.Layers) != 4 {
		return nil, errors.New("scene3d.NewTerrain: splat requires exactly 4 layers")
	}
	normalized := &TerrainSplatMaterial{
		Control: splat.Control,
		Layers:  append([]TerrainLayer{}, splat.Layers...),
	}
	for i := 0; i < 4; i++ {
		if normalized.Layers[i].Texture == 0 {
			return nil, errors.New("scene3d.NewTerrain: all 4 splat layers must define a non-zero texture")
		}
		if normalized.Layers[i].UVScale == 0 {
			normalized.Layers[i].UVScale = 1
		}
		if normalized.Layers[i].UVScale < 0 {
			return nil, errors.New("scene3d.NewTerrain: splat layer UVScale must be > 0")
		}
		if normalized.Layers[i].NormalScale < 0 {
			return nil, errors.New("scene3d.NewTerrain: splat layer NormalScale must be >= 0")
		}
	}
	return normalized, nil
}

func encodeTerrainSplatLayers(splat *TerrainSplatMaterial) []byte {
	w := codec.NewByteWriter(4 * (4 + 4 + 4 + 8 + 8))
	for i := 0; i < 4; i++ {
		layer := splat.Layers[i]
		w.WriteU32(int(layer.Texture))
		w.WriteU32(int(layer.Normal))
		w.WriteU32(int(layer.MetallicRoughness))
		w.WriteF64(layer.UVScale)
		w.WriteF64(layer.NormalScale)
	}
	return w.Bytes()
}

func buildTerrainPhysics(base *Physics) (*Physics, error) {
	if base == nil {
		return &Physics{
			Type:        Static,
			Layer:       voplay.CollisionLayerDefault,
			Mask:        voplay.CollisionMaskAll,
			Friction:    0.8,
			Restitution: 0.0,
		}, nil
	}
	if base.Type != Static {
		return nil, errors.New("scene3d.NewTerrain: terrain physics must use Static body type")
	}
	if base.Collider != (Collider{}) {
		return nil, errors.New("scene3d.NewTerrain: terrain physics must not define a parametric collider")
	}
	if base.Trimesh != nil || base.Heightfield != nil {
		return nil, errors.New("scene3d.NewTerrain: terrain physics must not predefine trimesh or heightfield")
	}
	return &Physics{
		Type:          base.Type,
		Collider:      base.Collider,
		Layer:         base.Layer,
		Mask:          base.Mask,
		Density:       base.Density,
		Friction:      base.Friction,
		Restitution:   base.Restitution,
		LinearDamping: base.LinearDamping,
		AngularDamping: base.AngularDamping,
		FixedRotation: base.FixedRotation,
		LockRotationX: base.LockRotationX,
		LockRotationY: base.LockRotationY,
		LockRotationZ: base.LockRotationZ,
	}, nil
}

func createTerrain(path string, scaleX, scaleY, scaleZ, uvScale float64, textureID int, normalTextureID int, metallicRoughnessTextureID int, normalScale float64, roughness float64, metallic float64) (int, int, int, []byte, error)
func createTerrainSplat(path string, scaleX, scaleY, scaleZ float64, controlTextureID int, layerData []byte) (int, int, int, []byte, error)
func createTerrainBytes(data []byte, scaleX, scaleY, scaleZ, uvScale float64, textureID int, normalTextureID int, metallicRoughnessTextureID int, normalScale float64, roughness float64, metallic float64) (int, int, int, []byte, error)
func createTerrainBytesSplat(data []byte, scaleX, scaleY, scaleZ float64, controlTextureID int, layerData []byte) (int, int, int, []byte, error)
func terrainHeightAt(worldID, bodyID int, x, z float64) (float64, bool)

package scene3d

import "math"
import "github.com/vo-lang/voplay"

type ThirdPersonCamera struct {
	Target           *Entity
	PivotOffset      voplay.Vec3
	Yaw              float64
	Pitch            float64
	MinPitch         float64
	MaxPitch         float64
	Distance         float64
	MinDistance      float64
	MaxDistance      float64
	Smoothing        float64
	CollisionEnabled bool
	CollisionOffset  float64
	AlignToTargetYaw bool

	currentPos    voplay.Vec3
	currentTarget voplay.Vec3
	initialized   bool
	lastTarget    *Entity
}

func NewThirdPersonCamera(target *Entity) *ThirdPersonCamera {
	return &ThirdPersonCamera{
		Target:           target,
		PivotOffset:      voplay.Vec3{Y: 1.6},
		Pitch:            0.3,
		MinPitch:         -1.3962634015954636,
		MaxPitch:         1.3962634015954636,
		Distance:         5.0,
		MinDistance:      1.0,
		MaxDistance:      20.0,
		Smoothing:        10.0,
		CollisionEnabled: true,
		CollisionOffset:  0.2,
		AlignToTargetYaw: false,
	}
}

func (c *ThirdPersonCamera) HandleInput(dx, dy float64) {
	c.Yaw += dx
	c.Pitch -= dy
	c.Pitch = thirdPersonClamp(c.Pitch, c.MinPitch, c.MaxPitch)
}

func (c *ThirdPersonCamera) HandleInputScaled(dx, dy, sensitivity float64) {
	c.HandleInput(dx*sensitivity, dy*sensitivity)
}

func (c *ThirdPersonCamera) Zoom(delta float64) {
	c.Distance = thirdPersonClamp(c.Distance+delta, c.MinDistance, c.MaxDistance)
}

func (c *ThirdPersonCamera) Update(scene *Scene, dt float64) {
	if c.Target == nil || !c.Target.Active || c.Target.scene == nil {
		return
	}
	c.Pitch = thirdPersonClamp(c.Pitch, c.MinPitch, c.MaxPitch)
	c.Distance = thirdPersonClamp(c.Distance, c.MinDistance, c.MaxDistance)
	pivot := c.Target.Position().Add(c.PivotOffset)
	desiredPos := c.desiredPosition(pivot)
	if c.CollisionEnabled && scene != nil {
		desiredPos = c.resolveCollision(scene, pivot, desiredPos)
	}
	targetChanged := c.Target != c.lastTarget
	c.currentTarget = pivot
	if !c.initialized || targetChanged {
		c.currentPos = desiredPos
		c.initialized = true
	} else if c.Smoothing <= 0 || dt <= 0 {
		c.currentPos = desiredPos
	} else {
		t := 1.0 - math.Exp(-c.Smoothing*dt)
		c.currentPos = c.currentPos.Lerp(desiredPos, t)
	}
	if c.CollisionEnabled && scene != nil {
		c.currentPos = c.resolveCollision(scene, pivot, c.currentPos)
	}
	c.lastTarget = c.Target
}

func (c *ThirdPersonCamera) Apply(cam *Camera) {
	cam.Position = c.currentPos
	cam.Target = c.currentTarget
}

func (c *ThirdPersonCamera) UpdateCamera(cam *Camera, scene *Scene, dt float64) {
	c.Update(scene, dt)
	c.Apply(cam)
}

func (c *ThirdPersonCamera) desiredPosition(pivot voplay.Vec3) voplay.Vec3 {
	orbitYaw := c.Yaw
	if c.AlignToTargetYaw {
		orbitYaw += c.targetBackYaw()
	}
	cosPitch := math.Cos(c.Pitch)
	return pivot.Add(voplay.Vec3{
		X: c.Distance * math.Sin(orbitYaw) * cosPitch,
		Y: c.Distance * math.Sin(c.Pitch),
		Z: c.Distance * math.Cos(orbitYaw) * cosPitch,
	})
}

func (c *ThirdPersonCamera) targetBackYaw() float64 {
	forward := c.Target.Rotation().RotateVec3(voplay.Vec3{Z: -1})
	planarBack := voplay.Vec3{X: -forward.X, Z: -forward.Z}
	if planarBack.LengthSq() == 0 {
		return 0
	}
	planarBack = planarBack.Normalize()
	return math.Atan2(planarBack.X, planarBack.Z)
}

func (c *ThirdPersonCamera) resolveCollision(scene *Scene, pivot, desiredPos voplay.Vec3) voplay.Vec3 {
	dir := desiredPos.Sub(pivot)
	dist := dir.Length()
	if dist <= 0.000001 {
		return desiredPos
	}
	dir = dir.Scale(1.0 / dist)
	origin := pivot
	remaining := dist
	travelled := 0.0
	var hit *RayCastHit
	for remaining > 0.000001 {
		hit = scene.RayCast(origin, dir, remaining)
		if hit == nil {
			return desiredPos
		}
		if hit.Entity != c.Target {
			travelled += hit.Distance
			break
		}
		step := hit.Distance + 0.05
		if step <= 0.0 {
			return desiredPos
		}
		travelled += step
		remaining = dist - travelled
		origin = pivot.Add(dir.Scale(travelled))
	}
	if hit == nil || remaining <= 0.000001 {
		return desiredPos
	}
	pullDist := travelled - c.CollisionOffset
	if pullDist < 0 {
		pullDist = 0
	}
	if pullDist > dist {
		pullDist = dist
	}
	return pivot.Add(dir.Scale(pullDist))
}

func thirdPersonClamp(v, lo, hi float64) float64 {
	if v < lo {
		return lo
	}
	if v > hi {
		return hi
	}
	return v
}

package scene3d

import (
	"encoding/json"
	"errors"
	"path/filepath"
)

const TrackBakeManifestPath = ".vopack/manifest.json"

type TrackBakeResource struct {
	Path string
	Kind string
}

type TrackBakeOutput struct {
	TrackPath string
	GeneratedManifestPath string
	Resources []TrackBakeResource
	HasTerrain bool
	HasVisualTrackMesh bool
	HasCollisionTrackMesh bool
	HasSurfaceMetadata bool
	HasGateMetadata bool
	HasRespawnMetadata bool
}

func BuildTrackBakeOutput(trackPath string, asset *TrackAsset) TrackBakeOutput {
	out := TrackBakeOutput{
		TrackPath: trackPath,
		GeneratedManifestPath: TrackBakeManifestPath,
		Resources: []TrackBakeResource{},
	}
	if trackPath == "" || asset == nil {
		return out
	}
	baseDir := filepath.Dir(trackPath)
	if asset.Terrain != nil {
		out.HasTerrain = true
		if asset.Terrain.Heightmap != "" {
			out = appendTrackBakeResource(out, mapResolvePath(baseDir, asset.Terrain.Heightmap), "terrain-heightmap")
		}
		if asset.Terrain.Texture != "" {
			out = appendTrackBakeResource(out, mapResolvePath(baseDir, asset.Terrain.Texture), "terrain-texture")
		}
		if asset.Terrain.Normal != "" {
			out = appendTrackBakeResource(out, mapResolvePath(baseDir, asset.Terrain.Normal), "terrain-normal")
		}
		if asset.Terrain.MetallicRoughness != "" {
			out = appendTrackBakeResource(out, mapResolvePath(baseDir, asset.Terrain.MetallicRoughness), "terrain-metallic-roughness")
		}
		out = appendTerrainSplatBakeResources(out, baseDir, asset.Terrain.Splat)
	}
	for _, terrain := range asset.TerrainChunks {
		out.HasTerrain = true
		if terrain.Heightmap != "" {
			out = appendTrackBakeResource(out, mapResolvePath(baseDir, terrain.Heightmap), "terrain-heightmap")
		}
		if terrain.Texture != "" {
			out = appendTrackBakeResource(out, mapResolvePath(baseDir, terrain.Texture), "terrain-texture")
		}
		if terrain.Normal != "" {
			out = appendTrackBakeResource(out, mapResolvePath(baseDir, terrain.Normal), "terrain-normal")
		}
		if terrain.MetallicRoughness != "" {
			out = appendTrackBakeResource(out, mapResolvePath(baseDir, terrain.MetallicRoughness), "terrain-metallic-roughness")
		}
		out = appendTerrainSplatBakeResources(out, baseDir, terrain.Splat)
	}
	for _, mesh := range asset.Meshes {
		if mesh.Model != "" {
			out = appendTrackBakeResource(out, mapResolvePath(baseDir, mesh.Model), "visual-track-mesh")
			if !mesh.Hidden {
				out.HasVisualTrackMesh = true
			}
		}
		collision := mesh.CollisionModel
		if collision == "" && mesh.Hidden && mesh.Model != "" {
			collision = mesh.Model
		}
		if collision != "" {
			out = appendTrackBakeResource(out, mapResolvePath(baseDir, collision), "collision-track-mesh")
			out.HasCollisionTrackMesh = true
		}
	}
	out.HasSurfaceMetadata = len(asset.Surfaces) > 0
	out.HasGateMetadata = len(asset.Gates) > 0
	out.HasRespawnMetadata = len(asset.Respawns) > 0
	return out
}

func ValidateTrackBakeOutput(asset *TrackAsset, out TrackBakeOutput) []TrackIssue {
	issues := ValidateTrackAsset(asset)
	if out.TrackPath == "" {
		issues = appendTrackIssue(issues, "track.bake.track", TrackIssueError, "trackPath", "baked output must include track.json")
	}
	if out.GeneratedManifestPath == "" {
		issues = appendTrackIssue(issues, "track.bake.manifest", TrackIssueError, "generatedManifestPath", "baked output must include generated manifest")
	}
	if !out.HasTerrain {
		issues = appendTrackIssue(issues, "track.bake.terrain", TrackIssueError, "terrain", "baked output must include terrain heightmap or terrain chunks")
	}
	if !out.HasVisualTrackMesh {
		issues = appendTrackIssue(issues, "track.bake.visual_mesh", TrackIssueError, "meshes", "baked output must include a visible visual track mesh")
	}
	if !out.HasCollisionTrackMesh {
		issues = appendTrackIssue(issues, "track.bake.collision_mesh", TrackIssueError, "meshes", "baked output must include a collision track mesh")
	}
	if !out.HasSurfaceMetadata {
		issues = appendTrackIssue(issues, "track.bake.surfaces", TrackIssueError, "surfaces", "baked output must include surface metadata")
	}
	if !out.HasGateMetadata {
		issues = appendTrackIssue(issues, "track.bake.gates", TrackIssueError, "gates", "baked output must include gate metadata")
	}
	if !out.HasRespawnMetadata {
		issues = appendTrackIssue(issues, "track.bake.respawns", TrackIssueError, "respawns", "baked output must include respawn metadata")
	}
	if len(out.Resources) == 0 {
		issues = appendTrackIssue(issues, "track.bake.resources", TrackIssueError, "resources", "baked output must include runtime resource files")
	}
	return issues
}

func MarshalBakedTrackAsset(asset *TrackAsset) ([]byte, error) {
	issues := ValidateTrackAsset(asset)
	if trackHasErrors(issues) {
		return nil, trackIssuesError("scene3d.MarshalBakedTrackAsset", issues)
	}
	return json.MarshalIndent(asset, "", "  ")
}

func TrackBakeDependencies(out TrackBakeOutput, requester string) []string {
	if requester != out.TrackPath {
		return nil
	}
	deps := make([]string, 0, len(out.Resources))
	seen := map[string]bool{}
	for _, r := range out.Resources {
		if r.Path != "" && !seen[r.Path] {
			seen[r.Path] = true
			deps = append(deps, r.Path)
		}
	}
	return deps
}

func AddTrackBakeResource(out TrackBakeOutput, path, kind string) TrackBakeOutput {
	return appendTrackBakeResource(out, path, kind)
}

func RequireValidTrackBakeOutput(asset *TrackAsset, out TrackBakeOutput) error {
	issues := ValidateTrackBakeOutput(asset, out)
	if trackHasErrors(issues) {
		return trackIssuesError("scene3d.RequireValidTrackBakeOutput", issues)
	}
	return nil
}

func appendTrackBakeResource(out TrackBakeOutput, path, kind string) TrackBakeOutput {
	if path == "" {
		return out
	}
	for _, existing := range out.Resources {
		if existing.Path == path {
			return out
		}
	}
	out.Resources = append(out.Resources, TrackBakeResource{Path: path, Kind: kind})
	return out
}

func appendTerrainSplatBakeResources(out TrackBakeOutput, baseDir string, splat *MapTerrainSplat) TrackBakeOutput {
	if splat == nil {
		return out
	}
	if splat.Control != "" {
		out = appendTrackBakeResource(out, mapResolvePath(baseDir, splat.Control), "terrain-splat-control")
	}
	for _, layer := range splat.Layers {
		if layer.Texture != "" {
			out = appendTrackBakeResource(out, mapResolvePath(baseDir, layer.Texture), "terrain-splat-texture")
		}
		if layer.Normal != "" {
			out = appendTrackBakeResource(out, mapResolvePath(baseDir, layer.Normal), "terrain-splat-normal")
		}
		if layer.MetallicRoughness != "" {
			out = appendTrackBakeResource(out, mapResolvePath(baseDir, layer.MetallicRoughness), "terrain-splat-metallic-roughness")
		}
	}
	return out
}

func EnsureBakedTrackJSONStable(asset *TrackAsset) error {
	a, err := MarshalBakedTrackAsset(asset)
	if err != nil {
		return err
	}
	b, err := MarshalBakedTrackAsset(asset)
	if err != nil {
		return err
	}
	if string(a) != string(b) {
		return errors.New("scene3d.EnsureBakedTrackJSONStable: deterministic marshal mismatch")
	}
	return nil
}

