func LoadTrackAsset(path string) (*TrackAsset, error) {
	if path == "" {
		return nil, errors.New("scene3d.LoadTrackAsset: path must not be empty")
	}
	data := os.ReadFile(path)?
	var asset TrackAsset
	json.Unmarshal(data, &asset)?
	issues := ValidateTrackAsset(&asset)
	issues = append(issues, validateTrackFilesystemResources(&asset, filepath.Dir(path))...)
	if trackHasErrors(issues) {
		return nil, trackIssuesError("scene3d.LoadTrackAsset", issues)
	}
	return &asset, nil
}

func LoadTrack(scene *Scene, path string) (*TrackSpawnResult, error) {
	asset, err := LoadTrackAsset(path)
	if err != nil {
		return nil, err
	}
	track, err := NewTrack(asset)
	if err != nil {
		return nil, err
	}
	return SpawnTrackWithAssets(scene, nil, track, filepath.Dir(path))
}

func LoadTrackWithAssets(scene *Scene, assets *voplay.Assets, path string) (*TrackSpawnResult, error) {
	if assets == nil {
		return LoadTrack(scene, path)
	}
	if path == "" {
		return nil, errors.New("scene3d.LoadTrackWithAssets: path must not be empty")
	}
	assets.VerifyPackDependencies(path)?
	data := assets.Bytes(path)?
	var asset TrackAsset
	json.Unmarshal(data, &asset)?
	issues := ValidateTrackAsset(&asset)
	issues = append(issues, validateTrackAssetsResources(assets, &asset, filepath.Dir(path))...)
	if trackHasErrors(issues) {
		return nil, trackIssuesError("scene3d.LoadTrackWithAssets", issues)
	}
	track, err := NewTrack(&asset)
	if err != nil {
		return nil, err
	}
	return SpawnTrackWithAssets(scene, assets, track, filepath.Dir(path))
}

func NewTrack(asset *TrackAsset) (*Track, error) {
	issues := ValidateTrackAsset(asset)
	if trackHasErrors(issues) {
		return nil, trackIssuesError("scene3d.NewTrack", issues)
	}
	return newTrackUnchecked(asset), nil
}

func newTrackUnchecked(asset *TrackAsset) *Track {
	effective := trackEffectivePointCount(asset)
	points := make([]TrackControlPoint, effective)
	for i := 0; i < effective; i++ {
		points[i] = asset.Centerline[i]
	}
	segmentCount := effective - 1
	if asset.ClosedLoop {
		segmentCount = effective
	}
	segmentStarts := make([]float64, segmentCount)
	segmentLengths := make([]float64, segmentCount)
	total := 0.0
	for i := 0; i < segmentCount; i++ {
		next := i + 1
		if next >= effective {
			next = 0
		}
		segmentStarts[i] = total
		length := points[i].Position.Vec3().Distance(points[next].Position.Vec3())
		segmentLengths[i] = length
		total += length
	}
	return &Track{asset: asset, points: points, segmentStarts: segmentStarts, segmentLengths: segmentLengths, length: total, closed: asset.ClosedLoop}
}

func (t *Track) Asset() *TrackAsset {
	if t == nil {
		return nil
	}
	return t.asset
}

func (t *Track) Length() float64 {
	if t == nil {
		return 0
	}
	return t.length
}

func (t *Track) ClosestPoint(pos voplay.Vec3) TrackPoint {
	if t == nil || len(t.points) == 0 || len(t.segmentLengths) == 0 {
		return TrackPoint{}
	}
	bestDistanceSq := math.MaxFloat64
	best := TrackPoint{}
	for i := 0; i < len(t.segmentLengths); i++ {
		a := t.points[i]
		next := i + 1
		if next >= len(t.points) {
			next = 0
		}
		b := t.points[next]
		ap := pos.Sub(a.Position.Vec3())
		ab := b.Position.Vec3().Sub(a.Position.Vec3())
		abLenSq := ab.LengthSq()
		segT := 0.0
		if abLenSq > 0 {
			segT = trackClamp(ap.Dot(ab) / abLenSq, 0, 1)
		}
		point := a.Position.Vec3().Lerp(b.Position.Vec3(), segT)
		distSq := pos.Sub(point).LengthSq()
		if distSq >= bestDistanceSq {
			continue
		}
		forward := ab.Normalize()
		right := forward.Cross(voplay.Vec3{Y: 1}).Normalize()
		if right.LengthSq() == 0 {
			right = voplay.Vec3{X: 1}
		}
		lateral := pos.Sub(point).Dot(right)
		halfWidth := trackLerp(a.Width, b.Width, segT) * 0.5
		bestDistanceSq = distSq
		best = TrackPoint{Position: point, Forward: forward, Right: right, Distance: t.segmentStarts[i] + t.segmentLengths[i] * segT, SegmentIndex: i, SegmentT: segT, LateralDistance: lateral, HalfWidth: halfWidth, OnRoad: math.Abs(lateral) <= halfWidth}
	}
	if t.closed {
		best.Distance = trackWrapDistance(best.Distance, t.length)
	}
	return best
}

func (t *Track) PoseAt(distance float64) TrackPose {
	if t == nil || len(t.points) == 0 || len(t.segmentLengths) == 0 {
		return TrackPose{Rotation: voplay.QuatIdentity(), Forward: voplay.Vec3{Z: -1}, Right: voplay.Vec3{X: 1}}
	}
	d := distance
	if t.closed {
		d = trackWrapDistance(d, t.length)
	} else {
		d = trackClamp(d, 0, t.length)
	}
	idx := t.segmentIndexAt(d)
	segStart := t.segmentStarts[idx]
	segLen := t.segmentLengths[idx]
	segT := 0.0
	if segLen > 0 {
		segT = trackClamp((d - segStart) / segLen, 0, 1)
	}
	a := t.points[idx]
	next := idx + 1
	if next >= len(t.points) {
		next = 0
	}
	b := t.points[next]
	pos := a.Position.Vec3().Lerp(b.Position.Vec3(), segT)
	forward := b.Position.Vec3().Sub(a.Position.Vec3()).Normalize()
	if forward.LengthSq() == 0 {
		forward = voplay.Vec3{Z: -1}
	}
	right := forward.Cross(voplay.Vec3{Y: 1}).Normalize()
	if right.LengthSq() == 0 {
		right = voplay.Vec3{X: 1}
	}
	yaw := trackYawFromForward(forward)
	return TrackPose{Position: pos, Rotation: voplay.QuatFromAxisAngle(voplay.Vec3{Y: 1}, yaw), Forward: forward, Right: right, Yaw: yaw, Distance: d, Bank: trackLerp(a.Bank, b.Bank, segT), HalfWidth: trackLerp(a.Width, b.Width, segT) * 0.5}
}

func (t *Track) PoseOnLine(lineName string, distance float64) (TrackRacingLinePose, error) {
	if t == nil || t.asset == nil {
		return TrackRacingLinePose{}, errors.New("scene3d.Track.PoseOnLine: track is nil")
	}
	if lineName == "" {
		return TrackRacingLinePose{}, errors.New("scene3d.Track.PoseOnLine: line name must not be empty")
	}
	for _, line := range t.asset.RacingLines {
		if line.Name == lineName {
			return t.poseOnRacingLine(line, distance), nil
		}
	}
	return TrackRacingLinePose{}, errors.New("scene3d.Track.PoseOnLine: racing line not found: " + lineName)
}

func (t *Track) poseOnRacingLine(line TrackRacingLine, distance float64) TrackRacingLinePose {
	if len(line.Points) == 0 {
		pose := t.PoseAt(distance)
		return TrackRacingLinePose{Pose: pose, LineName: line.Name}
	}
	d := t.normalizeDistance(distance)
	prev := line.Points[0]
	next := line.Points[len(line.Points)-1]
	if d <= line.Points[0].Distance {
		next = prev
	} else if d >= line.Points[len(line.Points)-1].Distance {
		prev = next
	} else {
		for i := 0; i < len(line.Points)-1; i++ {
			a := line.Points[i]
			b := line.Points[i+1]
			if d >= a.Distance && d <= b.Distance {
				prev = a
				next = b
				break
			}
		}
	}
	span := next.Distance - prev.Distance
	tval := 0.0
	if span > 0 {
		tval = trackClamp((d - prev.Distance) / span, 0, 1)
	}
	lateral := trackLerp(prev.Lateral, next.Lateral, tval)
	targetSpeed := trackLerp(prev.TargetSpeed, next.TargetSpeed, tval)
	pose := t.PoseAt(d)
	pose.Position = pose.Position.Add(pose.Right.Scale(lateral))
	return TrackRacingLinePose{Pose: pose, TargetSpeed: targetSpeed, LineName: line.Name}
}

func (t *Track) DistanceAlongTrack(pos voplay.Vec3) float64 {
	return t.ClosestPoint(pos).Distance
}

func (t *Track) SurfaceAt(pos voplay.Vec3) TrackSurfaceHit {
	cp := t.ClosestPoint(pos)
	best := TrackSurfaceHit{Name: TrackSurfaceOffroad, Kind: TrackSurfaceOffroad, Priority: -999999, Friction: 0.55, OnSurface: true, OnRoad: cp.OnRoad, Distance: cp.Distance, LateralDistance: cp.LateralDistance}
	if cp.OnRoad {
		best.Name = TrackSurfaceRoad
		best.Kind = TrackSurfaceRoad
		best.Priority = 0
		best.Friction = 1
	}
	if t == nil || t.asset == nil {
		return best
	}
	for _, surface := range t.asset.Surfaces {
		if !trackSurfaceContainsDistance(surface, cp.Distance, t.length, t.closed) {
			continue
		}
		left, right := trackSurfaceLateralBounds(surface, cp.HalfWidth)
		if cp.LateralDistance < left || cp.LateralDistance > right {
			continue
		}
		if surface.Priority < best.Priority {
			continue
		}
		friction := surface.Friction
		if friction == 0 {
			friction = 1
		}
		best = TrackSurfaceHit{Name: surface.Name, Kind: surface.Kind, Priority: surface.Priority, Friction: friction, Boost: surface.Boost, OnSurface: true, OnRoad: trackSurfaceIsRoad(surface, cp.OnRoad), Distance: cp.Distance, LateralDistance: cp.LateralDistance}
	}
	return best
}

func (t *Track) IsOnRoad(pos voplay.Vec3) bool {
	return t.SurfaceAt(pos).OnRoad
}

func (t *Track) NextGate(index int) TrackGate {
	if t == nil || t.asset == nil || len(t.asset.Gates) == 0 {
		return TrackGate{}
	}
	if index < 0 {
		index = 0
	}
	return t.asset.Gates[index % len(t.asset.Gates)]
}

func (t *Track) RespawnPoseNear(pos voplay.Vec3) TrackPose {
	if t == nil {
		return TrackPose{Rotation: voplay.QuatIdentity(), Forward: voplay.Vec3{Z: -1}, Right: voplay.Vec3{X: 1}}
	}
	cp := t.ClosestPoint(pos)
	if t.asset == nil || len(t.asset.Respawns) == 0 {
		return t.PoseAt(cp.Distance)
	}
	best := t.asset.Respawns[0]
	bestDelta := trackDistanceAbsDelta(cp.Distance, best.Distance, t.length, t.closed)
	for _, respawn := range t.asset.Respawns {
		delta := trackDistanceAbsDelta(cp.Distance, respawn.Distance, t.length, t.closed)
		if delta < bestDelta {
			best = respawn
			bestDelta = delta
		}
	}
	pose := t.PoseAt(best.Distance)
	if best.Position != (MapVec3{}) {
		pose.Position = best.Position.Vec3()
	}
	if best.Yaw != 0 {
		pose.Yaw = best.Yaw
		pose.Rotation = voplay.QuatFromAxisAngle(voplay.Vec3{Y: 1}, best.Yaw)
		pose.Forward = pose.Rotation.RotateVec3(voplay.Vec3{Z: -1})
		pose.Right = pose.Rotation.RotateVec3(voplay.Vec3{X: 1})
	}
	return pose
}

func ValidateTrackAsset(asset *TrackAsset) []TrackIssue {
	issues := []TrackIssue{}
	if asset == nil {
		return appendTrackIssue(issues, "track.nil", TrackIssueError, "$", "track asset is nil")
	}
	if asset.Version != 1 {
		issues = appendTrackIssue(issues, "track.version", TrackIssueError, "version", "unsupported track version: " + strconv.Itoa(asset.Version))
	}
	if asset.Name == "" {
		issues = appendTrackIssue(issues, "track.name", TrackIssueError, "name", "track name must not be empty")
	}
	if asset.Terrain != nil {
		err := validateMapTerrain(*asset.Terrain)
		if err != nil {
			issues = appendTrackIssue(issues, "track.terrain", TrackIssueError, "terrain", err.Error())
		}
		issues = validateTrackTerrain(*asset.Terrain, issues)
	}
	for i, terrain := range asset.TerrainChunks {
		path := "terrainChunks[" + strconv.Itoa(i) + "]"
		err := validateMapTerrain(terrain)
		if err != nil {
			issues = appendTrackIssue(issues, "track.terrain_chunk", TrackIssueError, path, err.Error())
		}
		issues = validateTrackTerrainAtPath(terrain, path, issues)
	}
	if len(asset.Meshes) == 0 && asset.Terrain == nil && len(asset.TerrainChunks) == 0 {
		issues = appendTrackIssue(issues, "track.resources", TrackIssueWarning, "meshes", "track has no mesh or terrain resources; callers must provide visuals and collision separately")
	}
	issues = validateTrackMeshes(asset.Meshes, issues)
	issues = validateTrackCenterline(asset, issues)
	issues = validateTrackSurfaces(asset, issues)
	issues = validateTrackGates(asset, issues)
	issues = validateTrackNamedPoses(asset, issues)
	issues = validateTrackRacingLines(asset, issues)
	issues = validateTrackElementNames(asset, issues)
	if !trackHasErrors(issues) {
		track := newTrackUnchecked(asset)
		issues = validateTrackDistanceSemantics(track, issues)
	}
	return issues
}

func ValidateTrackAssetFiles(asset *TrackAsset, baseDir string) []TrackIssue {
	return validateTrackFilesystemResources(asset, baseDir)
}

func ValidateTrackAssetResources(asset *TrackAsset, assets *voplay.Assets, baseDir string) []TrackIssue {
	return validateTrackAssetsResources(assets, asset, baseDir)
}

func CheckTrackTraversability(track *Track, opts TrackTraversabilityOptions) []TrackIssue {
	issues := []TrackIssue{}
	if track == nil {
		return appendTrackIssue(issues, "track.traversability.nil", TrackIssueError, "$", "track is nil")
	}
	sampleStep := opts.SampleStep
	if sampleStep <= 0 {
		sampleStep = 1
	}
	maxHeightDelta := opts.MaxHeightDelta
	if maxHeightDelta <= 0 {
		maxHeightDelta = 1.5
	}
	maxSegmentLength := opts.MaxSegmentLength
	if maxSegmentLength <= 0 {
		maxSegmentLength = 80
	}
	maxBoundaryDelta := opts.MaxBoundaryDelta
	if maxBoundaryDelta <= 0 {
		maxBoundaryDelta = sampleStep * 2 + 1
	}
	maxHeightProbeDelta := opts.MaxHeightProbeDelta
	if maxHeightProbeDelta <= 0 {
		maxHeightProbeDelta = 0.75
	}
	for i, length := range track.segmentLengths {
		if length > maxSegmentLength {
			issues = appendTrackIssue(issues, "track.traversability.segment_length", TrackIssueWarning, "centerline[" + strconv.Itoa(i) + "]", "centerline segment is longer than recommended")
		}
	}
	if track.length <= 0 {
		return appendTrackIssue(issues, "track.traversability.length", TrackIssueError, "centerline", "track length must be > 0")
	}
	lastPose := track.PoseAt(0)
	lastLeft, lastRight := trackBoundaryPoints(lastPose)
	if !track.IsOnRoad(lastPose.Position) {
		issues = appendTrackIssue(issues, "track.traversability.centerline_offroad", TrackIssueError, "distance:0.00", "centerline sample is not on road at " + trackFormatVec3(lastPose.Position))
	}
	issues = validateTrackHeightProbeSample(issues, opts.HeightProbe, lastPose, maxHeightProbeDelta)
	for d := sampleStep; d <= track.length; d += sampleStep {
		pose := track.PoseAt(d)
		heightDelta := math.Abs(pose.Position.Y - lastPose.Position.Y)
		if heightDelta > maxHeightDelta {
			issues = appendTrackIssue(issues, "track.traversability.height_delta", TrackIssueError, "distance:" + strconv.FormatFloat(d, 'f', 2, 64), "height delta exceeds configured threshold at " + trackFormatVec3(pose.Position))
		}
		if !track.IsOnRoad(pose.Position) {
			issues = appendTrackIssue(issues, "track.traversability.centerline_offroad", TrackIssueError, "distance:" + strconv.FormatFloat(d, 'f', 2, 64), "centerline sample is not on road at " + trackFormatVec3(pose.Position))
		}
		issues = validateTrackHeightProbeSample(issues, opts.HeightProbe, pose, maxHeightProbeDelta)
		left, right := trackBoundaryPoints(pose)
		if left.Distance(lastLeft) > maxBoundaryDelta || right.Distance(lastRight) > maxBoundaryDelta {
			issues = appendTrackIssue(issues, "track.traversability.boundary_gap", TrackIssueError, "distance:" + strconv.FormatFloat(d, 'f', 2, 64), "road boundary discontinuity near " + trackFormatVec3(pose.Position))
		}
		lastPose = pose
		lastLeft = left
		lastRight = right
	}
	if track.closed {
		a := track.PoseAt(0)
		b := track.PoseAt(track.length)
		if a.Position.Distance(b.Position) > trackContinuityTolerance {
			issues = appendTrackIssue(issues, "track.traversability.closed_loop", TrackIssueError, "centerline", "closed loop end pose does not match start pose")
		}
	}
	if track.asset != nil {
		for i, gate := range track.asset.Gates {
			pose := track.PoseAt(gate.Distance)
			if !track.IsOnRoad(pose.Position) {
				issues = appendTrackIssue(issues, "track.traversability.gate_offroad", TrackIssueError, "gates[" + strconv.Itoa(i) + "].distance", "gate is not reachable on road at " + trackFormatVec3(pose.Position))
			}
		}
	}
	return issues
}

func SpawnTrackWithAssets(scene *Scene, assets *voplay.Assets, track *Track, baseDir string) (*TrackSpawnResult, error) {
	if scene == nil {
		return nil, errors.New("scene3d.SpawnTrack: scene is nil")
	}
	if track == nil || track.asset == nil {
		return nil, errors.New("scene3d.SpawnTrack: track is nil")
	}
	result := &TrackSpawnResult{Track: track, Entities: []*Entity{}, Meshes: map[string]*Entity{}, CollisionMeshes: map[string]*Entity{}, Textures: []voplay.TextureID{}}
	success := false
	errdefer func() {
		if success {
			return
		}
		result.Destroy(scene)
		result.ReleaseTextures()
	}()
	if track.asset.Terrain != nil {
		mapResult := &MapSpawnResult{Textures: []voplay.TextureID{}}
		terrain, err := spawnMapTerrain(scene, assets, *track.asset.Terrain, baseDir, mapResult)
		if err != nil {
			return nil, err
		}
		result.Terrain = terrain
		result.Entities = append(result.Entities, terrain.Entity())
		result.Textures = append(result.Textures, mapResult.Textures...)
	}
	for _, terrainAsset := range track.asset.TerrainChunks {
		mapResult := &MapSpawnResult{Textures: []voplay.TextureID{}}
		terrain, err := spawnMapTerrain(scene, assets, terrainAsset, baseDir, mapResult)
		if err != nil {
			return nil, err
		}
		if result.Terrain == nil {
			result.Terrain = terrain
		}
		result.TerrainChunks = append(result.TerrainChunks, terrain)
		result.Entities = append(result.Entities, terrain.Entity())
		result.Textures = append(result.Textures, mapResult.Textures...)
	}
	for _, mesh := range track.asset.Meshes {
		visual, collision, err := spawnTrackMesh(scene, assets, mesh, baseDir)
		if err != nil {
			return nil, err
		}
		if visual != nil {
			result.Entities = append(result.Entities, visual)
			result.Meshes[mesh.Name] = visual
		}
		if collision != nil {
			result.Entities = append(result.Entities, collision)
			result.CollisionMeshes[mesh.Name] = collision
		}
	}
	success = true
	return result, nil
}

func (r *TrackSpawnResult) Destroy(scene *Scene) {
	if r == nil || scene == nil {
		return
	}
	for _, e := range r.Entities {
		if e != nil && e.scene == scene && e.Active {
			scene.Destroy(e)
		}
	}
	r.Entities = nil
	r.Terrain = nil
	r.TerrainChunks = nil
	r.Meshes = map[string]*Entity{}
	r.CollisionMeshes = map[string]*Entity{}
	r.ReleaseTextures()
}

func (r *TrackSpawnResult) HeightProbe() TrackHeightProbe {
	return func(pos voplay.Vec3) (float64, bool) {
		if r == nil {
			return 0, false
		}
		if h, ok := sampleSpawnedTerrainHeight(r.Terrain, pos); ok {
			return h, true
		}
		for _, terrain := range r.TerrainChunks {
			if terrain == r.Terrain {
				continue
			}
			if h, ok := sampleSpawnedTerrainHeight(terrain, pos); ok {
				return h, true
			}
		}
		return 0, false
	}
}

func sampleSpawnedTerrainHeight(terrain *Terrain, pos voplay.Vec3) (float64, bool) {
	if terrain == nil || terrain.entity == nil || !terrain.entity.Active || !terrain.entity.Visible {
		return 0, false
	}
	return terrain.HeightAt(pos.X, pos.Z)
}

func (r *TrackSpawnResult) ReleaseTextures() {
	if r == nil {
		return
	}
	for _, texture := range r.Textures {
		if texture != 0 {
			texture.Free()
		}
	}
	r.Textures = nil
}

func SpawnTrackDebugOverlay(scene *Scene, track *Track, opts TrackDebugOptions) (*TrackDebugOverlay, error) {
	if scene == nil {
		return nil, errors.New("scene3d.SpawnTrackDebugOverlay: scene is nil")
	}
	if track == nil {
		return nil, errors.New("scene3d.SpawnTrackDebugOverlay: track is nil")
	}
	opts = normalizeTrackDebugOptions(opts)
	model := opts.Model
	owned := false
	if model == 0 {
		model = CubeMesh()
		owned = true
	}
	overlay := &TrackDebugOverlay{Entities: []*Entity{}, model: model, ownedModel: owned}
	success := false
	errdefer func() {
		if success {
			return
		}
		overlay.Destroy(scene)
	}()
	if opts.Centerline {
		overlay.spawnTrackPolyline(scene, track, model, opts, 0, opts.CenterColor)
	}
	if opts.Boundaries {
		overlay.spawnTrackPolyline(scene, track, model, opts, -1, opts.BoundaryColor)
		overlay.spawnTrackPolyline(scene, track, model, opts, 1, opts.BoundaryColor)
	}
	if opts.Gates {
		for _, gate := range track.asset.Gates {
			pose := track.PoseAt(gate.Distance)
			width := gate.Width
			if width <= 0 {
				width = pose.HalfWidth * 2
			}
			ent := scene.Spawn(EntityDesc{Position: pose.Position.Add(voplay.Vec3{Y: opts.HeightOffset}), Rotation: pose.Rotation, Scale: voplay.Vec3{X: width, Y: opts.LineThickness, Z: opts.LineThickness}, Model: model, Tint: opts.GateColor, TintSet: true, Tag: "track_debug_gate_" + gate.Name, PickMode: PickDisabled})
			overlay.Entities = append(overlay.Entities, ent)
		}
	}
	if opts.Respawns {
		for _, respawn := range track.asset.Respawns {
			pose := track.PoseAt(respawn.Distance)
			ent := scene.Spawn(EntityDesc{Position: pose.Position.Add(voplay.Vec3{Y: opts.HeightOffset}), Rotation: pose.Rotation, Scale: voplay.Vec3{X: opts.LineThickness * 3, Y: opts.LineThickness * 3, Z: opts.LineThickness * 3}, Model: model, Tint: opts.RespawnColor, TintSet: true, Tag: "track_debug_respawn_" + respawn.Name, PickMode: PickDisabled})
			overlay.Entities = append(overlay.Entities, ent)
		}
	}
	success = true
	return overlay, nil
}

func (o *TrackDebugOverlay) Destroy(scene *Scene) {
	if o == nil {
		return
	}
	for _, e := range o.Entities {
		if e != nil && scene != nil && e.scene == scene && e.Active {
			scene.Destroy(e)
		}
	}
	o.Entities = nil
	if o.ownedModel && o.model != 0 {
		o.model.Free()
		o.model = 0
		o.ownedModel = false
	}
}

func (o *TrackDebugOverlay) spawnTrackPolyline(scene *Scene, track *Track, model voplay.ModelID, opts TrackDebugOptions, lateralSign float64, color voplay.Color) {
	for i := 0; i < len(track.segmentLengths); i++ {
		a := track.PoseAt(track.segmentStarts[i])
		b := track.PoseAt(track.segmentStarts[i] + track.segmentLengths[i])
		if lateralSign != 0 {
			a.Position = a.Position.Add(a.Right.Scale(a.HalfWidth * lateralSign))
			b.Position = b.Position.Add(b.Right.Scale(b.HalfWidth * lateralSign))
		}
		start := a.Position.Add(voplay.Vec3{Y: opts.HeightOffset})
		end := b.Position.Add(voplay.Vec3{Y: opts.HeightOffset})
		dir := end.Sub(start)
		length := dir.Length()
		if length <= 0 {
			continue
		}
		mid := start.Lerp(end, 0.5)
		yaw := trackYawFromForward(dir.Normalize())
		ent := scene.Spawn(EntityDesc{Position: mid, Rotation: voplay.QuatFromAxisAngle(voplay.Vec3{Y: 1}, yaw), Scale: voplay.Vec3{X: opts.LineThickness, Y: opts.LineThickness, Z: length}, Model: model, Tint: color, TintSet: true, Tag: "track_debug_line", PickMode: PickDisabled})
		o.Entities = append(o.Entities, ent)
	}
}

func validateTrackMeshes(meshes []TrackMesh, issues []TrackIssue) []TrackIssue {
	seen := map[string]bool{}
	for i, mesh := range meshes {
		path := "meshes[" + strconv.Itoa(i) + "]"
		if mesh.Name == "" {
			issues = appendTrackIssue(issues, "track.mesh.name", TrackIssueError, path + ".name", "mesh name must not be empty")
		}
		if seen[mesh.Name] {
			issues = appendTrackIssue(issues, "track.mesh.duplicate", TrackIssueError, path + ".name", "duplicate mesh name: " + mesh.Name)
		}
		seen[mesh.Name] = true
		if mesh.Model == "" {
			issues = appendTrackIssue(issues, "track.mesh.model", TrackIssueError, path + ".model", "mesh model is required: " + mesh.Name)
		}
		if mesh.Collision != "" && mesh.Collision != "none" && mesh.Collision != "trimesh" {
			issues = appendTrackIssue(issues, "track.mesh.collision", TrackIssueError, path + ".collision", "unsupported mesh collision: " + mesh.Name)
		}
		issues = appendFiniteVec3Issues(issues, path + ".position", mesh.Position.Vec3())
		issues = appendFiniteVec3Issues(issues, path + ".rotation", mesh.Rotation.Vec3())
		issues = appendFiniteVec3Issues(issues, path + ".scale", mesh.Scale.Vec3())
		if mesh.TintSet {
			issues = appendFiniteColorIssues(issues, path + ".tint", mesh.Tint)
		}
		if !trackFinite(mesh.Friction) || mesh.Friction < 0 {
			issues = appendTrackIssue(issues, "track.mesh.friction", TrackIssueError, path + ".friction", "mesh friction must be finite and >= 0")
		}
	}
	return issues
}

func validateTrackTerrain(terrain MapTerrain, issues []TrackIssue) []TrackIssue {
	return validateTrackTerrainAtPath(terrain, "terrain", issues)
}

func validateTrackTerrainAtPath(terrain MapTerrain, path string, issues []TrackIssue) []TrackIssue {
	issues = appendFiniteVec3Issues(issues, path + ".position", terrain.Position.Vec3())
	if !trackFinite(terrain.Width) || !trackFinite(terrain.Height) || !trackFinite(terrain.Depth) || !trackFinite(terrain.UVScale) || !trackFinite(terrain.NormalScale) || !trackFinite(terrain.Roughness) || !trackFinite(terrain.Metallic) || !trackFinite(terrain.Friction) {
		issues = appendTrackIssue(issues, "track.terrain.finite", TrackIssueError, path, "terrain numeric values must be finite")
	}
	if terrain.Splat != nil {
		if terrain.Texture != "" || terrain.Normal != "" || terrain.MetallicRoughness != "" || terrain.UVScale != 0 || terrain.NormalScale != 0 || terrain.Roughness != 0 || terrain.Metallic != 0 {
			issues = appendTrackIssue(issues, "track.terrain.splat_mix", TrackIssueError, path + ".splat", "terrain single-material fields cannot be mixed with splat")
		}
		if terrain.Splat.Control == "" {
			issues = appendTrackIssue(issues, "track.terrain.splat_control", TrackIssueError, path + ".splat.control", "terrain splat control is required")
		}
		if len(terrain.Splat.Layers) != 4 {
			issues = appendTrackIssue(issues, "track.terrain.splat_layers", TrackIssueError, path + ".splat.layers", "terrain splat requires exactly 4 layers")
		}
		for i, layer := range terrain.Splat.Layers {
			layerPath := path + ".splat.layers[" + strconv.Itoa(i) + "]"
			if layer.Texture == "" {
				issues = appendTrackIssue(issues, "track.terrain.splat_layer_texture", TrackIssueError, layerPath + ".texture", "terrain splat layer texture is required")
			}
			if !trackFinite(layer.UVScale) || !trackFinite(layer.NormalScale) {
				issues = appendTrackIssue(issues, "track.terrain.splat_layer_finite", TrackIssueError, layerPath, "terrain splat layer numeric values must be finite")
			}
			if layer.UVScale < 0 {
				issues = appendTrackIssue(issues, "track.terrain.splat_layer_uv_scale", TrackIssueError, layerPath + ".uvScale", "terrain splat layer uvScale must be >= 0")
			}
			if layer.NormalScale < 0 {
				issues = appendTrackIssue(issues, "track.terrain.splat_layer_normal_scale", TrackIssueError, layerPath + ".normalScale", "terrain splat layer normalScale must be >= 0")
			}
		}
	}
	if terrain.NormalScale < 0 {
		issues = appendTrackIssue(issues, "track.terrain.normal_scale", TrackIssueError, path + ".normalScale", "terrain normalScale must be >= 0")
	}
	if terrain.Roughness < 0 {
		issues = appendTrackIssue(issues, "track.terrain.roughness", TrackIssueError, path + ".roughness", "terrain roughness must be >= 0")
	}
	if terrain.Metallic < 0 || terrain.Metallic > 1 {
		issues = appendTrackIssue(issues, "track.terrain.metallic", TrackIssueError, path + ".metallic", "terrain metallic must be in range 0..1")
	}
	if terrain.Friction < 0 {
		issues = appendTrackIssue(issues, "track.terrain.friction", TrackIssueError, path + ".friction", "terrain friction must be >= 0")
	}
	if terrain.TintSet {
		issues = appendFiniteColorIssues(issues, path + ".tint", terrain.Tint)
	}
	return issues
}

func validateTrackElementNames(asset *TrackAsset, issues []TrackIssue) []TrackIssue {
	seen := map[string]string{}
	for i, mesh := range asset.Meshes {
		issues = appendTrackElementNameIssue(issues, seen, mesh.Name, "meshes[" + strconv.Itoa(i) + "].name")
	}
	for i, surface := range asset.Surfaces {
		issues = appendTrackElementNameIssue(issues, seen, surface.Name, "surfaces[" + strconv.Itoa(i) + "].name")
	}
	for i, gate := range asset.Gates {
		issues = appendTrackElementNameIssue(issues, seen, gate.Name, "gates[" + strconv.Itoa(i) + "].name")
	}
	for i, spawn := range asset.Spawns {
		issues = appendTrackElementNameIssue(issues, seen, spawn.Name, "spawns[" + strconv.Itoa(i) + "].name")
	}
	for i, respawn := range asset.Respawns {
		issues = appendTrackElementNameIssue(issues, seen, respawn.Name, "respawns[" + strconv.Itoa(i) + "].name")
	}
	for i, trigger := range asset.Triggers {
		issues = appendTrackElementNameIssue(issues, seen, trigger.Name, "triggers[" + strconv.Itoa(i) + "].name")
	}
	for i, line := range asset.RacingLines {
		issues = appendTrackElementNameIssue(issues, seen, line.Name, "racingLines[" + strconv.Itoa(i) + "].name")
	}
	return issues
}

func validateTrackDistanceSemantics(track *Track, issues []TrackIssue) []TrackIssue {
	if track == nil || track.asset == nil || track.length <= 0 {
		return issues
	}
	asset := track.asset
	if len(asset.Spawns) == 0 {
		issues = appendTrackIssue(issues, "track.spawn.missing", TrackIssueWarning, "spawns", "track has no spawn poses")
	}
	if len(asset.Respawns) == 0 {
		issues = appendTrackIssue(issues, "track.respawn.missing", TrackIssueWarning, "respawns", "track has no respawn poses")
	}
	for i, surface := range asset.Surfaces {
		path := "surfaces[" + strconv.Itoa(i) + "]"
		if !trackDistanceInRange(surface.Start, track.length) || !trackDistanceInRange(surface.End, track.length) {
			issues = appendTrackIssue(issues, "track.surface.distance_range", TrackIssueError, path, "surface start/end must be within track length")
		}
		if !track.closed && surface.Start > surface.End {
			issues = appendTrackIssue(issues, "track.surface.distance_order", TrackIssueError, path, "surface start must be <= end on open tracks")
		}
		if surface.Friction < 0 {
			issues = appendTrackIssue(issues, "track.surface.friction", TrackIssueError, path + ".friction", "surface friction must be >= 0")
		}
		if !trackSurfaceKindKnown(surface.Kind) {
			issues = appendTrackIssue(issues, "track.surface.kind_unknown", TrackIssueWarning, path + ".kind", "surface kind is game-defined: " + surface.Kind)
		}
	}
	for i, gate := range asset.Gates {
		path := "gates[" + strconv.Itoa(i) + "].distance"
		if !trackDistanceInRange(gate.Distance, track.length) {
			issues = appendTrackIssue(issues, "track.gate.distance_range", TrackIssueError, path, "gate distance must be within track length")
		}
	}
	for i, spawn := range asset.Spawns {
		path := "spawns[" + strconv.Itoa(i) + "]"
		if !trackDistanceInRange(spawn.Distance, track.length) {
			issues = appendTrackIssue(issues, "track.spawn.distance_range", TrackIssueError, path + ".distance", "spawn distance must be within track length")
		}
		pose := track.PoseAt(spawn.Distance)
		if spawn.Position != (MapVec3{}) {
			pose.Position = spawn.Position.Vec3()
		}
		if !track.IsOnRoad(pose.Position) {
			issues = appendTrackIssue(issues, "track.spawn.offroad", TrackIssueError, path + ".position", "spawn pose must be on the road")
		}
	}
	for i, respawn := range asset.Respawns {
		path := "respawns[" + strconv.Itoa(i) + "]"
		if !trackDistanceInRange(respawn.Distance, track.length) {
			issues = appendTrackIssue(issues, "track.respawn.distance_range", TrackIssueError, path + ".distance", "respawn distance must be within track length")
		}
		pose := track.PoseAt(respawn.Distance)
		if respawn.Position != (MapVec3{}) {
			pose.Position = respawn.Position.Vec3()
		}
		if !track.IsOnRoad(pose.Position) {
			issues = appendTrackIssue(issues, "track.respawn.offroad", TrackIssueError, path + ".position", "respawn pose must be on the road")
		}
	}
	for i, trigger := range asset.Triggers {
		path := "triggers[" + strconv.Itoa(i) + "]"
		if !trackDistanceInRange(trigger.Distance, track.length) {
			issues = appendTrackIssue(issues, "track.trigger.distance_range", TrackIssueError, path + ".distance", "trigger distance must be within track length")
		}
	}
	return issues
}

func validateTrackFilesystemResources(asset *TrackAsset, baseDir string) []TrackIssue {
	issues := []TrackIssue{}
	return validateTrackResourcePaths(asset, baseDir, func(path string) bool {
		_, err := os.Stat(path)
		return err == nil
	}, issues)
}

func validateTrackAssetsResources(assets *voplay.Assets, asset *TrackAsset, baseDir string) []TrackIssue {
	issues := []TrackIssue{}
	if assets == nil {
		return issues
	}
	return validateTrackResourcePaths(asset, baseDir, func(path string) bool {
		_, err := assets.Bytes(path)
		return err == nil
	}, issues)
}

func validateTrackResourcePaths(asset *TrackAsset, baseDir string, exists func(string) bool, issues []TrackIssue) []TrackIssue {
	if asset == nil || exists == nil {
		return issues
	}
	if asset.Terrain != nil {
		if asset.Terrain.Heightmap != "" {
			issues = appendMissingTrackResource(issues, "terrain.heightmap", mapResolvePath(baseDir, asset.Terrain.Heightmap), exists)
		}
		if asset.Terrain.Texture != "" {
			issues = appendMissingTrackResource(issues, "terrain.texture", mapResolvePath(baseDir, asset.Terrain.Texture), exists)
		}
		if asset.Terrain.Normal != "" {
			issues = appendMissingTrackResource(issues, "terrain.normal", mapResolvePath(baseDir, asset.Terrain.Normal), exists)
		}
		if asset.Terrain.MetallicRoughness != "" {
			issues = appendMissingTrackResource(issues, "terrain.metallicRoughness", mapResolvePath(baseDir, asset.Terrain.MetallicRoughness), exists)
		}
		issues = appendTerrainSplatResourceIssues(issues, "terrain", baseDir, asset.Terrain.Splat, exists)
	}
	for i, terrain := range asset.TerrainChunks {
		path := "terrainChunks[" + strconv.Itoa(i) + "]"
		if terrain.Heightmap != "" {
			issues = appendMissingTrackResource(issues, path + ".heightmap", mapResolvePath(baseDir, terrain.Heightmap), exists)
		}
		if terrain.Texture != "" {
			issues = appendMissingTrackResource(issues, path + ".texture", mapResolvePath(baseDir, terrain.Texture), exists)
		}
		if terrain.Normal != "" {
			issues = appendMissingTrackResource(issues, path + ".normal", mapResolvePath(baseDir, terrain.Normal), exists)
		}
		if terrain.MetallicRoughness != "" {
			issues = appendMissingTrackResource(issues, path + ".metallicRoughness", mapResolvePath(baseDir, terrain.MetallicRoughness), exists)
		}
		issues = appendTerrainSplatResourceIssues(issues, path, baseDir, terrain.Splat, exists)
	}
	for i, mesh := range asset.Meshes {
		path := "meshes[" + strconv.Itoa(i) + "]"
		if mesh.Model != "" {
			issues = appendMissingTrackResource(issues, path + ".model", mapResolvePath(baseDir, mesh.Model), exists)
		}
		if mesh.CollisionModel != "" {
			issues = appendMissingTrackResource(issues, path + ".collisionModel", mapResolvePath(baseDir, mesh.CollisionModel), exists)
		}
	}
	return issues
}

func appendTerrainSplatResourceIssues(issues []TrackIssue, path string, baseDir string, splat *MapTerrainSplat, exists func(string) bool) []TrackIssue {
	if splat == nil {
		return issues
	}
	if splat.Control != "" {
		issues = appendMissingTrackResource(issues, path + ".splat.control", mapResolvePath(baseDir, splat.Control), exists)
	}
	for i, layer := range splat.Layers {
		layerPath := path + ".splat.layers[" + strconv.Itoa(i) + "]"
		if layer.Texture != "" {
			issues = appendMissingTrackResource(issues, layerPath + ".texture", mapResolvePath(baseDir, layer.Texture), exists)
		}
		if layer.Normal != "" {
			issues = appendMissingTrackResource(issues, layerPath + ".normal", mapResolvePath(baseDir, layer.Normal), exists)
		}
		if layer.MetallicRoughness != "" {
			issues = appendMissingTrackResource(issues, layerPath + ".metallicRoughness", mapResolvePath(baseDir, layer.MetallicRoughness), exists)
		}
	}
	return issues
}

func appendMissingTrackResource(issues []TrackIssue, path, resource string, exists func(string) bool) []TrackIssue {
	if resource == "" || exists(resource) {
		return issues
	}
	return appendTrackIssue(issues, "track.resource.missing", TrackIssueError, path, "missing track resource: " + resource)
}

func validateTrackCenterline(asset *TrackAsset, issues []TrackIssue) []TrackIssue {
	if len(asset.Centerline) < 2 {
		return appendTrackIssue(issues, "track.centerline.count", TrackIssueError, "centerline", "centerline must contain at least 2 points")
	}
	for i, point := range asset.Centerline {
		path := "centerline[" + strconv.Itoa(i) + "]"
		if point.Width <= 0 {
			issues = appendTrackIssue(issues, "track.centerline.width", TrackIssueError, path + ".width", "centerline width must be > 0")
		}
		issues = appendFiniteVec3Issues(issues, path + ".position", point.Position.Vec3())
		if !trackFinite(point.Width) {
			issues = appendTrackIssue(issues, "track.centerline.width_finite", TrackIssueError, path + ".width", "centerline width must be finite")
		}
		if !trackFinite(point.Bank) {
			issues = appendTrackIssue(issues, "track.centerline.bank_finite", TrackIssueError, path + ".bank", "centerline bank must be finite")
		}
		if i > 0 {
			prev := asset.Centerline[i - 1].Position.Vec3()
			if prev.Distance(point.Position.Vec3()) <= 0 {
				issues = appendTrackIssue(issues, "track.centerline.zero_segment", TrackIssueError, path + ".position", "centerline segment length must be > 0")
			}
		}
	}
	if asset.ClosedLoop {
		first := asset.Centerline[0].Position.Vec3()
		last := asset.Centerline[len(asset.Centerline) - 1].Position.Vec3()
		if first.Distance(last) > trackContinuityTolerance {
			issues = appendTrackIssue(issues, "track.centerline.closed_loop", TrackIssueError, "centerline", "closed loop endpoints must be continuous within " + strconv.FormatFloat(trackContinuityTolerance, 'f', 2, 64))
		}
		if len(asset.Centerline) < 3 {
			issues = appendTrackIssue(issues, "track.centerline.closed_count", TrackIssueError, "centerline", "closed loop centerline must contain at least 3 points")
		}
	}
	return issues
}

func validateTrackSurfaces(asset *TrackAsset, issues []TrackIssue) []TrackIssue {
	seen := map[string]bool{}
	for i, surface := range asset.Surfaces {
		path := "surfaces[" + strconv.Itoa(i) + "]"
		if surface.Name == "" {
			issues = appendTrackIssue(issues, "track.surface.name", TrackIssueError, path + ".name", "surface name must not be empty")
		}
		if seen[surface.Name] {
			issues = appendTrackIssue(issues, "track.surface.duplicate", TrackIssueError, path + ".name", "duplicate surface name: " + surface.Name)
		}
		seen[surface.Name] = true
		if surface.Kind == "" {
			issues = appendTrackIssue(issues, "track.surface.kind", TrackIssueError, path + ".kind", "surface kind must not be empty")
		}
		if !trackFinite(surface.Start) || !trackFinite(surface.End) || !trackFinite(surface.Left) || !trackFinite(surface.Right) || !trackFinite(surface.Friction) || !trackFinite(surface.Boost) {
			issues = appendTrackIssue(issues, "track.surface.finite", TrackIssueError, path, "surface numeric values must be finite")
		}
		if surface.Left != 0 || surface.Right != 0 {
			if surface.Left > surface.Right {
				issues = appendTrackIssue(issues, "track.surface.lateral", TrackIssueError, path, "surface left bound must be <= right bound")
			}
		}
	}
	return issues
}

func validateTrackGates(asset *TrackAsset, issues []TrackIssue) []TrackIssue {
	seen := map[string]bool{}
	lastDistance := -math.MaxFloat64
	for i, gate := range asset.Gates {
		path := "gates[" + strconv.Itoa(i) + "]"
		if gate.Name == "" {
			issues = appendTrackIssue(issues, "track.gate.name", TrackIssueError, path + ".name", "gate name must not be empty")
		}
		if seen[gate.Name] {
			issues = appendTrackIssue(issues, "track.gate.duplicate", TrackIssueError, path + ".name", "duplicate gate name: " + gate.Name)
		}
		seen[gate.Name] = true
		if !trackFinite(gate.Distance) {
			issues = appendTrackIssue(issues, "track.gate.distance_finite", TrackIssueError, path + ".distance", "gate distance must be finite")
		}
		if gate.Distance <= lastDistance {
			issues = appendTrackIssue(issues, "track.gate.order", TrackIssueError, path + ".distance", "gate distance must be strictly increasing")
		}
		if gate.Width < 0 || gate.Radius < 0 {
			issues = appendTrackIssue(issues, "track.gate.size", TrackIssueError, path, "gate width and radius must be >= 0")
		}
		lastDistance = gate.Distance
	}
	return issues
}

func validateTrackNamedPoses(asset *TrackAsset, issues []TrackIssue) []TrackIssue {
	seenSpawns := map[string]bool{}
	for i, spawn := range asset.Spawns {
		path := "spawns[" + strconv.Itoa(i) + "]"
		if spawn.Name == "" {
			issues = appendTrackIssue(issues, "track.spawn.name", TrackIssueError, path + ".name", "spawn name must not be empty")
		}
		if seenSpawns[spawn.Name] {
			issues = appendTrackIssue(issues, "track.spawn.duplicate", TrackIssueError, path + ".name", "duplicate spawn name: " + spawn.Name)
		}
		seenSpawns[spawn.Name] = true
		if !trackFinite(spawn.Distance) || !trackFinite(spawn.Yaw) {
			issues = appendTrackIssue(issues, "track.spawn.finite", TrackIssueError, path, "spawn numeric values must be finite")
		}
	}
	seenRespawns := map[string]bool{}
	for i, respawn := range asset.Respawns {
		path := "respawns[" + strconv.Itoa(i) + "]"
		if respawn.Name == "" {
			issues = appendTrackIssue(issues, "track.respawn.name", TrackIssueError, path + ".name", "respawn name must not be empty")
		}
		if seenRespawns[respawn.Name] {
			issues = appendTrackIssue(issues, "track.respawn.duplicate", TrackIssueError, path + ".name", "duplicate respawn name: " + respawn.Name)
		}
		seenRespawns[respawn.Name] = true
		if !trackFinite(respawn.Distance) || !trackFinite(respawn.Yaw) {
			issues = appendTrackIssue(issues, "track.respawn.finite", TrackIssueError, path, "respawn numeric values must be finite")
		}
	}
	seenTriggers := map[string]bool{}
	for i, trigger := range asset.Triggers {
		path := "triggers[" + strconv.Itoa(i) + "]"
		if trigger.Name == "" {
			issues = appendTrackIssue(issues, "track.trigger.name", TrackIssueError, path + ".name", "trigger name must not be empty")
		}
		if seenTriggers[trigger.Name] {
			issues = appendTrackIssue(issues, "track.trigger.duplicate", TrackIssueError, path + ".name", "duplicate trigger name: " + trigger.Name)
		}
		seenTriggers[trigger.Name] = true
		if trigger.Kind == "" {
			issues = appendTrackIssue(issues, "track.trigger.kind", TrackIssueError, path + ".kind", "trigger kind must not be empty")
		}
		if !trackFinite(trigger.Distance) || !trackFinite(trigger.Radius) || trigger.Radius < 0 {
			issues = appendTrackIssue(issues, "track.trigger.finite", TrackIssueError, path, "trigger distance must be finite and radius must be >= 0")
		}
	}
	return issues
}

func validateTrackRacingLines(asset *TrackAsset, issues []TrackIssue) []TrackIssue {
	if len(asset.RacingLines) == 0 {
		return issues
	}
	if trackHasErrors(issues) {
		return issues
	}
	track := newTrackUnchecked(asset)
	for i, line := range asset.RacingLines {
		path := "racingLines[" + strconv.Itoa(i) + "]"
		if line.Name == "" {
			issues = appendTrackIssue(issues, "track.racing_line.name", TrackIssueError, path + ".name", "racing line name must not be empty")
		}
		if len(line.Points) < 2 {
			issues = appendTrackIssue(issues, "track.racing_line.points", TrackIssueError, path + ".points", "racing line must contain at least two points")
		}
		prevDistance := -1.0
		for j, point := range line.Points {
			pointPath := path + ".points[" + strconv.Itoa(j) + "]"
			if !trackFinite(point.Distance) || !trackFinite(point.Lateral) || !trackFinite(point.TargetSpeed) {
				issues = appendTrackIssue(issues, "track.racing_line.finite", TrackIssueError, pointPath, "racing line point values must be finite")
			}
			if point.Distance < 0 || point.Distance > track.length {
				issues = appendTrackIssue(issues, "track.racing_line.distance_range", TrackIssueError, pointPath + ".distance", "racing line point distance must be within track length")
			}
			if j > 0 && point.Distance <= prevDistance {
				issues = appendTrackIssue(issues, "track.racing_line.order", TrackIssueError, pointPath + ".distance", "racing line distances must be strictly increasing")
			}
			if point.TargetSpeed < 0 {
				issues = appendTrackIssue(issues, "track.racing_line.target_speed", TrackIssueError, pointPath + ".targetSpeed", "racing line target speed must be >= 0")
			}
			prevDistance = point.Distance
		}
	}
	return issues
}

func validateTrackHeightProbeSample(issues []TrackIssue, probe TrackHeightProbe, pose TrackPose, maxDelta float64) []TrackIssue {
	if probe == nil {
		return issues
	}
	height, ok := probe(pose.Position)
	path := "distance:" + strconv.FormatFloat(pose.Distance, 'f', 2, 64)
	if !ok {
		return appendTrackIssue(issues, "track.traversability.height_probe_miss", TrackIssueError, path, "height probe missed road or terrain at " + trackFormatVec3(pose.Position))
	}
	if !trackFinite(height) {
		return appendTrackIssue(issues, "track.traversability.height_probe_finite", TrackIssueError, path, "height probe returned non-finite value at " + trackFormatVec3(pose.Position))
	}
	if math.Abs(height - pose.Position.Y) > maxDelta {
		return appendTrackIssue(issues, "track.traversability.height_probe_delta", TrackIssueError, path, "height probe differs from centerline by more than configured threshold at " + trackFormatVec3(pose.Position))
	}
	return issues
}

func spawnTrackMesh(scene *Scene, assets *voplay.Assets, mesh TrackMesh, baseDir string) (*Entity, *Entity, error) {
	visualModel, visualOwned, err := loadTrackModel(assets, mapResolvePath(baseDir, mesh.Model))
	if err != nil {
		return nil, nil, err
	}
	visualSpawned := false
	errdefer func() {
		if !visualSpawned && visualOwned && visualModel != 0 {
			visualModel.Free()
		}
	}()
	visualDesc := EntityDesc{Position: mesh.Position.Vec3(), Rotation: mapRotation(mesh.Rotation), Scale: mapScale(mesh.Scale), Model: visualModel, Tag: mesh.Name, StaticRenderable: true}
	if mesh.TintSet {
		visualDesc.Tint = mesh.Tint.Color()
		visualDesc.TintSet = true
	}
	if visualOwned {
		visualDesc.OwnedModel = visualModel
	}
	collisionMode := mesh.Collision
	if collisionMode == "" && mesh.CollisionModel != "" {
		collisionMode = "trimesh"
	}
	if collisionMode == "trimesh" && mesh.CollisionModel == "" {
		visualDesc.Physics = TrimeshPhysics(visualModel)
		if mesh.Friction > 0 {
			visualDesc.Physics.Friction = mesh.Friction
		}
	}
	visual := scene.Spawn(visualDesc)
	visual.Visible = !mesh.Hidden
	visualSpawned = true
	if collisionMode != "trimesh" || mesh.CollisionModel == "" {
		return visual, nil, nil
	}
	collisionModel, collisionOwned, err := loadTrackModel(assets, mapResolvePath(baseDir, mesh.CollisionModel))
	if err != nil {
		scene.Destroy(visual)
		return nil, nil, err
	}
	collisionSpawned := false
	errdefer func() {
		if !collisionSpawned && collisionOwned && collisionModel != 0 {
			collisionModel.Free()
		}
	}()
	physics := TrimeshPhysics(collisionModel)
	if mesh.Friction > 0 {
		physics.Friction = mesh.Friction
	}
	collisionDesc := EntityDesc{Position: mesh.Position.Vec3(), Rotation: mapRotation(mesh.Rotation), Scale: mapScale(mesh.Scale), Model: collisionModel, Tint: voplay.White, TintSet: true, Tag: mesh.Name + "_collision", Physics: physics}
	if collisionOwned {
		collisionDesc.OwnedModel = collisionModel
	}
	collision := scene.Spawn(collisionDesc)
	collision.Visible = false
	collisionSpawned = true
	return visual, collision, nil
}

func loadTrackModel(assets *voplay.Assets, path string) (voplay.ModelID, bool, error) {
	if assets != nil {
		model, err := assets.Model(path)
		if err != nil {
			return 0, false, err
		}
		return model, false, nil
	}
	model, err := voplay.LoadModel(path)
	if err != nil {
		return 0, false, err
	}
	return model, true, nil
}

func normalizeTrackDebugOptions(opts TrackDebugOptions) TrackDebugOptions {
	if !opts.Centerline && !opts.Boundaries && !opts.Gates && !opts.Respawns {
		opts.Centerline = true
		opts.Boundaries = true
		opts.Gates = true
		opts.Respawns = true
	}
	if opts.LineThickness <= 0 {
		opts.LineThickness = 0.18
	}
	if opts.HeightOffset == 0 {
		opts.HeightOffset = 0.35
	}
	if opts.CenterColor == (voplay.Color{}) {
		opts.CenterColor = voplay.Color{R: 1, G: 0.9, B: 0.1, A: 1}
	}
	if opts.BoundaryColor == (voplay.Color{}) {
		opts.BoundaryColor = voplay.Color{R: 0.95, G: 0.15, B: 0.1, A: 1}
	}
	if opts.GateColor == (voplay.Color{}) {
		opts.GateColor = voplay.Color{R: 0.1, G: 0.8, B: 1, A: 1}
	}
	if opts.RespawnColor == (voplay.Color{}) {
		opts.RespawnColor = voplay.Color{R: 0.2, G: 1, B: 0.35, A: 1}
	}
	return opts
}

func trackEffectivePointCount(asset *TrackAsset) int {
	if asset == nil {
		return 0
	}
	count := len(asset.Centerline)
	if asset.ClosedLoop && count > 1 {
		first := asset.Centerline[0].Position.Vec3()
		last := asset.Centerline[count - 1].Position.Vec3()
		if first.Distance(last) <= trackContinuityTolerance {
			count--
		}
	}
	return count
}

func trackSurfaceContainsDistance(surface TrackSurface, distance, length float64, closed bool) bool {
	if length <= 0 {
		return false
	}
	start := surface.Start
	end := surface.End
	if start == 0 && end == 0 {
		return true
	}
	if closed {
		distance = trackWrapDistance(distance, length)
		start = trackWrapDistance(start, length)
		end = trackWrapDistance(end, length)
		if start <= end {
			return distance >= start && distance <= end
		}
		return distance >= start || distance <= end
	}
	return distance >= start && distance <= end
}

func trackSurfaceLateralBounds(surface TrackSurface, halfWidth float64) (float64, float64) {
	if surface.Left == 0 && surface.Right == 0 {
		return -halfWidth, halfWidth
	}
	return surface.Left, surface.Right
}

func trackSurfaceIsRoad(surface TrackSurface, centerlineOnRoad bool) bool {
	if surface.Kind == TrackSurfaceRoad {
		return true
	}
	if surface.Kind == TrackSurfaceOffroad {
		return false
	}
	return centerlineOnRoad
}

func (t *Track) segmentIndexAt(distance float64) int {
	if len(t.segmentStarts) == 0 {
		return 0
	}
	idx := len(t.segmentStarts) - 1
	for i := 0; i < len(t.segmentStarts); i++ {
		start := t.segmentStarts[i]
		end := start + t.segmentLengths[i]
		if distance >= start && distance <= end {
			return i
		}
	}
	return idx
}

func (t *Track) normalizeDistance(distance float64) float64 {
	if t == nil {
		return 0
	}
	if t.closed {
		return trackWrapDistance(distance, t.length)
	}
	return trackClamp(distance, 0, t.length)
}

func trackDistanceAbsDelta(a, b, length float64, closed bool) float64 {
	d := math.Abs(a - b)
	if closed && length > 0 {
		wrapped := length - d
		if wrapped < d {
			return wrapped
		}
	}
	return d
}

func trackYawFromForward(forward voplay.Vec3) float64 {
	forward.Y = 0
	if forward.LengthSq() == 0 {
		return 0
	}
	forward = forward.Normalize()
	return math.Atan2(-forward.X, -forward.Z)
}

func trackWrapDistance(d, length float64) float64 {
	if length <= 0 {
		return 0
	}
	d = math.Mod(d, length)
	if d < 0 {
		d += length
	}
	return d
}

func trackClamp(v, lo, hi float64) float64 {
	if v < lo {
		return lo
	}
	if v > hi {
		return hi
	}
	return v
}

func trackLerp(a, b, t float64) float64 {
	return a + (b - a) * t
}

func trackFinite(v float64) bool {
	return !math.IsNaN(v) && !math.IsInf(v, 0)
}

func trackFormatVec3(v voplay.Vec3) string {
	return "(" + strconv.FormatFloat(v.X, 'f', 2, 64) + ", " + strconv.FormatFloat(v.Y, 'f', 2, 64) + ", " + strconv.FormatFloat(v.Z, 'f', 2, 64) + ")"
}

func trackBoundaryPoints(pose TrackPose) (voplay.Vec3, voplay.Vec3) {
	left := pose.Position.Add(pose.Right.Scale(-pose.HalfWidth))
	right := pose.Position.Add(pose.Right.Scale(pose.HalfWidth))
	return left, right
}

func appendFiniteVec3Issues(issues []TrackIssue, path string, v voplay.Vec3) []TrackIssue {
	if !trackFinite(v.X) || !trackFinite(v.Y) || !trackFinite(v.Z) {
		return appendTrackIssue(issues, "track.vec3.finite", TrackIssueError, path, "vector components must be finite")
	}
	return issues
}

func appendFiniteColorIssues(issues []TrackIssue, path string, color MapColor) []TrackIssue {
	if !trackFinite(color.R) || !trackFinite(color.G) || !trackFinite(color.B) || !trackFinite(color.A) {
		return appendTrackIssue(issues, "track.color.finite", TrackIssueError, path, "color components must be finite")
	}
	return issues
}

func appendTrackElementNameIssue(issues []TrackIssue, seen map[string]string, name, path string) []TrackIssue {
	if name == "" {
		return issues
	}
	if prev, ok := seen[name]; ok {
		return appendTrackIssue(issues, "track.element.duplicate", TrackIssueError, path, "duplicate track element name: " + name + " already used at " + prev)
	}
	seen[name] = path
	return issues
}

func trackDistanceInRange(distance, length float64) bool {
	return trackFinite(distance) && distance >= 0 && distance <= length
}

func trackSurfaceKindKnown(kind string) bool {
	return kind == TrackSurfaceRoad || kind == TrackSurfaceOffroad || kind == TrackSurfaceBoost
}

func appendTrackIssue(issues []TrackIssue, code string, severity int, path, message string) []TrackIssue {
	return append(issues, TrackIssue{Code: code, Severity: severity, Path: path, Message: message})
}

func trackHasErrors(issues []TrackIssue) bool {
	for _, issue := range issues {
		if issue.Severity == TrackIssueError {
			return true
		}
	}
	return false
}

func trackIssuesError(prefix string, issues []TrackIssue) error {
	for _, issue := range issues {
		if issue.Severity == TrackIssueError {
			return errors.New(prefix + ": " + issue.Code + ": " + issue.Message)
		}
	}
	return nil
}

package scene3d

import (
	"errors"
	"github.com/vo-lang/voplay"
)

type VehicleAudioClips struct {
	Engine voplay.AudioClipID
	Skid voplay.AudioClipID
	Boost voplay.AudioClipID
	Collision voplay.AudioClipID
	Surface voplay.AudioClipID
}

type VehicleAudioConfig struct {
	EngineMinPitch float64
	EngineMaxPitch float64
	EngineMinVolume float64
	EngineMaxVolume float64
	EngineMaxSpeed float64
	SkidSlipThreshold float64
	SkidMaxSlip float64
	SkidMaxVolume float64
	BoostVolume float64
	SurfaceVolume float64
	RefDistance float64
	MaxDistance float64
}

type VehicleAudioInput struct {
	Speed float64
	RPM float64
	MaxRPM float64
	LongitudinalSlip float64
	LateralSlip float64
	Boost bool
	SurfaceAmount float64
	CollisionImpulse float64
}

type VehicleAudioState struct {
	EngineVolume float64
	EnginePitch float64
	SkidVolume float64
	BoostVolume float64
	SurfaceVolume float64
}

type VehicleAudio struct {
	Entity *Entity
	Clips VehicleAudioClips
	Config VehicleAudioConfig
	engine voplay.AudioSourceID
	skid voplay.AudioSourceID
	boost voplay.AudioSourceID
	surface voplay.AudioSourceID
}

func DefaultVehicleAudioConfig() VehicleAudioConfig {
	return VehicleAudioConfig{
		EngineMinPitch: 0.72,
		EngineMaxPitch: 1.85,
		EngineMinVolume: 0.18,
		EngineMaxVolume: 0.85,
		EngineMaxSpeed: 42.0,
		SkidSlipThreshold: 0.18,
		SkidMaxSlip: 1.2,
		SkidMaxVolume: 0.9,
		BoostVolume: 0.8,
		SurfaceVolume: 0.35,
		RefDistance: 3.0,
		MaxDistance: 80.0,
	}
}

func AttachVehicleAudio(entity *Entity, clips VehicleAudioClips, config VehicleAudioConfig) (*VehicleAudio, error) {
	if entity == nil || entity.scene == nil || !entity.Active {
		return nil, errors.New("scene3d.AttachVehicleAudio: entity must belong to an active scene")
	}
	config = normalizeVehicleAudioConfig(config)
	audio := &VehicleAudio{Entity: entity, Clips: clips, Config: config}
	var err error
	if clips.Engine != 0 {
		audio.engine, err = entity.AttachAudioSource(clips.Engine, config.EngineMinVolume, config.RefDistance, config.MaxDistance)
		if err != nil {
			return nil, err
		}
	}
	if clips.Skid != 0 {
		audio.skid, err = entity.AttachAudioSource(clips.Skid, 0, config.RefDistance, config.MaxDistance)
		if err != nil {
			audio.Destroy()
			return nil, err
		}
	}
	if clips.Boost != 0 {
		audio.boost, err = entity.AttachAudioSource(clips.Boost, 0, config.RefDistance, config.MaxDistance)
		if err != nil {
			audio.Destroy()
			return nil, err
		}
	}
	if clips.Surface != 0 {
		audio.surface, err = entity.AttachAudioSource(clips.Surface, 0, config.RefDistance, config.MaxDistance)
		if err != nil {
			audio.Destroy()
			return nil, err
		}
	}
	return audio, nil
}

func (a *VehicleAudio) Update(input VehicleAudioInput) VehicleAudioState {
	if a == nil {
		return VehicleAudioState{}
	}
	cfg := normalizeVehicleAudioConfig(a.Config)
	state := computeVehicleAudioState(input, cfg)
	if a.engine != 0 {
		a.engine.SetParams(state.EngineVolume, state.EnginePitch)
	}
	if a.skid != 0 {
		a.skid.SetParams(state.SkidVolume, 1.0)
	}
	if a.boost != 0 {
		a.boost.SetParams(state.BoostVolume, 1.0)
	}
	if a.surface != 0 {
		a.surface.SetParams(state.SurfaceVolume, 1.0)
	}
	if input.CollisionImpulse > 0 && a.Clips.Collision != 0 && a.Entity != nil && a.Entity.Active {
		volume := vehicleAudioClamp(input.CollisionImpulse, 0, 1)
		a.Entity.PlaySound3D(a.Clips.Collision, volume)
	}
	return state
}

func (a *VehicleAudio) Destroy() {
	if a == nil || a.Entity == nil || a.Entity.scene == nil || !a.Entity.Active {
		return
	}
	if a.engine != 0 {
		a.Entity.RemoveAudioSource(a.engine)
		a.engine = 0
	}
	if a.skid != 0 {
		a.Entity.RemoveAudioSource(a.skid)
		a.skid = 0
	}
	if a.boost != 0 {
		a.Entity.RemoveAudioSource(a.boost)
		a.boost = 0
	}
	if a.surface != 0 {
		a.Entity.RemoveAudioSource(a.surface)
		a.surface = 0
	}
}

func VehicleAudioInputFromVehicle(vehicle *Vehicle) VehicleAudioInput {
	if vehicle == nil {
		return VehicleAudioInput{}
	}
	slip := 0.0
	for _, wheel := range vehicle.Wheels {
		s := vehicleAudioAbs(wheel.LateralSlip)
		if s > slip {
			slip = s
		}
	}
	return VehicleAudioInput{
		Speed: vehicleAudioAbs(vehicle.Speed),
		LongitudinalSlip: 0,
		LateralSlip: slip,
		Boost: false,
	}
}

func computeVehicleAudioState(input VehicleAudioInput, cfg VehicleAudioConfig) VehicleAudioState {
	speedT := 0.0
	if cfg.EngineMaxSpeed > 0 {
		speedT = vehicleAudioClamp(vehicleAudioAbs(input.Speed)/cfg.EngineMaxSpeed, 0, 1)
	}
	rpmT := 0.0
	if input.MaxRPM > 0 {
		rpmT = vehicleAudioClamp(input.RPM/input.MaxRPM, 0, 1)
	}
	t := speedT
	if rpmT > 0 {
		t = rpmT
	}
	slip := vehicleAudioAbs(input.LateralSlip)
	if vehicleAudioAbs(input.LongitudinalSlip) > slip {
		slip = vehicleAudioAbs(input.LongitudinalSlip)
	}
	skidT := vehicleAudioClamp((slip-cfg.SkidSlipThreshold)/(cfg.SkidMaxSlip-cfg.SkidSlipThreshold), 0, 1)
	boostVolume := 0.0
	if input.Boost {
		boostVolume = cfg.BoostVolume
	}
	return VehicleAudioState{
		EngineVolume: vehicleAudioLerp(cfg.EngineMinVolume, cfg.EngineMaxVolume, t),
		EnginePitch: vehicleAudioLerp(cfg.EngineMinPitch, cfg.EngineMaxPitch, t),
		SkidVolume: skidT * cfg.SkidMaxVolume,
		BoostVolume: boostVolume,
		SurfaceVolume: vehicleAudioClamp(input.SurfaceAmount, 0, 1) * cfg.SurfaceVolume,
	}
}

func normalizeVehicleAudioConfig(config VehicleAudioConfig) VehicleAudioConfig {
	defaults := DefaultVehicleAudioConfig()
	if config.EngineMinPitch <= 0 {
		config.EngineMinPitch = defaults.EngineMinPitch
	}
	if config.EngineMaxPitch <= config.EngineMinPitch {
		config.EngineMaxPitch = defaults.EngineMaxPitch
	}
	if config.EngineMaxVolume <= 0 {
		config.EngineMaxVolume = defaults.EngineMaxVolume
	}
	if config.EngineMaxSpeed <= 0 {
		config.EngineMaxSpeed = defaults.EngineMaxSpeed
	}
	if config.SkidSlipThreshold <= 0 {
		config.SkidSlipThreshold = defaults.SkidSlipThreshold
	}
	if config.SkidMaxSlip <= config.SkidSlipThreshold {
		config.SkidMaxSlip = defaults.SkidMaxSlip
	}
	if config.SkidMaxVolume <= 0 {
		config.SkidMaxVolume = defaults.SkidMaxVolume
	}
	if config.BoostVolume <= 0 {
		config.BoostVolume = defaults.BoostVolume
	}
	if config.SurfaceVolume <= 0 {
		config.SurfaceVolume = defaults.SurfaceVolume
	}
	if config.RefDistance <= 0 {
		config.RefDistance = defaults.RefDistance
	}
	if config.MaxDistance <= config.RefDistance {
		config.MaxDistance = defaults.MaxDistance
	}
	return config
}

func vehicleAudioLerp(a, b, t float64) float64 {
	return a + (b-a)*vehicleAudioClamp(t, 0, 1)
}

func vehicleAudioClamp(v, lo, hi float64) float64 {
	if v < lo {
		return lo
	}
	if v > hi {
		return hi
	}
	return v
}

func vehicleAudioAbs(v float64) float64 {
	if v < 0 {
		return -v
	}
	return v
}

package scene3d

import (
	"errors"
	"github.com/vo-lang/voplay"
)

type VehicleDebugOptions struct {
	WheelContacts bool
	SuspensionRays bool
	MarkerSize float64
	LineThickness float64
	Model voplay.ModelID
	ContactColor voplay.Color
	RayColor voplay.Color
}

type VehicleDebugOverlay struct {
	Vehicle *Vehicle
	Entities []*Entity
	model voplay.ModelID
	ownedModel bool
	opts VehicleDebugOptions
}

type VehicleWheelDebugSnapshot struct {
	Index int
	InContact bool
	ContactPoint voplay.Vec3
	ContactNormal voplay.Vec3
	SuspensionLength float64
	SuspensionCompression float64
	Steering float64
	NormalLoad float64
	LongitudinalSlip float64
	LateralSlip float64
	SurfaceID string
}

type VehicleDebugSnapshot struct {
	Speed float64
	Grounded bool
	Surface TrackSurfaceHit
	Wheels []VehicleWheelDebugSnapshot
}

type RacingDebugOptions struct {
	Track TrackDebugOptions
	Vehicle VehicleDebugOptions
	SurfaceMarker bool
	SurfaceMarkerSize float64
	SurfaceColor voplay.Color
	Model voplay.ModelID
}

type RacingDebugOverlay struct {
	Track *Track
	Vehicle *Vehicle
	TrackOverlay *TrackDebugOverlay
	VehicleOverlay *VehicleDebugOverlay
	SurfaceEntity *Entity
	model voplay.ModelID
	ownedModel bool
	opts RacingDebugOptions
}

func BuildVehicleDebugSnapshot(vehicle *Vehicle, track *Track) VehicleDebugSnapshot {
	if vehicle == nil {
		return VehicleDebugSnapshot{}
	}
	if track == nil {
		track = vehicle.Track
	}
	snapshot := VehicleDebugSnapshot{Speed: vehicle.Speed, Grounded: vehicle.Grounded, Wheels: []VehicleWheelDebugSnapshot{}}
	if track != nil && vehicle.Body != nil {
		snapshot.Surface = track.SurfaceAt(vehicle.Body.Position())
	}
	for i := 0; i < vehicle.WheelCount(); i++ {
		state, ok := vehicle.WheelState(i)
		if !ok {
			continue
		}
		snapshot.Wheels = append(snapshot.Wheels, VehicleWheelDebugSnapshot{Index: i, InContact: state.InContact, ContactPoint: state.ContactPoint, ContactNormal: state.ContactNormal, SuspensionLength: state.SuspensionLength, SuspensionCompression: state.SuspensionCompression, Steering: state.Steering, NormalLoad: state.NormalLoad, LongitudinalSlip: state.LongitudinalSlip, LateralSlip: state.LateralSlip, SurfaceID: state.SurfaceID})
	}
	return snapshot
}

func SpawnRacingDebugOverlay(scene *Scene, track *Track, vehicle *Vehicle, opts RacingDebugOptions) (*RacingDebugOverlay, error) {
	if scene == nil {
		return nil, errors.New("scene3d.SpawnRacingDebugOverlay: scene is nil")
	}
	if track == nil {
		return nil, errors.New("scene3d.SpawnRacingDebugOverlay: track is nil")
	}
	if vehicle == nil {
		return nil, errors.New("scene3d.SpawnRacingDebugOverlay: vehicle is nil")
	}
	opts = normalizeRacingDebugOptions(opts)
	if opts.Model != 0 {
		if opts.Track.Model == 0 {
			opts.Track.Model = opts.Model
		}
		if opts.Vehicle.Model == 0 {
			opts.Vehicle.Model = opts.Model
		}
	}
	overlay := &RacingDebugOverlay{Track: track, Vehicle: vehicle, opts: opts}
	success := false
	errdefer func() {
		if success {
			return
		}
		overlay.Destroy(scene)
	}()
	trackOverlay, err := SpawnTrackDebugOverlay(scene, track, opts.Track)
	if err != nil {
		return nil, err
	}
	overlay.TrackOverlay = trackOverlay
	vehicleOverlay, err := SpawnVehicleDebugOverlay(scene, vehicle, opts.Vehicle)
	if err != nil {
		return nil, err
	}
	overlay.VehicleOverlay = vehicleOverlay
	if opts.SurfaceMarker {
		model := opts.Model
		if model == 0 {
			model = CubeMesh()
			overlay.ownedModel = true
		}
		overlay.model = model
		overlay.SurfaceEntity = scene.Spawn(EntityDesc{Model: model, Scale: voplay.Vec3{X: opts.SurfaceMarkerSize, Y: opts.SurfaceMarkerSize, Z: opts.SurfaceMarkerSize}, Tint: opts.SurfaceColor, TintSet: true, Tag: "racing_debug_surface", PickMode: PickDisabled})
	}
	success = true
	overlay.Update(scene)
	return overlay, nil
}

func (o *RacingDebugOverlay) Update(scene *Scene) VehicleDebugSnapshot {
	if o == nil {
		return VehicleDebugSnapshot{}
	}
	if o.VehicleOverlay != nil {
		o.VehicleOverlay.Update(scene)
	}
	snapshot := BuildVehicleDebugSnapshot(o.Vehicle, o.Track)
	if o.SurfaceEntity != nil {
		o.SurfaceEntity.Visible = o.Track != nil && o.Vehicle != nil && o.Vehicle.Body != nil
		if o.SurfaceEntity.Visible {
			pose := o.Track.PoseAt(snapshot.Surface.Distance)
			o.SurfaceEntity.SetPosition(pose.Position.Add(voplay.Vec3{Y: o.opts.Track.HeightOffset + o.opts.SurfaceMarkerSize}))
			o.SurfaceEntity.SetRotation(voplay.QuatIdentity())
			o.SurfaceEntity.SetScale(voplay.Vec3{X: o.opts.SurfaceMarkerSize, Y: o.opts.SurfaceMarkerSize, Z: o.opts.SurfaceMarkerSize})
		}
	}
	return snapshot
}

func (o *RacingDebugOverlay) Destroy(scene *Scene) {
	if o == nil {
		return
	}
	if o.TrackOverlay != nil {
		o.TrackOverlay.Destroy(scene)
		o.TrackOverlay = nil
	}
	if o.VehicleOverlay != nil {
		o.VehicleOverlay.Destroy(scene)
		o.VehicleOverlay = nil
	}
	if o.SurfaceEntity != nil && scene != nil && o.SurfaceEntity.scene == scene && o.SurfaceEntity.Active {
		scene.Destroy(o.SurfaceEntity)
	}
	o.SurfaceEntity = nil
	if o.ownedModel && o.model != 0 {
		o.model.Free()
		o.model = 0
		o.ownedModel = false
	}
}

func SpawnVehicleDebugOverlay(scene *Scene, vehicle *Vehicle, opts VehicleDebugOptions) (*VehicleDebugOverlay, error) {
	if scene == nil {
		return nil, errors.New("scene3d.SpawnVehicleDebugOverlay: scene is nil")
	}
	if vehicle == nil {
		return nil, errors.New("scene3d.SpawnVehicleDebugOverlay: vehicle is nil")
	}
	opts = normalizeVehicleDebugOptions(opts)
	model := opts.Model
	owned := false
	if model == 0 {
		model = CubeMesh()
		owned = true
	}
	overlay := &VehicleDebugOverlay{Vehicle: vehicle, Entities: []*Entity{}, model: model, ownedModel: owned, opts: opts}
	success := false
	errdefer func() {
		if success {
			return
		}
		overlay.Destroy(scene)
	}()
	for i := 0; i < vehicle.WheelCount(); i++ {
		if opts.WheelContacts {
			e := scene.Spawn(EntityDesc{Model: model, Scale: voplay.Vec3{X: opts.MarkerSize, Y: opts.MarkerSize, Z: opts.MarkerSize}, Tint: opts.ContactColor, TintSet: true, Tag: "vehicle_debug_contact", PickMode: PickDisabled})
			overlay.Entities = append(overlay.Entities, e)
		}
		if opts.SuspensionRays {
			e := scene.Spawn(EntityDesc{Model: model, Scale: voplay.Vec3{X: opts.LineThickness, Y: opts.LineThickness, Z: opts.LineThickness}, Tint: opts.RayColor, TintSet: true, Tag: "vehicle_debug_suspension", PickMode: PickDisabled})
			overlay.Entities = append(overlay.Entities, e)
		}
	}
	success = true
	overlay.Update(scene)
	return overlay, nil
}

func (o *VehicleDebugOverlay) Update(scene *Scene) {
	if o == nil || scene == nil || o.Vehicle == nil {
		return
	}
	idx := 0
	for i := 0; i < o.Vehicle.WheelCount(); i++ {
		state, ok := o.Vehicle.WheelState(i)
		if !ok {
			state = VehicleWheelState{}
		}
		if o.opts.WheelContacts {
			e := o.entityAt(idx)
			idx++
			if e != nil {
				e.Visible = ok && state.InContact
				e.SetPosition(state.ContactPoint)
				e.SetRotation(voplay.QuatIdentity())
				e.SetScale(voplay.Vec3{X: o.opts.MarkerSize, Y: o.opts.MarkerSize, Z: o.opts.MarkerSize})
			}
		}
		if o.opts.SuspensionRays {
			e := o.entityAt(idx)
			idx++
			if e != nil {
				o.updateSuspensionRay(e, state, ok && state.InContact)
			}
		}
	}
}

func (o *VehicleDebugOverlay) Destroy(scene *Scene) {
	if o == nil {
		return
	}
	for _, e := range o.Entities {
		if e != nil && scene != nil && e.scene == scene && e.Active {
			scene.Destroy(e)
		}
	}
	o.Entities = nil
	if o.ownedModel && o.model != 0 {
		o.model.Free()
		o.model = 0
		o.ownedModel = false
	}
}

func (o *VehicleDebugOverlay) entityAt(index int) *Entity {
	if o == nil || index < 0 || index >= len(o.Entities) {
		return nil
	}
	return o.Entities[index]
}

func (o *VehicleDebugOverlay) updateSuspensionRay(e *Entity, state VehicleWheelState, visible bool) {
	e.Visible = visible
	if !visible {
		return
	}
	start := state.Center
	end := state.ContactPoint
	dir := end.Sub(start)
	length := dir.Length()
	if length <= 0 {
		e.Visible = false
		return
	}
	mid := start.Lerp(end, 0.5)
	yaw := trackYawFromForward(dir.Normalize())
	e.SetPosition(mid)
	e.SetRotation(voplay.QuatFromAxisAngle(voplay.Vec3{Y: 1}, yaw))
	e.SetScale(voplay.Vec3{X: o.opts.LineThickness, Y: o.opts.LineThickness, Z: length})
}

func normalizeVehicleDebugOptions(opts VehicleDebugOptions) VehicleDebugOptions {
	if !opts.WheelContacts && !opts.SuspensionRays {
		opts.WheelContacts = true
		opts.SuspensionRays = true
	}
	if opts.MarkerSize <= 0 {
		opts.MarkerSize = 0.22
	}
	if opts.LineThickness <= 0 {
		opts.LineThickness = 0.08
	}
	if opts.ContactColor == (voplay.Color{}) {
		opts.ContactColor = voplay.Color{R: 0.1, G: 1, B: 0.25, A: 1}
	}
	if opts.RayColor == (voplay.Color{}) {
		opts.RayColor = voplay.Color{R: 1, G: 0.85, B: 0.1, A: 1}
	}
	return opts
}

func normalizeRacingDebugOptions(opts RacingDebugOptions) RacingDebugOptions {
	if opts.SurfaceMarkerSize <= 0 {
		opts.SurfaceMarkerSize = 0.42
	}
	if opts.SurfaceColor == (voplay.Color{}) {
		opts.SurfaceColor = voplay.Color{R: 1, G: 0.25, B: 0.9, A: 1}
	}
	if !opts.SurfaceMarker {
		opts.SurfaceMarker = true
	}
	return opts
}

package scene3d

import (
	"math"
	"github.com/vo-lang/voplay"
)

// VehicleRecoveryConfig controls generic vehicle recovery and respawn detection.
type VehicleRecoveryConfig struct {
	FallY             float64
	UpsideDownSeconds float64
	StuckSeconds      float64
	StuckSpeed        float64
	StuckThrottle     float64
}

type VehicleRecoveryInput struct {
	Throttle float64
	Reset    bool
}

type VehicleRecoveryState struct {
	Stuck          bool
	UpsideDown     bool
	ShouldRespawn bool
}

// VehicleRecovery tracks fall, upside-down, and stuck conditions for any track-bound vehicle.
type VehicleRecovery struct {
	Vehicle *Vehicle
	Track   *Track
	Config  VehicleRecoveryConfig
	stuckTimer float64
	upsideDownTimer float64
	state VehicleRecoveryState
}

func DefaultVehicleRecoveryConfig() VehicleRecoveryConfig {
	return VehicleRecoveryConfig{
		FallY:             -25,
		UpsideDownSeconds: 1.2,
		StuckSeconds:      2.0,
		StuckSpeed:        0.8,
		StuckThrottle:     0.55,
	}
}

func NewVehicleRecovery(vehicle *Vehicle, track *Track, config VehicleRecoveryConfig) *VehicleRecovery {
	if vehicle == nil {
		panic("scene3d.NewVehicleRecovery: vehicle must not be nil")
	}
	return &VehicleRecovery{Vehicle: vehicle, Track: track, Config: normalizeVehicleRecoveryConfig(config)}
}

func (r *VehicleRecovery) BindTrack(track *Track) {
	if r == nil {
		return
	}
	r.Track = track
}

func (r *VehicleRecovery) Update(input VehicleRecoveryInput, dt float64) VehicleRecoveryState {
	if r == nil || r.Vehicle == nil || r.Vehicle.Body == nil || dt <= 0 {
		return VehicleRecoveryState{}
	}
	r.Config = normalizeVehicleRecoveryConfig(r.Config)
	r.state.ShouldRespawn = input.Reset
	r.state.UpsideDown = false
	r.state.Stuck = false
	pos := r.Vehicle.Body.Position()
	if pos.Y < r.Config.FallY {
		r.state.ShouldRespawn = true
	}
	up := r.Vehicle.Rotation().RotateVec3(voplay.Vec3{Y: 1})
	if up.Dot(voplay.Vec3{Y: 1}) < 0.2 {
		r.upsideDownTimer += dt
		r.state.UpsideDown = true
	} else {
		r.upsideDownTimer = 0
	}
	if r.upsideDownTimer >= r.Config.UpsideDownSeconds {
		r.state.ShouldRespawn = true
	}
	if math.Abs(r.Vehicle.Speed) <= r.Config.StuckSpeed && input.Throttle >= r.Config.StuckThrottle {
		r.stuckTimer += dt
	} else {
		r.stuckTimer = 0
	}
	if r.stuckTimer >= r.Config.StuckSeconds {
		r.state.Stuck = true
		r.state.ShouldRespawn = true
	}
	return r.state
}

func (r *VehicleRecovery) State() VehicleRecoveryState {
	if r == nil {
		return VehicleRecoveryState{}
	}
	return r.state
}

func (r *VehicleRecovery) Respawn(pose TrackPose) {
	if r == nil || r.Vehicle == nil {
		return
	}
	r.Vehicle.SetPose(pose.Position, pose.Yaw)
	r.Reset()
}

func (r *VehicleRecovery) RespawnNear(pos voplay.Vec3) {
	if r == nil || r.Track == nil {
		return
	}
	r.Respawn(r.Track.RespawnPoseNear(pos))
}

func (r *VehicleRecovery) Reset() {
	if r == nil {
		return
	}
	r.stuckTimer = 0
	r.upsideDownTimer = 0
	r.state = VehicleRecoveryState{}
}

func normalizeVehicleRecoveryConfig(config VehicleRecoveryConfig) VehicleRecoveryConfig {
	defaults := DefaultVehicleRecoveryConfig()
	if config.FallY == 0 {
		config.FallY = defaults.FallY
	}
	if config.UpsideDownSeconds <= 0 {
		config.UpsideDownSeconds = defaults.UpsideDownSeconds
	}
	if config.StuckSeconds <= 0 {
		config.StuckSeconds = defaults.StuckSeconds
	}
	if config.StuckSpeed <= 0 {
		config.StuckSpeed = defaults.StuckSpeed
	}
	if config.StuckThrottle <= 0 {
		config.StuckThrottle = defaults.StuckThrottle
	}
	return config
}

package scene3d

import (
	"math"
	"github.com/vo-lang/voplay"
	"github.com/vo-lang/voplay/codec"
)

const (
	raycastVehicleWheelDescBytes = 18 * 8
	raycastVehicleWheelStateBytes = 1 + 12 * 8
)

type VehicleWheelConfig struct {
	Connection voplay.Vec3
	Direction voplay.Vec3
	Axle voplay.Vec3
	SuspensionRestLength float64
	Radius float64
	SuspensionStiffness float64
	SuspensionCompression float64
	SuspensionDamping float64
	MaxSuspensionTravel float64
	SideFrictionStiffness float64
	FrictionSlip float64
	MaxSuspensionForce float64
	Steer bool
	Drive bool
	Brake bool
}

type VehicleConfig struct {
	Wheels []VehicleWheelConfig
	MaxForwardSpeed float64
	MaxReverseSpeed float64
	EngineForce float64
	ReverseEngineForce float64
	BrakeForce float64
	CoastBrake float64
	BoostEngineForce float64
	MaxSteerAngle float64
	SteerRate float64
	DriftSteerScale float64
	DriftMinSpeed float64
}

type VehicleInput struct {
	Throttle float64
	Steer float64
	Drift bool
	Boost bool
}

type VehicleWheelState struct {
	Center voplay.Vec3
	ContactPoint voplay.Vec3
	ContactNormal voplay.Vec3
	SuspensionLength float64
	SuspensionCompression float64
	Steering float64
	Rotation float64
	NormalLoad float64
	LongitudinalSlip float64
	LateralSlip float64
	SurfaceID string
	InContact bool
}

type Vehicle struct {
	Body *Entity
	Config VehicleConfig
	Yaw float64
	Speed float64
	Grounded bool
	GroundNormal voplay.Vec3
	GroundPoint voplay.Vec3
	Track *Track
	Drifting bool
	SteerAngle float64
	WheelSpin float64
	Wheels []VehicleWheelState
	scene *Scene
	vehicleID int
}

func DefaultKartVehicleConfig() VehicleConfig {
	wheel := VehicleWheelConfig{Direction: voplay.Vec3{Y: -1}, Axle: voplay.Vec3{X: 1}, SuspensionRestLength: 0.56, Radius: 0.46, SuspensionStiffness: 28.0, SuspensionCompression: 4.4, SuspensionDamping: 5.8, MaxSuspensionTravel: 0.34, SideFrictionStiffness: 1.45, FrictionSlip: 4.2, MaxSuspensionForce: 18000.0, Brake: true}
	frontLeft := wheel
	frontLeft.Connection = voplay.Vec3{X: -0.84, Y: -0.34, Z: -0.82}
	frontLeft.Steer = true
	frontRight := wheel
	frontRight.Connection = voplay.Vec3{X: 0.84, Y: -0.34, Z: -0.82}
	frontRight.Steer = true
	rearLeft := wheel
	rearLeft.Connection = voplay.Vec3{X: -0.84, Y: -0.34, Z: 0.86}
	rearLeft.Drive = true
	rearRight := wheel
	rearRight.Connection = voplay.Vec3{X: 0.84, Y: -0.34, Z: 0.86}
	rearRight.Drive = true
	return VehicleConfig{Wheels: []VehicleWheelConfig{frontLeft, frontRight, rearLeft, rearRight}, MaxForwardSpeed: 38.0, MaxReverseSpeed: 10.0, EngineForce: 9200.0, ReverseEngineForce: 3600.0, BrakeForce: 150.0, CoastBrake: 6.0, BoostEngineForce: 4200.0, MaxSteerAngle: 0.54, SteerRate: 9.5, DriftSteerScale: 1.28, DriftMinSpeed: 7.0}
}

func NewVehicle(body *Entity, config VehicleConfig) *Vehicle {
	if body == nil || !body.Active || body.Physics == nil || body.Physics.bodyID == 0 || body.scene == nil {
		panic("scene3d.NewVehicle: body must be an active physics entity")
	}
	scene := body.scene
	scene.ensurePhysics()
	config = normalizeVehicleConfig(config)
	vehicleID := scene.nextVehicleID
	scene.nextVehicleID++
	v := &Vehicle{Body: body, Config: config, Yaw: vehicleYawFromRotation(body.Rotation()), GroundNormal: voplay.Vec3{Y: 1}, scene: scene, vehicleID: vehicleID}
	physBackend.CreateRaycastVehicle(scene.worldID, vehicleID, body.Physics.bodyID)
	for _, wheel := range config.Wheels {
		physBackend.AddRaycastVehicleWheel(scene.worldID, vehicleID, serializeVehicleWheelConfig(wheel))
	}
	scene.registerVehicle(v)
	return v
}

func (v *Vehicle) Destroy() {
	if v == nil || v.scene == nil || v.vehicleID == 0 {
		return
	}
	if v.scene.worldID != 0 {
		physBackend.DestroyRaycastVehicle(v.scene.worldID, v.vehicleID)
	}
	v.scene.removeVehicle(v)
	v.vehicleID = 0
	v.scene = nil
	v.Body = nil
	v.Wheels = nil
}

func (v *Vehicle) Update(input VehicleInput, dt float64) {
	if v == nil || v.Body == nil || v.Body.Physics == nil || v.vehicleID == 0 || dt <= 0 {
		return
	}
	scene := v.scene
	if scene == nil || scene.worldID == 0 {
		return
	}
	v.syncState()
	input.Throttle = vehicleClamp(input.Throttle, -1, 1)
	input.Steer = vehicleClamp(input.Steer, -1, 1)
	v.Drifting = input.Drift && math.Abs(v.Speed) >= v.Config.DriftMinSpeed && v.Grounded
	steerTarget := input.Steer * v.Config.MaxSteerAngle
	if v.Drifting {
		steerTarget *= v.Config.DriftSteerScale
	}
	v.SteerAngle = vehicleMoveTowards(v.SteerAngle, steerTarget, v.Config.SteerRate * dt)
	engineForce := 0.0
	brake := v.Config.CoastBrake
	if input.Throttle > 0 {
		if v.Speed < v.Config.MaxForwardSpeed {
			engineForce = input.Throttle * v.Config.EngineForce
			if input.Boost {
				engineForce += v.Config.BoostEngineForce
			}
		}
		brake = 0
	} else if input.Throttle < 0 {
		if v.Speed > 1.5 {
			brake = -input.Throttle * v.Config.BrakeForce
		} else if math.Abs(v.Speed) < v.Config.MaxReverseSpeed {
			engineForce = input.Throttle * v.Config.ReverseEngineForce
			brake = 0
		}
	}
	driveWheelCount := vehicleDriveWheelCount(v.Config.Wheels)
	for i, wheel := range v.Config.Wheels {
		steering := 0.0
		force := 0.0
		wheelBrake := 0.0
		if wheel.Steer {
			steering = -v.SteerAngle
		}
		if wheel.Drive {
			force = engineForce / driveWheelCount
		}
		if wheel.Brake {
			wheelBrake = brake
		}
		physBackend.SetRaycastVehicleWheelControl(scene.worldID, v.vehicleID, i, steering, force, wheelBrake)
	}
}

func (v *Vehicle) SetPose(position voplay.Vec3, yaw float64) {
	if v == nil || v.Body == nil {
		return
	}
	v.Yaw = yaw
	v.Speed = 0
	v.SteerAngle = 0
	v.WheelSpin = 0
	v.Drifting = false
	v.Body.SetPosition(position)
	v.Body.SetRotation(voplay.QuatFromAxisAngle(voplay.Vec3{Y: 1}, yaw))
	if v.Body.Physics != nil {
		v.Body.SetVelocity(voplay.Vec3{})
		v.Body.SetAngularVelocity(voplay.Vec3{})
		v.Body.Physics.velocity = voplay.Vec3{}
		v.Body.Physics.angularVelocity = voplay.Vec3{}
	}
	if v.scene != nil && v.scene.worldID != 0 && v.vehicleID != 0 {
		for i := 0; i < len(v.Config.Wheels); i++ {
			physBackend.SetRaycastVehicleWheelControl(v.scene.worldID, v.vehicleID, i, 0, 0, v.Config.BrakeForce)
		}
	}
}

func (v *Vehicle) Rotation() voplay.Quat {
	if v != nil && v.Body != nil {
		return v.Body.Rotation()
	}
	return voplay.QuatFromAxisAngle(voplay.Vec3{Y: 1}, v.Yaw)
}

func (v *Vehicle) Forward() voplay.Vec3 {
	if v == nil {
		return voplay.Vec3{Z: -1}
	}
	forward := v.Rotation().RotateVec3(voplay.Vec3{Z: -1})
	forward.Y = 0
	if forward.LengthSq() == 0 {
		return voplay.Vec3{Z: -1}
	}
	return forward.Normalize()
}

func (v *Vehicle) BindTrack(track *Track) {
	if v == nil {
		return
	}
	v.Track = track
}

func (v *Vehicle) VisualRotation() voplay.Quat {
	return v.Rotation()
}

func (v *Vehicle) WheelState(index int) (VehicleWheelState, bool) {
	if v == nil || index < 0 || index >= len(v.Wheels) {
		return VehicleWheelState{}, false
	}
	return v.Wheels[index], true
}

func (v *Vehicle) WheelCount() int {
	if v == nil {
		return 0
	}
	if len(v.Wheels) > 0 {
		return len(v.Wheels)
	}
	return len(v.Config.Wheels)
}

func (v *Vehicle) syncState() {
	if v == nil || v.scene == nil || v.scene.worldID == 0 || v.vehicleID == 0 {
		return
	}
	data := physBackend.RaycastVehicleState(v.scene.worldID, v.vehicleID)
	if len(data) < 12 {
		return
	}
	r := codec.NewByteReader(data)
	v.Speed = vehicleFiniteOr(r.ReadF64(), 0)
	count := r.ReadU32()
	maxCount := r.Remaining() / raycastVehicleWheelStateBytes
	if count > maxCount {
		count = maxCount
	}
	if len(v.Config.Wheels) > 0 && count > len(v.Config.Wheels) {
		count = len(v.Config.Wheels)
	}
	if len(v.Wheels) != count {
		v.Wheels = make([]VehicleWheelState, count)
	}
	v.Grounded = false
	v.GroundNormal = voplay.Vec3{Y: 1}
	v.GroundPoint = voplay.Vec3{}
	normalSum := voplay.Vec3{}
	pointSum := voplay.Vec3{}
	contactCount := 0
	for i := 0; i < count; i++ {
		if r.Remaining() < raycastVehicleWheelStateBytes {
			break
		}
		state := VehicleWheelState{}
		state.InContact = r.ReadBool()
		state.Center = voplay.Vec3{X: r.ReadF64(), Y: r.ReadF64(), Z: r.ReadF64()}
		state.ContactPoint = voplay.Vec3{X: r.ReadF64(), Y: r.ReadF64(), Z: r.ReadF64()}
		state.ContactNormal = voplay.Vec3{X: r.ReadF64(), Y: r.ReadF64(), Z: r.ReadF64()}
		state.SuspensionLength = vehicleFiniteOr(r.ReadF64(), 0)
		state.Steering = vehicleFiniteOr(-r.ReadF64(), 0)
		state.Rotation = vehicleFiniteOr(r.ReadF64(), 0)
		if i < len(v.Config.Wheels) {
			cfg := v.Config.Wheels[i]
			if cfg.SuspensionRestLength > 0 {
				state.SuspensionCompression = vehicleClamp((cfg.SuspensionRestLength - state.SuspensionLength) / cfg.SuspensionRestLength, 0, 1)
			}
			state.NormalLoad = state.SuspensionCompression * cfg.MaxSuspensionForce
			if cfg.Radius > 0 {
				wheelLinearSpeed := state.Rotation * cfg.Radius
				longitudinalVelocity, lateralVelocity := v.localWheelSlipVelocity()
				state.LongitudinalSlip = math.Abs(longitudinalVelocity - wheelLinearSpeed)
				state.LateralSlip = math.Abs(lateralVelocity)
			}
		}
		state.Center = vehicleCleanVec3(state.Center)
		state.ContactPoint = vehicleCleanVec3(state.ContactPoint)
		state.ContactNormal = vehicleCleanNormal(state.ContactNormal)
		state.SuspensionCompression = vehicleFiniteOr(state.SuspensionCompression, 0)
		state.NormalLoad = vehicleFiniteOr(state.NormalLoad, 0)
		state.LongitudinalSlip = vehicleFiniteOr(state.LongitudinalSlip, 0)
		state.LateralSlip = vehicleFiniteOr(state.LateralSlip, 0)
		if state.InContact && v.Track != nil {
			surface := v.Track.SurfaceAt(state.ContactPoint)
			state.SurfaceID = surface.Name
		}
		v.Wheels[i] = state
		if state.InContact {
			normalSum = normalSum.Add(state.ContactNormal)
			pointSum = pointSum.Add(state.ContactPoint)
			contactCount++
		}
	}
	if contactCount > 0 {
		v.Grounded = true
		v.GroundNormal = normalSum.Scale(1.0 / float64(contactCount)).Normalize()
		v.GroundPoint = pointSum.Scale(1.0 / float64(contactCount))
	}
	if len(v.Wheels) > 0 {
		totalRotation := 0.0
		for _, wheel := range v.Wheels {
			totalRotation += wheel.Rotation
		}
		v.WheelSpin = totalRotation / float64(len(v.Wheels))
	} else {
		v.WheelSpin = 0
	}
	if v.Body != nil {
		v.Yaw = vehicleYawFromRotation(v.Body.Rotation())
	}
}

func (v *Vehicle) localWheelSlipVelocity() (float64, float64) {
	longitudinal := v.Speed
	lateral := 0.0
	if v == nil || v.Body == nil || v.Body.Physics == nil {
		return longitudinal, lateral
	}
	vel := vehicleCleanVec3(v.Body.Physics.velocity)
	if vel.LengthSq() == 0 {
		return longitudinal, lateral
	}
	forward := v.Forward()
	right := v.Rotation().RotateVec3(voplay.Vec3{X: 1})
	right.Y = 0
	if right.LengthSq() == 0 {
		right = voplay.Vec3{X: 1}
	} else {
		right = right.Normalize()
	}
	longitudinal = math.Abs(vel.Dot(forward))
	lateral = vel.Dot(right)
	return longitudinal, lateral
}

func (s *Scene) registerVehicle(v *Vehicle) {
	if v == nil {
		return
	}
	s.vehicles = append(s.vehicles, v)
}

func (s *Scene) removeVehicle(target *Vehicle) {
	for i, vehicle := range s.vehicles {
		if vehicle != target {
			continue
		}
		last := len(s.vehicles) - 1
		s.vehicles[i] = s.vehicles[last]
		s.vehicles[last] = nil
		s.vehicles = s.vehicles[:last]
		return
	}
}

func (s *Scene) destroyVehiclesForBody(body *Entity) {
	for {
		var target *Vehicle
		for _, vehicle := range s.vehicles {
			if vehicle != nil && vehicle.Body == body {
				target = vehicle
				break
			}
		}
		if target == nil {
			return
		}
		target.Destroy()
	}
}

func (s *Scene) syncVehicles() {
	for _, vehicle := range s.vehicles {
		if vehicle == nil || vehicle.Body == nil || !vehicle.Body.Active {
			continue
		}
		vehicle.syncState()
	}
}

func serializeVehicleWheelConfig(wheel VehicleWheelConfig) []byte {
	w := codec.NewByteWriter(raycastVehicleWheelDescBytes)
	w.WriteF64(wheel.Connection.X)
	w.WriteF64(wheel.Connection.Y)
	w.WriteF64(wheel.Connection.Z)
	w.WriteF64(wheel.Direction.X)
	w.WriteF64(wheel.Direction.Y)
	w.WriteF64(wheel.Direction.Z)
	w.WriteF64(wheel.Axle.X)
	w.WriteF64(wheel.Axle.Y)
	w.WriteF64(wheel.Axle.Z)
	w.WriteF64(wheel.SuspensionRestLength)
	w.WriteF64(wheel.Radius)
	w.WriteF64(wheel.SuspensionStiffness)
	w.WriteF64(wheel.SuspensionCompression)
	w.WriteF64(wheel.SuspensionDamping)
	w.WriteF64(wheel.MaxSuspensionTravel)
	w.WriteF64(wheel.SideFrictionStiffness)
	w.WriteF64(wheel.FrictionSlip)
	w.WriteF64(wheel.MaxSuspensionForce)
	return w.Bytes()
}

func normalizeVehicleConfig(config VehicleConfig) VehicleConfig {
	defaults := DefaultKartVehicleConfig()
	if len(config.Wheels) == 0 {
		config.Wheels = defaults.Wheels
	}
	for i := 0; i < len(config.Wheels); i++ {
		config.Wheels[i] = normalizeVehicleWheelConfig(config.Wheels[i])
	}
	if config.MaxForwardSpeed <= 0 {
		config.MaxForwardSpeed = defaults.MaxForwardSpeed
	}
	if config.MaxReverseSpeed <= 0 {
		config.MaxReverseSpeed = defaults.MaxReverseSpeed
	}
	if config.EngineForce <= 0 {
		config.EngineForce = defaults.EngineForce
	}
	if config.ReverseEngineForce <= 0 {
		config.ReverseEngineForce = defaults.ReverseEngineForce
	}
	if config.BrakeForce <= 0 {
		config.BrakeForce = defaults.BrakeForce
	}
	if config.CoastBrake <= 0 {
		config.CoastBrake = defaults.CoastBrake
	}
	if config.BoostEngineForce <= 0 {
		config.BoostEngineForce = defaults.BoostEngineForce
	}
	if config.MaxSteerAngle <= 0 {
		config.MaxSteerAngle = defaults.MaxSteerAngle
	}
	if config.SteerRate <= 0 {
		config.SteerRate = defaults.SteerRate
	}
	if config.DriftSteerScale <= 0 {
		config.DriftSteerScale = defaults.DriftSteerScale
	}
	if config.DriftMinSpeed <= 0 {
		config.DriftMinSpeed = defaults.DriftMinSpeed
	}
	return config
}

func normalizeVehicleWheelConfig(wheel VehicleWheelConfig) VehicleWheelConfig {
	defaults := DefaultKartVehicleConfig().Wheels[0]
	if wheel.Direction.LengthSq() == 0 {
		wheel.Direction = defaults.Direction
	}
	if wheel.Axle.LengthSq() == 0 {
		wheel.Axle = defaults.Axle
	}
	if wheel.SuspensionRestLength <= 0 {
		wheel.SuspensionRestLength = defaults.SuspensionRestLength
	}
	if wheel.Radius <= 0 {
		wheel.Radius = defaults.Radius
	}
	if wheel.SuspensionStiffness <= 0 {
		wheel.SuspensionStiffness = defaults.SuspensionStiffness
	}
	if wheel.SuspensionCompression <= 0 {
		wheel.SuspensionCompression = defaults.SuspensionCompression
	}
	if wheel.SuspensionDamping <= 0 {
		wheel.SuspensionDamping = defaults.SuspensionDamping
	}
	if wheel.MaxSuspensionTravel <= 0 {
		wheel.MaxSuspensionTravel = defaults.MaxSuspensionTravel
	}
	if wheel.SideFrictionStiffness <= 0 {
		wheel.SideFrictionStiffness = defaults.SideFrictionStiffness
	}
	if wheel.FrictionSlip <= 0 {
		wheel.FrictionSlip = defaults.FrictionSlip
	}
	if wheel.MaxSuspensionForce <= 0 {
		wheel.MaxSuspensionForce = defaults.MaxSuspensionForce
	}
	return wheel
}

func vehicleDriveWheelCount(wheels []VehicleWheelConfig) float64 {
	count := 0
	for _, wheel := range wheels {
		if wheel.Drive {
			count++
		}
	}
	if count == 0 {
		return 1
	}
	return float64(count)
}

func vehicleYawFromRotation(rot voplay.Quat) float64 {
	forward := rot.RotateVec3(voplay.Vec3{Z: -1})
	forward.Y = 0
	if forward.LengthSq() == 0 {
		return 0
	}
	forward = forward.Normalize()
	return math.Atan2(-forward.X, -forward.Z)
}

func vehicleMoveTowards(current, target, maxDelta float64) float64 {
	if maxDelta <= 0 {
		return current
	}
	if current < target {
		current += maxDelta
		if current > target {
			return target
		}
		return current
	}
	current -= maxDelta
	if current < target {
		return target
	}
	return current
}

func vehicleClamp(v, lo, hi float64) float64 {
	if v < lo {
		return lo
	}
	if v > hi {
		return hi
	}
	return v
}

func vehicleFiniteOr(v, fallback float64) float64 {
	if math.IsNaN(v) || math.IsInf(v, 0) {
		return fallback
	}
	return v
}

func vehicleCleanVec3(v voplay.Vec3) voplay.Vec3 {
	return voplay.Vec3{X: vehicleFiniteOr(v.X, 0), Y: vehicleFiniteOr(v.Y, 0), Z: vehicleFiniteOr(v.Z, 0)}
}

func vehicleCleanNormal(v voplay.Vec3) voplay.Vec3 {
	v = vehicleCleanVec3(v)
	if v.LengthSq() == 0 {
		return voplay.Vec3{Y: 1}
	}
	return v.Normalize()
}

// Scheduler provides delayed and repeating callback timers.
// Within a single Update call, the firing order of simultaneously-due callbacks is
// not guaranteed. New entries added inside a callback are deferred to the next Update call.
package voplay

// SchedulerHandle is an opaque identifier for a scheduled entry.
// Handles are unique per Scheduler instance and start at 1.
type SchedulerHandle int

type schedulerEntry struct {
	handle    SchedulerHandle
	timer     float64
	interval  float64
	repeating bool
	fn        func()
	cancelled bool
}

// Scheduler manages delayed and repeating callbacks driven by a manual Update clock.
type Scheduler struct {
	entries     []*schedulerEntry
	pending     []*schedulerEntry
	nextHandle  SchedulerHandle
	activeCount int
	updating    bool
}

// NewScheduler creates a new empty Scheduler.
func NewScheduler() *Scheduler {
	return &Scheduler{}
}

// After schedules fn to be called once after delay seconds.
// delay may be 0 (fires on the first Update that consumes >= 0 seconds).
// Returns a handle that can be used to cancel the callback before it fires.
func (s *Scheduler) After(delay float64, fn func()) SchedulerHandle {
	if delay < 0 {
		panic("Scheduler.After: delay must be >= 0")
	}
	if fn == nil {
		panic("Scheduler.After: fn must not be nil")
	}
	return s.addEntry(&schedulerEntry{
		timer:     delay,
		repeating: false,
		fn:        fn,
	})
}

// Every schedules fn to be called repeatedly every interval seconds.
// The first call fires after the first full interval has elapsed.
// Returns a handle that can be used to cancel the repeating callback.
func (s *Scheduler) Every(interval float64, fn func()) SchedulerHandle {
	if interval <= 0 {
		panic("Scheduler.Every: interval must be > 0")
	}
	if fn == nil {
		panic("Scheduler.Every: fn must not be nil")
	}
	return s.addEntry(&schedulerEntry{
		timer:     interval,
		interval:  interval,
		repeating: true,
		fn:        fn,
	})
}

// Cancel cancels the scheduled entry with the given handle.
// Cancelling an already-fired or already-cancelled handle is a no-op.
func (s *Scheduler) Cancel(h SchedulerHandle) {
	for _, e := range s.entries {
		if e.handle == h && !e.cancelled {
			e.cancelled = true
			s.activeCount--
			return
		}
	}
	for _, e := range s.pending {
		if e.handle == h && !e.cancelled {
			e.cancelled = true
			s.activeCount--
			return
		}
	}
}

// Update advances all timers by dt seconds and fires any callbacks that become due.
// Multiple firings of a repeating callback may occur in a single Update if dt is large.
// Entries added inside a callback are deferred and will start on the next Update call.
func (s *Scheduler) Update(dt float64) {
	if dt < 0 {
		panic("Scheduler.Update: dt must not be negative")
	}
	s.updating = true
	i := 0
	for i < len(s.entries) {
		e := s.entries[i]
		if e.cancelled {
			s.removeAt(i)
			continue
		}
		e.timer -= dt
		if e.timer <= 0 {
			if e.repeating {
				for e.timer <= 0 && !e.cancelled {
					e.fn()
					e.timer += e.interval
				}
				if e.cancelled {
					s.removeAt(i)
				} else {
					i++
				}
			} else {
				e.fn()
				s.removeAt(i)
			}
		} else {
			i++
		}
	}
	s.updating = false
	if len(s.pending) > 0 {
		s.entries = append(s.entries, s.pending...)
		s.pending = s.pending[:0]
	}
}

// Len returns the number of active (non-cancelled) scheduled entries,
// including any entries added during the current Update.
func (s *Scheduler) Len() int {
	return s.activeCount
}

// Clear cancels all currently scheduled entries.
func (s *Scheduler) Clear() {
	for _, e := range s.entries {
		e.cancelled = true
	}
	s.pending = s.pending[:0]
	s.activeCount = 0
}

func (s *Scheduler) addEntry(e *schedulerEntry) SchedulerHandle {
	s.nextHandle++
	e.handle = s.nextHandle
	s.activeCount++
	if s.updating {
		s.pending = append(s.pending, e)
	} else {
		s.entries = append(s.entries, e)
	}
	return e.handle
}

func (s *Scheduler) removeAt(i int) {
	if !s.entries[i].cancelled {
		s.activeCount--
	}
	last := len(s.entries) - 1
	s.entries[i] = s.entries[last]
	s.entries[last] = nil
	s.entries = s.entries[:last]
}

package voplay

type State interface {
	FixedUpdate(g *GameCtx, dt float64)
	Update(g *GameCtx, dt float64)
	Draw(g *GameCtx)
}

type stateEnter interface {
	Enter(g *GameCtx)
}

type stateExit interface {
	Exit(g *GameCtx)
}

type statePause interface {
	Pause(g *GameCtx)
}

type stateResume interface {
	Resume(g *GameCtx)
}

type stateResize interface {
	OnResize(g *GameCtx, w int, h int)
}

type stateUpdateBarrier interface {
	BlocksUpdateBelow() bool
}

type stateDrawBarrier interface {
	BlocksDrawBelow() bool
}

type StateStack struct {
	ctx     *GameCtx
	states  []State
	iterBuf []State // reusable iteration buffer — avoids per-frame allocation
}

func NewStateStack(g *GameCtx) *StateStack {
	return &StateStack{ctx: g}
}

// reuseIterBuf copies src into s.iterBuf, growing it only when needed.
// This eliminates the per-frame allocation that cloneStateSlice caused.
// Callers iterate the returned slice; it is valid only until the next call.
func (s *StateStack) reuseIterBuf(src []State) []State {
	n := len(src)
	if cap(s.iterBuf) < n {
		s.iterBuf = make([]State, n)
	} else {
		s.iterBuf = s.iterBuf[:n]
	}
	copy(s.iterBuf, src)
	return s.iterBuf
}

func (s *StateStack) Len() int {
	return len(s.states)
}

func (s *StateStack) IsEmpty() bool {
	return len(s.states) == 0
}

func (s *StateStack) Top() State {
	if len(s.states) == 0 {
		return nil
	}
	return s.states[len(s.states)-1]
}

func (s *StateStack) Push(state State) {
	if state == nil {
		panic("Push: state must not be nil")
	}
	current := s.Top()
	if current != nil {
		if hook, ok := current.(statePause); ok {
			hook.Pause(s.ctx)
		}
	}
	s.states = append(s.states, state)
	if hook, ok := state.(stateEnter); ok {
		hook.Enter(s.ctx)
	}
}

func (s *StateStack) Pop() State {
	if len(s.states) == 0 {
		panic("Pop: state stack is empty")
	}
	last := len(s.states) - 1
	state := s.states[last]
	if hook, ok := state.(stateExit); ok {
		hook.Exit(s.ctx)
	}
	s.states[last] = nil
	s.states = s.states[:last]
	if len(s.states) == 0 {
		s.ctx.Quit()
		return state
	}
	if hook, ok := s.states[len(s.states)-1].(stateResume); ok {
		hook.Resume(s.ctx)
	}
	return state
}

func (s *StateStack) Replace(state State) {
	if state == nil {
		panic("Replace: state must not be nil")
	}
	if len(s.states) == 0 {
		s.states = append(s.states, state)
		if hook, ok := state.(stateEnter); ok {
			hook.Enter(s.ctx)
		}
		return
	}
	last := len(s.states) - 1
	current := s.states[last]
	if hook, ok := current.(stateExit); ok {
		hook.Exit(s.ctx)
	}
	s.states[last] = state
	if hook, ok := state.(stateEnter); ok {
		hook.Enter(s.ctx)
	}
}

func (s *StateStack) Reset(state State) {
	for i := len(s.states) - 1; i >= 0; i-- {
		current := s.states[i]
		if hook, ok := current.(stateExit); ok {
			hook.Exit(s.ctx)
		}
		s.states[i] = nil
	}
	s.states = s.states[:0]
	if state == nil {
		s.ctx.Quit()
		return
	}
	s.states = append(s.states, state)
	if hook, ok := state.(stateEnter); ok {
		hook.Enter(s.ctx)
	}
}

func (s *StateStack) Clear() {
	s.Reset(nil)
}

func (s *StateStack) Update(dt float64) {
	active := s.updateSlice()
	for _, state := range active {
		state.Update(s.ctx, dt)
		if s.ctx.closed {
			return
		}
	}
}

func (s *StateStack) FixedUpdate(dt float64) {
	active := s.updateSlice()
	for _, state := range active {
		state.FixedUpdate(s.ctx, dt)
		if s.ctx.closed {
			return
		}
	}
}

func (s *StateStack) Draw() {
	active := s.drawSlice()
	for _, state := range active {
		state.Draw(s.ctx)
		if s.ctx.closed {
			return
		}
	}
}

func (s *StateStack) Resize(w int, h int) {
	active := s.reuseIterBuf(s.states)
	for _, state := range active {
		if hook, ok := state.(stateResize); ok {
			hook.OnResize(s.ctx, w, h)
			if s.ctx.closed {
				return
			}
		}
	}
}

func (s *StateStack) updateSlice() []State {
	if len(s.states) == 0 {
		return nil
	}
	start := len(s.states) - 1
	for start > 0 {
		blocker, ok := s.states[start].(stateUpdateBarrier)
		if !ok || blocker.BlocksUpdateBelow() {
			break
		}
		start--
	}
	return s.reuseIterBuf(s.states[start:])
}

func (s *StateStack) drawSlice() []State {
	if len(s.states) == 0 {
		return nil
	}
	start := len(s.states) - 1
	for start > 0 {
		blocker, ok := s.states[start].(stateDrawBarrier)
		if !ok || blocker.BlocksDrawBelow() {
			break
		}
		start--
	}
	return s.reuseIterBuf(s.states[start:])
}

