func assertEvents(events []string, want []string, label string) {
	assert(len(events) == len(want), label + ": len")
	for i := range want {
		assert(events[i] == want[i], label + ": event")
	}
}

func assertFloatNear(got, want, tol float64, label string) {
	diff := got - want
	if diff < 0 {
		diff = -diff
	}
	assert(diff <= tol, label)
}

func assertFloatFar(got, want, tol float64, label string) {
	diff := got - want
	if diff < 0 {
		diff = -diff
	}
	assert(diff > tol, label)
}

func assertVec3Near(got, want voplay.Vec3, tol float64, label string) {
	assertFloatNear(got.X, want.X, tol, label + ": x")
	assertFloatNear(got.Y, want.Y, tol, label + ": y")
	assertFloatNear(got.Z, want.Z, tol, label + ": z")
}

func assertFiniteFloat(got float64, label string) {
	assert(!math.IsNaN(got) && !math.IsInf(got, 0), label)
}

func assertFiniteVec3(got voplay.Vec3, label string) {
	assertFiniteFloat(got.X, label + ": x")
	assertFiniteFloat(got.Y, label + ": y")
	assertFiniteFloat(got.Z, label + ": z")
}

func assertQuatNear(got, want voplay.Quat, tol float64, label string) {
	assertFloatNear(got.X, want.X, tol, label + ": x")
	assertFloatNear(got.Y, want.Y, tol, label + ": y")
	assertFloatNear(got.Z, want.Z, tol, label + ": z")
	assertFloatNear(got.W, want.W, tol, label + ": w")
}

func capturePanic(fn func()) (any, bool) {
	var recovered any
	var didPanic bool
	func() {
		defer func() {
			recovered = recover()
			didPanic = recovered != nil
		}()
		fn()
	}()
	return recovered, didPanic
}

