func testLifecycle() {
	ctx := newTestCtx()
	log := &eventLog{}
	a := &testState{name: "a", events: log, blockUpdateBelow: true, blockDrawBelow: true}
	b := &testState{name: "b", events: log, blockUpdateBelow: true, blockDrawBelow: false}
	c := &testState{name: "c", events: log, blockUpdateBelow: true, blockDrawBelow: true}
	ctx.States.Push(a)
	assert(ctx.States.Len() == 1, "push a len")
	assert(ctx.States.Top() == a, "push a top")
	assertEvents(log.items, []string{"a:enter"}, "push a events")
	ctx.States.Push(b)
	assert(ctx.States.Len() == 2, "push b len")
	assert(ctx.States.Top() == b, "push b top")
	assertEvents(log.items, []string{"a:enter", "a:pause", "b:enter"}, "push b events")
	popped := ctx.States.Pop()
	assert(popped == b, "pop returns b")
	assert(ctx.States.Len() == 1, "pop len")
	assert(ctx.States.Top() == a, "pop top")
	assertEvents(log.items, []string{"a:enter", "a:pause", "b:enter", "b:exit", "a:resume"}, "pop events")
	ctx.States.Replace(c)
	assert(ctx.States.Len() == 1, "replace len")
	assert(ctx.States.Top() == c, "replace top")
	assertEvents(log.items, []string{"a:enter", "a:pause", "b:enter", "b:exit", "a:resume", "a:exit", "c:enter"}, "replace events")
}

func testUpdateAndDrawBarriers() {
	ctx := newTestCtx()
	log := &eventLog{}
	base := &testState{name: "base", events: log, blockUpdateBelow: true, blockDrawBelow: true}
	overlay := &testState{name: "overlay", events: log, blockUpdateBelow: false, blockDrawBelow: false}
	pause := &testState{name: "pause", events: log, blockUpdateBelow: true, blockDrawBelow: false}
	ctx.States.Push(base)
	ctx.States.Push(overlay)
	assert(len(log.items) == 3, "overlay setup events")
	log.items = log.items[:0]
	ctx.States.Update(0.016)
	assertEvents(log.items, []string{"base:update", "overlay:update"}, "overlay update propagation")
	assert(base.updateCount == 1, "base updated once")
	assert(overlay.updateCount == 1, "overlay updated once")
	assert(pause.updateCount == 0, "pause update untouched")
	assert(base.fixedUpdateCount == 0, "base fixed update untouched")
	log.items = log.items[:0]
	ctx.States.FixedUpdate(0.016)
	assertEvents(log.items, []string{"base:fixed", "overlay:fixed"}, "overlay fixed update propagation")
	assert(base.fixedUpdateCount == 1, "base fixed updated once")
	assert(overlay.fixedUpdateCount == 1, "overlay fixed updated once")
	assert(pause.fixedUpdateCount == 0, "pause fixed update untouched")
	log.items = log.items[:0]
	ctx.States.Draw()
	assertEvents(log.items, []string{"base:draw", "overlay:draw"}, "overlay draw propagation")
	assert(base.drawCount == 1, "base drawn once")
	assert(overlay.drawCount == 1, "overlay drawn once")
	log.items = log.items[:0]
	ctx.States.Replace(pause)
	assertEvents(log.items, []string{"overlay:exit", "pause:enter"}, "replace overlay with pause")
	log.items = log.items[:0]
	ctx.States.Update(0.016)
	assertEvents(log.items, []string{"pause:update"}, "pause blocks update below")
	assert(base.updateCount == 1, "base not updated behind pause")
	assert(pause.updateCount == 1, "pause updated once")
	assert(base.fixedUpdateCount == 1, "base fixed update count preserved")
	log.items = log.items[:0]
	ctx.States.FixedUpdate(0.016)
	assertEvents(log.items, []string{"pause:fixed"}, "pause blocks fixed update below")
	assert(base.fixedUpdateCount == 1, "base fixed update blocked behind pause")
	assert(pause.fixedUpdateCount == 1, "pause fixed updated once")
	log.items = log.items[:0]
	ctx.States.Draw()
	assertEvents(log.items, []string{"base:draw", "pause:draw"}, "pause allows draw below")
	assert(base.drawCount == 2, "base drawn behind pause")
	assert(pause.drawCount == 1, "pause drawn once")
}

