func testActionMap() {
	ctx := newTestCtx()
	actions := ctx.Actions
	actions.Bind("left", voplay.KeyBinding("ArrowLeft"), voplay.KeyBinding("a"))
	actions.Bind("fire", voplay.PointerBinding(0))
	actions.Bind("right", voplay.KeyBinding("ArrowRight"), voplay.KeyBinding("d"))
	ctx.Input.KeyDown("a")
	assert(actions.IsDown("left"), "left action down from alternate key")
	assert(actions.IsPressed("left"), "left action pressed on first frame")
	assert(actions.Axis("left", "right") == -1, "axis negative")
	ctx.Input.EndFrame()
	assert(actions.IsDown("left"), "left action remains down after frame end")
	assert(!actions.IsPressed("left"), "left pressed clears after frame end")
	ctx.Input.KeyDown("ArrowRight")
	assert(actions.Axis("left", "right") == 0, "axis cancels when both sides held")
	ctx.Input.KeyUp("a")
	ctx.Input.KeyUp("ArrowRight")
	assert(actions.IsReleased("left"), "left action released")
	assert(actions.IsReleased("right"), "right action released")
	assert(actions.Axis("left", "right") == 0, "axis neutral after release")
	ctx.Input.EndFrame()
	ctx.Input.PointerDown(20, 30, 0)
	assert(actions.IsDown("fire"), "pointer binding down")
	assert(actions.IsPressed("fire"), "pointer binding pressed")
	ctx.Input.PointerUp(20, 30, 0)
	assert(actions.IsReleased("fire"), "pointer binding released")
	ctx.Input.EndFrame()
	ctx.Input.KeyDown("A")
	assert(actions.IsDown("left"), "uppercase letter key normalizes to bound lowercase key")
	ctx.Input.KeyUp("A")
	assert(actions.IsReleased("left"), "uppercase letter key release normalizes")
	actions.Rebind("left", voplay.KeyBinding("KeyA"))
	ctx.Input.EndFrame()
	ctx.Input.KeyDown("a")
	assert(actions.IsDown("left"), "host Key-prefixed binding normalizes to single-letter event")
	ctx.Input.KeyUp("a")
	assert(actions.IsReleased("left"), "normalized Key-prefixed binding releases correctly")
	actions.Rebind("left", voplay.KeyBinding("j"))
	ctx.Input.EndFrame()
	ctx.Input.KeyDown("j")
	assert(actions.IsDown("left"), "rebind replaces action binding")
	ctx.Input.KeyUp("j")
	actions.Unbind("right")
	assert(actions.IsReleased("left"), "rebound key released")
}

