	assertFloatNear(input.Throttle, 1, 0.000001, "racing input rebind gamepad")
}

func testRacingReplayContract() {
	rec := scene3d.NewRacingReplayRecorder(1.0 / 60.0)
	rec.RecordInput(0, scene3d.RacingInput{Throttle: 1.4, Steer: -2})
	rec.RecordTransform(0, voplay.Vec3{X: 1, Y: 2, Z: 3}, voplay.QuatIdentity())
	rec.RecordCheckpoint(10, "lap_start", 0)
	rec.RecordInput(10, scene3d.RacingInput{Throttle: 0.5, Brake: 0.25, Steer: 0.2, Drift: true})
	rec.RecordCheckpoint(20, "split_1", 120)
	replay := rec.Replay()
	assert(replay.FormatVersion == scene3d.RacingReplayFormatVersion, "racing replay format version")
	assert(replay.EngineVersion == scene3d.RacingReplayEngineVersion, "racing replay engine version")
	assertFloatNear(replay.FixedStep, 1.0 / 60.0, 0.000001, "racing replay fixed step")
	assertFloatNear(replay.Inputs[0].Input.Throttle, 1, 0.000001, "racing replay clamps throttle")
	assertFloatNear(replay.Inputs[0].Input.Steer, -1, 0.000001, "racing replay clamps steer")
	data, err := scene3d.MarshalRacingReplay(replay)
	assert(err == nil, "racing replay marshal")
	decoded, err := scene3d.UnmarshalRacingReplay(data)
	assert(err == nil, "racing replay unmarshal")
	cursor, err := scene3d.NewRacingReplayCursor(&decoded)
	assert(err == nil, "racing replay cursor")
	input, ok := cursor.InputAt(10)
	assert(ok, "racing replay cursor input at step")
	assertFloatNear(input.Throttle, 0.5, 0.000001, "racing replay cursor input value")
	checkpoints := cursor.CheckpointsAt(10)
	assert(len(checkpoints) == 1 && checkpoints[0].Name == "lap_start", "racing replay checkpoint at step")
	seq := scene3d.CheckpointSequence(decoded)
	assert(len(seq) == 2 && seq[0] == "lap_start" && seq[1] == "split_1", "racing replay checkpoint sequence")
	bad := decoded
	bad.Inputs = []scene3d.RacingReplayInputSample{{Step: 2}, {Step: 1}}
	err = scene3d.ValidateRacingReplay(bad)
	assert(err != nil, "racing replay rejects unordered inputs")
}

