	assert(stats.fileLoads == 1, "assets texture loaded via file")
	assets.EndGroup()
	assets.BeginGroup("level")
	tex3, err := assets.Texture("ui.png")
	assert(err == nil, "assets texture cross-group load")
	assert(tex3 == tex1, "assets texture shared across groups")
