	assert(audio1 != 0, "assets audio id")
	assets.EndGroup()
	assets.ReleaseGroup("level")
	assert(stats.textureFrees == 0, "shared texture not freed with remaining owner")
	assert(stats.fontFrees == 1, "font freed with owning group")
	assert(stats.audioFrees == 1, "audio freed with owning group")
