		_, _ = assets.TextureBytes("conflict.png", []byte{9, 9})
	})
	assert(didPanic, "assets source mismatch panics")
	assets.EndGroup()
	assets.ReleaseGroup("global")
	assert(stats.textureFrees == 1, "shared texture freed after last owner releases")
	assets.BeginGroup("transient")
	_, err = assets.ModelBytes("ship", []byte{7, 8})
	assert(err == nil, "assets model bytes load")
	assets.EndGroup()
	assets.ReleaseAll()
	assert(stats.modelFrees == 1, "release all frees remaining model")
}

