func testScheduler() {
	s := voplay.NewScheduler()
	assert(s.Len() == 0, "scheduler empty on creation")
	fired := 0
	_ = s.After(0.1, func() {
		fired++
	})
	assert(s.Len() == 1, "scheduler len after After")
	s.Update(0.05)
	assert(fired == 0, "not fired before delay")
	s.Update(0.05)
	assert(fired == 1, "fired exactly at delay")
	assert(s.Len() == 0, "one-shot removed after fire")
	s.Update(0.1)
	assert(fired == 1, "one-shot does not re-fire")
	repeatCount := 0
	s.Every(0.1, func() {
		repeatCount++
	})
	s.Update(0.25)
	assert(repeatCount == 2, "every fires twice in 0.25s with 0.1s interval")
	s.Update(0.1)
	assert(repeatCount == 3, "every fires third time")
	assert(s.Len() == 1, "repeating entry stays active")
	cancelCount := 0
	ch := s.After(0.2, func() {
		cancelCount++
	})
	s.Cancel(ch)
	s.Update(0.3)
	assert(cancelCount == 0, "cancelled one-shot does not fire")
	s.Clear()
	assert(s.Len() == 0, "clear empties scheduler")
	deferredFired := 0
	s.After(0.0, func() {
		s.After(0.0, func() {
			deferredFired++
		})
	})
	s.Update(0.0)
	assert(deferredFired == 0, "entry added in callback deferred to next update")
	s.Update(0.0)
	assert(deferredFired == 1, "deferred entry fires on next update")
	cancelDuringCount := 0
	var hCancel voplay.SchedulerHandle
	hCancel = s.Every(0.05, func() {
		cancelDuringCount++
		s.Cancel(hCancel)
	})
	s.Update(0.1)
	assert(cancelDuringCount == 1, "self-cancelling every fires exactly once")
	s.Update(0.1)
	assert(cancelDuringCount == 1, "self-cancelled every does not fire again")
	_, didPanic := capturePanic(func() {
		s.After(-1, func() {})
	})
	assert(didPanic, "After negative delay panics")
	_, didPanic = capturePanic(func() {
		s.Every(0, func() {})
	})
	assert(didPanic, "Every zero interval panics")
	_, didPanic = capturePanic(func() {
		s.After(0, nil)
	})
	assert(didPanic, "After nil fn panics")
}

func testTween() {
	tw := voplay.NewTween(0, 100, 1.0, voplay.EaseLinear)
	assertFloatNear(tw.Value(), 0, 0.000001, "tween initial value")
	assert(!tw.Done(), "tween not done initially")
	tw.Update(0.5)
	assertFloatNear(tw.Value(), 50, 0.000001, "tween midpoint linear")
	assertFloatNear(tw.Progress(), 0.5, 0.000001, "tween progress midpoint")
	tw.Update(0.5)
	assertFloatNear(tw.Value(), 100, 0.000001, "tween at end")
	assert(tw.Done(), "tween done after full duration")
	tw.Update(0.5)
	assertFloatNear(tw.Value(), 100, 0.000001, "tween stays at end after done")
	tw.Reset()
	assert(!tw.Done(), "tween not done after reset")
	assertFloatNear(tw.Value(), 0, 0.000001, "tween resets to start")
	doneFired := 0
	updateValues := []float64{}
	tw2 := voplay.NewTween(10, 20, 0.5, voplay.EaseLinear).WithOnUpdate(func(v float64) {
		updateValues = append(updateValues, v)
	}).WithOnDone(func() {
		doneFired++
	})
	tw2.Update(0.5)
	assert(doneFired == 1, "OnDone fired on completion")
	assert(len(updateValues) == 1, "OnUpdate called once")
	assertFloatNear(updateValues[0], 20, 0.000001, "OnUpdate receives final value")
	twLoop := voplay.NewTween(0, 1, 0.5, voplay.EaseLinear).WithLoop()
	twLoop.Update(0.75)
	assert(!twLoop.Done(), "looping tween never done")
	assertFloatNear(twLoop.Progress(), 0.5, 0.001, "loop tween at midpoint of second cycle after 0.75s")
	twPP := voplay.NewTween(0, 100, 0.5, voplay.EaseLinear).WithPingPong()
	twPP.Update(0.5)
	assertFloatNear(twPP.Value(), 100, 0.000001, "pingpong at endpoint")
	twPP.Update(0.25)
	assertFloatNear(twPP.Value(), 50, 0.000001, "pingpong reversed at midpoint")
	twPP.Update(0.25)
	assertFloatNear(twPP.Value(), 0, 0.000001, "pingpong back to start")
	assert(!twPP.Done(), "pingpong never done")
	twEase := voplay.NewTween(0, 1, 1.0, voplay.EaseInQuad)
	twEase.Update(0.5)
	assertFloatNear(twEase.Value(), 0.25, 0.000001, "EaseInQuad at 0.5 = 0.25")
	twOut := voplay.NewTween(0, 1, 1.0, voplay.EaseOutQuad)
	twOut.Update(0.5)
	assertFloatNear(twOut.Value(), 0.75, 0.000001, "EaseOutQuad at 0.5 = 0.75")
	assertFloatNear(voplay.EaseOutBounce(1.0), 1.0, 0.000001, "EaseOutBounce at 1.0")
	assertFloatNear(voplay.EaseOutBounce(0.0), 0.0, 0.000001, "EaseOutBounce at 0.0")
	assertFloatNear(voplay.EaseInBounce(0.0), 0.0, 0.000001, "EaseInBounce at 0.0")
	assertFloatNear(voplay.EaseInBounce(1.0), 1.0, 0.000001, "EaseInBounce at 1.0")
	assertFloatNear(voplay.EaseInOutBack(0.0), 0.0, 0.000001, "EaseInOutBack at 0.0")
	assertFloatNear(voplay.EaseInOutBack(0.5), 0.5, 0.000001, "EaseInOutBack at 0.5 = 0.5")
	assertFloatNear(voplay.EaseInOutBack(1.0), 1.0, 0.000001, "EaseInOutBack at 1.0")
	assertFloatNear(voplay.EaseInElastic(0.0), 0.0, 0.000001, "EaseInElastic at 0.0")
	assertFloatNear(voplay.EaseInElastic(1.0), 1.0, 0.000001, "EaseInElastic at 1.0")
	assertFloatNear(voplay.EaseOutElastic(0.0), 0.0, 0.000001, "EaseOutElastic at 0.0")
	assertFloatNear(voplay.EaseOutElastic(1.0), 1.0, 0.000001, "EaseOutElastic at 1.0")
	assertFloatNear(voplay.EaseInOutElastic(0.0), 0.0, 0.000001, "EaseInOutElastic at 0.0")
	assertFloatNear(voplay.EaseInOutElastic(0.5), 0.5, 0.000001, "EaseInOutElastic at 0.5")
	assertFloatNear(voplay.EaseInOutElastic(1.0), 1.0, 0.000001, "EaseInOutElastic at 1.0")
	clearUpdateCount := 0
	clearDoneCount := 0
	twClear := voplay.NewTween(0, 1, 0.1, voplay.EaseLinear).WithOnUpdate(func(v float64) {
		clearUpdateCount++
	}).WithOnDone(func() {
		clearDoneCount++
	})
	twClear.WithOnUpdate(nil)
	twClear.WithOnDone(nil)
	twClear.Update(0.1)
	assert(clearUpdateCount == 0, "WithOnUpdate(nil) clears callback")
	assert(clearDoneCount == 0, "WithOnDone(nil) clears callback")
	_, didPanic := capturePanic(func() {
		voplay.NewTween(0, 1, 0, nil)
	})
	assert(didPanic, "NewTween zero duration panics")
	_, didPanic = capturePanic(func() {
		voplay.NewTween(0, 1, -1, nil)
	})
	assert(didPanic, "NewTween negative duration panics")
}

