func testAnimController() {
	sheet := scene2d.NewSpriteSheet(voplay.TextureID(1), 16, 16, 4)
	clipIdle := &scene2d.AnimClip{Sheet: sheet, Frames: []int{0, 1, 2, 3}, FPS: 8, Loop: true}
	clipAttack := &scene2d.AnimClip{Sheet: sheet, Frames: []int{4, 5, 6}, FPS: 12, Loop: false}
	ac := scene2d.NewAnimController()
	assert(ac.CurrentClip() == "", "no clip initially")
	assert(!ac.Done(), "not done with no clip")
	ac.AddClip("idle", clipIdle)
	ac.AddClip("attack", clipAttack)
	ac.SetState("idle")
	assert(ac.CurrentClip() == "idle", "clip set to idle")
	assert(!ac.Done(), "idle loop not done")
	frameDur := 1.0 / 8.0
	ac.Update(frameDur * 2)
	x, y, w, h := ac.CurrentFrame()
	assert(w == 16, "frame width correct")
	assert(h == 16, "frame height correct")
	srcCol := int(x) / 16
	assert(srcCol == 2, "advanced to frame index 2 after 2 frame durations")
	_ = y
	ac.SetState("idle")
	assert(ac.CurrentClip() == "idle", "SetState no-op same clip")
	assert(srcCol == 2, "frame not reset on same-clip SetState")
	ac.SetState("attack")
	assert(ac.CurrentClip() == "attack", "transitioned to attack")
	assert(!ac.Done(), "attack not done immediately")
	attackFrameDur := 1.0 / 12.0
	ac.Update(attackFrameDur * 3)
	assert(ac.Done(), "attack done after all frames")
	ac.Update(attackFrameDur * 5)
	assert(ac.Done(), "attack stays done")
	x2, _, _, _ := ac.CurrentFrame()
	srcCol2 := int(x2) / 16
	assert(srcCol2 == 2, "attack stuck on last frame index (4+2=6 in sheet col 2)")
	ac.SetStateForce("attack")
	assert(!ac.Done(), "SetStateForce resets done")
	assert(ac.CurrentClip() == "attack", "SetStateForce set to attack")
	spr := &scene2d.Sprite{Tint: voplay.White}
	ac.ApplyToSprite(spr)
	assert(spr.Texture == voplay.TextureID(1), "ApplyToSprite sets texture")
	assert(spr.SrcW == 16, "ApplyToSprite sets SrcW")
	assert(spr.SrcH == 16, "ApplyToSprite sets SrcH")
	assert(ac.HasClip("idle"), "HasClip returns true for registered clip")
	assert(ac.HasClip("attack"), "HasClip returns true for attack")
	assert(!ac.HasClip("jump"), "HasClip returns false for unregistered clip")
	assert(!ac.HasClip(""), "HasClip returns false for empty name")
	onDoneFired := 0
	lastDoneClip := ""
	ac.WithOnDone(func() {
		onDoneFired++
		lastDoneClip = ac.CurrentClip()
	})
	ac.SetState("attack")
	ac.Update(attackFrameDur * 3)
	assert(onDoneFired == 1, "OnDone fires when non-looping clip ends")
	assert(lastDoneClip == "attack", "OnDone sees current clip as attack")
	ac.SetState("idle")
	ac.Update(1.0)
	assert(onDoneFired == 1, "OnDone not fired for looping clip")
	ac.WithOnDone(nil)
	ac.SetState("attack")
	ac.Update(attackFrameDur * 3)
	assert(onDoneFired == 1, "WithOnDone nil clears callback")
	_, didPanic := capturePanic(func() {
		ac.AddClip("idle", clipIdle)
	})
	assert(didPanic, "AddClip duplicate name panics")
	_, didPanic = capturePanic(func() {
		ac.SetState("unknown")
	})
	assert(didPanic, "SetState unknown clip panics")
	_, didPanic = capturePanic(func() {
		ac.ApplyToSprite(nil)
	})
	assert(didPanic, "ApplyToSprite nil panics")
}

