func testScene2DSetActive() {
	s := scene2d.New()
	e := s.Spawn(scene2d.EntityDesc{Position: voplay.Vec2{10, 20}, Size: voplay.Vec2{16, 16}, Tag: "player"})
	result := s.FindInRect(voplay.Rect{X: 0, Y: 0, W: 100, H: 100})
	assert(len(result) == 1, "active entity found in rect")
	s.SetActive(e, false)
	assert(!e.Active, "SetActive false sets Active")
	result = s.FindInRect(voplay.Rect{X: 0, Y: 0, W: 100, H: 100})
	assert(len(result) == 0, "inactive entity not found in rect")
	e.SetLocalPosition(500, 500)
	s.SetActive(e, true)
	assert(e.Active, "SetActive true sets Active")
	result = s.FindInRect(voplay.Rect{X: 0, Y: 0, W: 50, H: 50})
	assert(len(result) == 0, "reactivated entity not at old position")
	result = s.FindInRect(voplay.Rect{X: 490, Y: 490, W: 30, H: 30})
	assert(len(result) == 1, "reactivated entity found at new position")
	s.SetActive(e, true)
	result = s.FindInRect(voplay.Rect{X: 490, Y: 490, W: 30, H: 30})
	assert(len(result) == 1, "SetActive idempotent")
	s.Close()
}

func testScene3DThirdPersonCamera() {
	s := scene3d.New()
	target := s.Spawn(scene3d.EntityDesc{Position: voplay.Vec3{X: 1, Y: 2, Z: 3}})
	camCtl := scene3d.NewThirdPersonCamera(target)
	camCtl.PivotOffset = voplay.Vec3{Y: 1}
	camCtl.Distance = 4
	camCtl.MinDistance = 2
	camCtl.MaxDistance = 6
	camCtl.Smoothing = 0
	camCtl.CollisionEnabled = false
	camCtl.Yaw = 0
	camCtl.Pitch = 0
	camCtl.UpdateCamera(&s.Camera, s, 1.0 / 60.0)
	pivot := voplay.Vec3{X: 1, Y: 3, Z: 3}
	assertVec3Near(s.Camera.Target, pivot, 0.000001, "third person initial target")
	assertVec3Near(s.Camera.Position, voplay.Vec3{X: 1, Y: 3, Z: 7}, 0.000001, "third person initial position")
	target.SetRotation(voplay.QuatFromAxisAngle(voplay.Vec3{Y: 1}, math.Pi / 2))
	camCtl.UpdateCamera(&s.Camera, s, 1.0 / 60.0)
	assertVec3Near(s.Camera.Position, voplay.Vec3{X: 1, Y: 3, Z: 7}, 0.000001, "third person ignores target rotation by default")
	camCtl.AlignToTargetYaw = true
	camCtl.UpdateCamera(&s.Camera, s, 1.0 / 60.0)
	assertVec3Near(s.Camera.Position, voplay.Vec3{X: 5, Y: 3, Z: 3}, 0.000001, "third person optional target yaw alignment")
	camCtl.AlignToTargetYaw = false
	target.SetRotation(voplay.QuatIdentity())
	camCtl.UpdateCamera(&s.Camera, s, 1.0 / 60.0)
	assertVec3Near(s.Camera.Position, voplay.Vec3{X: 1, Y: 3, Z: 7}, 0.000001, "third person returning to free orbit")
	camCtl.HandleInput(0, -10)
	assertFloatNear(camCtl.Pitch, camCtl.MaxPitch, 0.000001, "third person pitch clamp max")
	camCtl.HandleInput(0, 20)
	assertFloatNear(camCtl.Pitch, camCtl.MinPitch, 0.000001, "third person pitch clamp min")
	camCtl.Zoom(100)
	assertFloatNear(camCtl.Distance, camCtl.MaxDistance, 0.000001, "third person zoom clamp max")
	camCtl.Zoom(-100)
	assertFloatNear(camCtl.Distance, camCtl.MinDistance, 0.000001, "third person zoom clamp min")
	camCtl.Distance = 4
	camCtl.Pitch = 0
	camCtl.Smoothing = 2
	target.SetPosition(voplay.Vec3{X: 10, Y: 2, Z: 3})
	camCtl.UpdateCamera(&s.Camera, s, 0.1)
	assertVec3Near(s.Camera.Target, voplay.Vec3{X: 10, Y: 3, Z: 3}, 0.000001, "third person target follows entity")
	assert(s.Camera.Position.X > 1, "third person smoothing advances camera")
	assert(s.Camera.Position.X < 10, "third person smoothing does not teleport")
	other := s.Spawn(scene3d.EntityDesc{Position: voplay.Vec3{X: -4, Y: 0, Z: 8}})
	camCtl.Target = other
	camCtl.UpdateCamera(&s.Camera, s, 0.1)
	assertVec3Near(s.Camera.Target, voplay.Vec3{X: -4, Y: 1, Z: 8}, 0.000001, "third person target switch target")
	assertVec3Near(s.Camera.Position, voplay.Vec3{X: -4, Y: 1, Z: 12}, 0.000001, "third person target switch snaps position")
	frozenPos := s.Camera.Position
	frozenTarget := s.Camera.Target
	camCtl.Target = nil
	other.SetPosition(voplay.Vec3{X: 100, Y: 100, Z: 100})
	camCtl.UpdateCamera(&s.Camera, s, 0.1)
	assertVec3Near(s.Camera.Position, frozenPos, 0.000001, "third person nil target freezes position")
	assertVec3Near(s.Camera.Target, frozenTarget, 0.000001, "third person nil target freezes target")
	staleTarget := s.Spawn(scene3d.EntityDesc{Position: voplay.Vec3{X: 20, Y: 1, Z: -5}})
	camCtl.Target = staleTarget
	camCtl.UpdateCamera(&s.Camera, s, 0.1)
	frozenPos = s.Camera.Position
	frozenTarget = s.Camera.Target
	s.Destroy(staleTarget)
	camCtl.UpdateCamera(&s.Camera, s, 0.1)
	assertVec3Near(s.Camera.Position, frozenPos, 0.000001, "third person destroyed target freezes position")
	assertVec3Near(s.Camera.Target, frozenTarget, 0.000001, "third person destroyed target freezes target")
	s.Close()
}

func testScene3DRacingCamera() {
	s := scene3d.New()
	camCtl := scene3d.NewRacingCamera()
	camCtl.CollisionEnabled = false
	camCtl.Smoothing = 0
	camCtl.TargetSmoothing = 0
	target := scene3d.RacingCameraTarget{Position: voplay.Vec3{}, Forward: voplay.Vec3{Z: -1}, Velocity: voplay.Vec3{Z: -20}, Speed: 20}
	camCtl.UpdateCamera(&s.Camera, s, target, 1.0 / 60.0)
	assert(s.Camera.Position.Z > 0, "racing camera stays behind kart")
	assert(s.Camera.Position.Y > target.Position.Y, "racing camera is above kart")
	assert(s.Camera.Target.Z < target.Position.Z, "racing camera looks ahead")
	normalPos := s.Camera.Position
	normalFov := s.Camera.Fov
	target.Drift = 1
	camCtl.UpdateCamera(&s.Camera, s, target, 1.0 / 60.0)
	assert(s.Camera.Position.X > normalPos.X, "racing camera drift offset moves to side")
	target.Drift = 0
	target.Boost = true
	camCtl.UpdateCamera(&s.Camera, s, target, 0.2)
	assert(s.Camera.Fov > normalFov, "racing camera boost increases fov")
	boostFov := s.Camera.Fov
	target.Boost = false
	camCtl.UpdateCamera(&s.Camera, s, target, 0.2)
	assert(s.Camera.Fov < boostFov, "racing camera boost fov returns")
	target.LandingShake = 1
	camCtl.UpdateCamera(&s.Camera, s, target, 0)
	assert(s.Camera.Position.Y > normalPos.Y, "racing camera landing shake hook offsets vertically")
	a := scene3d.NewRacingCamera()
	b := scene3d.NewRacingCamera()
	a.CollisionEnabled = false
	b.CollisionEnabled = false
	a.Update(s, target, 1.0 / 30.0)
	b.Update(s, target, 1.0 / 30.0)
	assertVec3Near(a.Position(), b.Position(), 0.000001, "racing camera deterministic position")
	assertVec3Near(a.Target(), b.Target(), 0.000001, "racing camera deterministic target")
	assertFloatNear(a.CurrentFov(), b.CurrentFov(), 0.000001, "racing camera deterministic fov")
	s.Close()
}

func testScene3DParticles() {
	s := scene3d.New()
	emitter := scene3d.NewParticleEmitter(3)
	emitter.Texture = voplay.TextureID(1)
	emitter.Rate = 10
	emitter.LifetimeMin = 10
	emitter.LifetimeMax = 10
	emitter.SpeedMin = 0
	emitter.SpeedMax = 0
	emitter.Gravity = voplay.Vec3{}
	emitter.Damping = 1
	s.AddEmitter(emitter)
	assert(len(s.Emitters) == 1, "scene3d add emitter")
	s.UpdateEmitters(0.25)
	assert(emitter.LiveCount() == 2, "scene3d emitter spawns from rate")
	s.UpdateEmitters(0.25)
	assert(emitter.LiveCount() == 3, "scene3d emitter ring buffer caps live particles")
	burst := scene3d.NewParticleEmitter(4)
	burst.Texture = voplay.TextureID(1)
	burst.Rate = 0
	burst.LifetimeMin = 0.5
	burst.LifetimeMax = 0.5
	burst.SpeedMin = 0
	burst.SpeedMax = 0
	burst.Gravity = voplay.Vec3{}
	burst.Damping = 1
	burst.EmitBurst(2)
	assert(burst.LiveCount() == 2, "scene3d burst emits particles")
	burst.Enabled = false
	burst.Update(1.0)
	assert(burst.LiveCount() == 0, "scene3d disabled emitter still advances live particles")
	d := voplay.NewDrawCtx()
	d.SetCamera3D(s.Camera.Position, s.Camera.Target, s.Camera.Up, s.Camera.Fov, s.Camera.Near, s.Camera.Far)
	baseLen := len(d.Bytes())
	emitter.Draw(d)
	assert(len(d.Bytes()) > baseLen, "scene3d particles write billboard draw commands")
	target := s.Spawn(scene3d.EntityDesc{Position: voplay.Vec3{X: 4, Y: 5, Z: 6}})
	attached := scene3d.NewParticleEmitter(2)
	attached.Texture = voplay.TextureID(1)
	attached.Attached = target
	attached.Rate = 0
	attached.LifetimeMin = 1
	attached.LifetimeMax = 1
	attached.SpeedMin = 0
	attached.SpeedMax = 0
	attached.Gravity = voplay.Vec3{}
	attached.Damping = 1
	attached.EmitBurst(1)
	s.AddEmitter(attached)
	assert(len(s.Emitters) == 2, "scene3d second emitter added")
	s.Destroy(target)
	assert(len(s.Emitters) == 1, "scene3d destroy removes attached emitters")
	assert(attached.Attached == nil, "scene3d destroy clears attached emitter target")
	s.RemoveEmitter(emitter)
	assert(len(s.Emitters) == 0, "scene3d remove emitter")
	assert(emitter.Attached == nil, "scene3d remove emitter clears attached target")
	clearTarget := s.Spawn(scene3d.EntityDesc{Position: voplay.Vec3{X: 1, Y: 2, Z: 3}})
	clearEmitter := scene3d.NewParticleEmitter(1)
	clearEmitter.Texture = voplay.TextureID(1)
	clearEmitter.Attached = clearTarget
	clearEmitter.Rate = 0
	clearEmitter.LifetimeMin = 1
	clearEmitter.LifetimeMax = 1
	clearEmitter.SpeedMin = 0
	clearEmitter.SpeedMax = 0
	clearEmitter.Gravity = voplay.Vec3{}
	clearEmitter.Damping = 1
	s.AddEmitter(clearEmitter)
	s.Clear()
	assert(clearEmitter.Attached == nil, "scene3d clear clears attached emitter target")
	s.Close()
}

