func testScene3DLightingProfile() {
	s := scene3d.New()
	profile := scene3d.KartRacingLightingProfile()
	assert(profile.Ambient.A > 0, "scene3d kart lighting ambient alpha")
	assert(profile.AmbientGround.A > 0, "scene3d kart lighting ground ambient alpha")
	assert(profile.AmbientGround != profile.Ambient, "scene3d kart lighting uses hemisphere ambient split")
	assert(len(profile.Lights) >= 2, "scene3d kart lighting has sun and fill")
	assert(profile.Lights[0].Type == scene3d.DirectionalLight, "scene3d kart lighting sun is directional")
	assert(profile.Lights[0].Intensity > profile.Lights[1].Intensity, "scene3d kart lighting sun stronger than fill")
	assert(profile.Fog.Mode == scene3d.FogLinear, "scene3d kart lighting fog is linear")
	assert(profile.Fog.End > profile.Fog.Start, "scene3d kart lighting fog range")
	assert(profile.ColorGrading.ToneMap == scene3d.ToneMapNone, "scene3d kart lighting preserves source texture color")
	assert(profile.ColorGrading.Exposure > 1, "scene3d kart lighting exposure lift")
	assert(profile.ShadowStrength > 0 && profile.ShadowStrength < 1, "scene3d kart lighting uses softened stylized shadows")
	s.ApplyLightingProfile(profile)
	assert(s.Ambient == profile.Ambient, "scene3d lighting profile applies ambient")
	assert(s.AmbientGround == profile.AmbientGround, "scene3d lighting profile applies ground ambient")
	assert(len(s.Lights) == len(profile.Lights), "scene3d lighting profile applies lights")
	assert(s.Fog == profile.Fog, "scene3d lighting profile applies fog")
	assert(s.ColorGrading == profile.ColorGrading, "scene3d lighting profile applies color grading")
	assertFloatNear(s.ShadowStrength, profile.ShadowStrength, 0.000001, "scene3d lighting profile applies shadow strength")
	profile.Lights[0].Intensity = 0
	assert(s.Lights[0].Intensity > 0, "scene3d lighting profile copies lights")
	s.Close()
}

