func trackIssuesHaveCode(issues []scene3d.TrackIssue, code string) bool {
	for _, issue := range issues {
		if issue.Code == code {
			return true
		}
	}
	return false
}

func trackIssuesHaveSeverity(issues []scene3d.TrackIssue, severity int) bool {
	for _, issue := range issues {
		if issue.Severity == severity {
			return true
		}
	}
	return false
}

func testScene3DTrackValidationAndQueries() {
	asset := newScene3DTestTrackAsset()
	asset.RacingLines = []scene3d.TrackRacingLine{{Name: "optimal", Points: []scene3d.TrackRacingLinePoint{{Distance: 0, Lateral: 0, TargetSpeed: 20}, {Distance: 100, Lateral: 4, TargetSpeed: 30}, {Distance: 200, Lateral: -2, TargetSpeed: 24}}}}
	issues := scene3d.ValidateTrackAsset(asset)
	assert(!trackIssuesHaveCode(issues, "track.centerline.closed_loop"), "scene3d valid track has continuous loop")
	assert(!trackIssuesHaveCode(issues, "track.gate.order"), "scene3d valid track has ordered gates")
	assert(!trackIssuesHaveSeverity(issues, scene3d.TrackIssueError), "scene3d valid track has no validation errors")
	track, err := scene3d.NewTrack(asset)
	assert(err == nil, "scene3d new track err")
	assertFloatNear(track.Length(), 400, 0.000001, "scene3d track length")
	p0 := track.PoseAt(0)
	p1 := track.PoseAt(track.Length())
	assertVec3Near(p0.Position, p1.Position, 0.000001, "scene3d closed track pose wraps")
	cp := track.ClosestPoint(voplay.Vec3{X: 3, Y: 0, Z: -20})
	assertFloatNear(cp.Distance, 20, 0.000001, "scene3d closest point distance")
	assertFloatNear(cp.LateralDistance, 3, 0.000001, "scene3d closest point lateral sign")
	assert(cp.OnRoad, "scene3d closest point on road")
	grass := track.SurfaceAt(voplay.Vec3{X: -7, Y: 0, Z: -20})
	assert(grass.Name == "grass_left", "scene3d surface picks highest priority offroad region")
	assertFloatNear(grass.Friction, 0.35, 0.000001, "scene3d surface friction")
	boost := track.SurfaceAt(voplay.Vec3{X: 0, Y: 0, Z: -25})
	assert(boost.Name == "boost_lane", "scene3d surface picks boost lane")
	assert(track.IsOnRoad(voplay.Vec3{X: 0, Y: 0, Z: -25}), "scene3d track reports road inside width")
	assert(!track.IsOnRoad(voplay.Vec3{X: 20, Y: 0, Z: -25}), "scene3d track reports offroad outside width")
	linePose, err := track.PoseOnLine("optimal", 50)
	assert(err == nil, "scene3d racing line pose err")
	assertFloatNear(linePose.TargetSpeed, 25, 0.000001, "scene3d racing line target speed interpolates")
	centerPose := track.PoseAt(50)
	assertVec3Near(linePose.Pose.Position, centerPose.Position.Add(centerPose.Right.Scale(2)), 0.000001, "scene3d racing line lateral offset")
	_, err = track.PoseOnLine("missing", 50)
	assert(err != nil, "scene3d racing line missing name errors")
	respawn := track.RespawnPoseNear(voplay.Vec3{X: 90, Y: 0, Z: -95})
	assertFloatNear(respawn.Distance, 180, 0.000001, "scene3d respawn near picks closest respawn")
	lastDistance := -1.0
	for i := 0; i < 80; i++ {
		d := float64(i)
		pose := track.PoseAt(d)
		along := track.DistanceAlongTrack(pose.Position)
		assert(along >= lastDistance, "scene3d distance along track is monotonic")
		lastDistance = along
	}
	querySum := 0.0
	for i := 0; i < 10000; i++ {
		p := voplay.Vec3{X: float64(i % 100), Y: 0, Z: -float64(i % 80)}
		querySum += track.ClosestPoint(p).Distance
	}
	assert(querySum > 0, "scene3d closest point benchmark loop returns data")
	badVersion := *asset
	badVersion.Version = 7
	assert(trackIssuesHaveCode(scene3d.ValidateTrackAsset(&badVersion), "track.version"), "scene3d track rejects unsupported version")
	badWidth := *asset
	badWidth.Centerline = append([]scene3d.TrackControlPoint{}, asset.Centerline...)
	badWidth.Centerline[1].Width = 0
	assert(trackIssuesHaveCode(scene3d.ValidateTrackAsset(&badWidth), "track.centerline.width"), "scene3d track rejects invalid width")
	badLoop := *asset
	badLoop.Centerline = append([]scene3d.TrackControlPoint{}, asset.Centerline...)
	badLoop.Centerline[len(badLoop.Centerline) - 1].Position = scene3d.MapVec3{X: 12, Y: 0, Z: 0}
	assert(trackIssuesHaveCode(scene3d.ValidateTrackAsset(&badLoop), "track.centerline.closed_loop"), "scene3d track rejects open closed-loop endpoints")
	badGates := *asset
	badGates.Gates = append([]scene3d.TrackGate{}, asset.Gates...)
	badGates.Gates[2].Distance = 10
	assert(trackIssuesHaveCode(scene3d.ValidateTrackAsset(&badGates), "track.gate.order"), "scene3d track rejects unordered gates")
	badMeshes := *asset
	badMeshes.Meshes = []scene3d.TrackMesh{{Name: "road", Model: "road.glb"}, {Name: "road", Model: "road_collision.glb"}}
	assert(trackIssuesHaveCode(scene3d.ValidateTrackAsset(&badMeshes), "track.mesh.duplicate"), "scene3d track rejects duplicate mesh names")
	badSurface := *asset
	badSurface.Surfaces = append([]scene3d.TrackSurface{}, asset.Surfaces...)
	badSurface.Surfaces[0].Left = 8
	badSurface.Surfaces[0].Right = 2
	assert(trackIssuesHaveCode(scene3d.ValidateTrackAsset(&badSurface), "track.surface.lateral"), "scene3d track rejects invalid surface bounds")
	badSpawns := *asset
	badSpawns.Spawns = []scene3d.TrackSpawn{{Name: "player_start", Distance: 0}, {Name: "player_start", Distance: 4}}
	assert(trackIssuesHaveCode(scene3d.ValidateTrackAsset(&badSpawns), "track.spawn.duplicate"), "scene3d track rejects duplicate spawn names")
	badTrigger := *asset
	badTrigger.Triggers = []scene3d.TrackTrigger{{Name: "lap", Distance: 0, Radius: -1}}
	assert(trackIssuesHaveCode(scene3d.ValidateTrackAsset(&badTrigger), "track.trigger.kind"), "scene3d track rejects invalid trigger kind")
	badLine := *asset
	badLine.RacingLines = []scene3d.TrackRacingLine{{Name: "bad", Points: []scene3d.TrackRacingLinePoint{{Distance: 20}, {Distance: 10}}}}
	assert(trackIssuesHaveCode(scene3d.ValidateTrackAsset(&badLine), "track.racing_line.order"), "scene3d track rejects unordered racing line")
	badFinite := *asset
	badFinite.Centerline = append([]scene3d.TrackControlPoint{}, asset.Centerline...)
	badFinite.Centerline[1].Position.X = math.Inf(1)
	assert(trackIssuesHaveCode(scene3d.ValidateTrackAsset(&badFinite), "track.vec3.finite"), "scene3d track rejects non-finite positions")
	badElementName := *asset
	badElementName.Surfaces = append([]scene3d.TrackSurface{}, asset.Surfaces...)
	badElementName.Surfaces[0].Name = "finish"
	assert(trackIssuesHaveCode(scene3d.ValidateTrackAsset(&badElementName), "track.element.duplicate"), "scene3d track rejects duplicate names across element types")
	badGateRange := *asset
	badGateRange.Gates = append([]scene3d.TrackGate{}, asset.Gates...)
	badGateRange.Gates[2].Distance = 999
	assert(trackIssuesHaveCode(scene3d.ValidateTrackAsset(&badGateRange), "track.gate.distance_range"), "scene3d track rejects gate outside track length")
	badRespawn := *asset
	badRespawn.Respawns = append([]scene3d.TrackRespawn{}, asset.Respawns...)
	badRespawn.Respawns[0].Position = scene3d.MapVec3{X: 40, Y: 0, Z: -10}
	assert(trackIssuesHaveCode(scene3d.ValidateTrackAsset(&badRespawn), "track.respawn.offroad"), "scene3d track rejects offroad respawn")
	warningOnly := *asset
	warningOnly.Spawns = nil
	warningOnly.Respawns = nil
	issues = scene3d.ValidateTrackAsset(&warningOnly)
	assert(trackIssuesHaveCode(issues, "track.spawn.missing"), "scene3d track reports missing spawn warning")
	assert(trackIssuesHaveCode(issues, "track.respawn.missing"), "scene3d track reports missing respawn warning")
	assert(!trackIssuesHaveSeverity(issues, scene3d.TrackIssueError), "scene3d warning-only track has no errors")
	_, err = scene3d.NewTrack(&warningOnly)
	assert(err == nil, "scene3d warning-only track can spawn runtime track")
}

func testScene3DTrackAssetFilesystemLoading() {
	dir, err := os.MkdirTemp("", "voplay-track-fs-")
	assert(err == nil, "scene3d track fs temp dir")
	defer os.RemoveAll(dir)
	err = os.WriteFile(filepath.Join([]string{dir, "height.png"}), []byte("height"), 0644)
	assert(err == nil, "scene3d track fs height")
	err = os.WriteFile(filepath.Join([]string{dir, "grass.png"}), []byte("grass"), 0644)
	assert(err == nil, "scene3d track fs texture")
	err = os.WriteFile(filepath.Join([]string{dir, "road.glb"}), []byte("road"), 0644)
	assert(err == nil, "scene3d track fs road mesh")
	err = os.WriteFile(filepath.Join([]string{dir, "road_collision.glb"}), []byte("collision"), 0644)
	assert(err == nil, "scene3d track fs collision mesh")
	validPath := filepath.Join([]string{dir, "track.json"})
	validJSON := `{"version":1,"name":"fs oval","closedLoop":true,"terrain":{"heightmap":"height.png","texture":"grass.png","width":20,"height":3,"depth":20},"meshes":[{"name":"road","model":"road.glb","collision":"trimesh","collisionModel":"road_collision.glb"}],"centerline":[{"position":{"x":0,"y":0,"z":0},"width":10},{"position":{"x":0,"y":0,"z":-100},"width":10},{"position":{"x":100,"y":0,"z":-100},"width":10},{"position":{"x":100,"y":0,"z":0},"width":10},{"position":{"x":0,"y":0,"z":0},"width":10}],"surfaces":[{"name":"road_main","kind":"road","start":0,"end":400,"left":-5,"right":5,"friction":1}],"gates":[{"name":"start","distance":0,"width":10},{"name":"back","distance":180,"width":10}],"spawns":[{"name":"spawn","distance":0}],"respawns":[{"name":"respawn","distance":0}]}`
	err = os.WriteFile(validPath, []byte(validJSON), 0644)
	assert(err == nil, "scene3d track fs valid json write")
	asset, err := scene3d.LoadTrackAsset(validPath)
	assert(err == nil, "scene3d LoadTrackAsset loads valid filesystem track")
	assert(asset.Name == "fs oval", "scene3d LoadTrackAsset preserves name")
	track, err := scene3d.NewTrack(asset)
	assert(err == nil, "scene3d LoadTrackAsset result creates runtime track")
	assertFloatNear(track.Length(), 400, 0.000001, "scene3d filesystem track length")
	badVersionPath := filepath.Join([]string{dir, "bad_version.json"})
	err = os.WriteFile(badVersionPath, []byte(strings.Replace(validJSON, `"version":1`, `"version":7`, 1)), 0644)
	assert(err == nil, "scene3d track fs bad version json write")
	_, err = scene3d.LoadTrackAsset(badVersionPath)
	assert(err != nil && strings.Contains(err.Error(), "7"), "scene3d LoadTrackAsset unsupported version includes version number")
	missingPath := filepath.Join([]string{dir, "missing_resource.json"})
	err = os.WriteFile(missingPath, []byte(strings.Replace(validJSON, `"heightmap":"height.png"`, `"heightmap":"missing_height.png"`, 1)), 0644)
	assert(err == nil, "scene3d track fs missing resource json write")
	_, err = scene3d.LoadTrackAsset(missingPath)
	assert(err != nil && strings.Contains(err.Error(), "missing_height.png"), "scene3d LoadTrackAsset missing resource includes path")
	duplicatePath := filepath.Join([]string{dir, "duplicate_mesh.json"})
	duplicateJSON := strings.Replace(validJSON, `],"centerline"`, `,{"name":"road","model":"road.glb"}],"centerline"`, 1)
	err = os.WriteFile(duplicatePath, []byte(duplicateJSON), 0644)
	assert(err == nil, "scene3d track fs duplicate json write")
	_, err = scene3d.LoadTrackAsset(duplicatePath)
	assert(err != nil && strings.Contains(err.Error(), "duplicate mesh name: road"), "scene3d LoadTrackAsset duplicate name includes duplicate")
	badGatePath := filepath.Join([]string{dir, "bad_gate.json"})
	badGateJSON := strings.Replace(validJSON, `"back","distance":180`, `"back","distance":0`, 1)
	err = os.WriteFile(badGatePath, []byte(badGateJSON), 0644)
	assert(err == nil, "scene3d track fs gate json write")
	_, err = scene3d.LoadTrackAsset(badGatePath)
	assert(err != nil && strings.Contains(err.Error(), "strictly increasing"), "scene3d LoadTrackAsset gate order error is deterministic")
}

func testScene3DTrackBakeContract() {
	asset := newScene3DTestTrackAsset()
	asset.Terrain.Texture = "grass.png"
	asset.Meshes = []scene3d.TrackMesh{{Name: "road", Model: "road.glb", Collision: "none"}, {Name: "road_collision", Model: "road_collision.glb", Collision: "trimesh", Hidden: true}}
	out := scene3d.BuildTrackBakeOutput("tracks/oval/track.json", asset)
	assert(out.TrackPath == "tracks/oval/track.json", "scene3d bake track path")
	assert(out.GeneratedManifestPath == scene3d.TrackBakeManifestPath, "scene3d bake manifest path")
	assert(out.HasTerrain, "scene3d bake requires terrain")
	assert(out.HasVisualTrackMesh, "scene3d bake requires visual track mesh")
	assert(out.HasCollisionTrackMesh, "scene3d bake requires collision track mesh")
	assert(out.HasSurfaceMetadata, "scene3d bake requires surface metadata")
	assert(out.HasGateMetadata, "scene3d bake requires gate metadata")
	assert(out.HasRespawnMetadata, "scene3d bake requires respawn metadata")
	issues := scene3d.ValidateTrackBakeOutput(asset, out)
	assert(!trackHasErrorsLocal(issues), "scene3d bake output validates")
	deps := scene3d.TrackBakeDependencies(out, "tracks/oval/track.json")
	assert(len(deps) == 4, "scene3d bake track dependency count")
	assert(stringSliceHas(deps, "tracks/oval/height.png"), "scene3d bake deps include heightmap")
	assert(stringSliceHas(deps, "tracks/oval/grass.png"), "scene3d bake deps include terrain texture")
	assert(stringSliceHas(deps, "tracks/oval/road.glb"), "scene3d bake deps include visual mesh")
	assert(stringSliceHas(deps, "tracks/oval/road_collision.glb"), "scene3d bake deps include collision mesh")
	dataA, err := scene3d.MarshalBakedTrackAsset(asset)
	assert(err == nil, "scene3d bake marshal A")
	dataB, err := scene3d.MarshalBakedTrackAsset(asset)
	assert(err == nil, "scene3d bake marshal B")
	assert(string(dataA) == string(dataB), "scene3d bake JSON is deterministic")
	err = scene3d.EnsureBakedTrackJSONStable(asset)
	assert(err == nil, "scene3d bake stable helper")
	bad := out
	bad.GeneratedManifestPath = ""
	issues = scene3d.ValidateTrackBakeOutput(asset, bad)
	assert(trackIssuesHaveCode(issues, "track.bake.manifest"), "scene3d bake rejects missing manifest")
}

