	h, ok := result.HeightProbe()(voplay.Vec3{})
	assert(ok && h == 0.1, "scene3d track terrain chunks height probe uses first visible chunk")
	result.Terrain.Entity().Visible = false
	h, ok = result.HeightProbe()(voplay.Vec3{})
	assert(ok && h == 0.2, "scene3d track terrain chunks height probe skips hidden chunk")
	result.TerrainChunks[1].Entity().Visible = false
