	assert(len(freed.items) == 2, "scene3d track terrain chunks frees owned terrain models")
	s.Close()
}

func stringSliceHas(values []string, want string) bool {
	for _, v := range values {
		if v == want {
			return true
		}
	}
	return false
}

func trackHasErrorsLocal(issues []scene3d.TrackIssue) bool {
	for _, issue := range issues {
		if issue.Severity == scene3d.TrackIssueError {
			return true
		}
	}
	return false
}

