	packPath := filepath.Join([]string{packDir, "track.vpak"})
	writeTestTrackPack(packPath, false)
	err = assets.Mount(packPath, 0)
	assert(err == nil, "scene3d track pack mount")
	assets.BeginGroup("track")
	s = scene3d.New()
	packed, err := scene3d.LoadTrackWithAssets(s, assets, "tracks/oval/track.json")
	assert(err == nil, "scene3d track loads from mounted vopack")
	assert(packed.Terrain != nil, "scene3d packed track creates terrain")
	assert(packed.Meshes["road"] != nil, "scene3d packed track creates visual mesh")
	assert(packed.CollisionMeshes["road"] != nil, "scene3d packed track creates collision mesh")
	assert(packed.Meshes["road"].Visible, "scene3d packed track visual mesh is visible")
	assert(!packed.CollisionMeshes["road"].Visible, "scene3d packed track collision mesh is hidden")
	assert(len(packed.Entities) == 3, "scene3d packed track entity count")
	packed.Destroy(s)
	assert(s.EntityCount() == 0, "scene3d packed track destroy removes all entities")
	assert(stats.modelFrees == 0 && stats.textureFrees == 0, "scene3d packed track destroy leaves asset group ownership")
	s.Close()
	assets.EndGroup()
	assets.ReleaseGroup("track")
	assert(stats.modelFrees == 2, "scene3d packed track asset group frees visual and collision models")
	assert(stats.textureFrees == 1, "scene3d packed track asset group frees terrain texture")
	stats = &assetRuntimeStats{}
	assets = voplay.NewAssetsWithLoaders(newMockAssetLoaders(stats))
	brokenPackPath := filepath.Join([]string{packDir, "broken-track.vpak"})
	writeTestTrackPack(brokenPackPath, true)
	err = assets.Mount(brokenPackPath, 0)
	assert(err == nil, "scene3d broken track pack mount")
	assets.BeginGroup("broken-track")
	s = scene3d.New()
	_, err = scene3d.LoadTrackWithAssets(s, assets, "tracks/oval/track.json")
	assert(err != nil, "scene3d packed track missing resource errors")
	assert(s.EntityCount() == 0, "scene3d packed track failed spawn rolls back entities")
	s.Close()
	assets.EndGroup()
	assets.ReleaseGroup("broken-track")
	issues := scene3d.CheckTrackTraversability(track, scene3d.TrackTraversabilityOptions{SampleStep: 10, MaxHeightDelta: 1, MaxSegmentLength: 120})
	assert(!trackIssuesHaveCode(issues, "track.traversability.height_delta"), "scene3d traversability accepts flat track")
	brokenAsset := newScene3DTestTrackAsset()
	brokenAsset.Centerline[1].Position.Y = 20
	broken, err := scene3d.NewTrack(brokenAsset)
	assert(err == nil, "scene3d broken traversability track still loads")
	issues = scene3d.CheckTrackTraversability(broken, scene3d.TrackTraversabilityOptions{SampleStep: 1, MaxHeightDelta: 0.1, MaxSegmentLength: 120})
	assert(trackIssuesHaveCode(issues, "track.traversability.height_delta"), "scene3d traversability catches height discontinuity")
	boundaryAsset := newScene3DTestTrackAsset()
	boundaryAsset.Centerline[1].Width = 100
	boundaryTrack, err := scene3d.NewTrack(boundaryAsset)
	assert(err == nil, "scene3d boundary traversability track still loads")
	issues = scene3d.CheckTrackTraversability(boundaryTrack, scene3d.TrackTraversabilityOptions{SampleStep: 100, MaxHeightDelta: 1, MaxSegmentLength: 120, MaxBoundaryDelta: 20})
	assert(trackIssuesHaveCode(issues, "track.traversability.boundary_gap"), "scene3d traversability catches road boundary discontinuity")
	offroadAsset := newScene3DTestTrackAsset()
	offroadAsset.Surfaces = append(offroadAsset.Surfaces, scene3d.TrackSurface{Name: "mud_center", Kind: scene3d.TrackSurfaceOffroad, Start: 0, End: 10, Left: -2, Right: 2, Priority: 100, Friction: 0.2})
	offroadAsset.Spawns = nil
	offroadAsset.Respawns = nil
	offroadTrack, err := scene3d.NewTrack(offroadAsset)
	assert(err == nil, "scene3d offroad traversability track still loads")
	issues = scene3d.CheckTrackTraversability(offroadTrack, scene3d.TrackTraversabilityOptions{SampleStep: 5, MaxHeightDelta: 1, MaxSegmentLength: 120})
	assert(trackIssuesHaveCode(issues, "track.traversability.centerline_offroad"), "scene3d traversability catches offroad centerline sample")
	assert(trackIssuesHaveCode(issues, "track.traversability.gate_offroad"), "scene3d traversability catches unreachable gate")
	issues = scene3d.CheckTrackTraversability(track, scene3d.TrackTraversabilityOptions{SampleStep: 25, MaxHeightDelta: 1, MaxSegmentLength: 120, HeightProbe: func(pos voplay.Vec3) (float64, bool) {
		return pos.Y, true
	}})
	assert(!trackIssuesHaveCode(issues, "track.traversability.height_probe_miss"), "scene3d traversability accepts height probe hits")
	issues = scene3d.CheckTrackTraversability(track, scene3d.TrackTraversabilityOptions{SampleStep: 25, MaxHeightDelta: 1, MaxSegmentLength: 120, HeightProbe: func(pos voplay.Vec3) (float64, bool) {
		return 0, false
	}})
	assert(trackIssuesHaveCode(issues, "track.traversability.height_probe_miss"), "scene3d traversability catches height probe misses")
	issues = scene3d.CheckTrackTraversability(track, scene3d.TrackTraversabilityOptions{SampleStep: 25, MaxHeightDelta: 1, MaxSegmentLength: 120, MaxHeightProbeDelta: 0.1, HeightProbe: func(pos voplay.Vec3) (float64, bool) {
		return pos.Y + 2, true
	}})
	assert(trackIssuesHaveCode(issues, "track.traversability.height_probe_delta"), "scene3d traversability catches height probe deltas")
}

func writeTestTrackPack(path string, missingCollision bool) {
	w, err := vopack.Create(path)
	assert(err == nil, "scene3d track pack create")
	w.SetManifestInfo("voplay-test-track", "1")
	trackJSON := `{"version":1,"name":"packed oval","closedLoop":true,"terrain":{"heightmap":"height.png","texture":"grass.png","width":20,"height":3,"depth":20},"meshes":[{"name":"road","model":"road.glb","collision":"trimesh","collisionModel":"road_collision.glb"}],"centerline":[{"position":{"x":0,"y":0,"z":0},"width":10},{"position":{"x":0,"y":0,"z":-100},"width":10},{"position":{"x":100,"y":0,"z":-100},"width":10},{"position":{"x":100,"y":0,"z":0},"width":10},{"position":{"x":0,"y":0,"z":0},"width":10}],"surfaces":[{"name":"road_main","kind":"road","start":0,"end":400,"left":-5,"right":5,"friction":1}],"gates":[{"name":"start","distance":0,"width":10},{"name":"back","distance":180,"width":10}],"spawns":[{"name":"spawn","distance":0}],"respawns":[{"name":"respawn","distance":0}]}`
	err = w.Add("tracks/oval/track.json", []byte(trackJSON), vopack.EntryOpts{Type: "track", Dependencies: []string{"tracks/oval/height.png", "tracks/oval/grass.png", "tracks/oval/road.glb", "tracks/oval/road_collision.glb"}})
	assert(err == nil, "scene3d track pack add track")
	err = w.Add("tracks/oval/height.png", []byte("height"), vopack.EntryOpts{})
	assert(err == nil, "scene3d track pack add height")
	err = w.Add("tracks/oval/grass.png", []byte("grass"), vopack.EntryOpts{})
	assert(err == nil, "scene3d track pack add texture")
	err = w.Add("tracks/oval/road.glb", []byte("road"), vopack.EntryOpts{})
	assert(err == nil, "scene3d track pack add visual mesh")
	if !missingCollision {
		err = w.Add("tracks/oval/road_collision.glb", []byte("collision"), vopack.EntryOpts{})
		assert(err == nil, "scene3d track pack add collision mesh")
	}
	err = w.Close()
	assert(err == nil, "scene3d track pack close")
}

func makeRaycastVehicleState() []byte {
	return makeRaycastVehicleStateWith(12.5, voplay.Vec3{X: 0, Y: 0.2, Z: -20}, voplay.Vec3{X: 0, Y: 0, Z: -20}, 0.28, -0.2, 1.25)
}

func makeRaycastVehicleStateWith(speed float64, center voplay.Vec3, contact voplay.Vec3, suspensionLength float64, steering float64, rotation float64) []byte {
	w := codec.NewByteWriter(128)
	w.WriteF64(speed)
	w.WriteU32(1)
	w.WriteBool(true)
	w.WriteF64(center.X)
	w.WriteF64(center.Y)
	w.WriteF64(center.Z)
	w.WriteF64(contact.X)
	w.WriteF64(contact.Y)
	w.WriteF64(contact.Z)
	w.WriteF64(0)
	w.WriteF64(1)
	w.WriteF64(0)
	w.WriteF64(suspensionLength)
	w.WriteF64(steering)
	w.WriteF64(rotation)
	return w.Bytes()
}

func makeBadRaycastVehicleState() []byte {
	w := codec.NewByteWriter(128)
	w.WriteF64(math.NaN())
	w.WriteU32(99)
	w.WriteBool(true)
	w.WriteF64(math.Inf(1))
	w.WriteF64(0.2)
	w.WriteF64(-20)
	w.WriteF64(0)
	w.WriteF64(0)
	w.WriteF64(-20)
	w.WriteF64(0)
	w.WriteF64(math.NaN())
	w.WriteF64(0)
	w.WriteF64(math.Inf(1))
	w.WriteF64(math.NaN())
	w.WriteF64(math.Inf(-1))
	return w.Bytes()
}

func makePhysicsBodyState(bodyID int, position voplay.Vec3, rotation voplay.Quat, velocity voplay.Vec3) []byte {
	return makePhysicsBodyStateWithAngular(bodyID, position, rotation, velocity, voplay.Vec3{})
}

func makePhysicsBodyStateWithAngular(bodyID int, position voplay.Vec3, rotation voplay.Quat, velocity voplay.Vec3, angularVelocity voplay.Vec3) []byte {
	w := codec.NewByteWriter(128)
	w.WriteU32(1)
	w.WriteU32(bodyID)
	w.WriteF64(position.X)
	w.WriteF64(position.Y)
	w.WriteF64(position.Z)
	w.WriteF64(rotation.X)
	w.WriteF64(rotation.Y)
	w.WriteF64(rotation.Z)
	w.WriteF64(rotation.W)
	w.WriteF64(velocity.X)
	w.WriteF64(velocity.Y)
	w.WriteF64(velocity.Z)
	w.WriteF64(angularVelocity.X)
	w.WriteF64(angularVelocity.Y)
	w.WriteF64(angularVelocity.Z)
	return w.Bytes()
}

func sumEngineForce(controls []testVehicleControl) float64 {
	total := 0.0
	for _, control := range controls {
		total += control.engineForce
	}
	return total
}

func maxAbsSteering(controls []testVehicleControl) float64 {
	best := 0.0
	for _, control := range controls {
		v := control.steering
		if v < 0 {
			v = -v
		}
		if v > best {
			best = v
		}
	}
	return best
}

func assertKartStateFinite(state scene3d.KartControllerState, label string) {
	assertFiniteFloat(state.SurfaceFriction, label + ": surface friction")
	assertFiniteFloat(state.DriftCharge, label + ": drift charge")
	assertFiniteFloat(state.Speed, label + ": speed")
}

func assertVehicleTelemetryFinite(vehicle *scene3d.Vehicle, label string) {
	assert(vehicle != nil, label + ": vehicle")
	assertFiniteFloat(vehicle.Speed, label + ": speed")
	assertFiniteFloat(vehicle.Yaw, label + ": yaw")
	assertFiniteVec3(vehicle.GroundNormal, label + ": ground normal")
	assertFiniteVec3(vehicle.GroundPoint, label + ": ground point")
	for i := 0; i < vehicle.WheelCount(); i++ {
		state, ok := vehicle.WheelState(i)
		assert(ok, label + ": wheel state")
		assertFiniteVec3(state.Center, label + ": wheel center")
		assertFiniteVec3(state.ContactPoint, label + ": wheel contact")
		assertFiniteVec3(state.ContactNormal, label + ": wheel normal")
		assertFiniteFloat(state.SuspensionLength, label + ": suspension length")
		assertFiniteFloat(state.SuspensionCompression, label + ": suspension compression")
		assertFiniteFloat(state.Steering, label + ": steering")
		assertFiniteFloat(state.Rotation, label + ": rotation")
		assertFiniteFloat(state.NormalLoad, label + ": normal load")
		assertFiniteFloat(state.LongitudinalSlip, label + ": longitudinal slip")
		assertFiniteFloat(state.LateralSlip, label + ": lateral slip")
	}
}

func testScene3DVehicleTelemetryAndKartController() {
	pb := &testScene3DPhysicsBackend{vehicleState: makeRaycastVehicleState()}
	prevPhys := scene3d.SetPhysicsBackend(pb)
	defer scene3d.SetPhysicsBackend(prevPhys)
	track, err := scene3d.NewTrack(newScene3DTestTrackAsset())
	assert(err == nil, "scene3d vehicle telemetry track err")
	s := scene3d.New()
	body := s.Spawn(scene3d.EntityDesc{Position: voplay.Vec3{Y: 1}, Physics: &scene3d.Physics{Type: scene3d.Dynamic, Collider: scene3d.Box(1, 0.5, 1), Layer: voplay.CollisionLayerDefault, Mask: voplay.CollisionMaskAll}})
	config := scene3d.DefaultKartVehicleConfig()
	config.Wheels = config.Wheels[:1]
	vehicle := scene3d.NewVehicle(body, config)
	vehicle.BindTrack(track)
	assert(vehicle.WheelCount() == 1, "scene3d vehicle wheel count before sync")
	vehicle.Update(scene3d.VehicleInput{Throttle: 1, Steer: 1}, 1.0 / 60.0)
	assert(len(pb.vehicleControls) > 0, "scene3d vehicle sends wheel controls")
	assert(pb.vehicleControls[0].steering < 0, "scene3d right steer uses backend sign convention")
	state, ok := vehicle.WheelState(0)
	assert(ok, "scene3d vehicle wheel state exists")
	assert(state.InContact, "scene3d vehicle wheel state contact")
	assert(state.Steering > 0, "scene3d wheel telemetry reports voplay right steer positive")
	assertFloatNear(state.SuspensionCompression, 0.5, 0.000001, "scene3d vehicle suspension compression")
	assert(state.NormalLoad > 0, "scene3d vehicle normal load approximated")
	assert(state.LongitudinalSlip > 0, "scene3d vehicle longitudinal slip approximated")
	assert(state.SurfaceID == scene3d.TrackSurfaceRoad || state.SurfaceID == "boost_lane", "scene3d vehicle wheel surface id")
	pb.bodyState = makePhysicsBodyState(body.ID(), body.Position(), body.Rotation(), voplay.Vec3{X: 4, Z: -12})
	pb.vehicleState = makeRaycastVehicleStateWith(12, voplay.Vec3{Y: 0.2, Z: -20}, voplay.Vec3{Z: -20}, 0.28, 0, 18)
	s.StepAndSyncPhysics(1.0 / 60.0)
	state, ok = vehicle.WheelState(0)
	assert(ok, "scene3d vehicle wheel state exists after physics sync")
	assert(state.LateralSlip > 3.9 && state.LateralSlip < 4.1, "scene3d vehicle lateral slip approximated from body velocity")
	assert(state.LongitudinalSlip > 3.6 && state.LongitudinalSlip < 3.8, "scene3d vehicle longitudinal slip uses body local velocity")
	debugSnapshot := scene3d.BuildVehicleDebugSnapshot(vehicle, track)
	assertFiniteFloat(debugSnapshot.Speed, "scene3d vehicle debug snapshot speed")
	assert(debugSnapshot.Grounded, "scene3d vehicle debug snapshot grounded")
	assert(debugSnapshot.Surface.OnSurface, "scene3d vehicle debug snapshot surface")
	assert(len(debugSnapshot.Wheels) == 1, "scene3d vehicle debug snapshot wheel count")
	assert(debugSnapshot.Wheels[0].LateralSlip > 3.9 && debugSnapshot.Wheels[0].LateralSlip < 4.1, "scene3d vehicle debug snapshot slip")
	racingOverlay, err := scene3d.SpawnRacingDebugOverlay(s, track, vehicle, scene3d.RacingDebugOptions{Model: voplay.ModelID(405), SurfaceMarker: true})
	assert(err == nil, "scene3d racing debug overlay spawns")
	assert(racingOverlay.TrackOverlay != nil && len(racingOverlay.TrackOverlay.Entities) > 0, "scene3d racing debug overlay track layer")
	assert(racingOverlay.VehicleOverlay != nil && len(racingOverlay.VehicleOverlay.Entities) == 2, "scene3d racing debug overlay vehicle layer")
	assert(racingOverlay.SurfaceEntity != nil && racingOverlay.SurfaceEntity.Visible, "scene3d racing debug overlay surface marker")
	debugSnapshot = racingOverlay.Update(s)
	assert(len(debugSnapshot.Wheels) == 1, "scene3d racing debug overlay update returns snapshot")
	surfaceMarker := racingOverlay.SurfaceEntity
	racingOverlay.Destroy(s)
	assert(!surfaceMarker.Active, "scene3d racing debug overlay destroys surface marker")
	racingOverlay.Destroy(s)
	pb.vehicleState = makeBadRaycastVehicleState()
	vehicle.Update(scene3d.VehicleInput{Throttle: 1}, 1.0 / 60.0)
	state, ok = vehicle.WheelState(0)
	assert(ok, "scene3d vehicle bad backend state still decodes one safe wheel")
	assert(vehicle.WheelCount() == 1, "scene3d vehicle bad backend count is capped")
	assertFiniteFloat(vehicle.Speed, "scene3d vehicle speed sanitized")
	assertFiniteVec3(state.Center, "scene3d vehicle wheel center sanitized")
	assertFiniteVec3(state.ContactNormal, "scene3d vehicle wheel normal sanitized")
	assertFiniteFloat(state.SuspensionLength, "scene3d vehicle suspension length sanitized")
	assertFiniteFloat(state.Steering, "scene3d vehicle steering sanitized")
	assertFiniteFloat(state.Rotation, "scene3d vehicle rotation sanitized")
	assertFiniteFloat(state.NormalLoad, "scene3d vehicle normal load sanitized")
	overlay, err := scene3d.SpawnVehicleDebugOverlay(s, vehicle, scene3d.VehicleDebugOptions{Model: voplay.ModelID(404)})
	assert(err == nil, "scene3d vehicle debug overlay spawns")
	assert(len(overlay.Entities) == 2, "scene3d vehicle debug overlay entity count")
	overlay.Update(s)
	assert(overlay.Entities[0].Visible, "scene3d vehicle debug overlay contact visible")
	assert(overlay.Entities[1].Visible, "scene3d vehicle debug overlay suspension visible")
	overlay.Destroy(s)
	overlay.Destroy(s)
	vehicle.SetPose(voplay.Vec3{Y: 1}, 0)
	pb.vehicleControls = nil
	pb.vehicleState = makeRaycastVehicleState()
	vehicle.Update(scene3d.VehicleInput{Throttle: 1, Steer: -1}, 1.0 / 60.0)
	assert(len(pb.vehicleControls) > 0, "scene3d vehicle sends left steer controls")
	assert(pb.vehicleControls[0].steering > 0, "scene3d left steer uses backend sign convention")
	pb.vehicleState = nil
	vehicle.Update(scene3d.VehicleInput{Throttle: 1}, 1.0 / 60.0)
	assert(vehicle.WheelCount() == 1, "scene3d vehicle missing state keeps configured wheel count")
	kart := scene3d.NewKartController(vehicle, track, scene3d.KartControllerConfig{})
	kart.ActivateBoost(0.5)
	kstate := kart.Update(scene3d.KartInput{Throttle: 1, Steer: 0.5}, 1.0 / 60.0)
	assert(kstate.Boosting, "scene3d kart controller boosting state")
	kart.Respawn(track.PoseAt(0))
	assertFloatNear(kart.BoostTimer, 0, 0.000001, "scene3d kart respawn clears boost")
	vehicle.Destroy()
	assert(len(pb.destroyVehicles) == 1, "scene3d vehicle destroy releases backend vehicle")
	_, ok = vehicle.WheelState(0)
	assert(!ok, "scene3d vehicle wheel state unavailable after destruction")
	s.Close()
}

func testScene3DKartControllerAcceptance() {
	pb := &testScene3DPhysicsBackend{vehicleState: makeRaycastVehicleStateWith(18, voplay.Vec3{Y: 0.2, Z: -20}, voplay.Vec3{Z: -20}, 0.28, 0, 12)}
	prevPhys := scene3d.SetPhysicsBackend(pb)
	defer scene3d.SetPhysicsBackend(prevPhys)
	track, err := scene3d.NewTrack(newScene3DTestTrackAsset())
	assert(err == nil, "scene3d kart acceptance track err")
	s := scene3d.New()
	body := s.Spawn(scene3d.EntityDesc{Position: voplay.Vec3{Y: 1, Z: -20}, Physics: &scene3d.Physics{Type: scene3d.Dynamic, Collider: scene3d.Box(1, 0.5, 1), Layer: voplay.CollisionLayerDefault, Mask: voplay.CollisionMaskAll}})
	config := scene3d.DefaultKartControllerConfig()
	config.Vehicle.MaxForwardSpeed = 30
	config.Vehicle.EngineForce = 6000
	config.Vehicle.BoostEngineForce = 2400
	config.Vehicle.DriftMinSpeed = 6
	config.MinTurboCharge = 0.2
	config.SuperTurboCharge = 0.8
	config.DriftChargeRate = 1.2
	config.BoostDuration = 0.35
	config.Recovery.StuckSeconds = 0.08
	config.Recovery.UpsideDownSeconds = 0.08
	vehicle := scene3d.NewVehicle(body, config.Vehicle)
	kart := scene3d.NewKartController(vehicle, track, config)
	pb.vehicleControls = nil
	roadState := kart.Update(scene3d.KartInput{Throttle: 1}, 1.0 / 60.0)
	assertKartStateFinite(roadState, "scene3d kart road state")
	roadForce := sumEngineForce(pb.vehicleControls)
	assert(roadState.SurfaceID == scene3d.TrackSurfaceRoad || roadState.SurfaceID == "boost_lane", "scene3d kart road surface id")
	assert(roadForce > 0, "scene3d kart road engine force")
	assertFloatNear(vehicle.Config.MaxForwardSpeed, config.Vehicle.MaxForwardSpeed, 0.000001, "scene3d kart road max speed")
	body.SetPosition(voplay.Vec3{X: -8, Y: 1, Z: -20})
	pb.vehicleState = makeRaycastVehicleStateWith(3, voplay.Vec3{X: -8, Y: 0.2, Z: -20}, voplay.Vec3{X: -8, Z: -20}, 0.28, 0, 3)
	pb.vehicleControls = nil
	grassState := kart.Update(scene3d.KartInput{Throttle: 1}, 1.0 / 60.0)
	assertKartStateFinite(grassState, "scene3d kart grass state")
	grassForce := sumEngineForce(pb.vehicleControls)
	assert(grassState.SurfaceID == "grass_left", "scene3d kart offroad surface id")
	assert(grassForce > 0 && grassForce < roadForce, "scene3d kart offroad engine force lower than road")
	assert(vehicle.Config.MaxForwardSpeed < config.Vehicle.MaxForwardSpeed, "scene3d kart offroad max speed lower than road")
	body.SetPosition(voplay.Vec3{Y: 1, Z: -20})
	pb.vehicleState = makeRaycastVehicleStateWith(3, voplay.Vec3{Y: 0.2, Z: -20}, voplay.Vec3{Z: -20}, 0.28, 0, 3)
	lowSpeedState := kart.Update(scene3d.KartInput{Throttle: 1, Steer: 1, Drift: true}, 1.0 / 60.0)
	assert(!lowSpeedState.Drifting, "scene3d kart drift blocked below minimum speed")
	pb.vehicleState = makeRaycastVehicleStateWith(18, voplay.Vec3{Y: 0.2, Z: -20}, voplay.Vec3{Z: -20}, 0.28, 0, 12)
	for i := 0; i < 20; i++ {
		_ = kart.Update(scene3d.KartInput{Throttle: 1, Steer: 1, Drift: true}, 1.0 / 60.0)
	}
	charged := kart.State()
	assert(charged.Drifting, "scene3d kart drift active above minimum speed")
	assert(charged.DriftCharge >= config.MinTurboCharge, "scene3d kart drift charges mini turbo")
	pb.vehicleControls = nil
	released := kart.Update(scene3d.KartInput{Throttle: 1, Steer: 1, Drift: false}, 1.0 / 60.0)
	assert(released.MiniTurboReleased || released.SuperTurboReleased, "scene3d kart releases turbo after charged drift")
	boostedAfterRelease := kart.Update(scene3d.KartInput{Throttle: 1}, 1.0 / 60.0)
	assert(boostedAfterRelease.Boosting, "scene3d kart boost active after turbo release")
	boostForce := sumEngineForce(pb.vehicleControls)
	assert(boostForce > roadForce, "scene3d kart boost increases engine force")
	kart.Respawn(track.PoseAt(0))
	assertFloatNear(kart.BoostTimer, 0, 0.000001, "scene3d kart acceptance respawn clears boost")
	assertFloatNear(kart.DriftCharge, 0, 0.000001, "scene3d kart acceptance respawn clears drift charge")
	assert(!kart.State().ShouldRespawn, "scene3d kart acceptance respawn clears state")
	body.SetPosition(voplay.Vec3{Y: -50})
	fallState := kart.Update(scene3d.KartInput{Throttle: 1}, 1.0 / 60.0)
	assert(fallState.ShouldRespawn, "scene3d kart fall below threshold requests respawn")
	body.SetPosition(voplay.Vec3{Y: 1, Z: -20})
	body.SetRotation(voplay.QuatFromAxisAngle(voplay.Vec3{X: 1}, math.Pi))
	upsideState := kart.Update(scene3d.KartInput{Throttle: 1}, 0.1)
	assert(upsideState.UpsideDown && upsideState.ShouldRespawn, "scene3d kart upside down requests respawn")
	body.SetRotation(voplay.QuatIdentity())
	pb.vehicleState = makeRaycastVehicleStateWith(0.1, voplay.Vec3{Y: 0.2, Z: -20}, voplay.Vec3{Z: -20}, 0.28, 0, 0)
	stuckState := kart.Update(scene3d.KartInput{Throttle: 1}, 0.1)
	assert(stuckState.Stuck && stuckState.ShouldRespawn, "scene3d kart stuck throttle requests respawn")
	kart.RespawnNear(voplay.Vec3{X: 99, Y: 2, Z: -99})
	assertFloatNear(vehicle.Speed, 0, 0.000001, "scene3d kart respawn near clears speed")
	assertFloatNear(vehicle.SteerAngle, 0, 0.000001, "scene3d kart respawn near clears steering")
	assert(!vehicle.Drifting, "scene3d kart respawn near clears drifting")
	assertVec3Near(body.Velocity(), voplay.Vec3{}, 0.000001, "scene3d kart respawn near clears cached velocity")
	assertVec3Near(body.AngularVelocity(), voplay.Vec3{}, 0.000001, "scene3d kart respawn near clears cached angular velocity")
	s.Close()
}

func testScene3DVehicleRecovery() {
	pb := &testScene3DPhysicsBackend{vehicleState: makeRaycastVehicleStateWith(0.1, voplay.Vec3{Y: 0.2}, voplay.Vec3{}, 0.28, 0, 0)}
	prevPhys := scene3d.SetPhysicsBackend(pb)
