	assert(err == nil, "scene3d vehicle recovery track err")
	s := scene3d.New()
	body := s.Spawn(scene3d.EntityDesc{Position: voplay.Vec3{Y: 1}, Physics: &scene3d.Physics{Type: scene3d.Dynamic, Collider: scene3d.Box(1, 0.5, 1), Layer: voplay.CollisionLayerDefault, Mask: voplay.CollisionMaskAll}})
	vehicle := scene3d.NewVehicle(body, scene3d.DefaultKartVehicleConfig())
	vehicle.BindTrack(track)
