	body.SetPosition(voplay.Vec3{Y: -20})
	state := recovery.Update(scene3d.VehicleRecoveryInput{Throttle: 1}, 1.0 / 60.0)
	assert(state.ShouldRespawn, "scene3d vehicle recovery fall requests respawn")
	body.SetPosition(voplay.Vec3{Y: 1})
	body.SetRotation(voplay.QuatFromAxisAngle(voplay.Vec3{X: 1}, math.Pi))
	state = recovery.Update(scene3d.VehicleRecoveryInput{Throttle: 1}, 0.1)
	assert(state.UpsideDown && state.ShouldRespawn, "scene3d vehicle recovery upside down requests respawn")
	body.SetRotation(voplay.QuatIdentity())
	vehicle.Speed = 0.05
	state = recovery.Update(scene3d.VehicleRecoveryInput{Throttle: 1}, 0.1)
	assert(state.Stuck && state.ShouldRespawn, "scene3d vehicle recovery stuck throttle requests respawn")
	body.SetVelocity(voplay.Vec3{X: 4})
	body.SetAngularVelocity(voplay.Vec3{Y: 8})
	vehicle.Speed = 12
	vehicle.SteerAngle = 0.4
	vehicle.Drifting = true
	recovery.RespawnNear(voplay.Vec3{X: 99, Y: 2, Z: -99})
