	assertFloatNear(vehicle.SteerAngle, 0, 0.000001, "scene3d vehicle recovery respawn clears steering")
	assert(!vehicle.Drifting, "scene3d vehicle recovery respawn clears drift state")
	assertVec3Near(body.Velocity(), voplay.Vec3{}, 0.000001, "scene3d vehicle recovery respawn clears linear velocity")
	assertVec3Near(body.AngularVelocity(), voplay.Vec3{}, 0.000001, "scene3d vehicle recovery respawn clears angular velocity")
	assert(track.IsOnRoad(body.Position()), "scene3d vehicle recovery respawn lands on road")
	assertVec3Near(vehicle.Forward(), track.RespawnPoseNear(voplay.Vec3{X: 99, Y: 2, Z: -99}).Forward, 0.000001, "scene3d vehicle recovery respawn aligns to track forward")
	recovery.Reset()
