	s.Close()
}

func testScene3DKartControllerSixtySecondStability() {
	pb := &testScene3DPhysicsBackend{}
	prevPhys := scene3d.SetPhysicsBackend(pb)
	defer scene3d.SetPhysicsBackend(prevPhys)
	track, err := scene3d.NewTrack(newScene3DTestTrackAsset())
	assert(err == nil, "scene3d kart stability track err")
	s := scene3d.New()
	pose := track.PoseAt(0)
	body := s.Spawn(scene3d.EntityDesc{Position: pose.Position.Add(voplay.Vec3{Y: 1}), Rotation: pose.Rotation, Physics: &scene3d.Physics{Type: scene3d.Dynamic, Collider: scene3d.Box(1, 0.5, 1), Layer: voplay.CollisionLayerDefault, Mask: voplay.CollisionMaskAll}})
	config := scene3d.DefaultKartControllerConfig()
	config.Vehicle.MaxForwardSpeed = 28
	config.Vehicle.EngineForce = 5200
	config.Vehicle.BoostEngineForce = 1800
	config.Vehicle.DriftMinSpeed = 5
	config.Recovery.StuckSeconds = 2.0
	config.Recovery.UpsideDownSeconds = 1.0
	vehicle := scene3d.NewVehicle(body, config.Vehicle)
	kart := scene3d.NewKartController(vehicle, track, config)
	dt := 1.0 / 60.0
	distance := 0.0
	speed := 0.0
	wheelRot := 0.0
	respawns := 0
	for frame := 0; frame < 3600; frame++ {
		pose = track.PoseAt(distance)
		steer := math.Sin(float64(frame) * 0.018) * 0.55
		drift := frame % 420 > 160 && frame % 420 < 250
		boost := frame % 900 == 120
		pb.bodyState = makePhysicsBodyState(body.ID(), pose.Position.Add(voplay.Vec3{Y: 1}), pose.Rotation, pose.Forward.Scale(speed))
		pb.vehicleState = makeRaycastVehicleStateWith(speed, pose.Position.Add(voplay.Vec3{Y: 0.25}), pose.Position, 0.32, -steer * config.Vehicle.MaxSteerAngle, wheelRot)
		s.StepAndSyncPhysics(dt)
		pb.vehicleControls = nil
		state := kart.Update(scene3d.KartInput{Throttle: 1, Steer: steer, Drift: drift, Boost: boost}, dt)
		assertKartStateFinite(state, "scene3d kart stability state")
		assertVehicleTelemetryFinite(vehicle, "scene3d kart stability telemetry")
		force := sumEngineForce(pb.vehicleControls)
		accel := force / 9000.0
		if force <= 0 {
			accel = -3.5
		}
		speed += accel * dt
		if speed > vehicle.Config.MaxForwardSpeed {
			speed = vehicle.Config.MaxForwardSpeed
		}
		if speed < 0 {
			speed = 0
		}
		distance += speed * dt
		wheelRot += speed / config.Vehicle.Wheels[0].Radius * dt
		if state.ShouldRespawn {
			respawns++
			kart.RespawnNear(pose.Position)
			speed = 0
		}
		assert(body.Position().Y > -10 && body.Position().Y < 10, "scene3d kart stability transform bounded")
	}
	assert(respawns == 0, "scene3d kart stability has no unrecovered respawns")
	assert(speed > 5, "scene3d kart stability reaches useful speed")
	s.Close()
}

