	pb := &testScene3DPhysicsBackend{}
	prevPhys := scene3d.SetPhysicsBackend(pb)
	defer scene3d.SetPhysicsBackend(prevPhys)
	s := scene3d.New()
	duplicateNodes := []scene3d.LevelNodeInfo{{Name: "spawn_player", ModelID: voplay.ModelID(501)}, {Name: "spawn_player", ModelID: voplay.ModelID(502)}}
