func testScene3DAnimationSemantics() {
	ab := &testAnimationBackend{}
	prevBackend := scene3d.SetAnimationBackend(ab)
	defer scene3d.SetAnimationBackend(prevBackend)
	s := scene3d.New()
	noModel := s.Spawn(scene3d.EntityDesc{Tag: "marker"})
	_, didPanic := capturePanic(func() {
		noModel.PlayAnimation(0, true)
	})
	assert(didPanic, "scene3d animation play without model panics")
	assert(ab.initCalls == 0, "scene3d invalid animation play does not init animation world")
	noSkeleton := s.Spawn(scene3d.EntityDesc{Model: voplay.ModelID(902), Tag: "no-skeleton"})
	_, didPanic = capturePanic(func() {
		noSkeleton.PlayAnimation(0, true)
	})
	assert(didPanic, "scene3d animation play without skeleton panics")
	assert(ab.initCalls == 0, "scene3d skeleton validation happens before animation world init")
	animated := s.Spawn(scene3d.EntityDesc{Model: voplay.ModelID(901), Tag: "animated"})
	drawCtx := voplay.NewDrawCtx()
	s.Draw(drawCtx)
	assert(ab.initCalls == 0, "scene3d draw rest pose does not init animation world")
	assertFloatNear(animated.AnimationProgress(), 0.0, 0.000001, "scene3d draw rest pose does not create animation progress state")
	assert(len(drawCtx.Bytes()) > 0, "scene3d draw rest pose writes skinned draw commands")
	_, didPanic = capturePanic(func() {
		animated.PlayAnimation(3, true)
	})
	assert(didPanic, "scene3d animation play invalid clip panics")
	assert(ab.initCalls == 0, "scene3d invalid clip does not init animation world")
	_, didPanic = capturePanic(func() {
		animated.CrossfadeTo(0, 0.1)
	})
	assert(didPanic, "scene3d crossfade without active animation state panics")
	_, didPanic = capturePanic(func() {
		animated.SetAnimationSpeed(1.5)
	})
	assert(didPanic, "scene3d set animation speed without active animation state panics")
	animated.PlayAnimation(1, true)
	assert(ab.initCalls == 1, "scene3d valid animation play inits animation world once")
	assert(ab.playWorld == 77, "scene3d animation play uses hooked world id")
	assert(ab.playTarget == 1, "scene3d animation play allocates first target id")
	assert(ab.playClip == 1, "scene3d animation play clip forwarded")
	assert(ab.playLoop, "scene3d animation play loop forwarded")
	assertFloatNear(ab.playSpeed, 1.0, 0.000001, "scene3d animation play default speed")
	assertFloatNear(animated.AnimationProgress(), 0.25, 0.000001, "scene3d animation progress uses hook")
	info := animated.AnimationModelInfo()
	assert(info.HasSkeleton, "scene3d animation model info has skeleton")
	assert(info.JointCount == 24, "scene3d animation model info joint count")
	assert(len(info.Clips) == 2, "scene3d animation model info clip count")
	animated.CrossfadeTo(0, 0.2)
	assert(ab.crossfadeWorld == 77, "scene3d crossfade uses hooked world id")
	assert(ab.crossfadeTarget == 1, "scene3d crossfade uses active target")
	assert(ab.crossfadeClip == 0, "scene3d crossfade clip forwarded")
	assertFloatNear(ab.crossfadeDur, 0.2, 0.000001, "scene3d crossfade duration forwarded")
	animated.SetAnimationSpeed(1.5)
	assert(ab.setSpeedWorld == 77, "scene3d set animation speed uses hooked world id")
	assert(ab.setSpeedTarget == 1, "scene3d set animation speed uses active target")
	assertFloatNear(ab.setSpeedValue, 1.5, 0.000001, "scene3d set animation speed value forwarded")
	s.TickAnimations(0.125)
	assert(ab.tickWorld == 77, "scene3d tick animations uses hooked world id")
	assertFloatNear(ab.tickDT, 0.125, 0.000001, "scene3d tick animations dt forwarded")
	assert(len(ab.tickBytes) == 12, "scene3d tick animations serializes active animated entity map")
	animated.StopAnimation()
	assert(ab.stopCalls == 1, "scene3d stop animation forwards to backend")
	s.Destroy(animated)
	assert(len(ab.removedTargets) == 1 && ab.removedTargets[0] == 1, "scene3d destroy removes animation target")
	s.Close()
	assert(len(ab.destroyWorlds) == 1 && ab.destroyWorlds[0] == 77, "scene3d close destroys animation world")
}

