	freed := &intList{}
	mb := &testFreeModelBackend{freed: freed}
	mb.prev = voplay.SetModelBackend(mb)
	defer voplay.SetModelBackend(mb.prev)
	pb := &testScene3DPhysicsBackend{panicOnSpawn: true}
	prevPhys := scene3d.SetPhysicsBackend(pb)
	defer scene3d.SetPhysicsBackend(prevPhys)
	s := scene3d.New()
	_, didPanic := capturePanic(func() {
		s.Spawn(scene3d.EntityDesc{OwnedModel: voplay.ModelID(701), Physics: &scene3d.Physics{Type: scene3d.Dynamic, Collider: scene3d.Box(1, 1, 1), Layer: voplay.CollisionLayerDefault, Mask: voplay.CollisionMaskAll}})
	})
	assert(didPanic, "scene3d spawn rollback panics on backend failure")
	assert(s.EntityCount() == 0, "scene3d spawn rollback leaves no entity behind")
	assert(!s.HasPhysics(), "scene3d spawn rollback destroys newly created physics world")
	assert(pb.initCalls == 1, "scene3d spawn rollback initializes physics once")
	assert(len(pb.destroyBodies) == 1 && pb.destroyBodies[0] == 1, "scene3d spawn rollback destroys allocated body")
	assert(len(pb.destroyWorlds) == 1 && pb.destroyWorlds[0] == 91, "scene3d spawn rollback destroys allocated world")
	assert(len(freed.items) == 1 && freed.items[0] == 701, "scene3d spawn rollback frees owned model")
	recovered := s.Spawn(scene3d.EntityDesc{Tag: "recovered"})
	assert(recovered.ID() == 1, "scene3d spawn rollback restores next entity id")
	s.Close()
	assert(len(pb.destroyWorlds) == 1, "scene3d close after rolled back spawn does not destroy absent world twice")
}

