func testScene3DPicking() {
	scene3DPickTestBounds = map[int]voplay.AABB{1: {Min: voplay.Vec3{X: -1, Y: -1, Z: -1}, Max: voplay.Vec3{X: 1, Y: 1, Z: 1}}, 2: {Min: voplay.Vec3{X: -1, Y: -1, Z: -1}, Max: voplay.Vec3{X: 1, Y: 1, Z: 1}}, 3: {Min: voplay.Vec3{X: -1, Y: -1, Z: -1}, Max: voplay.Vec3{X: 1, Y: 1, Z: 1}}}
	scene3DPickTestBoundsPresent = map[int]bool{1: true, 2: true, 3: true}
	scene3DPickTestBoundsCalls = 0
	prevBackend := voplay.SetModelBackend(&testPickModelBackend{})
	defer func() {
		voplay.SetModelBackend(prevBackend)
		scene3DPickTestBounds = nil
		scene3DPickTestBoundsPresent = nil
		scene3DPickTestBoundsCalls = 0
	}()
	s := scene3d.New()
	near := s.Spawn(scene3d.EntityDesc{Model: voplay.ModelID(1), Position: voplay.Vec3{Z: 0}, Tag: "near"})
	far := s.Spawn(scene3d.EntityDesc{Model: voplay.ModelID(2), Position: voplay.Vec3{Z: -6}, Tag: "far"})
	_ = s.Spawn(scene3d.EntityDesc{Model: voplay.ModelID(3), Tag: "hidden", PickMode: scene3d.PickDisabled})
	origin := voplay.Vec3{Z: 5}
	dir := voplay.Vec3{Z: -1}
	hit := s.PickRay(origin, dir, 20)
	assert(hit != nil, "scene3d pick ray returns hit")
	assert(hit.Entity == near, "scene3d pick ray returns nearest visible pickable entity")
	assertFloatNear(hit.Distance, 4.0, 0.000001, "scene3d pick ray distance uses nearest face")
	all := s.PickAllRay(origin, dir, 20)
	assert(len(all) == 2, "scene3d pick all ray returns visible pickable hits")
	assert(all[0].Entity == near, "scene3d pick all ray sorts nearest first")
	assert(all[1].Entity == far, "scene3d pick all ray includes farther hit second")
	filtered := s.PickRayFiltered(origin, dir, 20, func(e *scene3d.Entity) bool {
		return e.Tag == "far"
	})
	assert(filtered != nil && filtered.Entity == far, "scene3d pick ray filter selects matching entity")
	assert(scene3DPickTestBoundsCalls == 2, "scene3d pick caches bounds per model and skips disabled entities")
	s.Close()
}

func testScene3DAttachedSpatialAudio() {
	au := &testAudioBackend{nextSourceID: 1, positions: map[int]voplay.Vec3{}}
	prevBackend := voplay.SetAudioBackend(au)
	defer voplay.SetAudioBackend(prevBackend)
	s := scene3d.New()
	s.Camera.Position = voplay.Vec3{X: 0, Y: 2, Z: 5}
	s.Camera.Target = voplay.Vec3{X: 0, Y: 2, Z: 0}
	s.Camera.Up = voplay.Vec3{Y: 1}
	e := s.Spawn(scene3d.EntityDesc{Position: voplay.Vec3{X: 1, Y: 2, Z: 3}, Tag: "speaker"})
	e.PlaySound3D(voplay.AudioClipID(7), 0.5)
	assert(au.playedClip == voplay.AudioClipID(7), "scene3d entity play sound forwards clip")
	assertVec3Near(au.playedPos, voplay.Vec3{X: 1, Y: 2, Z: 3}, 0.000001, "scene3d entity play sound forwards position")
	assertFloatNear(au.playedVolume, 0.5, 0.000001, "scene3d entity play sound forwards volume")
	assertFloatNear(au.playedRefDist, 1.0, 0.000001, "scene3d entity play sound uses default ref distance")
	assertFloatNear(au.playedMaxDist, 50.0, 0.000001, "scene3d entity play sound uses default max distance")
	source, err := e.AttachAudioSource(voplay.AudioClipID(8), 0.7, 2.0, 30.0)
	assert(err == nil, "scene3d attach audio source err")
	assert(source == voplay.AudioSourceID(1), "scene3d attach audio source returns created id")
	e.SetPosition(voplay.Vec3{X: 4, Y: 5, Z: 6})
	s.UpdateAudio()
	assert(au.updateCalls == 1, "scene3d update audio calls backend update")
	assertVec3Near(au.positions[1], voplay.Vec3{X: 4, Y: 5, Z: 6}, 0.000001, "scene3d update audio syncs attached source position")
	assertVec3Near(au.listenerPos, s.Camera.Position, 0.000001, "scene3d update audio forwards listener position")
	assertVec3Near(au.listenerForward, voplay.Vec3{X: 0, Y: 0, Z: -1}, 0.000001, "scene3d update audio forwards listener forward")
	assertVec3Near(au.listenerUp, s.Camera.Up, 0.000001, "scene3d update audio forwards listener up")
	e.RemoveAudioSource(source)
	assert(len(au.removed) == 1 && au.removed[0] == 1, "scene3d remove audio source forwards removal")
	_, didPanic := capturePanic(func() {
		e.RemoveAudioSource(source)
	})
	assert(didPanic, "scene3d removing missing audio source panics")
	source2, err := e.AttachAudioSource(voplay.AudioClipID(9), 1.0, 1.0, 10.0)
	assert(err == nil, "scene3d second attach audio source err")
	assert(source2 == voplay.AudioSourceID(2), "scene3d second attach audio source returns next id")
	s.Destroy(e)
	assert(len(au.removed) == 2 && au.removed[1] == 2, "scene3d destroy removes attached audio sources")
	s.Close()
}

func testScene3DVehicleAudioHelpers() {
	au := &testAudioBackend{nextSourceID: 10, positions: map[int]voplay.Vec3{}, sourceVolumes: map[int]float64{}, sourcePitches: map[int]float64{}}
	prevBackend := voplay.SetAudioBackend(au)
