	assertVec3Near(au.positions[10], e.Position(), 0.000001, "scene3d vehicle audio source follows entity")
	audio.Destroy()
	assert(len(au.removed) == 4, "scene3d vehicle audio destroy removes loops")
	s.Close()
}

func testPrimitive3DModuleContract() {
	pb := &testPrimitiveMeshBackend{}
	prevPrimitiveBackend := voplay.SetPrimitiveMeshBackend(pb)
	defer voplay.SetPrimitiveMeshBackend(prevPrimitiveBackend)
	shapes := primitive3d.NewShapeRegistry()
	rounded := shapes.Shape(primitive3d.ShapeDesc{Kind: primitive3d.ShapeRoundedBox})
	roundedAgain := shapes.Shape(primitive3d.ShapeDesc{Kind: primitive3d.ShapeRoundedBox})
	assert(rounded == roundedAgain, "primitive3d shape registry reuses equal shape desc")
	roundedModel := shapes.Model(rounded)
	roundedModelAgain := shapes.Model(roundedAgain)
	assert(roundedModel == roundedModelAgain, "primitive3d shape registry reuses generated model")
	assert(pb.roundedBoxCalls == 1, "primitive3d rounded box creates one shared rounded model")
	sphere := shapes.Shape(primitive3d.ShapeDesc{Kind: primitive3d.ShapeSphere, Segments: 12})
	sphereAgain := shapes.Shape(primitive3d.ShapeDesc{Kind: primitive3d.ShapeSphere, Segments: 12})
	assert(sphere == sphereAgain, "primitive3d sphere shape desc is cached")
	shapes.Model(sphere)
	shapes.Model(sphereAgain)
	assert(pb.sphereCalls == 1, "primitive3d sphere model is cached")
	assert(pb.lastSphereSegments == 12, "primitive3d sphere forwards segment count")
	cone := shapes.Shape(primitive3d.ShapeDesc{Kind: primitive3d.ShapeCone, Segments: 9})
	wedge := shapes.Shape(primitive3d.ShapeDesc{Kind: primitive3d.ShapeWedge})
	shapes.Model(cone)
	shapes.Model(wedge)
	assert(pb.coneCalls == 1, "primitive3d cone uses cone mesh backend")
	assert(pb.wedgeCalls == 1, "primitive3d wedge uses wedge mesh backend")
	assert(shapes.Revision() == 4, "primitive3d shape registry revision changes on new shape")
	assert(len(shapes.Entries()) == 4 && shapes.Entries()[0].ID == rounded, "primitive3d shape registry exposes table entries")
	materials := primitive3d.NewMaterialPalette()
	red := materials.Material(primitive3d.MaterialDesc{Preset: primitive3d.MaterialToyPlastic, Base: voplay.MaterialColor(voplay.Red), Name: "red plastic"})
	redAgain := materials.Material(primitive3d.MaterialDesc{Preset: primitive3d.MaterialToyPlastic, Base: voplay.MaterialColor(voplay.Red), Name: "debug name ignored"})
	assert(red == redAgain, "primitive3d material palette reuses identical material entries")
	assert(materials.Revision() == 1, "primitive3d material palette revision changes on new material")
	assert(len(materials.Entries()) == 1 && materials.Entries()[0].ID == red, "primitive3d material palette exposes table entries")
	rubber := materials.Material(primitive3d.MaterialDesc{Preset: primitive3d.MaterialRubber})
	assert(materials.Desc(rubber).Roughness > 0.8, "primitive3d rubber preset is high roughness")
	builder := primitive3d.NewBuilder(primitive3d.BuilderDesc{Kind: primitive3d.StaticLayer, Chunking: primitive3d.ChunkingDesc{CellSize: 4}, Name: "builder_contract"})
	builderMat := primitive3d.MaterialDesc{Preset: primitive3d.MaterialToyPlastic, Base: voplay.MaterialColor(voplay.Red)}
	builder.AddPart(primitive3d.PartDesc{Shape: primitive3d.ShapeDesc{Kind: primitive3d.ShapeRoundedBox, BevelRadius: 0.1}, Material: builderMat, Position: voplay.Vec3{X: 0}})
	builder.AddPart(primitive3d.PartDesc{Shape: primitive3d.ShapeDesc{Kind: primitive3d.ShapeRoundedBox, BevelRadius: 0.1}, Material: builderMat, Position: voplay.Vec3{X: 6}})
	builderLayer := builder.Build()
	assert(builder.Shapes().Revision() == 1, "primitive3d builder reuses equal shape descs")
	assert(builder.Materials().Revision() == 1, "primitive3d builder reuses equal material descs")
	assert(builderLayer.Stats().TotalInstances == 2, "primitive3d builder emits layer instances")
	assert(builderLayer.Stats().TotalChunks == 2, "primitive3d builder preserves chunking")
	stream := voplay.NewDrawCtx()
	stream.UpsertPrimitive3DInstance(1, 2, 3, voplay.ModelID(4), voplay.Vec3{}, voplay.QuatIdentity(), voplay.Vec3{X: 1, Y: 1, Z: 1}, voplay.MaterialColor(voplay.Red), true)
	assert(len(stream.Bytes()) > 0 && stream.Bytes()[0] == 0x34, "primitive3d draw stream uses primitive upsert opcode")
	chunkStream := voplay.NewDrawCtx()
	chunkStream.ReplacePrimitive3DChunk(1, 2, 5, []voplay.Primitive3DInstanceDraw{voplay.Primitive3DInstanceDraw{ObjectID: 3, Model: voplay.ModelID(4), Rotation: voplay.QuatIdentity(), Scale: voplay.Vec3{X: 1, Y: 1, Z: 1}, Material: voplay.MaterialColor(voplay.Red), Visible: true}})
	assert(len(chunkStream.Bytes()) > 0 && chunkStream.Bytes()[0] == 0x38, "primitive3d draw stream uses chunk replace opcode")
	materialStream := voplay.NewDrawCtx()
	materialStream.UpsertPrimitive3DMaterials(1, 2, []voplay.Primitive3DMaterialDraw{voplay.Primitive3DMaterialDraw{ID: 7, Material: voplay.MaterialColor(voplay.Red)}})
	assert(len(materialStream.Bytes()) > 0 && materialStream.Bytes()[0] == 0x3A, "primitive3d draw stream uses material table opcode")
	refChunkStream := voplay.NewDrawCtx()
	refChunkStream.ReplacePrimitive3DChunkRefs(1, 2, 5, []voplay.Primitive3DInstanceRefDraw{voplay.Primitive3DInstanceRefDraw{ObjectID: 3, Model: voplay.ModelID(4), Rotation: voplay.QuatIdentity(), Scale: voplay.Vec3{X: 1, Y: 1, Z: 1}, MaterialID: 7, Visible: true}})
	assert(len(refChunkStream.Bytes()) > 0 && refChunkStream.Bytes()[0] == 0x39, "primitive3d draw stream uses compact chunk refs opcode")
	shapeStream := voplay.NewDrawCtx()
	shapeStream.UpsertPrimitive3DShapes(1, 2, []voplay.Primitive3DShapeDraw{voplay.Primitive3DShapeDraw{ID: 6, Model: voplay.ModelID(4)}})
	assert(len(shapeStream.Bytes()) > 0 && shapeStream.Bytes()[0] == 0x3B, "primitive3d draw stream uses shape table opcode")
	keyChunkStream := voplay.NewDrawCtx()
	keyChunkStream.ReplacePrimitive3DChunkKeys(1, 2, 5, []voplay.Primitive3DInstanceKeyDraw{voplay.Primitive3DInstanceKeyDraw{ObjectID: 3, ShapeID: 6, Rotation: voplay.QuatIdentity(), Scale: voplay.Vec3{X: 1, Y: 1, Z: 1}, MaterialID: 7, Visible: true}})
	assert(len(keyChunkStream.Bytes()) > 0 && keyChunkStream.Bytes()[0] == 0x3C, "primitive3d draw stream uses shape/material key chunk opcode")
	chunkVisibleStream := voplay.NewDrawCtx()
	chunkVisibleStream.SetPrimitive3DChunkVisible(1, 2, 5, false)
	assert(len(chunkVisibleStream.Bytes()) > 0 && chunkVisibleStream.Bytes()[0] == 0x3D, "primitive3d draw stream uses chunk visibility opcode")
	layer := primitive3d.NewLayer(primitive3d.LayerDesc{Kind: primitive3d.StaticLayer, Shapes: shapes, Materials: materials})
	id := layer.Add(primitive3d.Instance{Shape: rounded, Material: red, Position: voplay.Vec3{X: 1}})
	assert(id != 0, "primitive3d layer assigns object id")
	stats := layer.Stats()
	assert(stats.TotalInstances == 1, "primitive3d layer stats count instances")
	assert(stats.DirtyRanges == 1, "primitive3d layer marks add dirty")
	changes := layer.DrainChanges()
	assert(len(changes.Upserts) == 1 && len(changes.Removes) == 0, "primitive3d layer drains add as upsert")
	changes = layer.DrainChanges()
	assert(len(changes.Upserts) == 0 && len(changes.Removes) == 0, "primitive3d layer clean drain is empty")
	layer.Set(id, primitive3d.Instance{Shape: rounded, Material: red, Position: voplay.Vec3{X: 2}})
	changes = layer.DrainChanges()
	assert(len(changes.Upserts) == 1 && changes.Upserts[0].Position.X == 2, "primitive3d layer drains set as one upsert")
	layer.Remove(id)
	changes = layer.DrainChanges()
	assert(len(changes.Removes) == 1 && changes.Removes[0] == id, "primitive3d layer drains remove")
	chunkedLayer := primitive3d.NewLayer(primitive3d.LayerDesc{Kind: primitive3d.StaticLayer, Shapes: shapes, Materials: materials, Chunking: primitive3d.ChunkingDesc{CellSize: 10}})
	chunkedLayer.Add(primitive3d.Instance{Shape: rounded, Material: red, Position: voplay.Vec3{X: 0}})
	chunkedLayer.Add(primitive3d.Instance{Shape: rounded, Material: red, Position: voplay.Vec3{X: 20}})
	chunkedLayer.Build()
	assert(chunkedLayer.Stats().TotalChunks == 2, "primitive3d static layer builds grid chunks")
	assert(len(chunkedLayer.Chunks()) == 2, "primitive3d static layer exposes built chunks")
	changes = chunkedLayer.DrainChanges()
	assert(changes.All && len(changes.Upserts) == 2, "primitive3d build drains as whole-layer refresh")
	chunkedLayer.Invalidate()
	changes = chunkedLayer.DrainStaticChanges()
	assert(changes.All && len(changes.Upserts) == 0, "primitive3d static drain avoids whole-layer upsert allocation")
	sceneLayer := primitive3d.NewLayer(primitive3d.LayerDesc{Kind: primitive3d.StaticLayer, Shapes: shapes, Materials: materials})
	sceneLayer.Add(primitive3d.Instance{Shape: rounded, Material: red, Position: voplay.Vec3{X: 0}})
	sceneLayer.Add(primitive3d.Instance{Shape: rounded, Material: red, Position: voplay.Vec3{X: 1}})
	s := scene3d.New()
	handle := s.AddPrimitiveLayer(sceneLayer)
	assert(handle != 0, "scene3d primitive layer attach returns handle")
	d := voplay.NewDrawCtx()
	s.Draw(d)
	pstats := s.PrimitiveStats()
	assert(pstats.TotalInstances == 2, "scene3d primitive stats count layer instances")
	assert(pstats.ShapeMaterialGroups == 1, "scene3d primitive stats group shared shape/material")
	rstats := s.RenderStats()
	assert(rstats.UpsertedObjects == 2, "scene3d primitive first draw upserts layer instances")
	assert(rstats.BatchEligibleObjects == 2, "scene3d primitive instances are batch eligible")
	assert(rstats.BatchGroups == 1, "scene3d primitive shared material produces one batch group")
	d = voplay.NewDrawCtx()
	s.Draw(d)
	rstats = s.RenderStats()
	assert(rstats.UpsertedObjects == 0, "scene3d primitive clean second draw avoids upserts")
	assert(s.PrimitiveStats().DirtyRanges == 0, "scene3d primitive clean second draw has no dirty ranges")
	s.RemovePrimitiveLayer(handle)
	s.Close()
	culledLayer := primitive3d.NewLayer(primitive3d.LayerDesc{Kind: primitive3d.StaticLayer, Shapes: shapes, Materials: materials, Chunking: primitive3d.ChunkingDesc{CellSize: 10}})
	culledLayer.Add(primitive3d.Instance{Shape: rounded, Material: red, Position: voplay.Vec3{Z: -5}})
	culledLayer.Add(primitive3d.Instance{Shape: rounded, Material: red, Position: voplay.Vec3{Z: -2000}})
	culledLayer.Build()
	s = scene3d.New()
	s.Camera.Position = voplay.Vec3{X: 0, Y: 2, Z: 10}
	s.Camera.Target = voplay.Vec3{X: 0, Y: 2, Z: 0}
	s.Camera.Far = 100
	s.AddPrimitiveLayer(culledLayer)
	d = voplay.NewDrawCtx()
	s.Draw(d)
	pstats = s.PrimitiveStats()
	assert(pstats.TotalChunks == 2, "scene3d primitive stats keep total chunks")
	assert(pstats.VisibleChunks == 2, "scene3d primitive stats report uploaded chunks before Rust culling")
	assert(pstats.VisibleInstances == 2, "scene3d primitive stats report retained instances before Rust culling")
	assert(s.RenderStats().UpsertedObjects == 2, "scene3d primitive first draw uploads content chunks")
	s.Camera.Target = voplay.Vec3{X: 80, Y: 2, Z: 0}
	d = voplay.NewDrawCtx()
	s.Draw(d)
	assert(s.RenderStats().UpsertedObjects == 0, "scene3d primitive camera move emits no visibility patch")
	s.Close()
	stress := primitive3d.NewStressFixture(primitive3d.StressConfig{Count: 256, ShapeVariants: 4, MaterialVariants: 8, ChunkCellSize: 16})
	s = scene3d.New()
	s.Camera.Position = stress.Bounds.Center().Add(voplay.Vec3{Y: 80, Z: 90})
	s.Camera.Target = stress.Bounds.Center()
	s.Camera.Fov = 105
	s.Camera.Far = 500
	s.AddPrimitiveLayer(stress.Layer)
	first := voplay.NewDrawCtx()
	s.Draw(first)
	second := voplay.NewDrawCtx()
	s.Draw(second)
	assert(s.RenderStats().UpsertedObjects == 0, "scene3d primitive stress steady frame avoids upserts")
	assert(len(second.Bytes()) < len(first.Bytes()) / 10, "scene3d primitive stress steady frame is compact")
	s.Close()
}

func testScene3DRenderPerformanceContract() {
	ab := &testAnimationBackend{}
	prevBackend := scene3d.SetAnimationBackend(ab)
	defer scene3d.SetAnimationBackend(prevBackend)
	s := scene3d.New()
	for i := 0; i < 1000; i++ {
		x := float64(i % 50)
		z := -float64(i / 50)
		s.Spawn(scene3d.EntityDesc{Position: voplay.Vec3{X: x, Z: z}, Model: voplay.ModelID(77), StaticRenderable: true})
	}
	d := voplay.NewDrawCtx()
	s.Draw(d)
	stats := s.RenderStats()
	assert(stats.ModelEntities == 1000, "scene3d perf stats model count")
	assert(stats.BatchEligibleObjects == 1000, "scene3d perf stats batch eligible count")
	assert(stats.BatchGroups == 1, "scene3d perf stats shared model batch group")
	assert(stats.UpsertedObjects == 1000, "scene3d perf first retained draw upserts all objects")
	assert(stats.FlushCpuMs >= 0, "scene3d perf records retained flush cpu timing")
	assert(stats.FrameCpuMs >= 0, "scene3d perf records frame cpu timing")
	d2 := voplay.NewDrawCtx()
	s.Draw(d2)
	stats = s.RenderStats()
	assert(stats.UpsertedObjects == 0, "scene3d perf retained second draw avoids full scene serialization")
	assert(stats.FlushCpuMs >= 0, "scene3d perf second draw records flush cpu timing")
	assert(stats.FrameCpuMs >= 0, "scene3d perf second draw records frame cpu timing")
	s.Close()
	s = scene3d.New()
	s.Camera.Position = voplay.Vec3{X: 0, Y: 2, Z: 10}
	s.Camera.Target = voplay.Vec3{X: 0, Y: 2, Z: 0}
	s.Spawn(scene3d.EntityDesc{Position: voplay.Vec3{Z: -5}, Model: voplay.ModelID(78), StaticRenderable: true, CullDistance: 50, FrustumCull: true})
	s.Spawn(scene3d.EntityDesc{Position: voplay.Vec3{Z: 200}, Model: voplay.ModelID(78), StaticRenderable: true, CullDistance: 50, FrustumCull: true})
	d = voplay.NewDrawCtx()
	s.Draw(d)
	stats = s.RenderStats()
	assert(stats.ModelEntities == 2, "scene3d perf culling model count")
	assert(stats.VisibleEntities == 1, "scene3d perf culling visible count")
	assert(stats.CulledEntities == 1, "scene3d perf culling culled count")
	assert(stats.BatchEligibleObjects == 1, "scene3d perf culling batch eligible only visible")
	s.Close()
}

func testScene3DOwnedModelLifecycle() {
	freed := &intList{}
	mb := &testFreeModelBackend{freed: freed}
	mb.prev = voplay.SetModelBackend(mb)
	defer voplay.SetModelBackend(mb.prev)
	s := scene3d.New()
	eOwned := s.Spawn(scene3d.EntityDesc{OwnedModel: voplay.ModelID(101)})
	assert(eOwned.Model == voplay.ModelID(101), "scene3d owned model becomes entity model")
	s.Destroy(eOwned)
	assert(len(freed.items) == 1 && freed.items[0] == 101, "scene3d destroy frees owned model")
	eBorrowed := s.Spawn(scene3d.EntityDesc{Model: voplay.ModelID(102)})
	s.Destroy(eBorrowed)
	assert(len(freed.items) == 1, "scene3d destroy does not free borrowed model")
	s.Spawn(scene3d.EntityDesc{OwnedModel: voplay.ModelID(103)})
	s.Clear()
	assert(len(freed.items) == 2 && freed.items[1] == 103, "scene3d clear frees owned model")
	s.Spawn(scene3d.EntityDesc{Model: voplay.ModelID(104), OwnedModel: voplay.ModelID(104)})
	s.Close()
	assert(len(freed.items) == 3 && freed.items[2] == 104, "scene3d close frees owned model when model matches owned model")
}

